begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('eec321cc-9284-5262-af0a-024192820021', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-26', null, null, '通常 / U16作成', 'スライドも締め切りまでに無事提出できたとのことで作品の作成に戻りました。ガチャを引いたときに確率によって色々出るアイテムなどを作っていました。バグやアイデアについて困った点がないか時々質問しましたが、ないようで、順調に手を動かしていました。', null, '時間帯: その他'),
  ('bfb7c0f5-4425-5a66-a0b8-ff75ce6f7471', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-26', null, null, '通常 / 検定', '文章を読むのが苦手そうだったため、鉛筆で順番に示しながら案内したところ途中まで自力で出来そうでした。 最後、学校に入ったアルくんを見えなくする（隠す）方法について、パッと思い出せなくてで苦戦していました。 問題の⑧までは授業時間内に終わりましたが、⑨まではギリギリ終わ離ませんでした。', null, '時間帯: その他
タイピング: 集中して取り組めてました。'),
  ('559921f4-0361-5aa0-b9f1-5683ae3ff114', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-26', '16:30:00', null, '通常 / 検定の続き', '途中までは自分でやれていましたが、問題文の見落としでものすごく苦戦していました。自分では対処出来なさそうだったため、慣れている先生方に手伝ってもらい解決しました。 問題文最初の「旗が押されたら」を見落としていたらしく、 「前文で指示されて作っていたプログラムに全て連結する必要がある」と勘違いしていたため頭を悩ませていた様子です。 時間内に完成したので、アレンジとして魚の敵（ダイバー）を追加しました。 最後、ダイバーが動かなかったり想定通りの動きでは無かったようで、次回修正したいとのことです。 出来なくてイライラしている際は、本人に理由を深掘りするのではなくスプライトを見てアドバイスした方が良さそうだなと感じました。', null, 'タイピング: なし'),
  ('845c40d2-32a2-5c49-a1c3-d57996dadced', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-26', '17:30:00', null, '通常 / 【Prg】08 海にしずんだダイヤを探せゲームを作ろう！', 'プレイヤーのプログラムを組む際、 まだ「合図を送る」のプログラムを組んでいなくて前後関係が分かりにくいにも関わらず、「（緑旗ではなく）ゲーム開始を受け取ってからプレイヤーが動く」の意図をすぐに理解して進められており、良かったです。 シートでは①プレイヤー②ダイヤ③敵④背景で作成してもらう順に表記してありましたが、 このまま②ダイヤに進んでもどこから合図をもらって開始するのか分かりにくいなと思ったため、①プレイヤーの次は一旦④背景を作成させることにしました。結果そこまで詰まることなく一緒に敵の動きまで完成させることが出来ました。', null, 'タイピング: なし'),
  ('933ce770-f779-52a0-94b6-3b8f90ea7b5e', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-28', '16:30:00', null, '通常 / ドリル演習２', 'ドリル21まで進められました。 角度の概念が難しいとのことでしたが、問題19の「90度に変える」は知ってる！と言いながらサクサク出来ていました。 今回は見たところ「表示する」「隠す」のプログラムをどこに入れるかにやや苦戦していたようです。 特に問題21のキーごとの割り当てについて、 割り当て自体はすぐに出来ていましたが、 「隠す」「表示する」をプログラムに組まなければスプライト4種一気に出てきてしまうのに違和感を感じ、どうしたら上手く切り替えられるかを悩んでいました。 そこで、「『◯キーを押したら〜』と『緑の旗を押したら〜』は横に並べて使っても良いんだよ」と教えると、きちんと理解して組んでくれたので良かったです。', null, 'タイピング: 集中して取り組めてました。'),
  ('288cdfb1-6b2b-549f-8909-237a48c6063b', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-31', '16:30:00', null, '通常 / 3級 ブロンズ第18回 応用課題2', '前回作成した問題の魔法のプログラミング部分に続きがあると言っていたため、10分だけ時間を取って検定前に作成させました。 検定の参考動画を見た時、「向きが１からいくらまであるのか？」という変数を気にしてからスタートが出来ていて良かったです。 試験時間残り25分程度で裏面に取りかかれていましたが、最後の 「X 座標が135より大きくなる」のシンプルな組み方がわからず、最終的に試験時間ギリギリまで不等号・の演算をひたすら重ねて力技で解決しようとしていました。 「（X座標＞135）まで繰り返す」という答えを見せると、すぐ納得したようでした。 もしかすると以前習ったことの一部を忘れているのかもしれません。', null, 'タイピング: 集中して取り組めていました。'),
  ('c68e75af-6659-5723-956a-622e1b2e8bb8', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-31', '16:30:00', null, '通常 / 応用課題③ E017', '試験を受けることにあまり前向きではなさそうでしたが、 本番さながらであることを伝えると、しばらくしたらといつもより静かに取り組めているように姿勢を変えれていました。 こちらの不手際により本人にタイピングでの入力をさせる形になってしまい、試験時間が過ぎての完成となりました。 文字入力以外にも質問してきましたが、すぐ自己解決して黙々と取り組めており、 プログラミング自体はあまり問題無いのかなと感じました。', null, 'タイピング: PC画面の拡大縮小が勝手に動いてしまう動作バグに気を取られ、あまり集中できていなさそうでした。'),
  ('11bf49c2-ad12-5d60-9391-4f006ff5ceef', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-31', '16:30:00', null, '通常 / バイクラン完成', '前回残りの足場作りから始めましたが、とてつもなく集中力がなくなっていました。続いていたのは、飴を食べ終わったら次の雨を食べることくらいです。それくらいコード作成が途切れ途切れになっていて、最初の30分はあまり進みませんでした。後半は、一通り出来上がった後に、バグを直していきました。なかなか見つからず飽き飽きしそうでしたが、なんとか起こっている個所を誘導していかないと、進ませる気力が保たないです。', null, '盛り上がり: りょうやくんとのあおりあおられあいがほんと多いです。'),
  ('e3720372-73eb-5ee9-a561-b0eaaa5cbb88', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-31', '16:30:00', null, '通常 / エラー解決を楽しむ', '検定へのやる気があまり出ない状況だったため、「エラーで学ぶスクラッチ」に取り組みました。クイズのような形式でやると興味を持って進めてくれました。色々と試行錯誤して直しかたを考えていました。「ではないまで待つ」を一度やっていたため、ここの問題でも活用することができました。', null, '盛り上がり: 何回か集中が切れることはありましたがある程度頑張って進められました。'),
  ('5756b765-24cf-5ad9-b7c3-4fd14dcd97c8', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-31', '17:30:00', null, '通常 / U16作成', '書類提出が終わったので作品作りに戻りました。書類を出せたのが期限ギリギリだったとのことでねぎらいました。「たぶん書類選考が通らない」と消極的でしたが、ストーリーが面白いから可能性あるよと自信を持ってもらいました。作成は集中してできていました。', null, null),
  ('2d33a056-cdc9-5e1e-a9ac-8150d631d187', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-31', '17:30:00', null, '通常 / 演算の定着', '検定練習で演算の部分が慣れていなさそうだったため、単元別演習で細かく確認していきました。不等号はすでに習ったそうで、大小の向きもしっかり把握していました。ジャンプの変数やコスチューム番号といった難しい内容について等号や不等号をうまく使うことができたため、演算の応用力が身に着いたようでした。ゲーム内で虫が落ちてくる部分に少し困っていましたが、基本操作コースのキャッチゲームを思い出してもらうとできました。ここでも不等号が出てきましたが意味を理解していました。', null, null),
  ('8a6868e8-29a6-52b6-9562-4a68516c4e19', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-31', '17:30:00', null, '通常 / 「ではないまで待つ」を習得しよう', 'だるまさんが転んだの同様に、最初に細分化してゲームを楽しんでもらいました。それぞれの動きを把握はできていたので、あれこれ先にならないように、作るスプライトの順番を指定して作っていきました。連打の仕組みで「ではない」が使えそうな発想が出ていたが、どのように組むべきか悩んでいました。そこで、長押しと連打の違いを質問していくと、自らキーから離すことに気づけたので、それを形にしていけました。 次の順位付けのところは、「ではないまで待つ」より構成がうまくいかず、変数の使いどころ悩んでいました。こちらがアウトラインのヒントを与えても、組む順番に苦戦していました。少しコードの順序の組み立てが少し苦手な感じがします。その意味では検定練習はそこが鍛えられるのでいいと思います。', null, 'タイピング: 集中して打ててました
盛り上がり: ゴールしたら風船を飛ばすアイデアもよかったです。'),
  ('80469566-f022-543a-b762-f768857b3eab', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-31', '17:30:00', null, '通常 / 定義の基礎を学ぼう', '前回、定義の使い方があいまいな感じしたので、エキスパートにある掛け算とプログラムをまとめることをやっていきました。本人的にも引数の使い方がいまいちなところがあったので、簡単な計算問題作り身についていました。リストと組み合わせたものだったが、スムーズに作れていました。また、まとめる方では一文字ずつ繰りだす方法も教材であったので、参考になったそうでした。', '検定', 'タイピング: ほんと高速ですね'),
  ('b53196db-aa34-5d22-94b5-886116360d85', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-25', '16:30:00', null, '通常 / 自分のスキルチェックを兼ねて検定にチャレンジ', 'やる気はあるのですが、基本的に、常に先走って問題をきちんと読まない傾向があります。その結果、動きがおかしいと気づくと自己流で直そうとしていました。 結果としてコードを訳の分からない状態にしそうだったので、途中で声掛けをし、一度腰をすえてとにかく文章を頭から読んで、その通りに作成することが試験の主旨であり、今後もっと複雑なプログラミングができるようになるためにも、その訓練をした方が良いと伝えました。話は素直に聞いてくれて、声掛けをすると問題文を読み直してくれるようになりました。 それでも、黙って見ていると先走っていることが何度かありましたが、次に取り組んだ応用課題1では少し慣れてきて落ち着いて問題を読むことができるようになっていました。たいようくんも、これが本番なら受かるかも、とうれしそうでした。 「すべてをとめる」の3種類の使い分けがわかっていなかったため、何度か説明し、ようやく納得できたようでした。 お母さんによると、プログラミングは好きでもテストに受かるという自信はあまりなくて不安がるとのことだったので、今回は無理に飛び級をせずに4級から受験すること、受験を通して、自己流で先走らないで1つ1つをじっくりと考えるえ訓練にしようということで親子ともに合意しました。', '自己流で学習してきたため、本人が「できる」と言っていても、意外と抜けているスキルがあると思われます。楽しんで自己学習してきた反面、へこみやすいところもあるようなので、まだ完全にテスト形式ではなく、あと1～2回はスキルのすき間を埋める感じでやってあげた方が今後のモチベーションにつながるかと思われます。', '盛り上がり: プログラミングに対して饒舌なわりに、テストというと不安なところがあったようですが、2つ目の課題で少し慣れてくると、合格できるかもしれない！と何度も言って、楽しくなってきたようでした。お母さんにも、少しできるようになってきた！と嬉しそうに報告していました。'),
  ('0efe6ef6-ab78-51e4-aa1a-6c49ed2be3d6', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-25', '17:30:00', null, '通常 / U16大会のスライド完成、提出', '大会用のゲーム作成を進めたくて、スライドの最終確認を促してもすぐにScratchに戻るという繰り返しでした。 それでも授業時間終了間際になるとさすがに焦ったのか、頑張って修正や加筆を始め、授業終了後20分くらいでなんとか提出まで終えることができました！', null, '盛り上がり: 作品を作っているときがとにかく楽しそうで、スライド作成にはなかなか気が乗らなかったようでしたが、完成したときはさすがに嬉しそうで、やり切った！という感じで帰っていきました。'),
  ('543d4375-9bd7-5a62-818b-0cc9db2a6e15', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-25', '17:30:00', null, '通常 / U16大会のスライド完成、提出', '授業時間中は、プログラムの未完成部分でスライドに画像をはりたいところがあるからといって、コードは後回しにしてスプライトの画像部分だけを突貫工事で作成していたようでした。本人としては「スライド作成の為」という名目があったとしても、はたから見るとスライドではなくプログラムの方を作っているように見えるため、巡回中の先生からスライド作成を促されることもあり、少しイラついた様子も見せていました。授業時間中盤、お腹が痛いといってトイレに10分以上こもっていたりもしました。 作成の順序について本人のしたいように任せてからは、熱中しつつ機嫌よく作成も進み、提出前には先生たちに声をかけて見てもらいたそうにしていました。 20時ごろまでかかってようやく提出できたら、雄たけびをあげたり床にはいつくばったりして感動していて、相当嬉しかったようです。出すまでは、賞状より副賞だ、結局お金が一番うれしい！などとイキがって？言っていましたが、終わってからは、賞品もどうでもよくなって、この達成感がたまらない、と感慨深そうに言っていました。', null, '盛り上がり: 普段の作品も、途中までのアイディアは凝っているのに、最後は「もうこれで完成！」と大人から見ると半端なところで切り上げてしまうことが多い印象がありましたが、今回のスライドは、本人としてはギリギリまで頑張ってやり切った感が持てたようで、完成できたことにとても喜んでいる様子でした。
備考: お腹の具合が悪くなりやすいところがあるようで、一度トイレに入ると長時間出てこないことが多いです。お腹の具合は本人にはどうすることもできないので仕方ないのですが、それでトイレを我慢して、ギリギリになってしまう低学年の子が、ゆうまくんの後に慌ててトイレに駆け込んでトイレを汚してしまうパターンに二度遭遇しました…。'),
  ('072253f1-02a0-5383-92bd-8b5a80e74108', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-25', '18:40:00', null, '通常 / U16大会のスライド完成、提出', 'ゆうまくんと席が近かったせいか、同じ中学生ということで馴染んだのか、二人でしゃべりながら進めていました。スライド自体は文章は少なめでシンプルですが、画像をたくさん使用して見やすいスライドに仕上げていました。 オンラインの授業に参加したころは、PCの立ち上げからZoomへのログイン、教材の準備など、先生を呼んで頼りたがることもありましたが、回数を重ねて慣れたのか、提出の一連の流れを大人に頼ろうとせず自主的にやっていたところに成長を感じました。', null, '盛り上がり: 時間内にきっちりと提出することができ、満足そうにしていました。'),
  ('9cfbd2c0-0c2d-59f1-9a2d-ad44a72964fd', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-25', '18:40:00', null, '通常 / Excelの検定準備', '計画では模擬テストの予定でしたが、開始前に本人に確認したところ、関数から先は未履修とのことだったので、始めに軽く説明をすることにしました。 実技問題１の完成例から関数とグラフを削除して、関数の入れ方と数式のオートフィルを説明しました。オートフィルは面白かったようで、しきりと感心していました。 3級範囲の関数や範囲指定は特に問題なく、すぐに習得できました。 IF関数については、オンライン授業でも使ったといって、興味深そうに聞いてくれて、スムーズに理解できていました。 グラフの作成や書式設定も大体覚えられたようでした。', null, '盛り上がり: 動画視聴の学習では、よく眠そうな様子を見せていましたが、今日の履修範囲はExcelの面白さを感じられたのか、終始熱心に取り組んでいました。関数の理解はさすがに速かったです。'),
  ('2680bc96-66c9-53a0-bca1-35a8d06ae327', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-28', '17:30:00', null, '通常 / 検定4級1回目にやる問題', '検定の説明を一通りし、本人の希望も合って取り組むことになりました。 躓きやすいところを伝えてから取り組んでもらい、おおよそ自力でプログラムすることができました。「a, bの順に～～」などの独特な言い回しには少し困っていたようですが、時間内に取り組めていました。最後、アレンジまでプログラムし、紙にアレンジ内容を書くこともできていました。', null, 'タイピング: 得点も高く、集中して取り組めました。'),
  ('77c0412f-fbf8-5095-a3bd-0b77467adde7', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-28', '17:30:00', null, '通常 / 検定4級1回目にやる問題', 'プログラムする場所、順番など注意事項を伝えてから始めてもらいました。プログラムのスキルは問題がないようでしたが、文章の内容をプログラムにリンクさせるのが難しかったそうです。また自分から文章を積極的に読むことにもなれておらず、こちらから促すと取り組むことができました。 もう少し練習が必要かな？と感じました。', null, 'タイピング: 集中して取り組めました。'),
  ('5b5608b7-fad7-5161-8ca8-29d267f6dc0a', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-28', '16:30:00', null, '通常 / ドリル続き', '角度や座標のプログラムを復習しました。やる気もなく説明しても理解しきれない様子でした。作りたい作品があるのかと思って聞いてみましたが、そういうわけではないようです。動きよりも、大きさや音を鳴らす方が楽しそうでした。今回はドリル4問を取り組むことができたので、やりきれたという面では良かったです。', null, 'タイピング: 集中して取り組めました。
盛り上がり: 目的の作品を決めて作る方が好きかも？'),
  ('9a09ae36-10cf-52b2-833f-5302fc0b7604', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-28', '16:30:00', null, '振替 / 検定4級応用課題', 'メッセージが「送られ」の日本語のニュアンスでつまずきました。ブロックの「メッセージを送る」に内容が結びつかない様子でした。また、「～とき、そうでないとき～」が「もし～」と結びつかないようでしたが、これは「そうでないとき」を久しぶりに見たので忘れていたのが大きいようでした。 また日本語の量が多いと時間がかかる＆つまる様子。「まで繰り返す」のとき「ずっと」をいれてしまうこともあったので、特に強調して説明をしました。', null, 'タイピング: 集中して取り組めました。'),
  ('a156d635-41ba-5827-a637-a45b51b6c784', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-28', '17:30:00', null, '通常 / 検定2級練習', '時間を少しオーバーしてしまいましたが、時間中ずっと集中して取り組むことができました。変数の値のミス、制御ブロックの順番などのうっかりミスがあり残念でした。「クリックしたとき」のプログラムを手数多い方を使っていたので、ポイントを伝えて訂正してもらいました。 検定問題でしたが、プログラム全体の流れをおうことができていたので非常に良かったです。うまく動かない部分を自分で積極的に探すことが出来ていました。', null, 'タイピング: 集中して取り組めました。
盛り上がり: バイクランで1位になり、とても嬉しそうでした！'),
  ('0429b0c1-ee81-5681-b3bb-6760f72ea0e9', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-26', null, null, '通常 / 新しいタイプの検定問題にチャレンジする', 'ムービーを見た時の反応は、これなら作りやすそうといった感じでした。 時間には少し余裕を持って終わらせていましたが、動きがおかしいところがあるということで一緒に答え合わせをしていきました。その結果、以下の問題点が見つかりました。 ・割り算の記号がわからず、演算ができていなかった。 ・○○に向けるが思いつかず、ブロックを組み合わせて複雑なことをやろうとしていた。 ・割った数の切り下げの意味がわからず、割った余りのブロックを使っていた。 上記の解説後は、すべてきちんと動くようになり、本人も納得できたようでした。 デザインなどをうまく作り上げることができるせいか、自分の知っている範囲でなんとなく見た目のよい作品を仕上げることができていたので、こちらの想定外のスキルが抜けていたりすることが判明しました…。特に演算系のブロックは未履修だったようなので、もう少し類題をやっていけると良いかと思われます。', null, '時間帯: その他
盛り上がり: 知らなかったというブロックの説明をしたときは、スッキリした！といった感じでした。2級に取り組み始めたころほどの拒否反応はなく、前向きに取り組めていたと思います。'),
  ('74458c94-76ed-56a7-bc1e-1283f6eaa42d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-26', null, null, '通常 / Excel模擬テストに取り組む', 'テスト開始前に、簡単に履修が済んでいない項目の有無を確認しました。 関数名がよくわからないとのことなので、平均、最大、最小、IFなどを軽くおさらいしました。基本的に関数はウィザードからではなく手入力したいようでした。関数名を教えると、楽しそうに入力できていました。オートフィルや絶対参照は、興味深そうに覚えていました。スパークラインの作成を説明した後は、一人で進められていました。', null, '時間帯: その他
盛り上がり: Excelはわりと好きなのか、熱心に取り組めていました。'),
  ('a6c3fb4f-9eeb-579c-bae9-b3594d1e138e', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-26', null, null, '通常 / 検定問題に慣れる', '一文が短い問題で、読み飛ばさずにしっかり問題文を読む練習をするという目的は達成できたかと思います。 「まわす」と「むける」を混同しているところがありました。もう一度くらいおさらいできると良いかと思われます。 条件分岐の使い方は慣れたようで、特に問題なくできていました。', null, '時間帯: その他
盛り上がり: ハロウィンのためか、スパイダーマンのマスクをかぶって来室しました！ 検定問題終了後もスパイダーマンのゲームを探して楽しそうに遊んでいました。'),
  ('6b5fd6ae-6b9c-5cc5-a6c5-d44c70b4963c', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-01', '16:30:00', null, '通常 / 「～まで繰り返す」の復習も兼ねて、ゲーム作成', '検定の練習が2回続いたので、今日はゲームを一つ完成させようと伝えました。一日で完成させるということにしり込みしていたので、勉強したいコードだけ作成しようと誘うと、それならと乗り気になってくれました。 完成版から、「～まで繰り返す」が使用されているコード、プレイヤーの左右の動き、カミナリのクローンの動きなど、メインとなるコードのみを削除して、どのような動きをしていたか思い出させて文章化し、それを元にコード作成をしてもらいました。 カミナリのクローンのコードではクローンを削除するブロックをどこに入れるか悩んだり、ゲームオーバーのときのコードで「触れたではないまで繰り返す」が思いつかなかったりで少し手こずりましたが、辛抱強く考えて、ヒントを受けて完成させていました。 こちらが出した課題が完成したら、残り時間は楽しそうにアレンジをしていました。', '検定準備に戻ると予告してあります。', '盛り上がり: 検定準備の合間の良い気分転換になったようで、楽しそうに取り組めていました。'),
  ('76aa7cc8-8396-5eae-816c-3e8357103d79', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-01', '17:30:00', null, '通常 / 「検定」の形式に慣れる', 'はじめに検定とはどういうものか説明し、今日は検定問題が集中してできたら残り時間は自由にしようと約束してから始めました。 結果として、今回の問題にはセリフとメッセージが多く、日本語入力でかなりの時間を取られてしまったため、ほぼ授業時間全部を使って完成させることになりましたが、自由時間がなくなったのは気にならなかったようで、一生懸命に取り組むことができていました。（最後の4つくらいの日本語入力は、こちらが手伝いました） 「〇秒で座標を〇〇にする」を忘れていて、「〇秒待つ」「座標を〇〇にする」と２つのブロックを使っていました。動きがおかしいことは自分で気が付いていて、他にブロックがあったよね、というヒントで思い出すことができました。 一か所だけ、「メッセージを受け取った時」の後に書くべきコードを「旗がおされたとき」のコードに続けて書いていて、動きがおかしくなっていました。問題文の最初の読み落としに注意するように伝えました。 それ以外は自力でできていました！', null, '盛り上がり: 今日は結局、途中先生の名前を聞いてきたり、あさひくんが話しかけてくるのに答えたりする以外は、席に座って学習することができていました！本人も達成感を得られたのか、お母さんにも報告して完成した作品を得意げに見せていました。'),
  ('6fb49e47-9975-5e9b-8a7a-112c68d49934', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, 'c6e0a59d-ba8e-5893-a589-60b736d38bfe', '2024-11-01', '16:30:00', null, '通常 / アルスタジオレッスン「ゾンビを倒せ」', 'ゾンビを倒せ１で、スペースキーでビームを発射して右端まで動き続ける処理で少し手間取ったものの、ヒントを与えたら、いろんなことを思い出したみたいで、一気に作り上げることができました。さらに、自分でアレンジして、ゾンビに体力を変数で持たせて、それが減っていって０になったら終了するプログラムを自分で追加していました。実はそれが、「ゾンビを倒せ２」のレッスンだったため、一気に、２つのレッスンを終了した事になり「ゾンビを倒せ３」に進みました。これは、ビームをクローンで作成して左端に着いたらクローンを削除する処理のレッスンです。これはなかなか難しかったようで、クローンを作る処理と、クローンを作られた時の処理で分けて考えるように伝えて、なんとか作成完了することができました。ただ、クローンの扱い方をきちんと理解したかはまだ微妙な感じだと思うので、もう少し細分化して教えるべきだったなと反省しています（私自身もクローン処理のスクラッチでの本質を完璧に理解しておらず、すみません勉強します。普通のプログラミングでも似たような処理がありますが難しいところです...）', null, null),
  ('8ca308b3-53cc-51a5-8800-a4046256cbef', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-01', '18:40:00', null, '通常 / Excel検定の準備', '今日はとても疲れていたようで、途中何度か転寝をしていました。 それでも途中からは何とか起きて頑張っていました。 セルを結合して中央揃えを説明しました。 フォントやセルの色をパレットから選ぼうとしていたので、問題文中にある「〇行〇列目」のヒントがわかりやすいツールバーから色を探す方法を教えました。 問題文に書いてあった比率の計算式の入れ方を知らなかったようなので、Excelの計算式の入力方法（=から入力する）や、絶対参照を教えました。 さすがに、演算式の理解はわりと早かったです。', '問題2の(7)以降、スパークライン、グラフ、抽出などをやる予定', '盛り上がり: とても疲れていたようで、途中は何度声掛けをしても、話しているそばから目がとじるくらいでしたが、後半はしっかりと起きて、わからないところを質問してくれて、説明もしっかりと聞いていました。計算式の入力の方が、単調ではなくて眠くならないようでした。'),
  ('cae65245-cacb-5314-88a2-b4e2cff9e38d', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-01', '17:30:00', null, '通常 / 検定3級応用課題２', '音を鳴らす処理の、「”終わるまで”音を鳴らす」という部分で少し時間がかかってヒントを上げてできたようですが、それ以外は特に問題なくできていたようで、１０分余らせて３０分で完了させることができました。答え合わせも１００点でしたので、このレベルはきちんと理解できているのかなと思いました。', null, null),
  ('eddaf742-c469-5785-aab7-570f278510e5', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-01', '18:40:00', null, '通常 / だるまさんが転んだの続き', '先週は、だるまさんが転んだの途中で終了していたので、勝ち負けの処理を作るという、続きからスタート。最初は、負けの処理の作成から、かなり噛み砕いて、自分の手でプログラムを作成するようお話をしたのですが、どのブロックを使うかを自分では判断できず、さらに前半はやる気もだいぶ低下しているような状況でしたので、このブロックを使ってみたらと、半分答えを教えながら進めて、なんとか負けの処理を作成。それができたらやる気が出てきたのか、勝ちの処理も、負けの処理と同じように作れば良いと教えて、なんとか負けの処理を参考にして、ちょっとのヒントで勝ちの処理の作成はでき、だるまさんがころんだは完了しました。その後は、アレンジしてみたらと促しましたが、休憩モードで遊んで終了となりました。', null, 'タイピング: 集中して取り組んでいました'),
  ('e41131b2-c3dc-5713-b8da-528d9c637e43', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-29', '17:30:00', null, '振替 / 検定練習', 'しっかり時間を計って検定練習を行いました。「この一文がわからない」という場所があったようですが、本番の環境に近づけるために「一旦そこは飛ばして、解ける場所に集中しよう」と伝えました。結果、そこ以外のミスはほとんどなく、集中して最大限できていました。こんな感じでやれば合格圏内には入れると自信をもってもらいました。', null, null),
  ('232dc4c7-11ec-5949-9639-8cb08b45eb1a', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-29', '17:30:00', null, '振替 / 検定練習', '緊張感を持ってもらうため、本番に近い条件で検定練習を行いました。ギリギリまで迷っていた場所が1つだけあったようですが、粘り強く考えて時間最後で正解を導けていました。前回までで「文章の読み落としや読み間違いがないように丁寧に読んでいこう」と言われたのをきちんと覚えていて、それを意識してやってくれたとのことでした。答え合わせをするとパーフェクトで、成長に喜んでいた様子でした。', null, null),
  ('7331f7df-af8c-5304-9cca-57dd7546b2a9', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-02', null, null, '通常 / 検定の問題に慣れる', '前回、演算式のスキル不足が確認できたので、抵抗感をなくすため、最初に修正問題の演算式のところを一緒にやっていきました。前回のことをよく覚えていたようで、さほど困惑することもなく、問題文の日本語の順に使用するブロックをプログラムエリアに持ってきて、うまく組み合わせることができていました。前回未履修で困惑していた割り算や割り算の余り、切り下げなども、ブロックをきちんと覚えていました。 ゆうかちゃんが不安なときや、良く分からないときにいう「え？！」というつぶやきもなく、話しながらスラスラ解けていくのが楽しそうに見えました。 修正問題を一緒に解き終わり、「これだけできればもう大丈夫」と声掛けをして残りは自走させましたが、苦戦もせずに最後まで解き終わったようでした。 最後の動作確認でハンマーが自動で叩きまくるバグがあり、ひとしきり「スマブラみたい」とウケた後で、問題文の最初の「マウスがおされたとき」を入れ忘れていたことにすぐに気づいて直すことができました。 もう一か所、変数名の間違いがあったところもすぐに自分で気づいて直すことができました。 今回の作品は可愛くて楽しかったと言って、残り時間はアレンジを楽しんでいました。', '今回のアレンジが終わっていないのと検定問題が続いたこともあるので、次回は今回のアレンジの続きをさせてあげてください。', '時間帯: その他
盛り上がり: 今日の作品はゆうかちゃんが好きそうと思って選んだのですが、予想通り気に入ったようで、テスト対策というよりも、楽しく取り組めたようでした。 久しぶりにゲーム作りやアレンジの楽しさを味わうことができたのではないかと思います。'),
  ('05672dc4-9727-5f65-9877-2fc4d8462c4b', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-02', null, null, '通常 / 検定練習', '最初の動画の時点で、面白そうな感じで受け取っていたので、作るやる気は満たされていました。「までの距離」の知らないブロックについて、すぐに聞いてくれたのはありがったです。ほんの不等号のミスくらいだったので、能力的には成長していけました。あとは時間は少しギリギリなところもあるので、その辺は余裕が持てたらいいと思います。', null, '時間帯: その他
盛り上がり: アレンジで球の速度や変えてはまって最後まで遊んでいました。'),
  ('73e993cf-bea9-5e4b-8721-fe05e9d3a054', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-02', null, null, '通常 / 検定練習', '最初に、少し遊ぶ時間を設けたので、検定にうまく切り替えられていました。検定の内容は、物語型でした。やっている最中は、しっかりと集中して最後まで、誰ることなくできていました。「できた」と見せに来たときは、動画と飲み比べで、コスチューム変化がうまくできてなかったので、そこは前向きをもって気づけて直していけました。最後のコスチューム変化が止まることができていなかった些細なミスは、若干ぐずりそうになりかけったが、復習した時と同じ間違えだったので、直せませした。直しの作業も含めて、30分以内にすべて完成できたので、大きな一歩になりました。 コードを停止させるブロックの認識がまだ甘いので、最初に復習してもらえるとたすかります。', null, '時間帯: その他'),
  ('5b98fa7a-20f7-5231-a2db-a5c5d21e2664', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-02', '16:30:00', null, '通常', '終始、本人的には簡単すぎて、飽き飽きしているらしいです。', null, null),
  ('3403b0ae-1502-5e7e-9b35-da609bc385a2', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, null, '2024-11-02', '17:30:00', null, '通常', 'エクセル模擬試験2', null, null),
  ('ed125b90-b38a-5839-bb75-a732a949d44a', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-02', null, null, '通常 / 【Prg】09 ネコから逃げろゲーム', '完成系を見せただけで、どのように進めるかのイメージを掴めたのか、スライドの１ページ目から何も言わずとも自分の力だけでプログラムを始めました。途中「ネコチーム勝ちフラグ」って何？と言われたので、変数だよと教えたら、ネズミが猫に触れた時にこのフラグが１になって、このフラグが０から１になった時に、猫がネズミを捕まえた時の処理をすると即座に理解したようです。（小１レベルだと結構すごい理解力だと思いました）。何かものに触れた時に、変数を変えて、変数が変わったら、それに応じた処理をするという基本的な流れはしっかりと対応できていました。スライドの通りのコードではないですが、それなりに動くものはできたと思います。ゲーム開始イベントの処理はやらずじまいですが、やろうと思えば問題なくできると感じます。', null, '時間帯: その他'),
  ('726237c8-1552-5c47-8606-e65b9e8a39ee', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-02', '17:30:00', null, '通常 / 検定練習', '何度も積み重なっているので、今回の問題は、30分もかからずに、ノーミスで完成することができました。アレンジもカニを倒せる仕組みを作って、アレンジ店の評価も大丈夫そうです。', null, null),
  ('0a48de40-c35b-539c-9a23-b161ad4afe6e', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-02', '17:30:00', null, '通常 / 検定練習', 'ハンバーガーのリスト系の問題でしたが、40分くらいで1通りは終わりました。しかし、バグが残っていたので、バグの詳細を訊いてみると、うまくいかない条件を見極めてられていました。そこから、コードを修正するのはすぐだったので大丈夫でした。今回の問題は簡単らしいのので、リスト系は大丈夫です。', null, null),
  ('4b73a46d-3c76-5968-8315-b2ccca717907', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-02', null, null, '通常 / 検定4級②魚とサメの追いかけっこゲーム', '検定4級②は、２回目でしたが、正解率は60%いっていたか微妙な感じでした。特に以下の点、次の週も覚えていられたか、復習確認したほうが良いかなと感じました。（１）②「サメに触れるまでの繰り返し」の部分、繰り返しがついたブロックを選択できておらず、「マウスポインターへの位置へ動き続ける」の部分を、完全に忘れていました。それに対応するブロックが存在することも覚えていないような感じを受けました。（１）②「（魚が）ステージから消える」に対応するブロックが「隠す」であることがわからなかったようです。（２）③「⓵のあとの動作」と記載されていましたが、直前に説明されてたブロックに処理をくっつけてしまっていました。大きなミスとしてはこれらです。', '次回はこれらを復習した上で、次の検定問題に挑戦するので良いかなと思います。', '時間帯: その他
タイピング: ホームポジションを意識しつつ集中して取り組んでいました'),
  ('a337bc30-22c2-533b-8883-21e461938299', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-02', null, null, '通常 / 前回の検定の答え合わせと演算について', '前回、検定２級②が完了できず、自分の手のコスチュームが切り替わらない状態だったので、その修正から。問題文とにらめっこして無事、自分の力で修正完了して、答え合わせをして問題なしでした。余った時間で、G演算の問題に挑戦。G-1「滑らかにジャンプ」で、滑らかにジャンプさせる方法がイメージが湧かないのかだいぶ長い間悩んでいるようだったので、「ジャンプはやさ」という変数を作って、それでY座標を変化させることで、ジャンプを表現するというヒントを与えましたが、まだそれでも、うまくいかないようでした。変数の値をマイナスにしないと飛びっぱなしになってしまうのですが、マイナスにしなくちゃいけないというのに気づくのに時間がかかっていました。最終的には完成して、G-2の途中で今日は終了となっていまいました。次回は、ジャンプの際の変数操作について念のため、復習して、身についているかどうかを確認したほうが良いかと思います。', null, '時間帯: その他'),
  ('54669372-3f66-5277-9292-9727b59e479d', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-29', '16:30:00', null, '通常 / ゲーム完成', 'シューティングゲームの完成を目指して作成を進めました。集中しつつも、いろいろなスプライトをニワトリ関係のものに変えたりして、楽しみながら進めていました。残念ながらあと少しのところで終わらなかったのですが、来週もう一回来て終わらせ、アルスタジオの好きな作品を持って帰るという作業もすることになりました。', null, null),
  ('96e3899d-bc13-5f0e-b8bc-2cb4931955cc', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-04', '16:30:00', null, '通常 / 検定練習', '今日は先週と比べると、最初の方はやる気が上がっていました。わかるところは集中して自力で進めることができましたが、わからないところがあるとすぐ嫌になってしまうようでした。問題文の日本語が長かったり、少し言葉が難しかったりするときちんと読めなくなってしまっていると思われるため、文とブロックを対応させて理解する練習をしたほうがよさそうです。', null, null),
  ('16af3f01-d62f-5953-b1ed-831a260f5eef', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-10-29', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('7ff754f4-6b19-5503-be30-684722b4f1e4', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-05', '16:30:00', null, '通常 / 検定練習', '前回解いた検定類問に間違いが残っていたため、問題文の日本語と正解ブロックの対応を確認していくことで間違い直しを行っていきました。そうしていくと、問題の「ずっと繰り返し、以下を行う」に対応するブロックがないことに気付くことができました。コードが修正できるまではゲームがバグっていることに少しイライラしていましたが、バグが全て直ったあとは冷静になり、今日の振りかえりなどについてしっかりお話することができました。丁寧に文章を読んでブロックに変換していくこと、そしてたとえバグがあっても6割取れていれば受かるから気にせずできるところをやればいいことを理解してもらえました。', null, null),
  ('63de05cc-c85b-5e32-af4a-da7e0ead69a2', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-05', '16:30:00', null, '通常 / ゲーム完成、作品移植', 'まずは先週の続きのシューティングゲームを終わらせ、そのあと好きなアルスタジオの作品を自分のスクラッチアカウントに移植していきました。シューティングゲームを含めお気に入りの作品がいくつかあったようで、それらを移していきました。最終回らしく、心置きなく楽しむことができました。', null, 'タイピング: 集中していました'),
  ('75d5acfe-b75e-5134-95b0-44cc5c417c58', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-05', '16:30:00', null, '通常 / 検定練習', '久しぶりだったので難しくなさそうな類問に取り組みました。集中して解き進められました。一か所だけ「スプライトのコスチューム名」ブロックが慣れておらずミスしていましたが他はおおむねできていました。', null, null),
  ('67dd3cc9-307d-55bf-b512-401129d420d0', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-01', null, null, '通常 / U16大会の作品続き', '体力を示す変数がバーになっていたので指摘しました。変化量が見やすいという理由で採用していたようですが、画面上でバーを動かすと変数の値を変化できてしまうことを共有しました。本人的にはバーを採用するようです。 他の細かい点を調整していました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('2d15f505-a342-53bb-b69e-04ad0abb68b2', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-01', '17:30:00', null, '通常 / 検定2級応用課題3（S012_スロット）', '前回の検定練習から時間が空いてしまったので、完全な答え合わせよりかは注意点、自分の苦手な部分を一緒に確認しました。また応用課題3の問題文を見て少しビビッていたようですが、ほぼ時間内に解き終えることができました。変数名のミスと、制御の考え方のミス（日本語とプログラムが連動しきれていない）がありましたが、その他はおおよそよくできていました。このまま練習を積めば大丈夫かな？という印象です。', null, 'タイピング: 集中して取り組めました。'),
  ('b4fea306-71f8-595c-a4fc-2b9d6cfc4158', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-06', '17:30:00', null, '通常 / U16大会作品の作成続き', 'バッテリー部分やエンディング部分をプログラムしていました。ほぼ作成したようです。何度か声掛けをしましたが「大丈夫！」と言っていました。検定も受けたいようなので、次週以降、検定準備＋作品準備がよさそうです。ただ家でU16大会作品にも取り組んでいるようなので、少しこちらからアドバイス等が必要かもしれません。', null, 'タイピング: 集中して取り組めました。'),
  ('8b218bf1-9ac8-5b25-afe3-556369e9269d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-01', null, null, '通常 / Prg20 ジャンプゲームを作ろう！ ちょっとレベルアップしたジャンプゲームを作ろう、ということで声掛けをして。', '初めにカミナリの手直しをしました。カミナリの数を増やして難易度調整をしていました。 Prgジャンプでは、初めに草をスクロールさせました。座標の考え方はおおよそできていたけど、演算ブロックと制御ブロックを組み合わせた「左端に触れたら」のプログラムができなかった。 あるごんが木に触れたときのプログラムで画像効果をいろいろ試して楽しみました。ここ最近で一番楽しそうでした。 ゲーム作成よりも見た目の変更、アニメーションなどの方が本人に合うかも？と感じました。ジャンプのプログラムがかなり本人のアレンジが入っているので修正が必要そうです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('14bdc6a3-65f1-5ad4-8f34-f479e2391ffe', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-01', '16:30:00', null, '通常 / 4級検定問題 応用課題4', '検定の流れにはおおよそ慣れたようです。自信がないプログラムのときはたまに相談（？）されます。大体内容はあっているのですが、ついついヒントを出してしまうので、自分で最後までやりきる練習も必要かな？と思います。 「もし～でないなら～」の1箇所だけミスがありました。「ではない」を使っていたのですが、プログラム順番がうまくいっていなかったので、論理関係を説明しながら訂正しました。 授業後は17:30の人と楽しく交流していました！！', null, 'タイピング: 集中して取り組めました。'),
  ('23e3958f-6797-5cfb-9b08-51e90e42d3ee', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-07', '16:30:00', null, '通常 / 検定3級応用課題5 検定問題が続いているが、忘れているスキルもありそうなのと、本人がそれほど抵抗なさそうなので、違ったタイプの問題を。', 'ゲーム性の高い問題で嬉しそうでした。作成した後のアレンジやプレイをモチベーションに取り組めました。 読み飛ばし、読み間違い、制御ブロックの範囲の把握ミスがありました。時間は10分ほど余りましたが、答え合わせをしました。制御ブロックの範囲については、「以下」の言葉に惑わされたようでした。余った時間でアレンジをしました。全く違う他のゲームにアレンジしたいようでしたが、実際にアレンジするときの注意事項を伝えて取り組んでもらいました。', null, null),
  ('45584ec1-b44e-5bfa-b507-cd5b0429362c', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-07', '17:30:00', null, '通常 / 4級応用課題2 ある意味定番のゲーム作成に慣れてもらい、基本的なコードの確認ができるように。', 'セリフを消すブロックを新しく共有しました。また若干、時間が足りませんでした。かなり丁寧に間違えたところは①「～ならば」の範囲、また②変数の設定ミスがありました。①については詳しく解説と読むときの注意点を伝えました。同じようなミスが他にもあったので、2回目は自分で文章を参照して再確認してもらいました。よく取り組めていました。 アレンジでは、新しいスプライトを追加して楽しんでいました。', null, 'タイピング: 集中して取り組めました。'),
  ('5a904331-71d6-599c-aba9-8168f1bdf503', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-07', '17:30:00', null, '通常 / 検定1級応用課題4 前回定義の復習ができたようなので、今日は実践に戻ってみて。', '疲れた様子のようで少し寝てしまっている瞬間があったので、気分転換をするように促しました。気分が入れ替わったようで、その後は集中して取り組めていました。 時間を少し過ぎてしまいましたが、ほぼ正解でした。宝箱のプログラムも自分で確認して修正できていました。変数の値が見本と少しずれているのが気になっていたようですが、紙を見ながら論理関係を確認したところ見本も怪しいな？という結論になりました。（プログラムのミスが原因ではなさそうでした）', null, null),
  ('f2f4f500-cf2f-59a7-9b25-8751e898c84a', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-07', '17:30:00', null, '通常 / 単元別練習条件分岐', '前半はバイクランのバグ直しを探っていきました。沈み込んでいしまうバグは、定義のブロックの作り忘れだったり、「ずつ」と「になる」の混同があったり、バグの原因となるミスはいくつかありましたが、めどが立ちませんでした。こたろう君は、りょーや君がまみさんが一緒に解いていたことがあって、ふざけあうことがなく、少し離脱しそうなことがあったが、取り組んでれました。結局見つからなかったので、条件分岐の単元別練習に気分切替しました。 後半の、条件分岐のところでは、玉発射を作りました。「まで繰り返す」の使い方で、中に作ることとそのあとにつくることに区別が最初はわかっていませんでした。そこで、一緒に教えて、次の敵に当たるのところで「もし」を使う際に、「もし」の使い方が、わかっていたのに、わからなくなってしまいました。新しいものが入ってくると、以前のことがわからなくなっちゃう傾向があって、「もし」とか「まで繰り返す」の機能が区別の認識がうまくいっていない感じです。まだひとくくりになっている印象があります。', null, null),
  ('248f254d-7a93-5c33-aa9a-46e405504d6a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-07', '16:30:00', null, '通常 / 検定練習', '今日は時間がかかってもいいからタイピングを自分でやるようにさせました。 問題文の意味について、最初はすぐに「わからない」と言っていたのですが、 やまと先生から「本番は先生は助けられないから、今のうちにどうしたらいいかを今日やりながら考えたほうがいい」というアドバイスを受けると黙々とやり始めていました。 問題文をぱっと見たときに日本語を理解するのに苦しそうだったため、 「文章をわかる単語をまず囲み、選んだらチェックを引いて考えてみる」 という解き方のアドバイスをしました。 また、一旦自分で考えてみたかを確認してから教えるように心がけました。 ただ、序盤の問題の「走者」という熟語がわからないと言っていたため、 その意味を教えたのですが、わからない単語のある文章で行き詰まってしまったようです。 途中、私のミスで先に動画を見せるのを忘れていたため謝罪し、 「むしろ動画見てないで途中まで出来るなんてすごい」と誉めました。 検定を通して文章の意味を考える練習をするべきだなと感じました。 来週は途中になっている検定の続きができたらいなと思います。', null, null),
  ('15734bc9-c50f-57f9-9618-3f4a2e19382e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-07', '17:30:00', null, '通常 / 検定練習', '最初からやる気満々で、取り組んでくれました。とちゅう、セリフの「と」の使い方で十分に悩んでくれて、自力で導くことができていました。その後は、順調に、すすで生き、30分くらいで終えることができました。答え合わせすると、ほぼあっていましたが、もし条件の後についてくる「止める」の場所がずれていたくらいで、よくできていました。④の後、をしかっり見るようにアドバイスはしました。 アレンジは、不等号を使ったところで、セリフの追加をしてくれて、条件式の認識が上がってきています。', null, null),
  ('8a6bd388-e13c-5973-9839-a8666f6099c6', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-07', '16:30:00', null, '通常 / 検定への抵抗感をなくす', '授業開始時からこたろうくんのところに椅子を持って行っておしゃべりする気満々だったので、もぐらたたきゲームを作ろうと誘ってみました。 そこから、自分のスキルに全く自信がない、受からないからやるのも面倒、とぽつぽつ話し始めたので、今日とりあえずこの課題をやってみて、無理そうだと思ったら受験は先延ばしでもいいんだよ、と声をかけてみました。それに対する返答が、「検定に受からないとロブロックスがやれないから」でした。なので、ロブロックスをやるために検定を受ける、という目的意識はあるようでした。 とにかく自信がないから問題を見るのがつらい、という感じだったので、抵抗感をなくすために今日はほぼつきっきりで、モチベーションを少しでも上げることを目標としました。 一緒にやってみようと言うと、取り組む姿勢を見せてくれたので、りょうやくんの様子を見ながら問題文をこちらが読んだりりょうやくんに読ませたり、黙読させてみたりと対応を変えながらやらせてみました。 ストレートネックのせいもあるのか、たまにつらそうに椅子からおりて背中を伸ばしたりすることもありましたが、なんとか最後まで解き終えることができ、アレンジを楽しそうにしていました。 問題文さえ読めればコードはほぼ自力で持ってくることができ、複雑な演算式も、下手に日本語を深読みしないせいなのか、スラスラと完成させることができていました。', null, '盛り上がり: ゲームが完成できたことは嬉しかったようで、ネズミの耳の色を地面と同化させてひっかけさせるようなアレンジを楽しんでいました。
備考: お母さんが、LDのため問題文を読むのが苦手だと心配していました。スキル自体は十分2級相当に達しているので、本人がもう少し自信を持って落ち着いて取り組めるとよいのですが…'),
  ('ce3c008b-3aa2-50b7-a657-11a5b05d6972', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-07', '17:30:00', null, '通常 / コード探求【調べる#】スロットマシーン 「まで待つ」の使い方、コスチュームの使い方を学ぶ。', 'アルスパークでお手本を調べてもらう際、カタカナを打ったことが無いらしく、打ち方のサポートをしました。 また「スロットがどういうものかわからない」と言っていたので、 和先生から検定問題のスロットマシーンを紹介してもらい、これからどういったものを作るのかについて理解を深めました。 「スプライトの他のスクリプトを止める」の説明で、「スプライト」「スクリプト」がそれぞれ何を指しているのか、私もまだ理解が不十分だったのもあり、言葉ではなく図に描いて一緒に理解していきました。 「（◯こめの数字）を送る」「（◯こめの数字）を受け取ったとき」も同じく図で説明しました。 「（◯キーが押された)まで待つ」について、図で説明を試みようとしたのですが、簡単な言葉で説明をするのが私でも難しく、和先生に説明を手伝ってもらいました。 今回で私と3回目の授業で、会話の中で笑ってくれることが増えてきましたが、 本人が寡黙気味なので、当たり前に使っていた単語も本当にわかっているのかどうか、都度確認したほうが良さそうだと感じました。 目的となるプログラムの関門は超えたので、来週続きがやれたらいいなと思います。', null, 'タイピング: 集中して取り組めていました。'),
  ('40efa369-866c-5ccc-a1eb-779cfcb9569d', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-08', '16:30:00', null, '通常 / 検定練習', '検定はだいぶ慣れてきたそうです。最初ではわからないところも動画やコードの試しもあって、自力で解決に向かっていく姿をみえました。「まで繰り返す」の順序関係に悩んでいましたが、何回かの試行で解き明かせていました。時間的にもちょうどで解き終わり能力は就いてきたそうです。時間もあったので、アレンジのことも触れてみましたが、アレンジしたことを文章にすることが少し抽象的になりすぎることがあります。', null, 'タイピング: 頑張って打っていました'),
  ('420cced8-d3a3-55ae-bb35-2880bb6772b3', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-08', '17:30:00', null, '通常 / 検定練習', 'タイピングに時間をかけすぎてしまったので、検定になかなか進みませんでした。今回の問題は、セリフが多いものだったので、文字を打ち込んで、集中力が切らしてしまうことがたびたび発生しました。本来なら文字を打つことがないので、検定とは関係ないの要因でふらつくことが多かったです。進捗としては半分も終わっていない感じなので、次回は割り切って進んでいくべきです', null, 'タイピング: 20分以上かけて大ボリュームでした'),
  ('436882a6-b146-51aa-8483-c4690f4075bb', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-08', '17:30:00', null, '通常 / 検定練習', 'ここずっと検定練習が続いていて、ほかのことを提案したが、検定にやる気でした。今回の問題は回転と軽めの演算条件があったが、しっかり読み込んで解けていました、よくありがちな「まで繰り返す」の活用も判別つけていました。ただ、30分過ぎくらいで一度完成した時に、動画と比べて、判定が遅いバグがありました。必死に探してくれたが、見つからなかったが、音のブロックが「終わるまで」の有無のくらいの凡ミスだったので、もう余裕をもって合格できる能力はあると思います。', null, null),
  ('b47b008c-6b26-5ee6-bf59-b5fd1ea8ebe5', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-08', '17:30:00', null, '通常 / 検定問題にチャレンジする', '動画を見た時は、興味を持てそうなゲームだと感じたのか、普通に取り組み始めましたが、途中から面倒になってきたようで、何度も「無理―」と言って投げ出そうとしては、なんとなく作成に戻る繰り返しとなりました。 修正問題が特に面倒なようで、きちんとコードを確認しないで一から作成していることに途中で気づいていました。 作成したコードをきちんと整理しないで適当に重なったままコードを作成していくので、見落としが多いように見えました。 修正問題で、モグラとネズミのコードが似ているからと複製を使ったところまでは良いのですが、その後にきちんと一つ一つのブロックをチェックしていないため、最終的にモグラやネズミの出現する座標がおかしなことになっていました。 かろうじて最後までやり終えましたが、おそらく細かいところのチェックが不十分のためバグが多い状態で、そこであきらめてしまったようでした。 ゲームが始まらないバグについては、メッセージ「スタート」を受け取るが動いていないことに着目して、該当コードをパッと見て条件分岐のネストの段階がおかしいことにすぐに気づいて直すなどの対応ができていましたが、問題文をきちんと読まないといけない数値などをチェックするのは面倒なようでした。', '今日とは違う感じの問題がやりたいと言っていました。', 'タイピング: 毎回ローマ字に取り組んでいます
盛り上がり: 今日の検定問題はきつかったようでしたが、中学生コースの内容にはとても興味を示して、そのために検定に受からないといけないんだと、少しだけ前向きになれたようにも見えました。
備考: 前回ロブロックスの話を振った時は軽く流されてしまいましたが(-_-;)、今日は中学生コースの内容にとても興味を示していました。 お母さんが検定を受験できるレベルにあるのか心配されていたので、スキル的には十分合格の可能性があるが、集中力が持たないために見落としが多いこともお話しました。 今が年齢的にも経験年数的にもちょうど過渡期なこと、今回の2級は一発合格しなくても無理のない年齢であることなども軽く話しました。 ただ、今日の問題は諦めてしまいましたが、お母さんと中学生コースで何をやりたいか話しているうちに、けいとくんが少し前向きになったようで、今回はだめでも、これから上の級を取らないとな、という感じにはなっていました。教室に掲示してあるロジカル問題をコピーして家で解いてくると言って持ち帰るなど、少し風向きが変わったようにも見えました。'),
  ('561bd608-030e-5b80-96a0-190228fca5a1', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-08', '18:40:00', null, '通常 / ではないまで待つ」の活用を知ろう', '最初に遊んでもらうとき、長押しできないのと気づいてほしいポイントを言ってくれたので、今日やる長押し防止を作る目的がはっきりとできました。コード作成の際に、まず、「キー」を押して動かすところをノーヒントでやってもらいましたが、多少コードの場所にまよいはあったものの、自力で作れるのーりょくはありました。「ではないまで待つ」のコードは、こちらが紹介する形で、これが使うことで何ができるか一緒に閑雅てもらいました。おされたではない」がキーを離した状態に結びつくまでかなり時間はかかっていました。あさひくんもここは復習が必要だと感じます。ウサギへの作りはスムーズに作り変えられていました。 ここで、頭の理解がおなか一杯な感じあったので、順位の変数はこちらが先にコード作り、変数順位を言うでなんとセリフいうか予想する形をとりました。順位で1，2という認識はあったので、答えることはできましたが、変数の仕組みは別の機会で単体で学んだ方がいいと思います。', null, 'タイピング: 指を確認しながらやれていました。'),
  ('f9d3c72d-3e1d-5f8b-9332-b7b8ec0b566d', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-08', '17:30:00', null, '通常 / 検定問題に取り組む', '検定問題には素直に取り組んでいましたが、問題を解きながらアレンジをかけようとしていたので、まずは問題通り解いていくことを促しました。 昨年秋の受験時よりはだいぶ進歩したようで、一通り自力で解けたようでした。その後のアレンジが楽しかったのか、試験時間が過ぎても熱心に作業を続け、授業終了時間まで粘って、かなり雰囲気の変わったホラーゲームのようなイメージに仕上げていました。', null, '盛り上がり: アレンジがとにかく楽しかったようで、熱心に音楽や見た目の雰囲気を変えていました。集中力がすごかったです！'),
  ('2f559832-4452-594e-9586-87e75997bfa8', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-08', '18:40:00', null, '通常 / U16大会作品制作', '今回も細かい修正を行っていきました。修正していく中で、ステージの位置を下にずらしたいとが、書類と異なってしまうからやっていいのか悩んでいました。ゲームのシステムに大きく変わることがないので、その修正は大丈夫とアドバイスしてあげました。', null, null),
  ('9515cf5d-23b8-5597-b83c-550745c7ff14', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-08', '18:40:00', null, '通常 / アレンジのアイディアを考えて作成する', '今日は気が散りやすかったようで、頻繁に飴を食べに行っていました。 ジャンプゲームのアレンジ自体は、予想通り楽しかったようで、気のデザインや背景などを一生懸命いじっていました。木をピンク色にしたためか「花粉をよけろ」ゲームになったようで、あさひくんと盛り上がっていました。 アレンジを加えて完成できたのは嬉しかったようで、わざわざ先生を呼びに来て見せてくれました。 ジャンプゲームが完成した時点で残り20分だったのですが、今日はもう休憩、と言ってしばらくバイクランで遊んでいました。記録が伸びないとぼやいていたので、リミックスを進め、中のコードを見て、どこを変えたらジャンプがたくさんできるようになるかを考えさせました。ジャンプがどのくらいできるかは変数だというヒントで該当ブロックを見つけることができ、ジャンプの回数を100000000000000000000000回にして喜んでプレイしていました。', null, '盛り上がり: 集中力の持続はイマイチでしたが、それぞれの作品のアレンジは熱心に楽しそうにやっていました。ロブロックスがやってみたいと言って、何年生からできるのか、など、いろいろと質問してきていました。
備考: ナホ先生によくお世話になったことを覚えているようでした。'),
  ('64f63bea-c8ae-5858-9670-bfed5b95d5c2', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-09', null, null, '通常 / 2級シルバー第14回応用課題4のアレンジを楽しむ', 'アレンジに入る前に前回の難しい部分を一緒に理解できているのか、確認しながら復習しました。 今回の生徒さんはただ漠然とアレンジを考えてもらうのが難しそうな様子だったので、アレンジのヒントとして好きなゲーム作品を聞き、「それ風にアレンジしたり敵を増やしてみてはどうか」という提案をし、一緒に作ることにしました。 普段は生徒さんにスプライトなど作るのを任せるのですが、 最初に提案してから一旦10分考えてもらった後も「これだ！」というイメージがあまり固まっていなかったようなので、 待っている間に作成した生徒さんの好きなゲームの敵キャラのスプライトを描いて共有し、ゲームに使ってもらうよう更にアドバイスをしました。 イラストだけだと私だけのものになってしまうので、他のアレンジも考えてもらったりしました。具体的には特別なキャラの得点を考えたり、ハンマーを虹色にしたり、背景の色を変えてもらったりなどです。 授業後もしばらくアレンジ制作していたので、この調子で次回検定にも楽しくイメージしてもらえたらいいなと思っています。', null, '時間帯: その他
タイピング: 集中して取り組めていました'),
  ('21e22568-28d0-555e-90f8-86a4d8cc5558', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-09', '16:30:00', null, '通常 / 4級エントリー第16回応用課題2', '試験に入ろうとしたのですが、前回の検定問題のアレンジを始めたので無理に誘導せず様子見することにしました。 前回習った「スプライトの他のスクリプトを止める」を意味をきちんと理解して使おうとしていたり、イベントや制御、変数も自主的に利用しようとしていてすごいと思いました。 ただ、「メッセージを送る」でタイピングができないのか、メッセージ名が適当にタイピングしたもので非常にわかりにくくなっていました。本人に何度か「名前変えたら？」と提案したのですが、「自分がわかるから」とのことでそのままです。 検定ではローマ字表を使ったり私がセリフを打ったりしているのですが、 一人で受ける試験でのアレンジの表記が分かりにくくなるのではと若干懸念です。 30分経ったところでキリが良さそうだと思い、一旦保存して次回続きをやるよう提案して検定に入らせました。 問題を上から順番によく読むこと、鉛筆も使っていいよとアドバイスしスタートさせました。 「一個（スクリプトの塊が）できたら（緑の旗を）押して確認するようにする！」と言っており、進歩が見えました。 私の方ではPCでPDFの答えとアルスパークでの本人回答、 問題用紙の文章を見比べながらスクリプトの順番が間違っていないかに注目して確認しました。 本人は的には基本自分で解決したい様子で、詰まったらもう一度問題文を見るよう促し、それでも無理そうな場合はヒントを出し、どうしても難しい場合は最終的に一緒に考えるようにしました。 授業後も表の問題が終わるまで取り組められていました。', null, 'タイピング: なし'),
  ('d46a7d10-3ca8-5f6b-bfca-96c4f87abd55', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-09', null, null, '通常 / 基本操作コース続き', '座標と角度の考え方はあまり馴染めないようです。学年が低いので、概要だけ説明してさらっと流しました。細かい部分より、大枠を捉えてもらいました。論理関係はよく把握できていて、自力でコスチュームを変えたりゲームオーバーを作成したりできました。一方で乱数の使い方を忘れていたので、復習をしました。伝わったかどうかは不明です。 ゲームが面白くないようでやる気が低いのですが、復習を兼ねてスコアの部分だけでもプログラムしてほしいです。', 'ピンポンゲームのスコア作成。その後できればドット絵メーカーなど。', '時間帯: その他
タイピング: 集中して取り組みました。何周か取り組んでもらいました。
盛り上がり: ドット絵メーカーで自分でスプライトを作ったり、ロブロックスをやりたいそうです。（検定が必要なことは伝えました） 最終的にはマイクラを作りたいそうです。今日もよく言っていました。
備考: オリジナルの作品を自力でなんとか作ってみて、今の自分のスキルと理想の違いを把握してみるのが面白いかも？'),
  ('3ff0d739-fb96-5e8f-8f47-12114a12981e', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-09', null, null, '通常 / 今回は息抜きに、単元別G-2 の続きを バレリーナ―のジャンプなので、作品として楽しく作り、結果不等号やマイナスを体感できれば(^_^)v', '最初に左右にバレリーナを動かしたり、前回の変数を使ったジャンプを確認したりしました。その後アレンジを促しましたが内容を思いつかなかったようなので、ジャンプゲームのようなアレンジを提案しました。右側からボールが流れてくるプログラムはジャンプゲームの資料を見ながら作成しましたが、乱数を使ってオリジナルにできました。 「もし」を使うときにずっとを使ってしまうこと、ボールに触れた回数のカウントを「ボールに触れたら>2」でできると勘違いしていた、などがありましたが、指摘すると気が付いて直せていたので良かったです。変数の使い方自体に問題はありませんでした。 面白いアレンジになったと思います。音もこだわって選んでいました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('7d08d75a-4f44-5a9a-8785-cac070d67566', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-09', null, null, '通常 / 3級検定問題', '自分の苦手なところを再確認してから取り組みました。制御ブロックの範囲がどこまで有効なのか、などが苦手なようでした。 時間余裕で終わることができました。ミスはプログラムよりも読み間違いが多く、本人に聞くと国語のテストでもケアレスミスが多いようでした。かなりもったいないことも伝えました。 アレンジにもしっかり取り組めました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('77c02daf-c228-5e8a-a288-01affa57d83b', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-09', null, null, '通常 / U16大会作品の作成', '最初に「作りたい！」とのことだったので、作成になりました。（おそらく）大きい野球ボールの挙動が気に入らない様子で、何度もプログラムを動かしては修正していました。デバックに当たって武器の選択なども必要になるので、次作から開発者ボタンを付けることを提案しました。またプログラムがかなり長くなっていたので、定義ブロックを使って短縮できる可能性があることも共有しました。 膨大な数の変数やメッセージを把握してプログラムできていて素晴らしいです。', null, '時間帯: その他'),
  ('8f608b16-f059-5cbc-b438-7eb7edb67c93', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-09', null, null, '通常 / 検定4級応用課題3 【Prg】09ネコからにげろゲームを作ろう', 'Prgのネコで、プログラム終了後も時間のカウントが動いてしまっていたので、メッセージの役割や制御のブロックの意味合いを確認しながら修正しました。ステージがくるくる丸くなるのが好きだったようです。 応用課題or基本操作の続きを選んでもらったのですが、どちらでもよいということで、念のため応用課題に取り組みました。タイピングが多く時間内に終わるか不安でしたが、終えられました。読み落としが1つありましたが他はよくできていました。アレンジはオリジナル要素強めでドラゴンボールを作成していました。楽しそうで良かったです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('e211982c-e4f6-56be-8093-a7d7a3c94cd0', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-09', null, null, '通常 / 検定準備', '「3級は範囲が広いけどあおしくんにとってそこまで難しくないから経験を積めば大丈夫」と伝えると納得してくれて、集中して取り組めました。不等号の向きでミスしていましたが、「どっちが大きくてどっちが小さい？」と問いかけることで考えて理解することができました。それ以外の部分は、以前扱った「リンゴとバナナ」や「ではないまで待つ」などが身についていて、おおむねできていました。', null, '時間帯: その他
タイピング: 高めのレベルで頑張っています
盛り上がり: 今日はいつもと比べてやる気を持ってできました。'),
  ('9f76ea5b-74db-5455-9df6-418b1e4abb54', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-09', null, null, '通常 / 検定練習', '前半は、大体できているから自信は持っていいと伝えたうえで前回の見直しを行いました。3種類の「止める」の使い分けが課題だったので、どの部分を止めたいのか考えてもらったあと、「他のスクリプトを止める」の使い方を教えました。 後半は新しい問題に着手しました。「ここが上手く動かない」と困っていましたが、本番を考慮して、一旦できるところを終えてから戻ってくることを勧めました。時間はオーバーしてしまいましたが、なんとか粘って最後まで解き切れました。(見直し未完)', null, '時間帯: その他'),
  ('8c0e74e2-d5f7-55bc-90da-c264d5f2a577', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-09', null, null, '通常 / 検定見直し', '読解に少し不安があるということで前回の検定問題の復習を行いました。一緒にじっくりと読むと、「何がいつどうする」と言った日本語の内容はきちんと理解できました。前回間違えていた部分はコスチューム変化させるときの「-秒待つ」の使い方や「他のスクリプトを止める」でしたが、このコードが何をしているかについて納得できた様子でした。最後に、本番でもアレンジの問題があるということでその問題のアレンジをしました。背景やコスチュームの編集が多かったのですが、検定の基準に合わせて、動きをつけるアレンジもやることを勧めるとそうしていました。', null, '時間帯: その他
盛り上がり: 無理ないペースできちんと進められました。'),
  ('05bb083d-e9be-59ac-a379-01a54d34b6cd', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-09', null, null, '通常 / 検定練習', 'ここ最近検定問題が続いていましたが、飽きずにやる気が継続している様子だったので新しい問題に取り組みました。前々回などは本番同様の環境で行いましたが、今日は先生と少し相談しながら進めました。一通り作り終わった後、お手本ムービーと比べてボールの挙動が若干違うことに気づき原因を探ることができていました。最終結果としては数値の入力ミスがあったくらいでほとんどできていました。', null, '時間帯: その他
タイピング: ゲームとしてやりこんでいて、タイピング自体も真剣に取り組んでいます。'),
  ('084dc847-c4a7-5537-ab93-84562e2338a3', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-11', '16:30:00', null, '通常 / ドリル21、31～35くらいまで', 'ドリル21はすぐに終わり、角度のある問題を飛ばして27に取り組んだのですが、 「ペンを下げた/上げた時、それぞれ何歩ずつあれば合計200歩内で解答通り動けるのか」を一緒に考えたのですが、長時間苦戦してしまいました。 掛け算は九九を２学期の終わり頃に最後まで習ったそうですが、桁数の大きい時に使うような割り算の筆算までは習ったことがないようで、簡単に説明するのが難しかったです。 一応 「大きい歩数で小さい数で繰り返すのと、小さい歩数で大きく繰り返すのでは進む速さが違う」という他の先生方からのアドバイスについて理解はしていたようでした。 難しい内容ですが途中で諦めずに取り組もうとしていたので、 次回続きをやる際は、ゆき先生が書いてくださったように数直線を用いるやり方か、足し算方式で上から繋げていくやり方がいいのかなと感じました。', null, 'タイピング: 会話しながらでそんなに集中してない様子でした。'),
  ('fe00731e-53ef-5339-932e-d3c3df69fb9d', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-11', '16:30:00', null, '通常 / 単元別演習A-2～A-5（A-1はとばして）', '前回よりもかなり楽しく取り組めました。色を変える、大きさを変えるブロックについてはよく覚えていましたが、「もし～」と「ずっと～」を一緒に使うのがなかなか慣れない様子でした。 A-3でポインターの方に動かす、A-4でボールをずっと動かし続けるというのもよくできていましたが、ここでも「ずっと」がなかなか使えませんでした。条件分岐は、なんとなく考えてプログラムできているようです。今までやったことと似ているとビビッときたようでした。', null, 'タイピング: 「かんたん」を集中して取り組めました。'),
  ('a3ace09c-cd13-5723-b3ad-a8631402f444', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-11', '17:30:00', null, '通常 / S013 応用課題3', '時間をかなり残して終われました。 制御ブロックがどこまで有効なのかを把握しきれておらず、うまく動作していませんでした。また、うまくプログラムが動かなかったときに、怪しい箇所を見当づけることができていましたが、実際に修正するのは難しかったようです。また文章の読み間違いなどもったいないミスも2箇所ありました。 アレンジはやる気がほぼなかったのですが、注意事項を伝えて少しチャレンジしてもらいました。', null, null),
  ('d9673cec-7f0d-5ad8-be1e-87b3e1345f99', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-11', '17:30:00', null, '通常 / 4級応用課題2', '前回と比べて、自分から文章を読んでスムーズに取り組むことができていました！ほぼ時間内に取り組めました。最初だけ少し声かけをしました。 プログラムのスキルは問題ないのですが、制御のブロックをどこに使うか、どこまで使うか、を文章から読み取るのがかなり苦手なようです。（自分で決めて進むのでプログラミング自体は時間内に終わっている）一緒に文章を読んで振り返り、注意事項を確認した後、応用課題5の表面に取り組みました。 先ほどの苦手の確認効果かどうかは分かりませんが、表面はしっかり正解できました。次回、別の問題が終わったあと、余裕があれば裏面に挑戦してもいいかもしれません。', '先ほどの苦手の確認効果かどうかは分かりませんが、表面はしっかり正解できました。次回、別の問題が終わったあと、余裕があれば（応用課題5）裏面に挑戦してもいいかもしれません。', 'タイピング: 集中して取り組めました。'),
  ('32816a93-d35d-56f2-a081-b7dcfe5f659d', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-11', '17:30:00', null, '通常 / Scratchをやることに', '数字を打ち込むと任意の行先を表示させるシステムを作っていました。楽しそうでした。あまりブロック定義を使うことがないそうなので、参考までに同じようなブロックをまとめて変数だけ変化させて使うことができる紹介をしました。（使って慣れるのが一番だと思うので）', null, null),
  ('78c24a23-8a1a-58c6-b21b-26fcba07386d', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-11', '17:30:00', null, '通常 / 検定4級応用課題1', '検定問題を見ながらとりあえず最後まで入力してくれたみたいですが、 問題の読み間違いで指示に書いていないコードを入れようとしたり、半角数字を全角で入力してしまったりなど細かいミスが多かったです。 和先生からスクリプトの止め方について説明を受けており、その部分だけは改めて理解をすかめたようでした。 試験時間内から1~2分程度伸びましたが一応時間内に完成することができたので、次回はアレンジになると思います。', null, 'タイピング: 集中して取り組めていました。'),
  ('4a0ec635-47e7-5354-bc19-bb22f70c8267', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-12', '17:30:00', null, '振替 / 検定受験へのモチベーションを上げる', '前回のレッスン時、複雑な演算式の問題文をよく読めたことを褒めたせいか、このクラスの生徒が一人で遊び相手がいなかったためか、用意してあった検定問題を見ても嫌がらずにすぐに席についてくれました。 問題に取りかかる前に雑談を兼ねて、2級は問題文が長くなって読み落としも多くなりやすいため、気をつけるべきワード（ブロックに使用されているような単語）を一緒に確認しました。 LDだというお母さんからの情報を踏まえ、ディスレクシアの児童支援に使われるリーディングスラッガーを意識して、問題文1文のみを表示できるよう問題用紙を折るやり方を提案しました。実際にはいちいち問題用紙を折るのは面倒なため、りょうやくんがその方法をとるかはわかりませんが、そのときは「なるほど」と感心したあと、「今回の問題は短いから、そこまでしなくても読める気がする！」と言って、自分から問題文を読み始めました。前回は一緒に音読をしないとつらそうだったので、問題文への抵抗感がだいぶ薄れてきたのかな…？良い傾向だと思われます。 今回の問題文は、すべて自力で読むことができていました。途中2回ほど手を挙げて知らないブロック「入れ物の向き」と「○○を3で割った数の切り下げ」について聞いてきましたが、ヒントを出すと納得して問題に戻ることができていました。 最後の修正問題で少し疲れも見えましたが、あとちょっとだから頑張れという声掛けでなんとか最後まで解き終わり、ライオンの色を変えて面白がっていました。 自力で問題文を読んでやり切ることができたこと、本人があまり辛そうでなく、笑顔を見せながら取り組めたことが、今後のためにも良かったのではないかと思われます。', '検定に対する忌避感がなくなってきたので、うまく気持ちをもりあげてやってください。', '盛り上がり: すっぱいレモンキャンディを楽しみにしながら、よく頑張ることができました。作成した課題自体も楽しかったようで、完成したゲームで熱心に遊んでいました。'),
  ('6e59cbfa-7ae0-5988-9e5c-3ada86ba8e6a', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-14', '16:30:00', null, '通常 / 検定３級 応用６B022', '検定問題を授業ギリギリまで取り組んでいました。 問題文から変数や演算を利用して正しいコードを選択できていましたが、 「◯座標の移動量分動かす」の「移動量分」という単語が見慣れなく、単なる座標移動か変数での移動なのか判別が出来ず、うまくボールが落下せず長時間苦戦しているようだったので詰まっている部分についてヒントを出しながら自分で考えさせるようにしました。 ただ、どうしてもわからない様子だったので、最終的に諦めて答えを一緒に確認してしました。 PrgバレーボールでもY座標の動きで悩んでいたので、今後はうまく動作しなかった場合にどう振り返って修正すればいいのか考えられたらいいなと思いました。', null, 'タイピング: 集中して取り組めていました'),
  ('8f62d397-9dd4-5d99-982a-1a90ceef95bd', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-14', '16:30:00', null, '通常 / 検定4級応用課題5', 'タイピングが難しい以外で疑問に思った問題文に対して質問などはありましたが、「どうしてそうだと思うか」をヒントを交えながら聞いたりしてあげると、ほとんど自己解決出来ていた様子でした。 詰まった場合は前回同様、日本語の読み間違いが無いかどうか、今取り組んでいる問題は何のスプライトに対してなのかを都度確認しようと促したところ、実行してくれる回数が増えたように見えました。 また前回は質問の際は「先生わからない」が口癖でしたが、今回は「わからないときは手を挙げるように」と伝えたのでそういった私語は減ったようでした。 ただ、気が散った際の起立がいつもよりは多かったので、次回取り組むときはもう少し静かに座って取り組めたらいいなと思いました。', null, 'タイピング: なし'),
  ('34c5b0a9-92d4-5cee-8c58-c0016b7272f9', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-14', '17:30:00', null, '通常 / U16作成', 'U16の作品作りに取り組んでいきました。作品の性質上文章の量がとても多いので、その執筆をひたすら進めていました。逆にコーディング上の問題で止まることはほとんどなく、淡々と製作していきました。', null, null),
  ('ef43f4ea-fab7-5321-b253-b095ba8dd25d', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-14', '17:30:00', null, '通常 / 別のドリルで基礎を定着させる', 'スプライトの動きを見てスクリプトを選択肢から選ぶ検定「プロ検」に、ドリルのように取り組みました。今までやってきたドリルの復習にもなるという導入をして始めました。クイズのような形式なので楽しみながら進められていました。 解く過程で、「ブロックの順番を変えたらどうなるか」「[ずっと]ブロックがあるのとないのはどう違うか」などといった重要ポイントについて考えることができました。一度間違えても、あとの問題で同じポイントが出てくるときちんと押さえることができていました。やっていくごとに慣れていき、最終的に10問ぶん終わりました。', null, null),
  ('c1d7705a-6aac-538e-a4f3-9778009de630', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-14', '17:30:00', null, '通常 / 検定練習', 'この問題が一番難しいかもしれないからできないところがあっても焦らないで、と伝えたうえで始めました。疲れて眠かったようですが、モチベーション自体はあったので頑張っていました。「コスチュームを(変数)にする」とすることでコスチューム番号を指定できることは使う機会がなく知らなかったようなので覚えてもらいました。時間ギリギリまでやっていたので答え合わせまではできませんでしたが、一通り最後まで解くことはできました。どこかにバグが残ってしまい全くテストプレイができないそうでしたが、それでも6割できていれば合格だと安心させました。', null, null),
  ('d7678b21-dc1e-523d-8621-c6cfc600f590', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-14', '17:30:00', null, '通常 / 4級 エントリー第18回 応用課題4', '指示された問題文に対しては一人で黙々と取り組み、質問もなく完成させていました。 最後に動画を見ながら動作を見直してから完成したと伝えてくれており、手慣れた様子でいい取り組みだなと感じました。 残時間が約30分程度残っていたため、キャラクターを増やしたり音楽を流す等のアレンジの提案をしました。 ただこの時、「なぜスクリプトを変えちゃいけないのか」という理由を伝え忘れてアレンジに入らせてしまったので、次回検定時に伝える必要がありそうでした。 アレンジに関しては、もう一体走るキャラとBGMを追加してくれようと取り組んでいました。 BGMの導入の際、「音楽を入れたいけど、ゴールしたら止めるようにするにはどうしたらいいか分からない」 とのことだったので、「◯秒後に止める」や「端に触れたら〜」どうかとアイデアを提案しました。 「どのスプライト（キャラ）に対してコードを入力すれば思った通りに動くのか？」をあまり意識せず上から順番に取り組んでいたようだったので、 今後は自分の理想の動きが何のスプライトに関係しているのか？、というのを考える癖を身に付けてもらう必要がありそうだなと感じました。', null, 'タイピング: 集中して取り組めていました。'),
  ('061892de-f7ee-5718-8022-eb39e95255bf', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-14', '17:30:00', null, '通常 / 検定3級 応用８ B024', '問題の難しさに押されそうになっていましたが、実際のお手本動画を見させると「こんな感じなんだ！」と興味を持ってくれていたので、抵抗なく取り組めはしていました。 指示されたコードが長く重なっていくのに対し、合っているか不安そうだったので、 問題の項目ごとに合っているのか鉛筆で確認するか、動画の実際の動きと確認しながらやってみようと提案しました。 順番に入れていくだけでなく、問題がどのスプライトについての指示なのかを意識させようと声掛けをしました。 選ぶコードは合っていましたが順番が違ったせいでうまく動作しない様子だったのと、 数字を全角入力にしてしまっていたようなので、一通り入力させるのではなく問題が終わるごとに動作の確認をした方が良いのかなと思いました。', null, null),
  ('ec646b89-c4dd-548e-b114-1c294f06fdd9', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-08', '16:30:00', null, '通常 / 基本操作コース10_キャッチゲーム', 'お手本のカードと作品を見ながら作成していきました。本人のレベル的にもかなり簡単な内容だったようで、指示通りにサクサクと完成させていき、早々にアレンジへと取り掛かっていました。アレンジ部分では、落ちてくるものの追加やスコアをマイナスする要素などを作っていました。その後は、バイクランが楽しかったようでアレンジにチャレンジしていました。キャラクターが落ちてしまわないように、バイクの変数を変えて何度もジャンプできるようにして遊んでいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('505e1f5e-5c22-5548-bdd4-925c90f3984c', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-08', '17:30:00', null, '通常 / 大会提出作品制作', '締め切りも迫ってきたため、作品もいよいよ総仕上げに入っていました。石や草のデザインをどうするか悩んでおり、実際に撮影した写真やネット検索でのモデルから描き上げていました。デザインの他にも、川のどの部分に配置するのか考えており、リアルにできるだけ近づけていきたいようでとてもこだわっていました。今回の進捗で作品は細かい部分の修正のみとなっていたため、次回にて完成と何か別のこともできると思います。', null, null),
  ('2d7997bd-342b-5695-aa7e-e361bb53c89d', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-08', '17:30:00', null, '通常 / 検定4級 2回目に取り組む演習', '４級の問題では、時間に余裕を持って終えることができておりアレンジ部分まで完成させていました。答え合わせでも、不等号の向きを間違えていたのみでそれ以外は完璧に解答することができていました。本人としても、４級の問題は簡単だったようなので次回は４級の中でも難しい問題か３級にチャレンジしてみても良いかもしれません。', null, null),
  ('de5651b7-a1f6-5973-8efa-b648a9abeae5', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-14', '18:40:00', null, '通常 / 検定1級 応用課題2', '今回の検定問題では、定義の使い方とその応用について学びながら作成していきました。定義内で使用する引数についてかなり困惑していたようで、どこにどの順番で配置していくのかかなり悩んでいる様子でした。しかし、引数の性質について説明した後はしっかりと配置する箇所がわかったようで進めていくことができていました。次回では、この検定問題の答え合わせから入っていきたいです。', null, null),
  ('e560ac7a-5a57-5c47-8664-fce991d2e6c4', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-08', '18:40:00', null, '振替 / 検定3級 2回目に取り組む演習', '検定問題の仕様書に書いてある通りにサクサクと進めていくことができていました。時間としては、制限時間ちょうどに終わっており本人の体感としてもそれなりに難しい様子でした。しかし、答え合わせでは間違うことなく完璧に完成させることができていたため、自信がついた様子でした。このまま３級の問題に挑戦していき、難易度に慣れていけばさらに早く完成させることができそうです。', null, 'タイピング: 真剣に取り組むことができていました。'),
  ('e89ee380-84d6-562b-bdd9-2a6b88fa4f29', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-14', '16:30:00', null, '通常 / 野球ゲームを丁寧に作る', '先週までの課題として、コードの機能の区別がついていなかったり、一度分かったことも定着しなかったりということがありました。今回は、興味のありそうな野球ゲームを通してそういった基礎を固めていきました。最初から丁寧に細分化していき、誰がいつどうするのかを把握しながら作っていきました。「～にする」と「～ずつ変える」を間違えたときは、なぜ間違いなのかを考えてもらい、しっかり区別できるように促しました。前半は興味を持って取り組んでくれましたが、次第にりょうやくんに絡むなどしてペースが落ちてしまい、ボールの投球部分までは取り掛かれませんでした。', null, null),
  ('536dd9c8-a8d7-5801-97b6-d7ce7910eb0a', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-15', '16:30:00', null, '通常 / ゲームの精度を上げる', '検定まで残り2回なので類問を解くか、それとも検定練習が続いたのでガサガサのゲームを製作するかを提示したところ後者を選びました。一通り完成はしているのでアレンジをしていきました。特別な魚だけにマイクラの模様を描きこんでいて、それはそれで面白いのですが、ゲーム性に関わるアレンジもすることを勧めました。するとエサを追加して、網で魚を捕まえるときに使えるようにしていました。こたろうくんにされたちょっかいに乗ることもありましたが、題材が好きだからか普段よりは集中を保って取り組めていました。', null, null),
  ('9c0cdbcb-0496-5352-8dc0-6bfb401af999', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-15', '16:30:00', null, '通常 / 検定練習', '検定への取り組みは励んでいますが、一通り行って、バグが残ってしまうケースが多いです。今回も、上の繰り返しの部分に続いて作ってしまうことがありました。あとからのたいようくんの確認では発見できるので、落ち着いてやれば、できる感じです。だから、最初の所見読みの際に、最後までしっかり読むことをアドバイスをしました。', '4級2回目', 'タイピング: 結果を意図的にかはわかりませんが、あまり見せてくれません
盛り上がり: 先週楽しく話し合ったぶちょーがいなくて少し悲しそうでした'),
  ('4ea0034f-15b5-5103-930f-3b4de9f812bd', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-15', '17:30:00', null, '通常 / 検定練習', '検定の問題に対するコード能力は、もう大丈夫そうです。悩んだところを聞いても、「触れないまで待つ」のコード構成のところで悩んだくらいで、ほかはあっていました。それとは別に、作りながらアレンジをしてしまうので、そこでゆったりして作っていると、時間がんなくってしますことは注意しました。そして、「メッセージ名」やセリフも変えてしますと、アレンジでそのことを書かないと原点になってしまうことに伝えました。だから、特にメッセージ名はしないように注意しました。', null, null),
  ('cf39f28b-4673-548a-8ee2-0b893ecc9aa1', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-15', '17:30:00', null, '通常 / 検定練習', 'やっている最中は、「○○層に出す」などしな来ブロックがあった今までの中で過去一不安がって解いていましたが、必ず似た語句はブロック内にあるとアドバイスをして、最後まで一人で解きました。30分過ぎくらいで解き終わって答え合わせをすると、ノーミスでできていたので、満足感は得ていました。', null, 'タイピング: 集中して頑張っていました
盛り上がり: のこりは毛糸君の取り組みに惹かれていました。'),
  ('902815ae-16f0-54bb-be45-68be0bbe0aef', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-15', '18:40:00', null, '通常 / U16大会作品完成', 'まだ手直ししたいところがあるそうだったので、直していきました。いつ書類選考の結果がわかるかどうか気になるそうです。今回は、主に、音楽の調整をしていき、その最中に、クリアの演出にバグが見つかりました。メッセージの不必要な連続な送りをしていたので、、「まで待つ」の変更を提案しました。そこで、いつも判定してほしいなら「もし」、1度いいなら「まで待つ」の認識も伝えてあげました。', null, null),
  ('f77c43bc-9979-55df-9fa9-cc3ab76c9e90', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-15', '18:40:00', null, '通常 / 変数の使い方を復習しよう', '教室に来るまで、寝ていたそうで、授業もいつもの元気よさが薄まりかなり眠たい感じが漂っていました。最初は、前回の子復習をしましたが、今日の頭ではあまり理解できていないようでした。そこで、切り替えて、レースゲームの方に試遊したら、似たようなゲームだけど、楽しいんでくれました。しかし、プリント見ながら進めていったが、最初の方の初期設定では、文字の打ち込みがが多く、飽きることが多かったです。このような最初の設定が長いゲームは、低学年には不向きだと感じた。次回は、やっと車の動きに作れるので、お願いします', null, 'タイピング: 時間はかかりながらも、必死に取り組んでくれました。'),
  ('431c432e-5931-5192-8040-c917903947b7', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-15', '16:30:00', null, '通常 / 検定3級応用８', '集中して取り組んで、時間内に終わらせて、いざ動作確認というところで、きちんと動作せず。間違っているところを探すのに苦労しているようでした。ちょっと時間がかかりそうだったので、「変数の値が変わらないなら、変数を１にセットしている文章付近を見直してみたら？」というようなアドバイスを少しして、問題の箇所にたどりつきました。問題は、不等号を逆にしていたということ。日本文から、例えば「X > 1」なのか「X < 1」にするのかが元々きちんと理解できていたのか、あやふやな感じを受けました。今回不等号の扱い方を教えたので、来週きちんと覚えているか、チェックするところから始めたら良いかなと思います。４、５個くらい不統合部分の演算処理が全滅だったので、ギリ６０点取れるかもしれないけど、結構大きな減点になると感じました。', null, 'タイピング: 集中して取り組んでいました'),
  ('2c5ca9a1-d1b9-5e59-9eda-c27e173d980b', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-15', '17:30:00', null, '通常 / 4級応用課題④', '前回の検定の続きで、思い出しながら始めていきました。前半から中盤くらいまでは、できるだけ自分の力で進めるようアドバイスは最小限にしていたためか、なかなか進まず、集中が続かない時も見られました。後半は、少しだけ答えが分かりやすくなるようなアドバイスをしていくことで、進みが少し早くなって、それによって脱線も少なくなり集中するようになって、動かないのが悔しいらしくて、必死に頭を働かせていました。最後、ペンギンが動かないことが悔しくて、ぎりぎりまで粘って直そうとしていましたが、残念ながら直せず終了しました。かなり悔しかったみたいなので、この続きでペンギンを動かすところからでよいかもしれません。', null, null),
  ('1dc706e7-9adc-58ab-945d-84a5e5c384e9', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-15', null, null, '通常 / 検定3級応用課題１', '検定を受験するかどうかを聞きましたが、まだ検討中で、来週までに親と相談してくるとのことで、今日は検定問題３級応用１に挑戦しました。特にヘルプを求めることもなく、38分くらいでできたというので、動作確認させてみたら、魚とカニがきちんと動きませんでした。ひとつずつ答え合わせをしてみていきましたが、日本語の一文一文をきちんとコードに反映できていない部分があり、一文ごとに日本語を丁寧に読んで終わったらチェックをつけるというような作業で、細かいケアレスミス的なものを減らせていけるかなと思いました。（言えばわかっていたので）また、不等号の演算処理が反対になっており、この辺の日本語→コード変換がうまくできていないというか、感覚でやっているのかなと感じました。ケアレスミスを減らす、感覚でやっているような部分をきちんと理解する（理解力はあると思います）という事が必要かなと感じました。', null, '時間帯: その他
タイピング: 集中していていました'),
  ('ed7dd95d-3b07-5ffe-84fb-694bb82dd362', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-15', null, null, '通常 / エクセル３級模擬問題３', '声がけしても特に、不明点はないとのことで自分のペースで進めていました。途中疲れていたのか、１０分くらいは寝てしまっていましたが、起きて再開していました。模擬問題３の問題１を終わらせて、問題２の途中で終了となりました。', null, '時間帯: その他'),
  ('36ce83fa-0708-5c97-a6e1-e486e3c534f2', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-12', '16:30:00', null, '振替 / 検定問題の数をこなす', '席につくなり、眞子ちゃんに話しかけられていて、最初は驚いたようでしたが、そのうち雑談をしたりして楽しそうに過ごしていました。 検定問題については、わかるところとわからないところがハッキリしているようで、こちらに質問してくるときもわからないところだけを端的に聞いてきました。 （質問は、「入れ物」の「向き」と「切り下げ」くらいでした） 問題文のヒントや日本語の書かれ方に注意するとブロックが探しやすくなることを伝え、納得してくれたようでした。', null, '盛り上がり: 眞子ちゃんも同じ2級にチャレンジしていたため、話も合ったようで、たまに問題への感想を言ったりしながら、楽しそうに取り組んでくれました。'),
  ('e0e5853c-a58c-5821-a9db-d9f0a79f9e35', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-16', null, null, '通常 / 検定問題に慣れる', '開始前に、じゃんけんの勝ち負け判定の処理部分が難しいので、考えてもわからない時は、声をかけてねと伝えた上でスタート。動作確認や見直しをした上で、38分程で完了。途中特に何の質問もありませんでした。答え合わせをしたところ、全て正解でした。勝ち負け判定の部分をきちんと初見で、アドバイスなしで解けたのは素晴らしいと思います。その後は自由にアレンジをして終了となりました。', null, '時間帯: その他
タイピング: 集中して取り組んんでいました'),
  ('1a89d04f-9752-5598-81e0-cc2118b49115', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-16', null, null, '通常 / 検定3級応用課題7', '検定問題に対してあまり集中力がないようで、時々手を止めたりサボってしまう箇所が見受けられました。実力としては、十分完成させることが可能であるため集中力を上げて取り組んでいけばより早く終えることができると感じました。本番までに集中力を上げて、完成から見直しまでの時間を余裕を持って確保できるように、積極的に取り組んでもらう方法を見つけていきたいです。', null, '時間帯: その他
タイピング: 集中して取り組むことができていました。'),
  ('39dbf36c-6d8d-59af-869f-18ed72f42187', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-16', null, null, '通常 / 検定問題に慣れる', '検定問題にはだいぶ慣れてきたようで、自分ですぐに取りかかっていました。 時間内に余裕を持って完成した後、動きがおかしいところがあると言って、自分でムービーを見直して直すことができていました。 アレンジとして、登場するお化けの種類を増やそうとしてスプライトを増やしてしまい、困っていたので、コスチュームの増やし方を教えました。その後は自分でコスチュームを追加して乱数の数値を変えることができ、満足のいく仕上がりになったようでした。', null, '時間帯: その他
盛り上がり: 問題を読むのも速くなり、応用もきくようになってきたためか、楽しんで取り組むことができていました。'),
  ('fa1993c5-6e5d-5a9f-a138-e9f946ffb18a', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-16', null, null, '通常 / 検定2級応用課題4', '複雑な演算の入力はある程度は自力で出来ていたようですが、難易度設定のコードで調べるの「〜と入力されたら」 の次に、対応する変数を演算に組み込めていないといったミスは見受けられました。 また、一番難しいとされるもぐらが穴から出てくる演算の式も、日本語の文章から読み取って入力するということが出来ていなかったので、次回はその説明からできたら良いなと思いました。', null, '時間帯: その他
タイピング: 集中して取り組めていました'),
  ('7e249d2b-820d-5f4e-902f-580825fdcb57', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-16', '16:30:00', null, '通常 / プロゲート', 'JavaScriptのコードについて学習していきました。事前にスライドで内容を確認して、支持された通りにコードを入力していくものだったため、少しでも違う箇所があるとエラーを出されてしまいストレスが溜まっているようでした。さらに、本人の性格としてお手本通りに作ることがあまり好きではないようで、集中力もすぐに切れてしまい長く続きませんでした。そのため、ある程度思考力も必要とする自由度の高い問題を解いていく方が肌に合っているのではないかと感じました。', null, null),
  ('d45cb5d4-fe4f-5497-be05-a2d289d23353', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-16', null, null, '振替 / 変数の使い方、ボールがランダムに落ちてくるときの初期位置の設定の仕方などの学習', '変数のフラグは、完成版を見ただけですぐに理解していました。自分でRPGを作った時に、使ったことがあるそうです。 ボールが上のランダムな位置にいくやり方については少し悩んでいました。使用するブロックをヒントに出したところ、なんとなく作成してみたがうまく動かないということで、一緒に見直したところ、演算式のy座標のプラスとマイナスを間違えていました。また、変数を1ずつ変えると１にするの間違いがありました。 それ以外はほぼ自力でできていましたが、やや早とちりなところがあるため、落ち着いてじっくり取り組む経験もさせたいところです。 完成後に、とても楽しそうにアレンジをしていましたが、こちらの提案は聴きつつもしっかりと完成せず、「見た目のインパクトが与えられれば成功」という感じで完成度にやや惜しい点が見られました。', null, '時間帯: その他
盛り上がり: ゲーム自体は終始楽しそうに作成していて、アレンジもノリノリでした。
備考: ご両親が、中学生コースに非常に興味をお持ちでした。検定もご両親は受けさせたいようでした。'),
  ('108a7d63-1e32-5f24-a6dc-68a48bfd13d6', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-16', '16:30:00', null, '通常 / 大会作品制作', '作成したホームページに打ち込んだ電話番号がローカル変数へと入った後に、呼び出すことができない状態のため、バグ修正をおこなっていきました。しかし、出力された文字が文字化けしていたり、サイトの画像がうまく表示されないなどの障害が起こってしまい、ついにmonacaのサーバが落ちてしまったようで作業の続行が不可能となってしまいました。本人も家などで直してみるとみると言っていたため、来週の作業ではしっかりと修正していきたい様子でした。', null, null),
  ('47e80f59-a8da-52bf-a7e4-4d3e9f9f8540', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-16', '17:30:00', null, '通常 / 検定4級応用課題3', '一度もぐずること無く検定を時間内にやり切ることが出来ました。 授業が始まってからもしばらくゲームで遊びたそうだったので、 適度に検定も促しつつも、 本人のやりたいことに乗ってあげるコミュニケーションを心がけて接しました。 検定問題文の日本語は、最初は私が普段どう打っているのか、ゆっくりお手本を見せながら代わりに打っていました。 タイピングについて本人に聞いたところ「最近ホームポジションを習っている」とのことだったので、 ローマ字表を持ってきてあげると「やっぱり自分で打つ」とのことで、 最終的に後半の問題はほとんど自分で入力をしていました。 前回から言ってきた「１つのスプライトにつき作り終わったら動作の確認をしてから進めよう」を本人も心がけて取り組めていたのがとても良かったです。 頑張って作ったのにも関わらず、 どこだか分からない部分で思うよう動かずイライラしてしまうのかなと思い、 今のところは解答と本人解答を参照しながら適宜修正するようアドバイスをしていますが、最終的に一人で動作確認をしながら最後まで静かに解けたら良いなと思いました。', null, 'タイピング: 無し'),
  ('dd0d281d-1fb1-5432-8985-5b9eb7668b18', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-16', null, null, '通常 / 検定問題に慣れる', '日本語文を一つ一つ丁寧に読んで、スクリプトを書いて、終わったところをチェックするよう指示してスタート。集中して取り組んでいました。ただ、どうしてもわからなくてアドバイスを求める事が多かったです。「〜に触れるまで、繰り返す」や「ずっと、繰り返す」をスクリプトになかなか反映できず、また、これら２つの違いも理解できていなかったようでしたので細かく説明しました。それと「(3)(2)の後に、〜をする」のような部分で、（複数箇所）ミスが見られました。(3)の処理を、(2)の繰り返し処理の中に入れていたので、(2)の処理ははどこからどこまでか？を説明してもらい、その後ろに(3)を置くことを納得してもらいました。「スプライトの他のコードを止める」で、どのコードを使うかも理解していなかったようなので説明しました。全体的に、日本語の文章からどのブロック・スクリプトを使うという変換がまだ甘い部分があるので、繰り返し復習して身につけるしかないか・・・。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('9d9a4306-f042-5bcc-8b50-17b630f22c9e', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-15', '16:30:00', null, '通常 / ⇒最近、ゲーム制作しているので ⇒家でも、結構いろいろ作っているっぽいので ⇒いままで使ったコードの集大成という意識付けしてもらい ⇒キャッチゲーム、「まで待つ」「メッセージ」など、 を使いこなす ⇒【Prg】06 星とりゲーム ⇒【Prg】07 （06の続きの）ストーリーを作ろう', 'キャッチゲームの続きに取り組もうと思ったのですが、ファイルを確認するとジャンプゲームに取り組んでおらず、本人もやってみたい様子だったので、ジャンプゲームに取り組みました。 基本的な操作はよくできていました。かなり簡単なようです。ジャンプのプログラムはアスレチックを作った影響なのかブロック定義を使ってまとめていました。卵の動くプログラムは見本とは違いますが、よく考えてプログラムできました。アレンジ内容に困っていたので少し提案したところ、上下にスプライトがでてくる方式になりました。となりでたまに様子を見ていた良志くんも楽しそうで良かったです。', null, 'タイピング: 集中して取り組めました。'),
  ('63cfe44d-eda7-5710-9ff0-a731d482a3d1', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-15', '17:30:00', null, '通常 / ⇒検定2級 続きで類問か？ ＊前回のマミさんの記録、必ず読んでおいてね ＊スランプ中なので(*´艸`*)', '検定2級を一緒に読みながら取り組もうと声をかけましたが、かなり嫌そうだったので、気晴らしに一緒にオリジナル作品を作ることにしました。 少し前に円を描くプログラムを作っていたので、円を使ってさくらんぼを描くプログラムを作成しました。デザインはチャットGPTにアドバイスをもらったり、色を変えたりして楽しむことができました。円の大きさや位置、軸も描けるプログラムを作成しました。最後は「線香花火に似ている」ということで、円の周りに線を足して、線香花火を作成していました。 次回は検定問題に取り組めるかは分かりませんが、終始楽しそうだったのでそこは良かったです。', null, 'タイピング: 集中して取り組めました。'),
  ('1b2f9b0d-f462-57f3-a6ab-39cce801e7cc', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-18', '16:30:00', null, '通常 / ドリル31~35', '今回は31~33までクリアしました。 上下左右に動かそうという問題文はすぐに理解出来ており、 右向きが90度で左向きが-90度であることも即座にわかるぐらい理解出来ていました。 繰り返すのコードを選ぶ際、「◯回繰り返す」を選ぶのが癖になっていたようなので、「問題文に◯回繰り返すと書いていない場合はずっとでいい」というのを、具体例を交えて説明しました。 また、33の矢印キーの問題で「〜に触れたら」の触れた対象のスプライト選び方が不自然だったり、左向きキーが押された時の動きのコードについて他のスクリプトに変な形で繋げようとしていたため、 まみ先生からどのスプライトに対してコードを入力しないと上手く動作しないのかを説明していただきました。', null, 'タイピング: なし'),
  ('469486f6-cf4a-5c1b-9652-43419c7d0938', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-18', '16:30:00', null, '振替 / 検定2級応用課題5', '今回は２級の応用課題５に挑戦していきました。内容としては、シューティングゲームの敵を順番通りに撃ち落としていくというもので、変数に数字を文字列として代入する特殊な使い方が出されていました。この特殊な使い方に悩んでいたようで、文字列として加えるの意味がわからなかったようです。答え合わせの際に、文字列の仕様やなぜこの問題で使われているのかを説明したところ、理解することができたようで1人で修正することができていました。次回の授業で検定前最期となりますが、現在の実力であれば合格はほぼ確実だと感じました。', '（大原追記：検定の問題はよく解けているので、次回は息抜きに他の課題をするか、もう1題検定問題をやるか、好きな方で構わないと伝えました。土曜日までに考えてくるそうです。）', null),
  ('ab5b8bf5-f1cf-5770-aa11-d61ef6eb20db', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-18', '17:30:00', null, '通常 / 検定4級②2回目に取り組む演習', '問題文を1行ずつではなく塊としてとらえており、 目についたものから作成してしまった結果、順番が入れ替わっている場面が数回見られていたので、アレンジをかけずに1行ずつ確実に作成するよう伝えました。 問題文の「セリフは消えない」がどういうことか（どのスクリプトを止めて、どれを動かしておけばいいのか）が曖昧だったため、スクリプトの中身をよく確認させて納得してもらいました。 繰り返しの中に「〇秒待つ」が入る場合も、間に入れるだけではなく最初か最後にも必要なことを、実際の動きを見させて理解させました。 試験時間3分前には解き終わることが出来たので、残りの時間は曹も混じってアレンジを考えることにしました。 アレンジの際は調べるや演算、変数などまだしっかり習っていないものもありましたが、「やったことあるかも」と都度思い出してくれたようで、まみ先生のアドバイスもありアレンジまでしっかり完成させることが出来ました。', null, 'タイピング: 集中して取り組めていました。'),
  ('1a495e3f-3a20-5a1a-bf0c-ab64887da291', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-18', '17:30:00', null, '通常 / 検定4級応用課題3', '今回は４級の応用課題３に挑戦していきました。問題の内容をしっかりと理解しながら、時間に余裕を持って得ことができていました。答え合わせにおいても、どうしてこのような動きをするのかを説明することができていたため、理解度はかなり高くすることができているようです。その後は、検定問題をアレンジしていきました。新たなキャラクターを登場させ、物語の進行中に話しかけてくるというものでした。本人としては結構気に入っていたようで、作品を見ながら楽しんでいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('bc78cf1b-a5b2-56f9-8a42-1cd85e9467af', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-18', '17:30:00', null, '通常 / Roblox体験', '以前作成していたデータが消えてしまったようなので、1から作り直していきました。作成内容としては、アスレチックとバトルを掛け合わせたゲームを作成しており、ゾンビが追いかけてくる中アスレチックをクリアしていくという非常に緊張感のあるゲームになる予定であると話していました。地形をどのようにすればジャンプでギリギリ届くのか、どれくらいの速さであれば追いつかれないのかを何回も試してゲームとしての面白さを追求していました。今回までで作成したものは一旦公開して、次回以降また続けていく予定です。', null, null),
  ('bd0201af-ea77-5bbf-bd65-6b01660076f6', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-12', '16:30:00', null, '通常 / 検定対策', '検定の問題自体は、一応終了時間の5分前に解き終わりました。ただ、本人が言うには、修正問題はわけがわからない、とのことでした。 「答えをきいてまつ」のブロックを忘れていたようで、ヒントを聞いてようやく履修したことがあると思い出せたようでした。 今日初めて一緒になった夏芽ちゃんにいろいろ話しかけていて、こういう問題は難しいよね、などと言い合ったり、同じ曜日に来ないかと誘ったりと楽しそうでした。咲良ちゃんがやめてしまって寂しいようです。 試験は苦手、難しいとよくぼやいていますが、なんだかんだ言いつつ、やる気はそこそこありそうで、手はしっかりと動かしていました。', '修正問題のところをもう一度、一緒に解き直してみてください。', '盛り上がり: 夏芽ちゃんや先生たちとよくしゃべっていて、教室にいる時間は楽しめているようでした。'),
  ('2403e390-ad9c-57f7-b281-3d01c209a60d', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-12', '16:30:00', null, '通常 / 検定対策', '試験問題自体は自分でできている部分も多いのですが、一度行き詰まると机の下に沈み込んでいってしまい、一気に集中力が途切れる傾向が見られました。 問題文中に「スプライトの向き」など、言葉として知らないものが出てくると、そのブロック自体は結果として知っているものだったとしても、考えるのを放棄して嫌になっているようでした。 条件分岐がネスト構造になるときなど、問題文のレベルとブロックのレベルが合っていないことがあり、一度それで作成してしまうと後から間違いを見つけるのが面倒なため、問題文を読む時点で文章のレベルに着目するように伝えました。', 'スキル自体はついてきているのですが、問題文の書かれ方によってはうまくコードに結び付けることが難しいようです。問題文を読んでわかりにくいときは、ムービーを見直して、自分で作成するときのようにスプライトの動きからブロックを考えていくことを勧めてみてください。', '盛り上がり: 順調に解けているときはしっかりと集中できていて、やる気も見られました。躓き（と本人が思い込んでいる？）さえなければ、それなりの速さで完成させられると思われるのですが…。'),
  ('1834b2d3-d69a-565f-b76e-0b405c1aed9e', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-18', '17:30:00', null, '通常 / 今後の課題を決める', '授業開始時に、縁くんがやっていたロブロックスの画面とProgateの画面を見せて、今後やっていきたいことを確認しました。わりと即答で、「Monacaをもう一度やりたい」とのことだったので、お家の人に有料アカウントが必要なことを話してもらうよう伝え、次回以降に準備しておくと話しました。Scratchでの作品作りもまだまだやっていきたいようなので、教室でもProgateなどと並行して進められることを話し、納得したようでした。 ロブロックスにはあまり興味がなく、将来JRで働きたいのでテキスト言語を習得したいようでした。 今日はProgateとScratchのどちらをやるか選ばせ、最近作り始めたScratchの京王ライナーのシステム？を熱心に作成していました。 途中3回くらい、電車が好きだと言う秋くんがのぞきに行っていて、会話はありませんでしたが、画面自体は快く見せてくれました。', null, '盛り上がり: 電車関係の作品を作ることが多いので、何か月か前に、鉄道会社で働きたいのかと聞いてみた時は「別に」という感じだったのですが、今日は「JRとかで働きたいからプログラミングを勉強したい」と口に出していて、ひいろくんの成長を感じました。'),
  ('7b178577-5d2d-5226-8621-6c6bbfb1321b', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-19', '16:30:00', null, '通常 / レースゲーム完成、検定練習', '前半は前回のレースゲームを完成させました。まず、前回作っていたとき勇作くんにわかりやすく教えてあげていたことについて声かけして、自信を持ってもらいました。メッセージ周りでバグがあったときに、「このメッセージを送った場所のコードを見よう」と自主的に確認することができていました。手順書通りに作り終わった後、敵のスピードが遅すぎることに気付くと調整していました。 後半は検定の類問を解きました。完璧にこなすことができていました。3種類の「止める」ブロックを意識して使い分けていたとのことで理解が深かったです。', null, '盛り上がり: 落ち着いている一方でやる気がある様子でした。'),
  ('e6b2f0e2-853f-5c2d-a443-786dfa1ab149', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-19', '17:30:00', null, '振替 / 検定練習', '検定前の最終回として類問に取り組みました。わからない場所があったら線を引いておくとやりやすいかもとアドバイスするとそのようにしてくれました。検定に不安があるとのことでしたが、問題文の日本語の理解を含めておおよそできていました。セリフの中に変数を入れる方法やセリフを消す方法といった、あらかじめ知っておかないといけない場所だけミスしていたので、本番に向けて覚えておこうと伝えました。', null, '盛り上がり: いつもと違う環境だったと思いますが集中してできていました。'),
  ('d338a1e0-ee08-5b2a-95c8-1d2d5a1635f2', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2024-11-19', '16:30:00', null, '休み（未対象）', null, null, null),
  ('39ffc32f-0ccc-5971-87f2-5b9b97b894c4', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-21', '16:30:00', null, '通常 / 検定3級応用課題8', '今回は検定前最後の授業で、特に質問や苦戦など無く時間内に解き終わりました。アレンジではえみちゃんの読んでいたハリーポッター風にしてみなよと提案したところ、キャラを増やすだけでなく背景も変えたいとのことで、コードを変えない代わりに既存の背景を消していいかどうかまみ先生に確認してから無事完成させました。 今まではコード作成ですぐ分からないと諦めていた様子でしたが、慣れてきたのかなと思いました。', null, 'タイピング: 集中して取り組めていました。'),
  ('661973b1-e590-5e67-ab70-9cd4e84b09ad', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-21', '16:30:00', null, '通常 / 検定対策', '今日は検定前最後なので、途中で席を立たずにさっさと終わらせてフリータイムにしよう、と持ち掛けると、こたろうくんの誘惑にも席を立たずに頑張っていました。 以前提案した、問題用紙を折ってリーディングスラッガーの代わりにする方法を実行していて、今読んでいるところに着目しようとする姿勢が見られました。（お母さんからの情報では、学校でもリーディングスラッガーを提案されたことはあるけれど、面倒がって受け入れなかったとのこと、こちらの教室でやるようになったことを喜んでいました。） 上記の効果か、一文まとめて読み飛ばしてしまうことはなくなっていましたが、変数名やメッセージ名の変更のし忘れが2か所ありました。 変数とコスチュームの番号をかける演算式を作成するところで、問題文の書かれ方がわかりにくかったらしく、一度嫌になりかけていましたが、単語を一つ一つ読んで、そのブロックを持ってくるうちに組み合わせがどんどん閃いてきたようで、その先は自己解決できていました。 似たようなスプライトの修正問題では、コードをかたまりとしてとらえて「ここは複製できる」と判断する能力がなかなかでした。発達診断でも、そのあたりの能力は高く出ているとのことでした。', null, '盛り上がり: 今回のスロットマシーンはゲームとしても面白かったのか、一度嫌になりかけた以外は集中して作成できていました。できあがったゲームを何度かプレイして満足そうでした。 残り15分くらいは約束通りのフリータイムということで、こたろうくん、るいくん、そうた ろうくんと椅子を並べて楽しそうに遊んでいました。'),
  ('aad6219d-abbc-535d-9c59-ab14808a5b32', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-21', '16:30:00', null, '通常 / 検定4級応用課題4', '今回は本番通り静かにやれるよう、隣で立って見守っていました。 問題文での日本語の言い回しとコードでの日本語の表記が脳内で合致し難いのか、 「ずっと、繰り返し」を「ずっと〜」と「◯回繰り返す」を使わなければいけないと勘違いしたり、「まで繰り返す」と「〜なら、でなければ」が問題文から推測が出来ない場面がありました。 そういった困難に直面した時は自力で解決出来なくなりやる気が無くなってしまうので、 一緒に文章を四角で括ってチェックしたり、実際のコードを指して問題内の言い回しと同じように置き換えて説明するなどサポートをしました。 また、セリフを消す仕組みも難しいため実際に例を出しながら説明しました。 試験中は問題で詰まって集中力が切れるまでは静かに取り組めて自己解決出来ていました。', null, 'タイピング: なし'),
  ('66f10832-de9b-599c-a8bb-16fdbe260e66', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-21', '17:30:00', null, '通常 / オリジナル作品の作成', '授業開始時に、今後作成したいものについて話をしました。 今回のU16大会作品については、作成が終わってないから通らなくていいと思っていたけれど、実際に通らなかったとなったらとても悔しかったそうです。 来年は、もっとプログラミングのスキルを活かせるものにするか、題材を審査員に好まれそうなものにするなど、対策を練って良く考えてチャレンジしたいとのことです。まだまだチャレンジする気持ちはありそうでした。 とりあえず、今作成しているものは完成させたいとのことで、今日はひたすらお話の続きを打ち込んでいました。 昨日まで期末試験で、明日も一日学力試験があるとかで、眠たがったりもしていましたが、最後までしっかりとPCに向かっていました。', null, '盛り上がり: 今回の大会結果は残念そうではあったものの、まだまだやる気はあるようで、前向きに今後のことを考えていました。 今作成中の小説も、公開を目指して頑張って作り続けたいとのことでした！'),
  ('7e80e041-2091-555b-befe-8e95a3dc8870', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-21', '16:30:00', null, '通常 / 野球ゲームを作る', '前回の続きとして、ボールの動作の作成を試みました。周りが、検定練習モードだったので、作成に向き合ってくれるかと思ったが、まずまずでした。どのような過程を経て作ればいいかわかっていない感じでした。そのため、どこから投げてどこへ向かっていくことを質問して整理していき、答えることができましたが、じゃあそれをコードを直していこうとなると、手が進みずらいです。できたとしても、はい今日は終わりと授業の時間が30分も残っていてもよそに気に入っちゃていしまいます。その原因としては、能力的にはこたろうくん自身が、コードの種類を把握できていないと感じます。性格的には、こたろうくん自身のやることのハードルの低さが見られます。「1つ作れば、今日は終わり」感が最近続いている感じします。あとあめの食べ過ぎも眠気を誘発している。だから、小粒なものでも、何個か動きを作り続けられるように、ドリルの教材をやってもいい気がする。レベル3くらいのもので', null, null),
  ('09dddd97-9ace-53e0-add5-b5e5853fc857', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-21', '17:30:00', null, '通常 / 検定練習復習', '1級の練習問題が一通り解き終わっていたので、苦手あった定義の問題があるものをまたやってみました。やっている最中は、引数のところの使い方に悩んでいたが、時間をかけてできるようになっていました。全体としても時間内に完成できたので、能力としては大丈夫そうです。', null, null),
  ('de73a1ba-9947-5883-b2e3-9f4db6f6bf87', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-21', '17:30:00', null, '通常 / アルスタジオレッスン/ベーシック/宇宙バトル1', '隣で一緒にレッスン動画を見ながらコード作成をしていました。 動画を見ながら進めることをおすすめしてはいたのですが、本人的に動画の指示とは別に先に作りたい箇所があったり、選ぶスプライトも動画とは別でアレンジをしたい様子で、レッスンだと少し物足りないのかな？と感じました。 また、以前作ろうとしていたスロットマシーンよりかはシューティングゲームのような遊ぶゲーム性が高いものが好きそうだったので、ドリルで基礎的な技術を学びつつも、ゲームで都度必要な知識を自分から学習する方がもしかしたら好きかもしれないと思いました。', null, 'タイピング: 集中して取り組めていました。'),
  ('b8c65148-b9b5-55ba-8087-38853b71f6a8', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-21', '17:30:00', null, '通常 / 検定対策', '開始前に問題文の読み方をもう一度復習しました。「繰り返し」「受け取ったとき」など、キーワードに〇をつけさせて、その中にどこまでの文章が入るのか、あらかじめマーキングするやり方を見せたところ、素直に感心して先に問題に目を通してチェックをしていました。また、数値の半角全角の打ち間違いを後から見つけるのが難しいことも身に染みてわかったようで、入力前には必ずチェックをすることを決めてから取りかかりました。 その成果があったのか、今日の問題は相性が良かったのか、途中でつまるところもなく、15分前に嬉しそうに完成を告げてきました。 時間が余ったのでアレンジをすると言って、おばけのコスチュームを増やしてたくさんお絵描きをし、コスチュームを決める乱数の数値もきちんと編集して、満足のいく作品に仕上げることができました。', null, 'タイピング: 真面目にやっていましたが、いつもと違うPC（Windows）でキーの感覚が違ったのか、本人がいうには「ちょっと失敗しちゃった」だそうでした。
盛り上がり: 今日は満足のいく出来だったようで、ずっとニコニコしながらPCに向かっていました。自信を持って最後の対策が終えられたようで良かったです。'),
  ('37882377-69a2-5f80-b4de-c3118ed77171', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-21', '17:30:00', null, '通常 / 検定練習', '一人で十分に取り組むことができ、時間も10分で余らせて、完璧にできていました。そのため、アレンジの部分もやっていました。一見、悩んだ様子を見せたが、ゴールに二人とも喜ぶように変えてくれて、そのことを、伝わるように文章にできていたので、アレンジもやっても得点につながると思います。', null, '盛り上がり: アクション系に最近ははまっています。'),
  ('f81fe867-f17e-5abe-9d07-0a13c7e2fabf', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-22', '17:30:00', null, '通常 / 検定2級応用課題3', '前回の検定問題にて、文章が複雑になっていたためやる気を削がれてしまったようなので、今回はそれほど複雑ではないものに挑戦していきました。問題内容については、どういった内容でどのように動いているのかはしっかりと把握することができていたようです。唯一間違っていた箇所も不等号も向きが逆というものでしたので、こういったケアレスミスに注意していけば満点を取ることも十分可能であると感じました。本番に対しての気合も十分あったため、この調子で臨んでもらいたいです。', null, 'タイピング: 一つ上の級に到達できるように頑張っていました。'),
  ('44dc797a-5056-5137-b930-b17f6f9ece7b', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-22', '18:40:00', null, '通常 / 検定1級応用課題2 答え合わせ 検定1級応用課題3', '前回途中まで作成していた1級応用課題2について答え合わせを行っていきました。作成していた部分までは完璧にできていたようなので、残りの部分を完成させながら内容の確認をしていきました。その後、応用問題3に取り組んでいきましたが時間がそれほど残っていなかったため、途中まで完成させて、その部分まで答え合わせしていきました。残りの時間では、息抜きとしてタイピングを行っていきました。実力としては十分に合格できる力を持っているため、制限時間に注意して取り組むことが重要になると感じました。', null, null),
  ('d3eab78e-9df5-5687-84e8-3b6c76ab018b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-22', '18:40:00', null, '通常 / 検定3級応用課題7', '前回不等号についてミスがあったため、その部分に注意して検定問題に挑戦していきました。問題内容をしっかりと理解しながら作成することができていたようで、動きや変数の意味を自身で説明することができており、答え合わせにおいても間違うことなく完璧に作成することができていました。今回の検定問題を通して自信がついてようで、本番の問題もスラスラと解いていきたいと意気込んでいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('286bd635-6d2f-5047-95ba-c7c3990f5a45', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-22', '16:30:00', null, '通常 / 「〜まで待つ」「まで繰り返す」の活用を学ぶ', '教材を見てサクサクと進めていましたが、見本のスクリプトをわからないまま写している雰囲気があったので、分からない部分を確認していきました。基本的なブロックは問題ないようでしたが、「〜まで待つ」「最前面へ移動する」「スプライトの他のスクリプトを止める」が特によくわかってなかったので、細かく教えて納得してもらい、この教材の肝となる部分は完成させました。小２という年齢を考えればよくできていると思います。あと、一応報告しておきますと、教材が10歳くらいから対象となっているのか、読めない漢字がところどころあったようです。', null, null),
  ('d81ae57f-731e-5858-88fb-29a19c281080', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-22', '17:30:00', null, '通常 / 基本操作コース', 'キー入力によって、ネズミを上下左右に向きを変えて進む処理、壁にぶつかったらそれ以上動かなくなる処理、チーズに触れたら音がなって、チーズが別の場所に表示される処理をしてもらいました。それぞれの処理で、まだ細かいアドバイスが必要でしたが、教えることで理解して納得してもらえました。まだ、基本の部分でもスムーズにスクリプトを作成できている感じではないので、いろんなスクリプトを組んで慣れていく段階なのかなと感じています。', null, null),
  ('95f257c2-e254-5e3f-8676-d212f5fe3f21', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-11-22', null, null, '通常 / 検定問題に慣れる', '制限時間を１０分くらい余らせた状態で終わったとのことで、「きちんと動くことも確認した？見直ししなくても大丈夫？」との問いかけに「うん」とのことだったので、答え合わせをしましたが、残念ながら、間違い回答が多くて、今回が本番だったとしたら、結構厳しい点数かなと思います。ただ、今日は全体的に集中力がない状態だったのかなと思いました。答え合わせの途中に、半分寝てしまうような状況で、眠たいと聞くと「うん」と回答したり、返事もうわの空な感じでしたので。先週は、ここまでひどくなかったので、眠気からくる意欲＆集中力の低下だった可能性もあるのですが、すみませんが、今回でとうきくんを見るのが２回目なので判断ができないですm(__)m', null, '時間帯: その他'),
  ('c0a4eeb5-a480-5482-9f7c-1ae73fe963ae', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-23', null, null, '通常 / 検定練習', '始まる前は検定に対してモチベーションがあまりなかったですが、今回の問題がボールを弾ませるゲームっだったので、かなり変数の使いところが多かったですが、集中してできていました。確認してみると、ずつと似カエルの変数の１ミスくらいでよくできていました。アレンジもサッカーにして遊んでいてよかったです。', null, '時間帯: その他'),
  ('87b178fe-27b3-5f83-b316-eb525d829603', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-23', null, null, '通常 / 検定2級 応用2（012）スロット', '30分ですべて解き終わり、全問正解しました。 アレンジが全く思いつかないとのことだったので、「出てくるものがコインじゃないスプライトにしてみたら？」や、「好きなものをモチーフにアレンジしてみては？」と提案しましたが、スロット内の絵を数字に変えるなど微妙な微調整ばかりでした。 アレンジを考えるのが苦手らしく、「色を変えてみるとかコインのスプライトを変えるだけでもアレンジになるよ」と伝えました。見た目の他にも、もう少しゲーム性のあるアイデアをこちらで提示出来たら良かったのかもしれません。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('0c1dc64e-a24c-506f-b577-ec7629fe2720', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-23', '16:30:00', null, '通常 / 検定練習ラスト', '演算式が多く、変数に文字式を入れる系の問題でしたが、特に迷うことなく、解き終えていました。途中で止まることなく、着々と解けていたので、本番でも能力的には大丈夫だと思います。', null, 'タイピング: よくできていました。'),
  ('8a87ed78-aa3b-5797-8970-21a804349c01', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-11-23', '17:30:00', null, '通常 / 検定1級 応用2', '試験時間10分前に解き終わり、内容も全問正解していました。内容に特に問題点も無さそうだったのでアレンジをすることを提案しました。アレンジの内容としては、画面内キャラと対戦するキャラを新しく作るといった内容で、不備なく遊べたものになっていたので良かったです。', null, 'タイピング: なし'),
  ('9f8c90ea-55c1-5a59-9e14-686f5a4c59a1', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-23', '16:30:00', null, '通常 / ゲームを細分化してく作ろう', '最初の試遊で、クローン使ってそう、回転の演出おもしろそうなど楽しんでくれたので、政策に取り組みやすかったです。そこで上がった意見が、いろいろととちっていたので、まずはわかりやすいビルの動きについて方針を立ててあげました。作っていく中で、クローンの削除条件として、左端の座標判定を「ずっと」の中の「もし」を使って作れていましたが、「まで繰り返す」の提案をしてあげると、「そういえばそんなのあった」と反応をしてくれました。この反応をなくすために、見たことあるブロックを使えるブロックにしてあげる機会を増やすためにいい機会でした。変数によるフライングは元のゲームを変数の変化を読み取って、自力でその仕組みを組み立てられていました。また、今回の悩みとして、飛んでる時の回転角度に範囲制限がある仕組みについて悩んでいました。あれやこれやと考えてくれましたが、自力ではいかず、ヒントとして、位置の場合で例えるとどうなるか考えてもらいました。そしたら、条件式が立てられていたので、角度の対しても同様に考えることができました。', 'つづき、通り抜けた数でスピードアップする仕組みから', null),
  ('2c5dd8ea-e29c-5d0c-a9f1-17a8a62708f1', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-23', null, null, '通常 / 検定練習', '前回の答え合わせが未完でしたが、今日で1つの問題を最後までやりきるため、次の問題に切り替えて取り組みました。意識を持ってもらうため、本番では30分経ったら回収だということを確認してから始めました。ここにきて慣れてきたようで、(本番で不要なタイピング部分以外は)制限時間に収めることができました。「止める」ブロックの使い分けだけミスしていましたが、そのことを言われるとすぐにピンときて思い出していました。', null, '時間帯: その他'),
  ('ca008936-60ee-5900-9367-7ccfd4b26773', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-23', null, null, '通常 / 検定練習', '検定の最後の練習に取り組みました。「層を下げる」や「向きブロック」といった、知識が必要なところだけ少し抜けていましたが、それ以外はきちんとできていて構造を理解していました。隔週ですが感覚を忘れることはなくできていました。軽いアレンジまでして終わることができました。', null, '時間帯: その他'),
  ('63a827ea-a11c-5939-b521-58f6f1252163', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-23', null, null, '通常 / U16作成', 'U16大会の本選準備を行いました。最初は敵の攻撃に関するブロック定義などゲームのコードを少し作成し、複雑な引数や演算なども使いこなしていました。そのあと、はるくんと一緒に過去の本選の動画を見ました。発表の仕方に関して参考になったという様子でした。', null, '時間帯: その他'),
  ('a6b3e898-e65e-5d35-a766-67870b34cf51', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-23', null, null, '通常 / 興味のある題材で作成する', '先週まででやる気がダウンしていたため、息抜きとしてドット絵を描き、それをゲームのスプライトとして使うということをしました。マイクラの剣が好きなようだったのでiPadで描いてもらい、その剣を刀剣ゲーム(手順書を見ながら作る)に入れようと提案しました。興味を持ってくれて、レッスン時間が終わってもしばらくゲームを作成していました。', null, '時間帯: その他'),
  ('10d72638-76cd-5f0e-a736-346505c31d8c', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-23', null, null, '通常 / 検定練習', '検定の最終練習に取り組みました。時間に余裕を持って解き切り、パーフェクトでできていました。そのあとキャラクターを増やす面白いアレンジをしていましたが、けっこう複雑なコードを使ったので本番はシンプルなものにしたほうが点が取りやすいよと伝えました。', null, '時間帯: その他
タイピング: 楽しくやっていました。'),
  ('2575bab1-3635-5761-8fd7-b6a67409469d', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-23', null, null, '通常 / 検定練習', '検定を始める時間をこうしろうくん自身で決めてやったので、スムーズに始められました。文字の打ち込みが多い問題だったので、大変だったら呼んでと呼びかけしたら、セリフの部分は用意された段階でサポートすることができました。一通り解いて、まだバグを残っていたら、ぐずらずに、見直す動作ができていました。今回は、そこで続けて作っていたのを分割するように自分で治せていたので良かったです。', 'ドライブにあるかーびいの絵を使ってドット絵をかきに、それを使ったゲームを作成', '時間帯: その他
盛り上がり: 終わりにはじめくんのドット絵に感化されて楽しんでいました。'),
  ('c647be03-3933-5ca1-b6e9-2e5aaae2acd6', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-11-23', null, null, '通常 / 検定練習', '検定の最終練習に取り組みました。解いている途中に膝立ちするなど体勢を崩すことが多かったですが、やる気がないわけではなくむしろノリノリで作成していました。ただ、本番はとても真面目なテストだから同じことしたら失格だよと伝えておきました。本人いわく問題は簡単だったとのことで、アレンジとその説明を含めて完全にできていました。', null, '時間帯: その他'),
  ('28b36dae-0f19-582e-9102-91044861febc', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-23', null, null, '通常 / 検定練習', '解いてる最中は、テスト勉強も疲れもあって、変数の変え方がわからんとか表示されないなど事例が起こり、切り替えができていない感じがあったが、自己修正して、時間内には完成できていました。ミスもなかったので大丈夫です。', null, '時間帯: その他'),
  ('4191208e-50a7-5000-aedc-34bfd13718d6', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-23', null, null, '通常 / 本選発表資料つくり', '本選に向けて、プレゼンの準備をしていました。', null, '時間帯: その他'),
  ('820cdf7c-e6d6-582f-bb1b-8f09475cbca8', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-11-22', '17:30:00', null, '通常 / 検定問題を最後まで解く', 'タイピングの途中から、画面が急にズームしたり上下に動いたりすること気になってしまい、だんだんイライラしてきたようでした。マウスポインタが補助機能で円になっていたこともあり、操作しづらそうにしていたので、設定を解除したり、トラックパッドが使えないようにしたりと環境を整えて本人に納得させるまでに時間を要しました。 前回から取り組んでいる応用課題4がうまく動いていないことは覚えていたので、もう一度最初から解き直しをしました。前回までは、修正しようとしてブロックの位置を変えて元の状態がわからなくなっていたようで、一からやり直すと順序などがおかしくなっていたところにも気づけたようでした。 流石に一度解いた問題でもあるため、今日は無事に解き終わることができ、ペンギンが勝てるように歩数を調節したりしてアレンジを楽しんでいました。', null, 'タイピング: 熱心に取り組んでいましたが、タイピング中にトラックパッドに手首が触れて画面が動いたりすることに、かなりイラついていました。
盛り上がり: ようやく課題が完成したのがとても嬉しかったようで、お迎えのお母さんを呼んで熱心に作品の説明をしていました。'),
  ('ddf8a07d-5859-5cdb-91dc-da57ee19e16b', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-25', '16:30:00', null, '振替 / 検定練習', '最初に止めるのブロックの種類を確認してから、始めました。ゆったりとして解いていき、とまるのブロックが出てきても正しい対処ができいました。残り2分くらい一通りは作り終わったが、魚に元にすぐ言って食べられてしまうバグがありました。そこで、どこがおかしそうかか尋ねたところ、サメの動きのところ着目して、「魚へ行く」になっていたところを、「魚へ向く」に自分で修正できて、時間内に修正できました。アレンジもコスを変え、文章にする練習もできました。', null, 'タイピング: なし'),
  ('5b0cc43f-745b-5a84-b1f4-3ec94a7a37af', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-11-25', '17:30:00', null, '通常 / 検定練習', 'じゃんけんの問題に取り組んでいきました。この問題は、とにかく変数の演算が多いので、やりながらそのことを愚痴っていました。この問題の山場の勝敗判定のところに悩み止まっていました。5分ほど悩んで進んでいなかったので、先に進むのもありと提案しても、ずっとかたくなに考えてくれました。その結果、できそうなコードは思いついたものの、作るのがめんどくさいと後回しにしました。ほかの動作も作っていき、悩んだところ以外を答え合わせると、できていました。そのあとに、勝敗判定のところ、自力で作ってもらったできていたので、「できるんだから、自信もって作ってあげて」と熱烈にアドバイスししました。 今回は悩んで解けたからいいけど、ほんとにわかなかったら次に進むことも薦めました。', null, 'タイピング: 検定前の肩慣らしにやってくれました。'),
  ('7dbc2f53-4ea0-5b7d-b86e-150472ef8c85', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-25', '16:30:00', null, '通常 / ドリル34～ ここ数回、ドリルを頑張ってやっていますが、ドリルを始めてみて、集中しきれていないようなら以下に切り替えて⇓ アルスタジオレッスン/ベーシック/宇宙バトル1またはゾンビをたおせ1', 'ドリル34・35：「クリックする」のプログラムが「触れた」と「押された」から構成されているのが理解できなかったようなので、「ドアを開ける」の動作を例に詳しく説明しました。また「もし」を使うときにずっともセットなことを忘れがちなので、何度も強調して説明しました。 後半は宇宙バトル1をやりました。動画は見ずに話しながら進めました。ドリルでやった内容がゲームに結びつくのが嬉しい様子でした。コインを上下に動かすのはスムーズにできました。右に行くまで動かすときに「〇回繰り返す」を使うと、見える速度でスムーズに動かせることを説明しました。右から左に何度か動くようになったので、次回は表示非表示のタイミングの調整とアレンジです。', '宇宙バトル1、おそらく完成させたいと思うので、できれば。', 'タイピング: 正誤率が気になるようで、何度か挑戦していました。丁寧に取り組めました。'),
  ('651c609c-0f0a-52ce-bd63-3652a5595e7e', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-25', '17:30:00', null, '通常 / 検定4級②2回目に取組む演習 本番の問題形式に近いことを伝えて。 これまでも良くできているので、終わったら疲れすぎないように。', '20分ほどで完成できました。もっと早くできていたそうですがが、声をかけて動画を見て再度見直しをするように促しました。0.1秒ごとにプログラムを繰り返すときに、0.1秒待つの数が少なくミスになっていましたが、その他の部分はよくできていました、制御ブロックの使い方もバッチりでした！ アレンジの注意点を共有し、5分ほどで取り組んでもらったものの、紙に書いて説明するのが難しく、かなり時間がかかってしまいました。よく頑張っていたので素晴らしかったです！！', null, 'タイピング: 集中して取り組めました。
盛り上がり: 電車が好きなようで、家でScratch(で?)の電車の動画をよく見るそうです。'),
  ('f92873fb-a091-5582-b0f2-ce98095d91df', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-11-25', '17:30:00', null, '通常 / 検定4級応用課題3 問題を1文ずつしっかり読んで、、自分が今、どこに取り組んでいるのか見失わないように誘導してあげてください', '最初に自分で分かっている間違えやすいポイントを聞いたところ、誤読しやすいと把握できていました。注意しながら取り組んでもらい、文章に✓を付けるように伝えました。時間中かなり眠そうなときがあったので、時間を10分確保して寝てもらいました。 時間はギリギリでした。他のスクリプトを止める指示が文章で理解しにくかったそうです。アレンジは時間の都合で取り組めませんでした。当日の検定に少し不安があったそうなので、例題を出しながら詳しく流れを説明したり、質問に答えたりしました。', null, 'タイピング: 集中して取り組めました。'),
  ('df34c0be-071c-5378-ae96-5193f87760e2', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-22', null, null, '通常 / 検定4級応用課題3、4', '本番も近いということで、今回は２つの検定問題に挑戦していきました。１つ目の問題では、どのような動きをするかは理解できていたようですが、順番が違ったり数値が違ったりと問題文をしっかりと読んでいなかったようなので、そういった部分を直していきたいです。２つ目の問題では、その反省を活かしてしっかりと文章を読み込みながら取り組んでいました。その結果、１つも間違うことなく完璧に解くことができていました。本番でもこういった部分に気をつけながら取り組んでほしいです。', null, '時間帯: その他'),
  ('d0ccda91-7319-5956-9029-0c12edb79811', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-22', '16:30:00', null, '通常 / 検定3級応用課題6', 'もうすぐ本番ということで、今回の検定問題を通じて苦手部分の克服を目指していきました。問題を解いている際に、わからない部分の原因を探すことを諦めてしまうことがあったため、分からなかった部分を一緒に考えながら取り組んでいきました。本人も一緒に考えていった際には、どこが分からないのかを積極的に探していました。そして、分からない原因を見つけた際にはその理由に納得して、探すコツを掴むことができたようなので、本番でもそのコツを使って満点を目指していきたいといっていました。', null, 'タイピング: 集中して取り組めていました。'),
  ('902dede4-debb-5779-adc2-11c1c9e3431a', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-22', '16:30:00', null, '通常 / 大会作品制作', '大会本番に向けて作品制作の続きを行なっていきました。テストで点数があまり良くなかったようで、かなり落ち込んだ状態で始めましたが、作成中はしっかりと向き合って取り組めていたようで、土煙がうまく消えない不具合起きた際には処理の順番が違うということに気づいてしっかりと修正することができていました。次回の作業にて作品自体は完成させることができるということなので、作品完成とできれば資料や発表用の台本なども作成していきたいです。', null, null),
  ('dac9f114-867d-576c-ae2d-a06f923c554e', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-11-22', '18:40:00', null, '通常 / 大会作品制作', '発表に向けて、作品のスタート部分とゲーム画面への移動部分を作成していきました。以前にプレイした際に表示されている勝利画面が、次のゲームスタート時に表示されてしまう不具合が起こっていたようなので、一緒に解決していきました。変数やメッセージを送るタイミングが噛み合っていなかったのが原因だったため、その部分の修正とデザイン面に関しても一緒に変更していきました。次回の授業でも作品制作をしていき、次次回くらいには完成させていく予定だそうです。', null, null),
  ('9cbdb0d3-8fdc-591b-9133-f0b1fdee45bd', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-02', '16:30:00', null, '通常 / アルスタジオでコードを見てみたい作品を探す→アレンジ', '検定のゲームをアレンジしました。 最初に出す魔法の種類を変更できたり、数字キーで技を打てるようにしたり、大きい龍のスプライトを加えていました。 アレンジが終わった後は別のオリジナルゲームを作成しようと、ネットで女の子のイラストを探しそうとしていました。いい画像がDL出来なく、代わりにアルスパークの素材で代用していました。 「もっと可愛い運動が得意そうな女の子の絵があったらいいのに」と言っていました。', null, 'タイピング: なし'),
  ('13be5b14-bcc1-59da-8810-b4b3eef9ac99', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-02', '16:30:00', null, '通常 / アルスタジオでコードを見てみたい作品を探す→アレンジ', 'いちごの反乱でアレンジをしました。 イラストをDLしてスプライトの変更を主にしており、 私が本人に伝達部毒で新しくコードを加えるといったアレンジは出来ていなかったです。 ゲームオーバー時、主人公が真っ二つになるクローンをスプライトに当てはめる際に苦戦していました。', null, 'タイピング: なし'),
  ('ac7d52e8-a733-51f5-91b5-53d9ce5f1f84', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-02', '17:30:00', null, '通常 / ロブロックス 前回の続き', '動画を見ながら進めるのと、自分で遊ぶのと両方を進めるように伝えたのですが、ほぼ自分で遊んでいました。その効果でロブロックスの操作は一通り覚えたようで、剣を持ってゾンビと戦うようなゲームを作って遊んでいました。動画の方も、足場を変えられるので面白そうだと感じたのですが、えにしくん的にはあまり興味はなかったのかな？少しだけ動画は見ていました。 今後、操作に困ることはほぼないかな？と思います。', null, null),
  ('e4310328-0caf-5d35-a5f4-9b1f46e5bd5b', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-02', '16:30:00', null, '通常 / アルスタジオでコードを見てみたい作品を探す→アレンジ', 'しばらくゲーム選びに悩んでいた様子だったので、 本人が好きな鉄道のゲームをアルスパークで探してみたら？とアレンジしたところ、 鉄道シュミレーターを見つけ、気に入って使ってもらいました。 新幹線の色や背景を変えてアレンジしていました。 自分の伝達不足でコードを変更するといったアレンジはほとんどしていませんでした。', null, 'タイピング: 集中して取り組んでいました。'),
  ('993f0670-885e-5158-9ef0-5dcdfb8b0b46', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-02', '17:30:00', null, '通常 / 検定お疲れさまデー。 アルスタジオでコードを見てみたい作品を探す （多少時間がかかってもOKだが、できれば30分以内） 作品が決まったら、1つ(そうたくんは3つ以上)でいいのでコードをアレンジ', 'いくつか作品を見ていましたが、選ばれたのは射的ゲームでした。球数を増やす、色を変えるなどを行っていました。球数を変更しても、変数のプログラムがきちんと動かなかったので、私の方で解説しつつ、内容をかなり変更しました。楽しく取り組めました。 スプライトの見た目の編集にまだ少し慣れていない様子なので、今後アレンジなどを通して慣れていってほしいです。', null, 'タイピング: 丁寧に取り組めていました。'),
  ('443274be-ecca-565c-97d6-3ee00032141f', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-02', '16:30:00', null, '通常 / 宇宙バトル1 チュートリアルを見ながら', '宇宙バトルよりもゾンビを倒せを作りたかった（レベルもほぼ変わらない）ようなので、内容を変更しました。キーを押したときの動きのプログラムは少し慣れてきたようで、角度と歩数に気を遣うことができました。一方で、「調べる」にある「～キーが押されたとき」のブロックにはなかなか気づくことができませんでした。少し元気すぎました。落ち着いて考えると分かることが、分からなくなってしまうこともあった（ビームの動き方や端に着いたらなど）ので、落ち着いて取り組むことが大事かな？と思いました。 プログラムの途中で自動でビームが発射されるようになったのですが、本人はそれが良いようで、ひとまず完成しました。「全て止める」「隠す」は自分でプログラムすることができました。', null, 'タイピング: 集中して取り組めました。'),
  ('0b8c8915-9921-5d68-90a8-008f26ff1bb1', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-02', '16:30:00', null, '通常 / 自分で決めたゲームを最後まで作成する', '前回作成していた宇宙バトルが一応途中でしたが、本人はもう完成したので新しいものを一から作りたい、とのことで次の作品に入りました。 勇作君と盛り上がった「ゾンビをたおせ」を教材にしましたが、何度か遊んだ後は、自分の手順で作成したがったため、チュートリアルはほぼ見ませんでした。（2か所ほど、やり方につまったときに参考として確認するよう促しました。） 必要なスプライトと、それがどのような動きをするかという口頭での細分化はできていましたが、細分化した日本語の文章からブロックにつなげるスキルがまだ弱いというか、偏りがありました。座標のプラスマイナスや繰り返し、キーが押されたとき、すべてを止める、○○に触れた、などはよく覚えていて自分でスラスラ作成できていましたが、「もし～なら」がなかなか出てこなかったようでした。 作りたいことを文章化してそれを実行しようとするときは積極的でしたが、後半になると、自分では難しいから「先生やって」と甘えてくる姿勢が見られました。（ドラゴンの向きの判定を入れて、発射するビームが向かう方向を変える） ただ、こちらのヒントで、それが自分にできるレベルかどうかはわりと正確に判断していて、自分でできそうなものは最後まで自分でやっていました。', null, '盛り上がり: 久しぶりに勇作君と同じ作品を作ったためか、二人で話しながら楽しそうに作成していました。時間ぎりぎりまで投げ出さずに、「作品を最後まで作ってから遊ぶ」という目標を守ることができていました。'),
  ('52a99b98-261e-5ce1-8c27-8790dc2e53ff', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-02', '17:30:00', null, '通常 / 自作ゲームの作成', '授業開始時に少し話をしました。 今後、オンラインで授業を受けるのは大丈夫とのことですが、そちらを受講するかどうかはまだ考え中なので、早めに決めるとのことでした。 オンラインの曜日など、簡単にメモしたものを持って帰っていました。 現状、教室ではScratchで好きなものを作るというやり方で満足している様子でした。 今日も作成中に京王線システムを作ると言って、熱心に作成していました。途中、秋くんが興味津々でのぞきにきていました。', null, 'タイピング: 順調にスピードアップしているようです
盛り上がり: 作成しているものについては、特に困った様子も見せないため、こちらも教えるというよりは話しかけるというスタイルになっていますが、話しかけたことに対してはよくしゃべってくれました。'),
  ('1d0d81e6-348c-50c0-b748-207b1f9eb843', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-02', '17:30:00', null, '通常 / ゲームのアレンジを考える', '今日は試験あけなので、既存のゲームから好きなものを選んで、コードのアレンジを3つ以上する、という目標を伝えたところ、喜んですぐに作品選びに入っていました。 チーズを探せは簡単すぎないかと思われましたが、昔作ったゲームを今の自分ならこんなアレンジができる、という感じで、クローンを使ってだんだん難しくなる仕様にしていました。 検定を受けたことで上級レベルになってきたという自覚が芽生えたのか、こちらの予想以上に熱心に、ゲームとして面白くしようとアレンジを考えてくれていました。 後半はえにしくんと話が合ってきたようで、いちごの反乱をやりながらフォートナイトの話をしたりと楽しそうでした。', null, '盛り上がり: えにしくんとだいぶ仲良くなれたようで、マイクラやフォートナイトの話を熱心にしていました。おしゃべりしつつも、二人とも手はきちんと動かせていました。'),
  ('bfcf5954-a0fe-5d10-a7cc-5e65ef042840', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-03', '16:30:00', null, '振替 / アルスタジオでコードを見てみたい作品を探す→アレンジ', 'アレンジする題材のゲームに迷っていたため、とりあえず面白そうなゲームにしてみては？といちごの反乱をおすすめしたのですが、コードの内容が複雑で難しく、頭を悩ませていました。 大和先生にアドバイスをもらい、もっとアレンジがしやすいシンプルな射的ゲームのアレンジをすることにしました。 アレンジ内容としては的の速さを変えたり、当てるとゲームオーバーになる的を作る、背景を変えるといったことをしていました。', null, 'タイピング: 集中して取り組めていました。'),
  ('ea3cf6b6-db50-5fb0-844a-55bb129ba36b', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-03', '16:30:00', null, '通常 / 射的ゲームの作成＆アレンジ', 'かなり気に入った様子だったので、復習も兼ねてイチから作りました。座標の向きや、ずっとの忘れなどがありましたが、プログラムを進めていくと少しずつ思い出せました。ボールの動きは乱数を使ってほぼ自力でプログラムすることができました。 ビームの動きはとっかかりがつかめていなかったので、細分化を手伝いました。その後は自分で考えて作成できていました。アレンジとして変数を使ったゲームクリアのプログラム、ボールの色の変更などを行いました。楽しそうで良かったです。 検定の方は、まこちゃんよりもお母さんの方が心が折れている(?)様子でした。次回の検定の日を気にしていました。', null, 'タイピング: 集中して取り組めました。'),
  ('632522a0-974d-5436-9774-c577112dc3a7', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-03', '16:30:00', null, '通常 / アルスタジオでコードを見てみたい作品を探す→アレンジ', 'シューティングゲームを選んで黙々とアレンジしていました。 的からも攻撃がくるような対人戦のゲームにしたようです。', null, 'タイピング: 集中して取り組んでいました'),
  ('6c6dbe2a-f0fa-520e-bdfa-9ae91840521d', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-05', '17:30:00', null, '通常 / 自由気ままに', '検定後だったので、今回は、自由にアレンジとかしてもらいたかったです。けど、1級という大台だったので、バイクランやツムツムで遊んでしまっているのをよしとしました。またバイクランのランキングが始まっていたので、600m を超える大記録を達成していました。ずっと、検定練習だったので、解放されてゲームに集中していました。', null, 'タイピング: あと10文字ほどで、次に級でした。'),
  ('a166937d-774c-58ee-a3fc-f35cef3abb3b', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-05', '16:30:00', null, '通常 / 作品のアレンジ続き', '前回最後の方に取り組んでいた女の子を使ったゲームは飽きたとのことで、いちごの反乱と、検定で作成した魔法使いのゲームのアレンジに取り組んでいました。 いちごの反乱では、フリー画像をDLして敵のスプライトを宇宙人にしたり、弾幕のスプライトを宇宙人にちなんだ爆弾にするなどしてアレンジしていました。 魔法使いのゲームの方は、水属性を新しく追加するとのことで、ネットから雫やもっと強そうな魔法使いののフリー画像をDLし、細かく配置を調整しながら集中して取り組めていました。', null, 'タイピング: 集中して取り組めていました'),
  ('7fbda077-6a1e-5cc9-b4d2-6a12b9ebdd4e', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-05', '16:30:00', null, '通常 / ドリルを進める', 'ドリルの問題33-39が終わったら自由時間だと伝えて始めました。前回どこまでやったのかも覚えていて、最初はやる気があったのですが、やはりりょうやくんの作っているゲームなどが気になるようでたびたび脱線していました。取り組んでいるときに様子を見ようとするとそのたびに「自分でできるから大丈夫！」と言っていたのですが、脱線するので連れ戻しました。こたろうくんなら集中すればできる難易度だからと伝えて、なんとか36番まで終わることができました。 飴を食べすぎることで立ち歩きが多く、健康にもよくないので、数を制限したほうがいいかもしれません。', null, '備考: お迎えのお母さんに、きちんとやっていますかと聞かれ、正直返答につまりました。（こたろうくんがこちらをガン見していたので(^^;)） 正直、最近は集中力に欠けていますが、みんなが検定をしている中で少しつまらなそうにしていたのも事実で…習い事の野球や学校の係については、責任感を持って熱心に取り組んでいるようなので、こちらでもしっかりした目標があった方がやる気が出るかも、と話をしたら、こたろうくんも真面目な顔になって頷いていました。お母さんは、検定レベルに達していないと思って申し込みをしなかったとのことですが、目的意識を持ってやれば十分受験できるレベルだと伝えると、次回はぜひ考えたいですとのことでした。（大原付記）'),
  ('272f4cff-16f8-531f-b55d-3daa459e167a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-05', '16:30:00', null, '通常 / 好きな箇所のコードを読み取る', '好きな作品を探してアレンジをしようと促しても、何をしていいか全くわからないとのことだったので、塁くんが一番好きだという「いちごの反乱」をもう少しやってみようと勧めました。前回はコスチュームのアレンジがメインで、コードのアレンジは難しいと尻込みするため、このゲームは難しいか簡単かと問いかけたところ、最初の方は簡単だとのこと。それなら、ゲームを難しくしてみようと勧めると「やってみたい」と食いついてきました。 作品のコードを開いて、何に手を付けていいかわからないと言うため、どのスプライトを編集すれば難しくなるのか、そのスプライトの何を（速さ、数など）変えたら難しくなるか、と少しずつ問いかけていって、パンチが出てくるコードを見つけ出すことができました。ブロックの複製をしてパンチの数が増えたのを確認できるととても面白がって、その後は一人でどんどん数を増やすアレンジをしていました。この部分のコードには興味を持ってくれて、熱心に複製をして座標を入れていたので、今日は一つだけ勉強しようと声掛けをし、で乱数の復習をしました。パンチがどこから出てくるかわからなくなる、というのも塁くんには面白かったようで、複製したすべてのブロックのx座標を熱心に乱数に置きかえていました このアレンジを全部手作業でして、それが大変だったことを実感した上で、もっと簡単にできないかを考えさせ、繰り返しを使うことができました。 繰り返しの数を変えることにより、一気にゲーム序盤の難易度が上がって、えみちゃんや良冶くんにゲームをプレイしてもらって嬉しそうにしていました。', null, '盛り上がり: コードのアレンジは難しい、何をしたらいいのかわからない、と言っていた当初から、自分でもゲームを難しくするアレンジができるとわかってからの取り組み方の違いが顕著でした。満足のいくアレンジができて嬉しそうでした。
備考: 検定は残念でしたが、がんばったことを評価すると、少し神妙に頷いていました。（その数秒後にはいつもの調子に戻っていました）'),
  ('3b30c339-573b-547a-bc6b-e3854fb1fc27', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-05', '16:30:00', null, '通常 / 自由製作', '検定明けだったので、自由気ままにアルスタジオにあるゲームをアレンジしていきました。マリオのゲームが気にとまったらしく、世界観を変えてくアレンジをしていきました。最初は、不潔で支離滅裂な方法に行きそうになったが、ハワイアン風に方法を変えてくれました。ばねも、ヤシの実みたいになって、ステージ背景も夕暮れ時になり、世界観がつく変えてできていました。そのご、ルイ君やこたろうくんに遊んで、楽しんでくれてました。', null, null),
  ('08d68c4b-54aa-5046-bdba-7294b4cf8e88', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-05', '17:30:00', null, '通常 / オリジナル作品の作成', '作成中の小説ゲームは、少し疲れたので一旦はなれて今日は別の作品を考えてみたいとのこと。来年に対する意欲もあって、今回と同じくScratchで挑戦したいそうです。テーマを審査員受けしそうな方にするか、スキルで勝負するかと考えた時、自分がどのくらいスキルで勝負できるかはわからないが、作り甲斐のあるものにチャレンジしたいそうです。 まだ時間はたっぷりあるので、いろいろ試してみてもよいかな、ということで、最近小説に出てきて興味を持った将棋をテーマに、試作を作ることにしました。 対局ゲームはかなり難しそうなので、詰め将棋を提案したところ興味を持って、詰め将棋のゲームをいくつかプレイしてどのようなものか熱心に研究していました。 たくさんある詰め将棋のゲームの中で、どのようにオリジナリティを出していくかを考えながら、少しScratchをいじっていました。', null, '盛り上がり: 将棋は小説で読んだ程度なのでよくわからないけど、と言いながら、何度か詰め将棋にチャレンジしていくうちにルールを理解できていったようでした。作るのも難しそうと言いつつアイディアも出していて、創作意欲はあるようでした。'),
  ('d101ec14-d2b6-5fc5-b0b2-9f17a3ee3dbc', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-05', '17:30:00', null, '通常 / 息抜きアレンジ', '検定後の息抜きとして、アルスタジオでコードを見てみたい作品を探してアレンジしました。色々ゲームを見ていましたが、迷路脱出ゲームが難しすぎるけど楽しいからクリアしたいということで、ゲームの難易度を下げるアレンジをやってみました。壁の速度を遅くしてみたりしましたがそれでも難しいので壁を途中で止めることにしました。「～秒待つ」ブロックを入れればいいことは分かっていましたが、ブロックを入れる場所を間違えて動かなかったので、どこで止めたいか問いかけて考えてもらいました。最終的に自分でアレンジしたバージョンでクリアして満足げでした。', null, 'タイピング: ミス率が減っていました'),
  ('f6e74e59-a378-5e40-956a-814aca3e1afa', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-05', '17:30:00', null, '通常 / 【DKゲーム】03レースゲーム', '今回はなるべく本人に考えて作成してもらう回でした。 変数は前に使ったことがあるみたいでしたが、変数の概念について改めて説明をしました。 「メッセージを送る・受け取る」は知っていたようなのですぐ理解してくれました。 ただ、別のコードを空いている空白に埋めて組み合わせるといったやり方に関して、 不慣れなようだったのでヒントや解説を挟んで作成してもらいました。 一番難しい「ではないまで待つ」も、最初は首を傾げていましたが 間違ったコードを打つと上手く動かない と実演してあげるとすぐ修正できていました。 以前からもですが、こちらが根気強く教えると楓太くんも頑張って約１時間集中してついてきてくれるので、 これほど集中力があれば今後興味があることに対しても伸び代が期待出来るのではないかな、と良い印象を受けました。', '順位をつける', 'タイピング: 集中して取り組めていました。'),
  ('b90f1bf1-4235-55d8-a289-acc50d678a18', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-06', '16:30:00', null, '通常 / 検定おつかれゲームアレンジ等', '自分で描いたビット絵をスクラッチで動かしたいということで、ビット絵の作成から開始。鉄砲を持ったキャラクター、左右うごときバージョンと停止バージョンを作って、１からゲーム作成をしていました。自分で作ったキャラを動かして、ボタン押下で弾を発射して敵をやっつけるというところまで出来ました。自分作製のキャラを動かせて楽しそうでした。基本的に、先生の助けを得ずに、簡単ではあるもののやりたい事をスクリプトで表現できているので小一レベルをかなり上回っているなと改めて感じさせられました。', null, null),
  ('ff877320-630d-5e90-89dc-67c541462bbd', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-06', '17:30:00', null, '通常 / 検定おつかれゲームアレンジ等', 'アルスタジオの探すから、気に入ったゲームを選んでアレンジするとのこと。なかなかアレンジがうまく浮かばず、ビット絵でキャラクターを自作するのはどうと提案すると、それが気に入ったようで、ドット絵キャラクターを嬉しそうに作っていました。自分の中でそのキャラクターのストーリー設定までして楽しんでいました。その自作キャラをゲームのプレイヤーと差し替えて動けるようにしてゲームを楽しんでいました。プレイヤー差し替えの際、ただ単に元々のスクリプトを、自作キャラのスプライトにコピーしただけでは動かず、動かない理由をコードを一つずつ追っていて突き止めて、それを修正して動くようにしました。２つのゲームでそれをやっていました。それと、スプラんキーという音楽のゲームが好きなようで、それをスクラッチでもできたらなーという話をしました。', null, null),
  ('85215779-07d5-52ae-933b-4fc8c3d6262d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-06', null, null, '通常 / 検定おつかれゲームアレンジ等', '自分で好きなゲーム（プラットフォーマー）を選んでアレンジをしていました。簡単なゲームだったようなので、それのハードモードを作っていました。ただの障害物を敵に変えて触レたらゲームオーバーにしたり色を変えたりと、特に先生にヘルプを求めることもなく黙々と完成させていました。その後は、時間が余ったので、ビット絵の作成ツールで、何かキャラを作ってみない？と提案して、その作成している途中で時間になってしまいました。', null, '時間帯: その他'),
  ('2d00dcd0-adc1-5e97-ac84-0c771a0d0d05', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-07', null, null, '通常 / 検定お疲れ様ゲームアレンジ', '「いちごの反乱」をアレンジした。クリアするのが難しいということで、少し難易度を落とすようなアレンジをしようとの事でスタート。キャラの速度を早くしたり、大きさを小さくしたり、一回の接触でゲームオーバーではなく、体力変数を作って、何回か接触しても体力が残っている限りは生き残る仕様にした。体力の処理は、短時間で作るのは難しそうだったので、私が見本を作って、それコピーしつつを説明して、理解してもらいました。', null, '時間帯: その他'),
  ('f12eaec0-588a-59a4-a3e8-3e2f3aa6d484', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-07', null, null, '通常 / 検定おつかれゲームアレンジ等', '「マリオVSルイージ」を選択してそれをアレンジしたいとのこと。アレンジ内容も、上からクッパが降ってきて、それをマリオルイージが触れたらゲームオーバーにしたいとのこと。 どうやれば実現できるかを細分化して、一つずつ作業を進めていった。クッパのスクリプトを作成する→５秒待ってクッパを画面上部に出現させる。X座標は乱数で決定。→Y座標をいじって画面下まで徐々に移動させる→マリオルイージがクッパに触れたら体力が減って体力が０になったらゲームオーバーにする。小学生低学年では少し難しいかも知れなかったので、一つ一つ見本のコードを私が作って、それをコピーしてもらいつつ細かく説明して理解してもらいました。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('1cb05791-42e9-5c9d-8455-3a5ffd634fc8', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-07', null, null, '通常 / プロゲート', '好きなゲームのアレンジとプロゲートのどちらが良いかを聞いて、プロゲートを選択。プロゲートを最低３単元進めたら自由時間という約束をして開始。３単元分、特に質問等なく、スムーズに進められたようです。if文の使い方をメインにやっていたようです。その後は、約束通りということで自由時間となり、自分の好きなゲーム等をやっていたようです。', null, '時間帯: その他'),
  ('1bb7ffef-dbdc-5ac4-96d7-d37204e43b17', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-07', null, null, '通常 / 検定おつかれゲームアレンジ', '「【Prg】21 アイテムで脱出ゲームを作ろう！」を選んでアレンジしていました。具体的にはハードモードを作成していました。壁を増やしたり、鍵を増やしたり。動く障害物を作ったりして、かなり難しいモードを作成していました。どのようにアレンジするかのアドバイスはしましたが、実際のスクリプトの作成部分は、自分の力で作成できていたようです。', null, '時間帯: その他'),
  ('1c37d8b2-6918-56b6-beb1-f53c55168ca5', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-07', null, null, '通常 / 検定おつかれゲームアレンジ', '最初にビット絵の作成をやってみたいとのことだったので、それからスタート。ドラゴンボールの悟空やピッコロ、クリリン等書こうとしてうまくいかないとの事で、ゲームアレンジに方向転換しました。おそらく、きちんとしたものを書こうとして、てきとうになものでは納得がいかなかったのだと思います。 「射的ゲーム」を選んでアレンジしていました。ハードモードを作っていました。今日は兄弟揃ってハードモード作りでしたね。射的の弾丸のスピードを速くしたり、ターゲットになるボールの大きさや、動きに修正を加えていました。スクリプト修正のヘルプはほとんどなく自力で修正していました。', null, '時間帯: その他'),
  ('bb506f39-09e2-5d12-9a93-c1a778b49dfd', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2024-12-09', '17:30:00', null, '休み（未対象）', null, null, null),
  ('441d7503-4a49-5d3e-bf8a-57b085e64f70', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-09', '16:30:00', null, '通常 / ドット絵メーカーでオリジナルキャラ作りをしてから、今まで作成したゲームのアレンジ', '横にいた勇作くんと楽しそうにドット絵で剣を描いていました。 ドット絵に対しては特に苦戦なく、綺麗に絵や配色を考えて完成させることが出来ました。 作った絵をインポートするところまで出来ましたが、ゲームのアレンジはあまり手を付けられていませんでした。', null, 'タイピング: なし'),
  ('aff7cd2c-e4cb-5a91-9583-5ffaafc5d7c5', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-09', '16:30:00', null, '通常 / ドット絵メーカーでオリジナルキャラ作りをしてから、今まで作成したゲームのアレンジ', 'ドット絵のイラストを描くのに苦戦していて、自分で作ったもの(マイクラのダイヤの剣)に満足していなかったのか、最終的にネットで検索したダイヤの剣をインポートして使うことにしました。剣をお手本通り描くのが難しかったみたいです。 また、今回岳くんと隣の席で嬉しかったのか、かなり元気で騒がしい様子でした。', null, 'タイピング: なし'),
  ('9db1b0fe-4364-5e96-9c7e-92e0ea4c11f9', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-09', '17:30:00', null, '通常 / やりたい学習を進める', '最近作成しているオリジナル作品、Monaca、ゲームのアレンジの三択から、今日はMonacaをやってみたいとのことで、大原のアカウントを貸して、スライドや動画教材を見ながら自主学習をしてもらいました。以前にどこまでやったかもなんとなく覚えていたようで、自分から第4章を選んで始めていました。 第4章、第5章はとくに行き詰まるところもなく、順調に終えることができました。', null, 'タイピング: 黙々とやっていました
盛り上がり: Monacaは久しぶりだったからか、わかりやすい箇所だったからか、熱心にサクサクと進めていました。 授業の終わりに、秋くんが山手線をドット絵で描いて鉄道シミュレータで動かしていたのを、同じ電車好きとして見てもらいました。電車が山手線だと当ててくれたため、秋くんが嬉しそうでした。 秋くんのお迎えにきたお母さんに、秋くんが好きな電車の話を周りにしても、あまり話が通じなくて…と話しかけられて、大きく頷いていました💦秋くん親子から尊敬のまなざしで見られてちょっと照れていました。'),
  ('f65cbf53-f96d-5a79-972f-0a786df2d9bc', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-09', '16:30:00', null, '振替 / 大会発表準備', '持参してきたPCに発表用の原稿を作成しました。事前に動画を見てきてくれたので、「やばい」ということが認識できていました。事前に作品の内容は箇条書きで書き出してきてくれました。 〇今日きめたこと ・1~2分スライドで話して3~4分作品を見せながら説明する ・スライドで話すことは操作説明、ストーリー、ターゲットなど ・作品を見せながら説明することは、バッテリー、監視カメラ、シャッターなどのこだわりポイント ・作品として見せる部分は特にこだわった冒頭～前半部分 こだわりポイントの説明文を次回（明日）までに書いてくるようにお願いしました。また作品のバグがあったようなので、一緒に確認して修正しました。本人も少し慌てて焦っていたので、修正できて良かったです。', '原稿完成 スライドづくり（近藤が作った簡単な下書きあり）', null),
  ('6a618311-c715-559e-8c0a-a5501af896dd', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-09', '17:30:00', null, '通常 / ドット絵を作ってうごかす', 'ドット絵でかきたいものはすぐに決まったようで、PCで電車の写真を見ながらドット絵でかいていました。山の手線の写真の指定がありました。 丁寧に書けたので、プログラム中で動かすことを提案しました。座標の考え方を忘れかけていたので復習しつつ取り組みました。自分で表示非表示、待つなど工夫して作成できました。BGMもつけられて満足そうでした！', null, 'タイピング: 集中して取り組めました。'),
  ('51482e69-c217-5c90-9b8d-4b340dc1f060', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-09', '17:30:00', null, '通常 / ドット絵を作ってうごかす', 'スマブラの点滅した様子、息を吐く様子を作りたかったようで、ドット絵を作っていました。元あるプログラムにアレンジを加えて表現できました。またピカチュウも作成し、スマブラに参戦させていました。来週からのゲーム大会をかなり楽しみにしていました！', null, 'タイピング: 集中して取り組めました。'),
  ('b26eca2d-b74b-5279-bfbe-994e1396158f', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-09', '17:30:00', null, '通常 / ドット絵メーカーでオリジナルキャラ作りをしてから、今まで作成したゲームのアレンジ', '絵を描くことや何を描くべきか分からないなど、あまり自信が無さそうな様子だったので側に付きながら何が描きたいのか？を一緒に探っていました。 最初は猫を描こうとしていましたが形を捉えるのに苦戦しており、最終的にスシローの鰻が好物なようなのでそれを描いていました。 様子をみたところ、猫の毛の白や寿司のシャリの白、鰻のツヤの白の配色に迷っていたのでアドバイスをしながら一緒に完成させていきました。', null, 'タイピング: なし'),
  ('bfc706e6-41b8-5c4c-9814-93e94a12f72f', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-09', '17:30:00', null, '通常 / ドット絵を作って動かす', '好きなキャラクターはないようで、何を書くかに少しこまったようです。ドットで書くのが少し難しかったのかな？きれいな丸が書けたので、前回作成したプログラムに追加しました。 ゼロから自分で作るのは苦手なようで、問題があった方が取り組みやすいようです。最後はジャンプゲームを遊んでもらい、イメージをもってもらいました。プレイが難しかったようです。', null, 'タイピング: 集中して取り組めました。'),
  ('84ef6307-222b-5432-954d-8f1e1dfe9c1e', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-07', null, null, '通常 / 星取りゲームを参考にオリジナルゲームの作品', '好きなプログラムを探しました。星取ゲームが好きなようで、それを参考にイチからプログラムを作成することになりました。キャッチゲームにストーリー要素を取り入れていました。 制御ブロックや作品全体の進行をうまくコントロールすることができています。一方で動きのブロックは苦手なようで、上からスプライトを落とすプログラムに困っていました。考え方の順序を共有しました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('c5d47d39-d990-5589-9746-214245aa5ad5', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-07', null, null, '通常 / 射的ゲームアレンジ', '30分頑張ることを約束しましたが、本人もはまったようで50分近く頑張れました。射的ゲームを改造して、それぞれの体力も設定して対戦ゲームになりました。コスチュームやステージ背景も自分で作成しました。変数の設定は最初こそ手伝いましたが、2つめのスプライトに体力を設定するころには全部自力でプログラムできました。かなり楽しそうで良かったです！自分で進められるところは進めて、できたところまで教えてくれました！', null, '時間帯: その他'),
  ('849df971-c5c1-5eed-9c68-745308a5047c', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-07', null, null, '通常 / オリジナルゲームの編集', '以前、クローンを知らないで作った作品を編集してクローンを使ってアレンジしました。クローンを発生させるまではスムーズに考えられましたが、その後に初期位置→動かすプログラムを一つのスクリプトにまとめられずに困っていたので、プログラム方法を少し共有しました。「ずっと」を使うときの注意点についても伝えました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('1acbe2dc-7c5d-5cd7-8acc-3886237f4741', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-07', null, null, '通常 / 剣ふる作品', '前回まで作っていた剣をふる作品がお気に入りなようで今日は続きをしました。上からリンゴを落とすプログラムを作成しました。進度から考えてレベル高いかな？と感じたのですが、比較的スムーズにプログラムできました。 剣と主人公が同時に動くような仕組みを作成しました。「～へ行く」とうまく動かせることを詳しく紹介しました。また話すブロックの復習しました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('85418f3e-def7-508a-9134-0b258c7d6660', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-10', '16:30:00', null, '通常 / ゲーム大会を楽しもう！', '授業開始前からゲーム大会が気になっているようだったので、5分ほど前倒しで始めました。 今日はとにかく饒舌で、向かい合わせに座った祥太君と、直接会話するというわけでもないのですが、お互いにゲームについてかなりしゃべりまくっていました。 フンツノゼミではそれなりの記録が出せて嬉しかったようですが、開始20分くらいで「作る方をやりたい」となり、フンツノゼミのアレンジをひたすらやっていました。 今日はお楽しみということで、アレンジに対する課題や制限をしなかったせいもあるのか、ひたすら楽しそうにコスチュームを変え、自分から進んでコードを見て数値をいじったりもしていました。', null, '盛り上がり: 今日は楽しかったのか、とにかくよくしゃべっていました。アレンジも集中して、最後まで「楽しんでいる」感が良く出ていました。'),
  ('52622110-bed3-5a07-a6e7-97330da3cdec', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-10', '16:30:00', null, '通常 / ゲーム大会・フンツノアレンジ', '低学年向けのゲームの方が難しく感じたそうです。ジャンプのタイミングに苦戦していました。フンツノもかなりプレイをし、コスチュームの大小を工夫したり、見た目をアレンジしたりして楽しんでいました。プログラムの仕組みについても大枠を把握できていたので良かったです。', null, null),
  ('297b54eb-5517-51a9-91ca-123b3e685179', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-10', '17:30:00', null, '通常 / 大会発表準備', '考えてきてくれた文章を元に、発表原稿を作りました。印刷しました。持って帰ってもらい、読み慣れてくるように伝えました。 また後半はスライド作成をしました。提出した資料を基に、スライドを作成しました。スライドの視覚的な役割を説明し、画像をたくさんいれるように伝えました。ゲームのスクリーンショットをキャプチャし、載せる作業もある程度できました。まだ埋まっていない部分があるので、家で取り組んでもらうように伝えました。 次回は発表練習です。読む＆スライドを見せる→作品を見せるの動作の練習をしたいです。作った発表原稿が何分かかるかが分からないので、最終調整もしたいです（短めに原稿は作ってあります）', null, null),
  ('383e51a4-7bcd-5bfc-ba5c-cfb350124b80', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-10', '17:30:00', null, '通常 / U16大会の準備', '本番に使用するお父さんのPCに制限がかかっているということで、お父さんと一緒に来室しました。本番中のトラブルを防ぐという趣旨にお父さんが賛同してくれたため、PCにScratch Desktopをインストールし、使用するファイル類もすべてローカルに入れてもらいました。 PCをプロジェクターに接続するなどのセッティングの練習も無事にできました。 発表用原稿はGoogleドキュメントで作成しているようです。（IT自由研究室のみんなのGoogleドライブ>マイドライブ直下の「友清瑞 発表用台本」） 発表の練習ではかなり早口で、2分45秒で発表が済んでしまいました。操作方法の説明が予選のスライドのままだったので、Scratchで見せた方が良い場面を相談し、アプリの切り替えタイミングを考えました。 時間にかなり余裕があるので、作成の動機やアピールポイントをもう少し考えてきてもらうこと、ゆっくり話す練習をしてくることを課題にしました。', '発表の練習', '盛り上がり: 思ったよりも発表練習を素直にやってくれました。照れくさそうではありましたが、全体の雰囲気がつかめたので少し安心できたようでもありました。
備考: 中学校に主催者側から連絡がいったようで、そのとき職員室にどよめきが走ったそうです(^^)'),
  ('27523ecc-2b84-5154-b101-53ebe285d9d0', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-10', '17:30:00', null, '振替 / U16大会の準備', '準備をきちんとしてきていて、プロジェクターやPCの準備も率先してやってくれました。準備ができたら自主的に練習を始めていました。 発表の内容は概ねわかりやすかったのですが、発表時間の配分が惜しいところがあったため、時間をとられていた開発環境などは、スライドを見せて「ご覧の通りです」で済ませ、実際のアプリのアピール時間を増やすようにしました。 話すときに語頭がはっきりしない癖があるため、言い回しを工夫するようにしました。（不要です、を必要有りませんにするなど）', null, '盛り上がり: パソコンまわりの機材のことなど、話したり手伝ってくれたりするのが楽しかったようで、時間中ずっと生き生きとしていました。プロジェクターの設定なども完全にお任せして、積極的に動いてくれました。'),
  ('97b0be55-19bf-5b15-af10-04631a8658a4', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2024-12-12', '17:30:00', null, '休み（未対象）', null, null, null),
  ('e5cc9543-daac-5b43-ac06-2173afce13e7', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-12', '16:30:00', null, '通常 / ゲーム大会', 'るいくんは小3でしたが、よけろフンツノゼミの方も頑張ってくれました。跳べ！りさちゃんの方はあまり気に入らなかったらしく最初の方にやった記録で満足していました。途中、秋が生じたのか、今回のゲーム大会と関係のないゲームをやり始めたので、元のゲームで遊ぶかアレンジに進むか進めましたが、なかなか戻らないときはありました。', null, '盛り上がり: 最終的には、りょうやくんとこたろうくんの記録に並ぶほどのスコアに近づいて楽しんでいました。'),
  ('d3bbea26-6dd0-5d07-b32c-b1ab921b80ed', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-12', '16:30:00', null, '通常 / ゲーム大会を楽しむ', 'ゲームには、かなり真剣に取り組んでいました。 途中飽きることもなく、時間中ほぼずっと、記録更新にチャレンジしていました。', null, '盛り上がり: 検定の認定証が届いたことに加え、クラスの中では最高得点を出すこともでき、嬉しそうに帰っていきました。
備考: 真剣にゲームをしているときにこたろうくんにちょっかいを出され、振り払おうとしてこたろうくんのうなじに引っかき傷を作ってしまいました。 こたろうくんには、人が真剣なときに邪魔をしないこと、りょうやくんには、とにかく手を出さないことを伝えました。 傷を作ったことはなんとかあやまったのと、その後でこたろうくんが「親に言う」「病院にいったら賠償金が云々」とあおってきたことに対しては言い返しも無視もせずに普通に会話をして受け流し、その後は仲直りしたのか二人でずっと盛り上がっていましたが…。 帰りもこたろうくんを乗せていってるようです。'),
  ('01d82c80-5851-5f78-9b19-b659d0402a11', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-12', '17:30:00', null, '通常 / ゲーム大会', 'このゲームを見つけると最初から200点を超えるほどに安定していました。その様子を、りょうやくんやこたろうくんがみて、格の違うわと驚かれていました。その後は、何度からスランプ状態になったが、あきらめは悪いのでとことんやり続け、終盤に自分の記録を抜かされましたw', null, null),
  ('d4f0fa42-0550-520f-a34a-de4c7c866c35', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-12', '16:30:00', null, '通常 / ゲーム大会', '「よけろ！フンツノゼミ」ゲームでスコアが２桁以上から伸びない…とのことで低学年向けのゲームに挑戦していましたが、こちらも苦戦していて、結局もともと作っていたゲームのアレンジをしていました。 ただ、帰る頃に挑戦したらスコアが120を越えれていたのでよかったです。', null, 'タイピング: なし'),
  ('260ba91b-5280-5afb-8d1e-f295ddfac6b6', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-12', '17:30:00', null, '通常 / ゲーム大会', 'ゲーム大会に参加しました。個人戦のりさちゃんを特に頑張っていました。ベストスコア更新を目指して粘り、最後の最後で達成したときはとても喜んでいました。りさちゃんのスコアで、暫定ではぶっちぎりの1位を取ることができました。チーム戦も勝とうと気にかけて、自分で頑張ったり先生に助っ人を頼んだりしていました。', null, null),
  ('670baab3-69b2-5841-bf71-8a940258be54', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-12', '16:30:00', null, '通常 / ゲーム大会', '「よけろ！フンツノゼミ」ゲームでお邪魔で出てくるキャラクターに興奮した様子で「ムカつく！」と楽しそうに遊んでいました。いつもは黙々と授業に取り組んでいますが、ゲームに熱中して楽しそうな様子をみれてよかったです。', null, 'タイピング: なし'),
  ('c63cf790-d4a6-5c4a-8c9c-7b45dd68e949', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-12', '17:30:00', null, '通常 / ゲーム大会を楽しむ', '初めてのゲーム大会でしたが、時間いっぱい楽しめたようでした。 比較的安定したスコアを出していて、わりと満足できたようでした。 今日は敢えて他の子と席を近づけたためか、隣のそうたろうくんをのぞいたり、先生に話しかけたりと積極的な様子も見せていました。', null, '盛り上がり: 検定の認定証がもらえたこと、ゲーム大会でそれなりの記録が出せたことが嬉しそうでした。'),
  ('7e5e9694-4bdf-5510-817f-e66ab17e1550', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-12', '17:30:00', null, '通常 / ゲーム大会', '始まる前から取り組んでいて、2回目で250点以上とかなり好成績を残していました。だが、なかなか300点を超えることが難しく、残された最後の一回で、ノーミスでレベル7まで到達で来てHP8のアドバンテージが発揮できて、現時点細孔の451点を到達しました。助っ人のそうちゃｎ(コウ君の記録除く)', null, '盛り上がり: 最後の一回でかなり満足できたみたいなので、かなりルンルンに帰っていきました。'),
  ('b397e2c7-61ef-57d5-8e7a-3ff4820de0d2', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-12', null, null, '通常 / ゲーム大会', 'ゲーム大会に参加しました。りょうやくんと横並びの席で、競い合うような形で頑張っていました。最終的には2人同点のベストスコアで暫定1位を取り、満足して終わることができました。', null, '時間帯: その他'),
  ('5b1acc8f-0c5b-5fc7-95b4-3352726a818a', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-07', '16:30:00', null, '通常 / 好きなゲームを探して、アレンジ', '今週は検定お疲れ様デーということで、アルスタジオやScratchから好きな作品をアレンジしていきました。にゃんこ大戦争のアレンジゲームをScratchから見つけてきて、その作品をオマージュしたものを作成していきました。イラスト部分にかなりこだわっていたようで、タブレットのドット絵ツールを使うのではなく、PCでしっかりと曲線を表現しながら書いていました。', null, null),
  ('6e03de77-aac6-5b2a-a3f2-403ba09aa81f', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-06', '16:30:00', null, '通常 / 検定お疲れさまデー', 'オリジナルゲームの作成をおこなっていきました。イラスト部分に特にこだわっていたようで、タブレットを使用してキャラクターや背景の絵を描いていきました。物の輪郭や造形の表現が非常に上手く、未完成の状態であっても何のキャラクターを描いているのかがしっかりとわかるように書いていました。作品の出来としても満足していたようで、完成したものを見て、喜んでいました。', null, null),
  ('24e15760-eb2c-5763-85b9-9324317238b6', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-06', '17:30:00', null, '通常 / 検定お疲れさまデー', 'オリジナルゲームの作成をおこなっていきました。ストーリーとしては、キャンプに来てテントを建てたり、火を起こすといったことを連打回数で成果が変わるゲームでした。以前にいったキャンプでの思い出を参考に、作りたいと思っていたものを作っていき、いろいろなアイディアを作品へと取り入れていました。', null, null),
  ('3a5d57ce-dd76-5a51-8849-c09783c6ad00', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-13', '18:40:00', null, '通常 / 大会作品台本制作', '本番も近づいてきたため、大会発表用の台本制作に取り掛かっていきました。前回大会の映像を見ながら、大枠からどういった内容をアピールしていくのかを中心に考えていきました。Googleドキュメントにはメモ書き程度に書いておき、大体の流れを掴みながら時間配分について考えていきました。本人の中でもある程度の構想は固まっているようなので、次回で残りの部分の完成と練習まで行っていきたいです。', null, null),
  ('c75fdd40-273c-53b4-8e49-fbe4c0e00dfa', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-13', '17:30:00', null, '通常 / 大会台本制作', '大会本番に向けて、発表の練習と時間配分の確認をしていきました。事前にある程度の練習を行っていたようなので、通しで行ってみてどういった部分が問題なのかを洗い出していきました。実際にコードを見せての説明で詰まってしまう箇所が多かったため、今回と次回でその部分を完璧にしていきたいです。そして、話し方についても次回の授業でしっかりと把握してきたいです。', null, null),
  ('eaa4c0ef-4a6b-5be6-b0e7-7739a8043b20', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-13', '16:30:00', null, '通常 / 大会台本作成', '大会本番に向けて、資料を確認しながら台本制作に取り掛かっていきました。作品内でアピールしたい箇所については、資料製作中にまとめていたようなのでそれをもとに時間配分に特に気をつけて作成していきました。全体の完成ができた後には、通しで発表を行っていき課題を洗い出してきました。次回の授業で、課題部分とコードを見せながらの発表を行っていき、最終調整を行っていきます。', null, null),
  ('e82716ad-0172-5c17-82b3-9d6c782906de', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-06', '18:40:00', null, '通常 / 大会資料制作', '大会発表用の資料に手をつけていなかったようなので、前回大会の映像を見ながら資料作成を始めていきました。書類審査で提出した資料をもとに作成を行っていったため、サクサクと進めていくことができていました。しかし、台本部分については手をつけることができなかったため、次回の授業にて完成から発表の練習まで行っていきたいため、かなり急ぎめで行っていく必要があると思います。', null, null),
  ('740d976d-9aeb-5dbb-b542-475bc350deec', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-13', '16:30:00', null, '通常 / ゲーム大会', '最初の方は、なかなかスコアが伸びずに、悩んでいた増した。ところどころ、コツをつかんできて、1次間通しにやり続け、最後の1回で1位まであと3点までのスコアに伸ばせました。特に苦にならずにやっていました。', null, null),
  ('fc6c97c2-f30f-5363-9ac3-f1240f53bc5d', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-13', '16:30:00', null, '通常 / ゲーム大会参加', '楽しく取り組めました。バグ問題を促しましたが、今日は取り組みませんでした。大会にはかなり集中していました。 バグ問題は来週やるかな？と思っています。', null, null),
  ('683ef0cd-68ac-5a13-9ce1-29c69495dde9', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-13', '17:30:00', null, '通常 / ゲーム大会', 'ゲーム大会としり、楽しんで取り組んでくれまhした。フンツノの方が、楽で最初は楽しくやっていましたが、手の疲れだったり、ウサギのあおりのかなりゲームに対して切れていましたｗ。そして、個人戦のリサちゃんの方に変わると、こっちの方が面白みがって、マリパのゲームに似ているとはまってくれました。バグの方は来週委後回しで、当時で3位の記録が残り、満足気に帰っていきました。', null, null),
  ('c1d45a20-afc7-55f9-b3c4-3c6e1ff5fcdd', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-13', null, null, '通常 / Excel模擬問題4', '集中して取り組めました。つまづいた点としては、インデントを数字で設定すること、ROUNDDOWN関数で数値と桁数を入れる、分かりにくい日本語、列幅の設定がありました。最後に全て復習をしましたが、よく覚えていました。 ROUNDDOWN関数を例に関数の考え方（カンマで区切って引数を複数設定できることなど）を共有しました。うっすら分かってくれたようです。', null, '時間帯: その他'),
  ('3259af64-b259-545b-b8a2-fbea20306c76', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-13', '17:30:00', null, '通常 / 大会発表準備', '家でスライドを作って原稿も考えてくれました。今までのものと合わせて再整理し紙にまとめ、読みながらスライドを動かす＆作品を動かす練習をしました。家でも練習をしているそうであまりやりたくない様子でしたが、一緒に少しずつ進めました。スライドも大きく見やすくできました。また家で練習したかいがあり、声がとても聞き取りやすかったです。 本番がんばれ！！', null, 'タイピング: スキップ'),
  ('4d6198c3-83ab-5db6-9dba-28190c59e0e5', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-13', '16:30:00', null, '通常 / ゲーム大会参加', 'かなり楽しそうに遊んでいましたが「飽きる」とのことでした。検定の合格証をもらってかなり嬉しそうでした！！バグ問題を促しましたが、「バグ発見」の経験がなかったのでやりたくなさそうでした。重要性は料理に例えて説明しました。少しわかったそうです。今日はやらないですが来週はやるとのことだったので、次回はやってくれると思います。 またバグ問題ですが、正解と同じ形にプログラムをするのは少し難しいかな？と感じました。座標でやればうまく行けるかも？', null, null),
  ('050346f4-bda5-56db-9a28-55a2ee96a89c', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-13', '17:30:00', null, '通常 / U16発表作り', '基本的に、のころのゲームの細部の仕上げと、原稿の直しをやっていきました。ゲームの方は自分でペースがつかめているので、黙々と進めていきました。原稿は、中身の句ふんテントはしっかりつかめていたが、最初のつかみ導入が悩んでいました。そこで、このゲームの魅力について深堀させて、一般的視野に広げることで文章が作れていました', null, '盛り上がり: 体調にお気を付けに'),
  ('48eefbed-7b00-5659-8524-62c670226a2c', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-13', '18:40:00', null, '通常 / ゲーム大会', 'リサちゃんは最初の数階で30回も超えて、あとはフンツノのはまっていました。200以上は超えるが中なkスコアが伸びませんでした。そこで、切り替えにバグ直しをしてコスチューム変化も自分で作り出せていました。そして、最後には、250程度まで伸ばせることができました。', null, '盛り上がり: とうき君と楽しく話しながらやっていました。'),
  ('0aba4cfa-494f-59f3-9f01-3826d7790049', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-13', '16:30:00', null, '通常 / ゲーム大会', '低学年用ゲームの方は、あまり回数をこなさず、高学年用のフンソウゼミをずっと挑戦していました。低学年ということもあり、あまり高得点は出せていませんでしたが、先生助っ人はどうかと打診しても、自分のチカラでやるとの力強いお言葉をいただきました。あとは、フンソウゼミの体力を増やしたり、体力を減ら無いようにしたりアレンジをしていました。残念ながらバグ取りまではできませんでした。来週はバグ取りにも挑戦してほしいです。', null, null),
  ('924e243f-9c52-5bf3-83ed-4c1630733e0c', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-13', '17:30:00', null, '通常 / ゲーム大会', '高学年用のフンソウゼミにかなり集中して挑戦していました。色々と文句を言いながらも楽しそうに挑戦していたとお思います。私がみていた限りでは、バグ取りには挑戦していなかったと思いますので、来週は、バグ取りしたかどうかを確認して、させるようにしたら良いと思います。', null, null),
  ('b8f662c5-c21f-541d-9328-8ca952250f21', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-13', null, null, '通常 / ゲーム大会', 'フンソウゼミのランキングの3位に入ってやると、集中的にとても楽しんで挑戦していたように思います。結果としては、301点となかなか良い点を取れていました。私がみていた時間では、バグ取りはできていなかったと思うので、来週は一応やったか確認した上でバグ取りをするよう声がけした方が良いと思います。', null, '時間帯: その他'),
  ('949f084d-5d08-5dd0-9897-56f65457a9cb', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-13', '18:40:00', null, '通常 / ゲーム大会', '最初から跳べ！りさちゃんに飛びついて、今ある記録を超えようとしていました。やっている最中は、いじわるな転がり方もあり、ときどき切れ気味でしたが、決して止めることなくやっていました。アレンジの方も福引のことで知ると進んでやり、登記君にとってはコスチューム変化は簡単だよと言っていました。30点からの伸びはなかなかなかったですが、最後の1回というものが大きく記録を伸ばしました。', null, null),
  ('e67b9cfe-1560-5bd3-8acf-10e0a407c537', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-13', '18:40:00', null, '通常 / プレゼン資料つくり', '一度形になった原稿で練習をしてみました。時間がかなり余っていたので、ほかのアピールポイントやゲーム操作を見せながら発表をするなどの候補アイデアを作り出しました。間延びしないように頑張ってください', null, null),
  ('4f2c62f1-7364-5de3-9ff4-754159b60115', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-14', null, null, '通常 / ゲーム大会', 'ゲーム大会とのことで、かなり張り切っていました。はじめはレベル7まで届くには難しいところはあったが、蒼紫君とコツを共有しあい、めちゃくちゃ上達していきました。最終的は、300点以上を記録し、クラス対抗では暫定1位になりました。', 'バグつぶし', '時間帯: その他'),
  ('9eac4515-e236-590e-96ce-3a2d6054da5d', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-14', null, null, '通常 / ゲーム大会', 'フンツノゼミに挑戦、同じ時間のあおし君、結喜君が声を出しながらワイワイ挑戦していたのとは対照的に、静かに挑戦していました。２９２点と頑張っていました。来週はバグ潰しを忘れ無いようにできたらと思います。', null, '時間帯: その他'),
  ('3d6b3d6c-4a8c-5fec-9bbc-c1cea314e650', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-14', '16:30:00', null, '通常 / 大会発表練習', '明日の本番に向けての最終調整を行っていきました。発表内容や時間配分については、事前にしっかりと準備をすることができていたため、気になる言い回しや順番について少し変えていきました。作品の完成度がかなり高いものであるため、台本や言い回しを修正していくことで、さらに評価を上げることができたのではないかと思います。本人も修正内容に納得しており、仕上がりとしても良いものになったと感じていたようです。', null, null),
  ('ec60675e-889c-55fe-b48f-18e32ee4fdf6', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-14', '16:30:00', null, '通常 / ゲーム大会', '最初にプロゲートの方を進めましたが、圧倒的にゲームの方がいいと好んで取り組んでいきました。最初からバグつぶしのことをやり始めましたが、元の完成しているものから引っ張って転用していたので、ちゃんと考えるように仕向けました。そこでバグ直しは完了したが、フンツノゲームにはなかなかお気に召さず、たびたび理不尽さに切れていました。そして、最後10分くらいには飽きてしまいロブロックスに移っていました。', null, null),
  ('2ad5f967-43da-560d-a8e8-03af6bc6363d', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-14', null, null, '通常 / ゲーム大会', '低学年用の個人戦ゲームと、チーム戦のフンツノゼミ、どちらもノア君と一緒になって、（悪い意味ではなく）ゲームに対しての文句を言いつつも楽しく挑戦していました。得点としては、高くはありませんでしたが、良い息抜きになったのではと思いました。来週はもしできればバグ潰しもできたらなと思います。', null, '時間帯: その他'),
  ('0fe0c07f-ac19-52c4-8f91-79adc6b29e39', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-14', '17:30:00', null, '通常 / ゲーム大会', 'さすが中学生のこともあり、1発目から200オーバーのスコアを出て、熱中していました。途中で、だれることもなく、進められていて、300点は超えていました。やはり、中学生になると、みな300点超えるですね。', null, null),
  ('73d5d00d-254d-5cb7-8d43-5383acd8ff13', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-14', null, null, '通常 / ゲーム大会', 'とべ！りさちゃんと、フンツノゼミ、どちらもワイワイ楽しく挑戦していました。こうしろう君と一緒になって、若干うるさい感じがあったので、U16の作業に取り掛かっているハルくんのために、少し声を抑えるよう促した方が良かったかも知れ無いなとも今思いました。以後気をつけます。バグ潰しはしてい無いので、来週可能であれば挑戦してもらいたいです。', null, '時間帯: その他'),
  ('67d6f5e4-29e3-531a-81be-ac75459a7f96', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-14', null, null, '通常 / ゲーム大会', 'ゲーム大会に参加しました。最初は難しそうにやっていましたが、集中してやると次第にコツをつかみ、488点という高得点を取って個人戦・チーム戦ともに1位に浮上しました。そのときはみんなで盛り上がって喜ぶことができました。', null, '時間帯: その他'),
  ('d3bb4881-d433-581b-879b-6f96ab342d06', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-12-14', '16:30:00', null, '通常 / 大会発表練習', '資料作成がまだ終わっていなかったため、そちらから先に仕上げていきました。前回までに作っていた部分と、書類審査の際に提出したものを利用してサクサクと進めていくことができていました。その後は台本作成に取り掛かっていき、資料部分の説明内容を記載したものを作りました。そして発表練習では、資料部分では初回からほとんど詰まることなく完璧に発表することができていました。そのため、プレイしながらの説明部分を家で完璧にしてくるそうなので、本番でどれほどの力を発揮できるのかが鍵となってくると思います。', null, null),
  ('d7345a2c-8ecb-5174-9b9e-d4d5014c8a61', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-14', null, null, '通常 / ゲーム大会', 'お菓子を獲得したいと意気込んでゲームを始めました。チーム戦はそこそこにして個人戦をとても頑張っていました。途中でランキングを更新して1位になることができましたが、月曜日の人に追いつかれないようにとさらにスコアを伸ばすことを狙いました。実際にもう一度スコアを伸ばすことができ、お菓子獲得がほとんど確実になったことを喜んでいました。', null, '時間帯: その他'),
  ('1d628362-cb3a-5217-9071-d7bcf433b843', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-14', null, null, '通常 / ゲーム大会', 'やる気満々でゲーム大会に臨みました。2つのゲームとも、難しいけど楽しいということで頑張っていました。入賞はならなかったものの、最後の方でフンツノゼミの自己ベストを大幅に更新したとき、自分との戦いに勝った達成感を感じたようでした。', null, '時間帯: その他'),
  ('7366abf1-67df-59ab-9fdb-9ce3086e6014', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-14', '17:30:00', null, '通常 / ゲーム大会', '最初は中学生も取り組んでいもいいのかと取り組んでいいのかと、控え気味でしたが、やってみると、はまってやっていました。受験勉強で最近はゲームをやれていなかったみたいで、良い気分転換になったそうです。300点も超えてよい成績になりました。結局、中学生が上位を独占してしまっている感じはしますが', '検定の証書が届き次第、渡してください', null),
  ('26b51d59-355a-5569-98ce-743a482e30a9', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-16', '17:30:00', null, '通常 / ゲーム大会', '低学年向けのジャンプゲームに積極的に挑戦していました。 フンツノゼミのゲームにも挑戦していましたが記録が伸びず難しかったようです。', null, 'タイピング: なし
備考: お母さんから、タイピングのホームポジションをしっかり教えてほしいとの要望がありました。（大原追記）'),
  ('e0e76dfb-dae2-5cf7-a94e-e47fe8be17b0', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-16', '16:30:00', null, '通常 / ゲーム大会', '勇作君とジャンプゲームで盛り上がっていました。 最初の記録は低かったですが、最終的に勇作君と共に入賞までランクインすることが出来てとても嬉しそうでした。', null, 'タイピング: なし'),
  ('5e93503e-e884-515c-8f3a-cb2b33070b70', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-16', '17:30:00', null, '通常 / ゲーム大会を楽しむ', 'はじめはあまり記録が伸びなかったせいもあるのか、いつものオリジナル電車作品をいじったりもしていましたが、だんだん盛り上がってきたのか、授業後半は熱心にチャレンジして、新記録が出るたびに報告してくれました。 今後の授業内容について、オンライン授業については回答に迷っているようだったので、冬休みにゆっくり考えるよう伝えました。 Excelは興味があると即答だったので、通常授業内に取り入れていきたいです。', null, 'タイピング: 自主的にやっていました
盛り上がり: 後半になってゲームの記録が伸びてくると、かなり熱心にやっていました。
備考: 昨年は、やりたくないといって拒否したタイピングの案内を熱心に見ていたので、今年はやってみる？と声をかけると、やりますとのこと。得意なことを頑張ろうとする姿勢になってきたのは良い傾向だと思われます。'),
  ('4fec8e69-509b-5f5a-bcb1-379defa9c191', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-16', '16:30:00', null, '通常 / ゲーム大会', '岳くんと共にジャンプゲームを頑張っていました。最初は中々記録が伸びませんでしたが、最後まで取り組んだ結果入賞するまでのスコアを出せたみたいで、よかったです。 岳君ととても仲が良く、「俺が入賞したら岳にもお菓子を分ける！」と意気込んでいました。', null, 'タイピング: なし'),
  ('c0d093c3-bd29-52af-bf74-f1aef6cf4116', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-16', '17:30:00', null, '通常 / ゲーム大会', '集中して取り組んでいました。あおしくんのスコアをとても気にしていました。後半はゲームのアレンジや改善点についてけいとくんと話していてとても良かったです。分岐や無敵時間などいろいろな話をされたのですが、自分でアレンジしてくれると嬉しいなぁという気持ちです。', null, null),
  ('65f68246-dae4-520c-b285-bd16d9018511', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-16', '17:30:00', null, '通常 / ゲーム大会', '冒頭はゲームの内容に少し不満そうでしたが、慣れたようです。後半はそうたくんやけいとくんと話してゲームの難易度やアレンジについてたくさん話していました。もう少し落ち着いてくれると嬉しいかな？という感じです。', null, null),
  ('c5b7112c-f925-5d64-94cd-3ed562849d0b', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-16', '17:30:00', null, '通常 / ゲーム大会', '楽しく取り組めました。点数もそこそこ高くて嬉しそうでした。振替でしたが、周りの人と馴染めていて良かったです。後半はゲームのアレンジについてそうたくんとたくさん話していました。また途中、HPの回復量を多くして遊んでいました。楽しそうでした。', null, null),
  ('350dadef-c85a-56ca-a104-bc44760fc184', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-16', '16:30:00', null, '通常 / ゲーム大会', 'フンツノゼミゲームでは難易度的に難しかったようですが、隣にいる夏芽ちゃんと邪魔をするウサギのセリフを変えたりなど、楽しそうにアレンジをしていました。', null, 'タイピング: なし'),
  ('28e6a261-b217-5dfc-99c6-8fa7ac923447', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-17', '16:30:00', null, '通常 / ゲーム大会', '眞子ちゃんとお互いの学校でのことを話ながら、楽しそうにゲームとアレンジに取り組んでいました。', null, 'タイピング: なし'),
  ('0e57fccb-8bd0-53e8-8ac4-14c2be2959f5', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-17', '16:30:00', null, '通常 / ゲーム大会・バグ探し', 'リベンジにはなりませんでしたが、楽しく遊んでいました。途中飽きてしまったので、バグ探しに誘導しました。フンツノの修正はだいぶ悩んでいたので、考え方の筋道を伝えました。ポイントとしては、クワガタがクローンされたものなので、旗を押したとき～のブロックではうまくクワガタのプログラムが動かないところかな？と感じました。りさちゃんのバグ修正もし、アレンジも加えて楽しんでいました。', null, null),
  ('b4dcbea8-c4ac-5a11-b471-a46af82bcf3d', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-17', '17:30:00', null, '振替 / ゲーム大会・バグつぶし', 'バグ潰しは両方のプログラムやっていました。りさちゃんの方は難しく考えすぎていたようでしたが、コスチュームを確認するように伝えるとすぐに気が付けました。フンツノのアレンジも高度な論理で考えていましたが、クワガタがクローンであることが影響してうまくできず残念でした。最後はこちらから助言をしつつ、とてもシンプルなプログラムを作成することができて嬉しそうでした。アレンジとして降ってくる薬の量を増やして遊んでいました。かなり楽しそうでした。', null, null),
  ('adf3e608-246a-541e-9fdc-16c8ef618bfa', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-17', '17:30:00', null, '振替 / ゲーム大会・バグ探し', '楽しく取り組めました。バグ修正はフンツノを取り組みました。 考え方が難しかったようなので質問をして掘り下げました。「端にふれたとき～」でうまくプログラムを作ることができました。またプレイをしながらアレジをたくさん思いついてようだったので、メモをして共有しました。 ＜αポーション＞ ・ピンチのとき、自分で落とすもの（数字キーなど） ・取るとプレイヤーの体の色が虹色になる ・取ると無敵時間になる。ー体力が減らない、よけた数が自動で増える 土曜日に取り組みたいようです。楽しそうでよかったです。', null, null),
  ('a4060013-ed90-5791-909d-7b6c83915aef', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-17', '16:30:00', null, '通常 / ゲーム大会', '今日は同学年がいなかったのか前回より大人しく、低学年向けのジャンプゲームにしばらく挑戦してもらいました。しばらく取り組んで飽きてきた…とのことだったので、一緒にバグ潰しに挑戦しました。 少しずつヒントを与えながら、「ずっと」の制御のコードを適切に使ってもらうことに成功しました。 最後の「↓キーを押された後に立つスプライトに戻す」の方法が私でも説明が難しいと感じたのですが、大和先生から「◯秒待つ」を使ってみようとのことですぐに理解して解決してくれました。', null, 'タイピング: なし'),
  ('23b8960a-f248-5cef-8389-c52a6669870f', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-12-19', '16:30:00', null, '通常 / ゲーム大会', 'しばらくゲームに取り組んでもらった後、私の私物のipadを使いながらイラストについて楽しく会話させてもらいました。 話を聞いたところ、レイヤーや不透明度の話などデジタルイラストの技術をかなり知っていたので驚きました。 好きな絵柄や、学校でのことについて話せてよかったです。', null, 'タイピング: なし'),
  ('6a6c2ccd-62b5-5513-a162-08c161269a70', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-19', '16:30:00', null, '通常 / ゲーム大会', '20分ほど遊んでバグ探しに取り組みました。コスチュームの存在に気づくまではかなり悩んでいましたが、コスチュームに気が付くとすぐにプログラムを作成できました。「●秒待つ」もしっかり使えました。また以前自分がプログラムのコスチュームを変更させていました。サルが出るようになりました。コスチュームの割り当てがうまくいかず悩んでいたので、プログラムを一緒に確認して修正しました。最後には地形を変化させて楽しんでいました。', null, null),
  ('2209e233-011c-53f5-b58d-c23a443432b9', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-19', '17:30:00', null, '通常 / ゲーム大会', '楽しくゲーム大会できました。バグ探しはポイントはしっかり押さえられました。「フンツノより下にいったとき」という考え方から「下の方にいったとき」につなげるところは手伝いました。その後「クローンが削除されたとき」という考え方で、最小の労力でバグを訂正することができました！ とべりさちゃんの方も記録に挑戦していました！楽しそうでした。', null, null),
  ('8b22e15e-d957-5709-874e-192d0603704f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-19', '17:30:00', null, '通常 / ゲーム大会', 'おかしをもらえてとても嬉しそうでした。今日はよくしゃべっていました。自分の過去の記録を超えることもできました。 バグ探しは取り組むのに時間がかかりましたが、一度始めるとすぐにプログラムできました。コスチュームに気が付かず困っていたのでサポートしました。 楽しそうで良かったです。', null, null),
  ('e65fe976-d078-5791-a2fb-96db0df16bfb', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-19', '16:30:00', null, '通常 / ゲーム大会', 'ゲーム大会は初めて20分くらいで飽きてしまったようなので、バグ探しに移りました。ほぼ自力で取り組みましたが、「旗をおされたら」の代わりに「クローンされたら」を使うのが少し難しかったようです。また検定の練習問題のアレンジを進めていました。みずを使った攻撃を作成していました。満足のいく仕上がらいになったようで、本人の希望もあって公開しました。', null, null),
  ('a5ac5e6d-3935-5bd8-a617-92bc69ea3c06', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-19', '16:30:00', null, '通常 / ゲーム大会のリベンジとバグつぶし', '最初はゲーム大会のリベンジを狙いました。残り30分になったところでバグつぶしに誘導し、少しやる気が出ないと言いつつもこたろうくんと協力して取り組んでくれました。y座標に注目したのはいいアイデアでしたが、不等号ではなく等号を使って判定していたので、「クワガタがフンツノゼミの真横を通らずに下に行っちゃったらどうする？」などと問いかけることで不等号を使わないといけないことに気付いてもらえました。バグつぶしに成功した後はスコア狙いに戻っていました。', null, null),
  ('82da9f0e-c522-579d-b7e5-9969fdd569a0', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-19', '16:30:00', null, '通常 / バグつぶしとリベンジ', '前半はゲーム大会のリベンジを狙い、残り30分のところでバグつぶしに移ってもらいました。問いかけをして、誰がどうなったらスコアが増えるのかなど考えてもらいました。難しいところはりょうやくんに協力を求めるなどして、バグ解決まで取り組めました。時間が少し余ったのでそこでも自己ベスト更新を狙っていました。', null, null),
  ('b82e5790-73d1-5471-a529-485607f38e78', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-19', '17:30:00', null, '通常 / リベンジ戦とバグつぶし', 'バグつぶしは比較的最初の方に取り組み、当たり判定用のスプライトを準備すればいいことにすぐ気づいて難なく終わらせました。先週の自己ベストが高すぎてなかなか超えられなかったようですが楽しんでいました。', null, null),
  ('28b83f07-ab5c-5a6a-a8a8-33add661fdfe', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-19', '17:30:00', null, '通常 / リベンジ戦とバグつぶし', 'バグつぶしのとき、レベル別のクワガタ全てを直すのは大変だといって、「よけた数カウント」のスプライトの方でコードを作るという工夫を思いつきました。クワガタを色で判定しないといけない影響で一度誤判定が出ましたが、スプライトの位置を調整することできちんと動くようになりました。残りの時間はリベンジを狙い、見事先週の自己ベストを更新することができました。お菓子ももらって楽しく終わることができました。', null, null),
  ('bcf4fbab-abdb-5893-b4aa-cc92a60d08e4', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-19', '17:30:00', null, '通常 / リベンジ戦とバグつぶし', 'バグつぶしを前半の方で済ませてしまおうとやる気を持ってくれたのですが、手が止まっていたので、まずどこがバグなのかをゲームプレイしながら一緒に確認しました。そのあとは、コスチュームを変えればいいことや何秒か待って姿が戻ることを自分で気づいて修正することができました。そのあとはりさちゃんとフンツノゼミの自己ベストを更新しようと楽しんでいました。', null, null),
  ('2c1c39a1-2378-5498-882d-1fac47d7989d', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-20', '16:30:00', null, '通常 / ゲーム大会リベンジ', 'アルスタジオ', null, '盛り上がり: 前半はバグ直しも含めてたいようくんと楽しくフンツノに遊んでくれました。ただ、スコアの伸びにくさや1位との圧倒的な差からフンツノに飽きてしまっていました。太陽君のあおりもありほかの過去の作品を掘り起こして自分が作ってきたゲームの見せ合いになりました。まあずーーとしゃべりパなしでしたが、楽しそうでした。'),
  ('d44c8eea-4660-58bc-af29-c9313c0abcb9', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-20', '16:30:00', null, '通常 / ゲーム大会リベンジ', '先週からゲームがうまくできていなかったため、今週もなると、福引よりも飽きでほかのことに気が移ることが多かったです。それは、スクラッチで遊んでいるのは意外にも少なく、学校で作っているものをたっちゃんにも共有させて楽しんでいました。 フンツノは単なる避けゲーなので、あまりスコアが伸びない子にとってはスコア伸ばしよりつまらなくなる傾向が多いです', null, null),
  ('86f0e35e-e97b-5583-9b19-6520a53dca66', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-20', '17:30:00', null, '通常 / 自由', '大会お疲れ様だったので、コンテストのゲームを進めてみましたが、あまり負荷をかけずに自由に遊んでいました。たいようくんのにぎやかさもつながりもあって、久しぶりに自由に気ままにゲームができたと思います。', null, null),
  ('2aa025a4-a57c-5b66-869b-9f5128691ff4', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-20', '16:30:00', null, '通常 / ゲーム大会リベンジ週', '跳べ！りさちゃんで、先週の記録を超えて４２点を取ることができました。フンツノゼミの方は、あまり興味がなかったようで、１度しか挑戦していませんでした。そこで、りさちゃんのバグ取りを促したところ、すぐに挑戦を始めて、自分の力で難なく修正できました。低学年レベルのバグ取りだとリョウマくんには簡単すぎるかもしれません。', null, null),
  ('d5ca6414-a81a-51e1-b148-c37c0f9615fb', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-20', '17:30:00', null, '通常 / ゲーム大会リベンジ', '前回で遊びつくしてしまって、最初から飽き気味でした。アレンジもバグ直しも前回したそうだったので、ある程度遊んでから自作ゲームに移りました。その途中、はる君やたいようくんとの作品見せ合いもあって、楽しんでいました。最後の方は、マグネットのやつもいじって自由気ままでした。', null, '盛り上がり: 飴をクラッカー替わりに脅かすのやめよう'),
  ('e767f789-1ff4-5acb-8886-cd203ad4876b', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-20', '17:30:00', null, '通常 / ゲーム大会リベンジ週', '先週の記録を超えると福引が２倍になることを伝えると、やる気が出てりさちゃんを繰り返し続けていました。結果先週を大きく上回る５０回を記録しました。さらに、総合で3位以内に入りたいと必死に続けていましたが残念ながらそれはかないませんでした。ふんつのぜみも挑戦していましたが、こちらは難しかったようで、なかなか続きませんでした。途中バグ潰しを促しましたが、りさちゃんの記録更新に夢中でできませんでした。ゲームがうまくいかない時に、大声で叫ぶことが多かったので、そこは迷惑になるのでもう少し小さい声で悔しがってねと促すことが多かったです。', null, null),
  ('32375e0a-10de-560a-9517-81311d0ba038', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-12-20', null, null, '通常 / ゲーム大会リベンジ週', '先週の得点超えで新年の福引が２倍になるということを伝えてやる気を出して、りさちゃんをひたすら続けていました。結果、先週の得点を超えることはできました。フンツノゼミも何回かは挑戦していましたが、りさちゃんをより高得点を目指して時間がきても、あと１回やらせてというくらい熱中していました。残念ながらバグ取り出来なかったのですが、だいぶ集中して楽しみながらゲームに夢中になっていたと思います。', null, '時間帯: その他'),
  ('e1366590-6ab7-5dcf-9cce-85bc2dfe953e', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-20', '16:30:00', null, '通常 / ゲーム大会リベンジ', '入室した時から、前回のを超えるぞーとやる気が活きこんでいました。あさひ君的にはフンツノの楽しくほとんど授業時間やっていました。今回はみるみると成長していき、200点くらいまではＨＰ7以上を保つことが多く、最終的に350点を超えることができました。楽典的にはリベンジはリサちゃんですが、フンツノでかんばっていたので、リベンジ達成だと感じます。', null, '盛り上がり: フンツノとリサちゃんでやっているものは違ったが、ずーとたのしく話していました。'),
  ('384ff404-228c-596c-af16-d4513799ed8e', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-21', null, null, '通常 / ゲーム大会リベンジ', '今週火曜にフンツノの方のバグ直しに取り掛かっていたので、リサちゃんのバグの方を直していきました。以外にも数秒たってから元の姿に戻すことがなかなかうまく言っていきませんでした。何秒待つのコードの存在が抜けていたみたいです。 フンツノの方は着実にスコアを挙げていき、200中盤くらいの自己ベストを出せたそうです', null, '時間帯: その他'),
  ('27b3bcde-edeb-58ad-9b66-d6049a7ffadd', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-21', null, null, '通常 / ゲーム大会リベンジ', 'クラス対抗1位だったので、まずはバグ直しの方をやっていきました。少しは悩み考えていましたが、簡単に端に触れるたらで自力で導き出せて、気持ちよく解いていました。その後のフンツノも追い込んで、楽しくできていました。', null, '時間帯: その他
盛り上がり: おめでとクラス対抗1位！'),
  ('c8daf665-9d23-5ef5-ba1c-dfe58c80eeae', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-21', null, null, '通常 / ゲーム大会リベンジ', 'まずはバグ直しをやりました。淡々と進んできていて能力的に余裕そうでした。その後、フンツノをやっていきましたが、前回ほどは伸びず、若干な秋はあったが、最後の一回で、本日のスコアを更新していました。', null, '時間帯: その他'),
  ('1d0a583e-3f17-5dde-9365-f3d2e23dd273', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-21', null, null, '通常 / 自由', '最初はフンツノにやる気を示していましたが、圧倒的スコア差を感じ、のらりくらりとscratchをいじっていました。まあ少しはやってる所見せて、プロゲートを1仮定は進めてくれました。ここで、思う存分ゲームができたと思います。', null, '時間帯: その他
盛り上がり: 受験勉強頑張ってくれ'),
  ('1bd499e2-f659-5959-b3d0-3c6291f6cffe', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-21', null, null, '通常 / ゲーム大会のリベンジ', 'バグつぶしのとき、適当だと言いつつもy座標を不等式で評価してきちんと直すことができていました。そのあとはフンツノゼミのアレンジをして、薬を大量に置くなどして遊んでいました。リベンジ戦にも参加し、自己ベスト更新はなりませんでしたが先週同様高い記録が出ていました。', null, '時間帯: その他'),
  ('5f18b7b3-22f8-51d0-b8af-3b1c9b529470', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-21', null, null, 'ゲーム大会のリベンジ', 'バグつぶしをパズルのように楽しく取り組んでいました。最初はフンツノゼミの横を通ったときにスコアを増やすようにしていましたが、下の端で判定したほうがシンプルだと気づくとそのように直しました。クローンとスプライト本体の動きを混同していた部分があり、今回流れてくるクワガタはクローンなので「クローンされたとき」で動きを書くことを整理しました。無事にバグつぶしを終えるとスコアを狙って遊びました。ランキングのレベルの高さに驚きながらも楽しんでいました。', null, '時間帯: その他'),
  ('65cdadd3-ecef-5e57-adf2-686803d89a5f', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-21', null, null, '通常 / ゲーム大会リベンジ', '最初にバグつぶしをやっていきました。コスチューム変化の対応はコードにも落とし込みていました。そのまま、アレンジもやりたそうにしていたので、続けてもらい、セリフもありつつ、自由に動けるゲームに変化していました。途中左右の動かしが、できないと、質問してくれたり、必死にセリフを考えてくれたり、元あるコードをうまくいかせていました。ほんと作るのが好きそうです。', null, '時間帯: その他')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('38fad973-fc39-5b4d-bfcf-291ba28c0169', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-21', null, null, '通常 / ゲーム大会のリベンジ', 'バグつぶしでは、作るブロックは合っていましたが入れる位置が違ったので、「地面にいるときいつでも反応してほしいならどこに置く？」と問いかけると直すことができました。そのあとは、ゲームのアレンジなどもしましたが最後はのあくんと仲良く競うようにりさちゃんを遊んでいました。', null, '時間帯: その他'),
  ('e6e6f5e9-421f-5c76-8f63-63f5f54db707', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-21', '18:40:00', null, '通常 / ゲーム大会リベンジ', 'リサちゃんの方は、1週目で1位だったので、きょうはフンツノに全集中でした。記録が更新される度に、報告してくれて大いにタニシんでくれていました。ただ、やっている最終は体も一緒に動いてしまっていたので、椅子の座りかげんは注意しておきました。かずまくんの大スコアもあり、クラス対抗1位でめちゃくちゃヨロこんでいました。', null, null),
  ('90cf6215-0256-5aa6-9e80-62f14baa2f05', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-21', null, null, '通常', 'バグつぶしは前半のうちに取り組み、こうしろうくんと協力するような形で進めました。下向きキーを押したときにしゃがむコードを考えて書くことができました。後半は、こうしろうくんと仲良くりさちゃんの記録を狙っていました。', null, '時間帯: その他'),
  ('6dbf3e76-0424-5469-a208-f5314f1ed641', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-12-20', null, null, '通常 / ゲーム大会リベンジ', 'かなり集中してきた時からずっとやっていました。300超え、350超え、と着実にスコアを伸ばしていき、最終的には392点と仰天なスコアを出してくれました。かなりゲームのコツを塾で来ていたそうです。', null, '時間帯: その他
盛り上がり: お迎えが来たら切り替えよう'),
  ('d46ee1b8-c361-5de1-8361-4d69e71e2b58', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-21', null, null, '通常 / バグつぶしとゲーム大会リベンジ', 'バグつぶしは簡単だったようでさくっと終わらせてしまい、そのあとはゲーム大会で遊びました。600点を超える大記録を出して個人・チームともに1位に躍り出ました。同じクラスの藤田兄弟がかずまくんのプレイにしきりに感心していましたが、本人はいたって冷静でした。', null, '時間帯: その他'),
  ('e775c9ae-4397-55cb-9d0f-d20479de158a', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-12-21', null, null, '通常 / バグつぶしとゲーム大会リベンジ', 'バグつぶしを最初に取り組みました。考え方自体はすぐわかったようですが、「クワガタのy座標<フンツノゼミのy座標」「クワガタのy座標=-170」などで作ってバグっていました。なぜそれではうまくいかないのかを一緒に考え、学びになったようでした。そのあとはゲーム大会で遊び、自分のスコアはそんなに高くないと言いつつも楽しんでいました。', null, '時間帯: その他'),
  ('4a898430-f152-5701-b8fc-dd4c67221135', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-23', '16:30:00', null, '通常 / ゲーム大会・バグ探し', 'いつもよりも落ち着きがありませんでした。お家でいろいろあったのかな？ バグ探しは発想は良かったのですが集中力が続かず残念でした。自分からは進められませんでしたが、こちらから質問をすると思い出しながらプログラムできました。 ゲーム大会は楽しく進められました。高学年用のゲームも遊んでいました。', null, null),
  ('13e826e1-a49c-5b9b-aaef-74c4c9946177', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-23', '17:30:00', null, '通常 / ゲーム大会・バグ探し', 'ゲーム大会はひかりちゃんと話ながら楽しく取り組めました。 バグ探しはかなり余裕そうでした。もとのプログラムをよく見て考えてプログラムできていました。楽しかったようで何よりです。', null, null),
  ('4ca1448d-3320-5773-b5a4-0011107a4dde', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-23', '17:30:00', null, '通常 / ゲーム大会・バグ探し', 'ゲーム大会はそうたくんと話ながら楽しく取り組めました。 バグ探しはクローンを知らなかったので困っていました。使い方を解説しました。プログラムのシナリオは、クワガタが消えたときをベースに発想できていたので良かったです。', null, 'タイピング: 集中して取り組めました。'),
  ('a750b85c-bb89-5f78-a44b-fa041ed69d20', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-12-23', '16:30:00', null, '通常 / ゲーム大会・バグ潰し', '前週でランクインできて嬉しそうでした！お菓子楽しく選べていました！ バグ探しはコスチュームのヒントを出しましたが、少し難しかったようです。必要なブロックを揃えた後も少し詰まりました。もし～の使い方がまだ苦手な様子です。 ゲーム大会はゆうさくくんと楽しく取り組めていました。', null, null),
  ('aeaec2c6-6297-5ac2-9f95-92f2ad346e6e', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-23', '17:30:00', null, '通常 / ゲーム大会リベンジ・バグ探し', '授業開始時にやりたいことの確認をしましたが、ゲームのリベンジをする気満々だったので、そのままリベンジとバグ探しをやってもらいました。 バグ探しは、ゲームにつかれたときに気晴らしに手を付けて、あっという間に終わらせていました。 ゲーム自体は、前回の記録より80点ほどスコアを伸ばすことができて、嬉しそうに席で両手をあげて先生に声をかけられるのを待っていました(^^) 授業終わりの15分ほどは、タイピングを熱心にやっていました。毎パソの和文形式は苦手だと言っていたので、ローマ字にしぼってチャレンジするようです。現段階で1級を取れているようなので、初段を目指すよう目標をたてました。', null, 'タイピング: 授業の後半に自主的にやっていました。 毎パソの和文は、こういうの苦手、と言って、ローマ字で初段を狙うそうです。
盛り上がり: ゲームのリベンジができたときは、珍しく嬉しい！という感情をおおっぴらに見せてくれました。'),
  ('2a6dc6c6-447c-5eff-90ce-a551c6d63c81', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-12-23', '17:30:00', null, '通常 / ゲーム大会リベンジ・バグ探し', '今日は終始嬉しそうにパソコンに向かっていました。 りさちゃんの記録も前回を上回ることができて、嬉しそうに教えに来てくれました。 バグ探しも、すぐにスプライトのどの部分がおかしいかを口頭で伝えてくれて、必要なブロックもすぐに作成することができていました。 ただ、自分で作成した「もし」をどのレベルに入れるかが曖昧で、なんとなく下につなげていてうまく動かないようでした。 目が悪いこともあるため、ブロックを拡大して構造をよく見るよう勧めたところ、無事に直すことができました。 バグつぶしと自己ベストが出て満足したのか、しばらくフンツノゼミで遊んだ後、作成途中の「目白駅」を作りたいと言ってきたのでOKしました。 アナウンスや電車の音を一生懸命作成していたので、拡張「おんがく」ブロックを使って目白駅の発車メロディが作れるよ、と見せてみたところ、熱心に作り方を覚えて作成していました。 できたところをお母さんに見せて嬉しそうにしていました。', null, '盛り上がり: 今日は何をやっても楽しそうで、ずっと目をキラキラさせていました。自分でやりたいことなどもよく話してくれるとお母さんに伝えたところ、いつもはしゃべることが苦手なので、教室でしゃべっているということは余程教室が好きなんですね、と喜んでくださいました。'),
  ('0856705c-3f83-5dac-ba8e-542f702f07fd', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-11', '16:30:00', null, '通常 / エラースクラッチ', '年始なので、ゆっくり進んでいきました。最初の数の入れ替えは、コードを見ただけではわかっていなかったが、実物を使って操作を行った際に、もう1つの場所が必要であることに気づけて、コードに作れていました。変数を50で止めることは、普段座標判定やスコア判定の時に、どう使っているか思い出してもらったら取り組めていました。年始なんで、何かの引き出しをつくってあげれば進める状態でした。ほかに、タイマーを留めるところでは、最初から四捨五入の選んでいて勘がよかったです。', null, 'タイピング: 数を重ねるたびにスコアが伸びてきました'),
  ('c39ecb45-b375-5fa0-af25-b8c721483b6e', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-11', null, null, '通常 / エラースクラッチ', '足し算は、すぐにコードの違い気づけていました。半角全角問題はさすがにずるいと感じていました。気合の問題は、間に隙間を作ることの発想にたどり着くまでに、ヒントをあれやこれやしなが悩みながらやっていました。スタンプの問題は、もともとの機能がはっきり認識していなかったので、説明をしながらやっていきました。ヒントとして現状は同じ場所に4回打っているからどうすればいい？まで進めてきましたが、あまり動くことの存在に気づける時間をかけました。', null, '時間帯: その他
タイピング: ミスも少なく打てていました
盛り上がり: 福引は、完全にくじ狙いで2枚引きウッディに文房具を取っていきました。'),
  ('33b4b3e5-4c18-5cfe-af71-3ed8e092aee6', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-11', '16:30:00', null, '通常 / タイピング、エラーで学レベル①', 'マシュマロ獲得を目指してレベル１の教材に一生懸命取り組んでいました。 「このコードを使うかもしれない、一旦確認したいから待って！」 と自力で問題解決したいんだというこだわりを強く感じるので、 次週も誘導する程度のヒントを与えつつ、本人が満足するまで様子を見守ろうと思います。', null, 'タイピング: 最初に取り組んだタイピングは難易度が高そうでしたが、 ローマ字表をみながら自分から英語１文字のタイピングに挑戦していて、 しかも１行打ちきることが出来ていました。 ハマっていたのか何度も繰り返し挑戦していたので、 来週もやる習慣が身に付けばタイピング能力が高くなるかもしれません。'),
  ('7af9acfe-5f10-5d28-b56a-621c3a6d7cc0', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-11', '17:30:00', null, '通常 / エラースクラッチ', 'エラースクラッチはレベル3でも5分以内にすべて解き終わるくらいに余裕に解けていました。追加で、カーリングの問題取り掛かっても、特に思い悩むことなく的確に答えラテていました。残りの時間は自分で作っている作品に続きをやっていました。', null, 'タイピング: かなり上位を狙えるスコアでした'),
  ('2e047cc6-2903-5ba5-a196-16c26767cc71', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-11', '17:30:00', null, '通常 / タイピングとエラーで学レベル', 'レベル１の問題に取り組んでいました。 最初は演算の複雑な部分を変えようとしていたので、隣でヒントを与えて誘導するよう努めました。 すぐ「あのパターンか」と言った具合で理解してくれたので、割とサクサク解けていました。（先にお兄さんが目の前で解いていたのもあり、先にヒントを得ていたのもありますが…）', null, 'タイピング: ローマ字でのタイピングはまだ難しかったようなので、 「ホームポジションの基礎」で英語１文字のみでのタイピングを取り組ませました。'),
  ('f8ca8ae4-7354-5279-899e-a7324619cae5', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-11', null, null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', 'レベル②の数字の入れ替えには少し説明が必要でした。レベル②の問題も、エラーを探すコツをつかむまでは導入を一緒にやったりもしていましたが、後半から慣れてきたようで、レベル③はほぼ自分で解けていました。', null, '時間帯: その他
タイピング: 練習するごとに級を上げていました
盛り上がり: 問題チャレンジもつかみ取りも、楽しそうにやれていました。 タイピングも昨年から言っていただけあって、熱心に練習していました。'),
  ('b5d2f16f-d17c-5f75-9053-d3b5040f86db', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-11', '17:30:00', null, '通常 / タイピングとエラーで学レベル', 'レベル１は何も悩むことなく簡単に解いてしまいました。 レベル２も順調そうでしたが、変数の箱の問題では詰まってしまったようです。 先生からの説明を元に、変数内での数字の移動の仕組みに気がつけていたようですが 「3つ目の箱の変数を追加する」というアイデアまでは浮かばず苦戦していたようでした。', null, 'タイピング: 集中して取り組めていました。'),
  ('142ee2d3-78ee-58e6-8c02-627b0e0672f0', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-11', null, null, '通常 / タイピングの練習', 'Excelの検定については、家で相談して候補日を連絡してくるとのことでした。 Excelの練習をするか、つかみ取り大会への参加を勧めましたが、今日はタイピングをやりたい気分とのことだったので本人の希望に任せました。 マイPCを持ってきていたのですが、いつも使用しているものとは違うのでキーが打ちづらいと言って、教室の色々なPCで試していました。 結果、ハリータイプのPCが一番やりやすいと言って納得していました。', 'タイピングの練習のときだけ、ハリーかロンかポチを貸してあげてください。', '時間帯: その他
タイピング: いろいろとパソコンを変えて、入力しやすいキーボードを検討しつつ、熱心に練習していました。
盛り上がり: キーボードの打ちやすさについて、嬉しそうに語っていました。'),
  ('26de4b59-6bab-5def-be86-eeb44248bfaa', '57f45872-1f3e-5540-b676-bf9023444e39', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-09', '16:30:00', null, '通常 / タイピングとエラーで学レベル', '今回はレベル１の問題に取り組んでいました。 ただ、スタンプのやり方などの復習問題では詰まってすぐ諦めていたようで、 以前習得したはずのことをいくつか忘れてしまっているみたいです。 授業の取り組み方もアレンジや遊びや友達との雑談がメインになりがちなところがあるので、年が近い周りの生徒さん達との差を埋めるためにも改めて基礎をやり直す必要がありそうで、授業に対する意欲を上げる必要性があるのかなと感じました。', null, 'タイピング: 集中して取り組めていました。'),
  ('b555cacd-fe55-59e9-a20d-1a542571f199', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-09', '17:30:00', null, '通常 / タイピングとエラーで学レベル', 'レベル１を一緒に考えながら解いていきました。途中、「変数を〜ずつ変える」の「ずつ変える」の概念がピンと来なかったので時間がかかってしまいましたが、私の説明に対して根気強く聞こうとしてくれており、最終的に理解して進むことができました。 また、タイピング大会に参加は難しそうとのことでしたが、 ローマ字表を見ながら指でガイドしてあげると自分で入力するようになったので、一旦様子見でも良いかと思います。 今回は特殊文字の入力の仕方も教えてあげました。', null, 'タイピング: 難易度が高そうなためタイピング大会参加は様子見とのことです。'),
  ('63456f49-4a4f-5be3-8f2e-78fffb02b337', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-11', null, null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', 'レベル③の方は、行き詰まることもなく自力でしっかりと解けていました。 カーリングはやったことがあると言っていたのですが、ビリヤードの問題がなかったため、復習でカーリングの問題に再チャレンジしてもらいましたが、思ったより苦戦したようで、時間を少し過ぎるまで頑張っていました。', null, '時間帯: その他
タイピング: 入試とかぶるので参加は厳しいと言いながら、練習はしっかりとしていました。
盛り上がり: 入試で大変と言いつつも、どの課題にも熱心に取り組んでいました。
備考: お母さんがお菓子を持ってご挨拶に見えました。 こちらに通って検定1級とタイピングの級がとれたことを喜んでくださってました。 今後のことはまたご相談させてください、とのことでした。 入試が終わって落ち着いたらということで…'),
  ('f79091e2-5bcf-5240-823f-16e336fc4d6e', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-09', '17:30:00', null, '通常 / タイピングとエラーで学レベル', '問題はレベル１〜２までの２枚を取り組んでいました。 最終的に２まで解くことができましたが、 途中の問題では入力するコードをつい複雑に考えてしまい、 詰まって手が止まる様子も見受けられました。 例）「必要無いのに演算を使ってコードを複雑にさせてしまう」 と言った様子です。 また、不等号を扱う問題の「５秒経過」について、 徒競走で使うタイマーのイメージで説明してみたのですが、 「経過」という概念にそもそもピンときていなかったようで、 次回詰まった場合は熟語の意味もわかるかどうか確認しながら一緒に考えていけたら良いなと思いました。', null, 'タイピング: 集中して取り組めていました。'),
  ('89634a4b-2df7-5a6e-9f07-849bf116c158', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-09', '16:30:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', '最初の入れ替えの問題で挫折しそうになっていましたが、なんとか説明を聞いて完成させ、その後の問題は今のよりも簡単だというと、一応やってみる、という感じで取り組み…その後は、わりとサクサク解けたので自信がついたようで、一気にレベル③までやり切ることができました。 コードをパッと見て「ここが違う」と見つけることがとても得意です。検定でも修正の方が得意でしたが、ブロックの並びを見て判断する能力はとてもすばらしいです。', null, 'タイピング: 昨年ほど拒否反応も示さず、なんだかんだで練習できていました。
盛り上がり: 後半にいくについれてどんどん調子が上がり、時間いっぱい使ってレベル③までやりきっていました。景品も欲しかったものがとれたようで、嬉しそうでした。'),
  ('6e18f347-a3c2-5d5d-a340-5543519c4a94', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-09', '17:30:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', 'レベル②から始めるというと、えー？！と言いつつも、上級者扱いされたのが少し得意そうでした。 数値の入れ替えは、実際に紙の箱を使ってようやく納得ができたようですが、それ以降の問題はほぼ自力で頑張って解いていました。', null, 'タイピング: 昨年に比べてだいぶ入力できるようになりました
盛り上がり: やり切った感があり、すっきりして帰っていきました。'),
  ('a1886052-380b-5856-bb23-4ce57fcc22c5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, null, '2025-01-10', '16:30:00', null, '休み（未対象）', null, null, null),
  ('d7d7dad8-ec83-50c0-984c-04a10cd1ae83', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-10', '16:30:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', '問題解決方式は楽しかったようで、とても気合を入れて取り組んでいました。 たいようくんと進行状況を話し合ったりしながら、楽しそうにできていました。 数値の入れ替えと、和や積の意味を説明するくらいで、あとは自力でできました！ ギリギリまで③の問題にもチャレンジしていました。', null, 'タイピング: 入力は楽しいようで、かなり熱心に練習し、数回で10級判定から6～7級まで判定を上げることができました。
盛り上がり: タイピングもエラー探しも、とても楽しそうに取り組んでいました。たいようくんとよくしゃべっていました。'),
  ('23500011-7c7b-57c8-a28c-5798a229fd7a', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-13', '17:30:00', null, '通常 / エラーで学ぶ', 'エラーで学ぶスクラッチとつかみどり大会を行いました。早くつかみどりをしたい気持ちでレッスン時間前から始めていました。変数の入れ替えをするとき、入れ替えたあとの数字を直接打ち込もうとするなど裏技(?)でクリアしようとしていたので、ルールを追加して正攻法で考えてもらいました。紙を使って数字を動かしてもらうと比較的すぐにひらめいたようでできていました。そのあとの問題も裏技を使おうとしていましたが、「この変数はどう変わってほしい？」などと問いかけしていくと最終的には全てきちんとした方法で解くことができました。', null, 'タイピング: 受検するレベルを決めるためにお試しでやってみました。
盛り上がり: お菓子を取った後えにしくんと盛り上がっていました。'),
  ('dfeb747f-0cc1-5b18-b8bc-0719652fd9d3', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-13', '16:30:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', 'つかみ取りに興奮して、問題に取りかかるまでには少し説得が必要でしたが、始めてみると意外と簡単！となり、一気にレベル①を終わらせることができました。 文字列の結合は初めてだったので一緒にやりましたが、他はわりと勘がよく、自分で答えを見つけることができていました。こういう形式の問題はわりと得意なのかもしれません。 気分が盛り上がって②もやってみたいとのことだったので、学年やScratch歴を考慮して、②の最初と最後の問題を免除しました。かけ算までは家で学習しているとかで、計算問題も問題なく、統合や不等号も理解できていました。', null, 'タイピング: 少し誘導してみましたが、タイピングはやらない！とのことでした
盛り上がり: 普段の授業よりもかなり頑張って、熱心に取り組むことができました。 つかみ取りもとても楽しかったようで、くじ引き4枚も当て、妹ちゃんへのお土産を一生懸命選んでいました。'),
  ('b1fdd350-bfad-5bb0-9ad6-758d30e6bb45', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-13', '17:30:00', null, '振替 / エラーで学ぶ', '上級の問題でしたが、1回問題の意味を取り違えていたとき以外は比較的スムーズに解き終えることができました。時間が余ってカーリングの問題に取り組みましたが、これにはやや苦戦していたのでバグをいくつかに分けて整理し、見かけより単純なバグもあると伝えると考えられたようでした。最後のセリフが出現しないバグを直す時、「～秒言う」を使うのと「全てを止める」を削除するという複数の解決策を思いついていました。', null, null),
  ('fc264f7c-731f-59f3-8228-bc13a2c15e84', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-13', '17:30:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', '教室に来てすぐにつかみ取りが気になったようで、授業時間前から問題に取りかかっていました。 最初の数値の入れ替えは、もともと入っていた数値を一度コピーして、などと複雑に考えてしまって混乱し、途中で嫌になってしまったようでしたが、一時用の変数が必要ということは理解していて、最後は順番に入れ替えていくというのを納得して解くことができました。 エラーチェックで学ぶというよりも、問題の作られ方が気になってしまうようで、最初からこう作っておけばいいのに、などと、根本的にコードを書きかえたいけどそれは面倒、というような様子が見られました。 それでもつかみ取りは楽しかったようで、なんとか③まで解き終えて、箱の中をのぞいて何を狙うか熟考して引いていました。 残り10分間は、そうたくんと楽しそうにロブロックスをプレイしていました。', null, '盛り上がり: 最初の問題で一度切れかけましたが、その後は、たまにそうたくんとおしゃべりしながら頑張って取り組めていました。 つかみ取りをしたお菓子の味見をして、そうたくんやみずきくんに話しかけたりしていました。'),
  ('fd13ffa8-2c99-5c41-b195-2ffce6b5dc11', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-13', '17:30:00', null, '通常 / エラーで学ぶスクラッチ', '上級の問題をやってもらいましたが、解決策が思いつかないこともあった様子でした。だいたいの問題はすぐにできましたが、ペンの問題はあまり慣れていなかったのか適切なブロックがわからないようでした。ペンのブロックを一通り見てもらい、ペンを下ろす/上げる のどちらの状態なのかが大事だと納得して解くことができました。カーリングにも取り組み、ヒントに基づいて最後まで解決することができました。', null, 'タイピング: 一度毎パソで練習して、受けるかどうか考えてもらいました'),
  ('52242284-c920-5a50-a655-f3df1573fd66', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-10', '16:30:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', '問題をぱっとみて、「あー、わかるわかる！」と即答し、それが合っているときと勘違いしているときがありましたが、概ね楽しそうに解いていました。りょうまくんとだいぶ気が合ったようで、問題についてのコメントなどをしながら盛り上がっていました。', null, '盛り上がり: 同じ問題に取り組んでいたことで、お互い感想を言い合ったりしながら進めらるのが楽しそうでした。'),
  ('b7ca8b39-8fc3-567e-bc84-131c5c1768e6', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-10', '17:30:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', '学年とレベル的に②から始めようとしましたが、最初の問題でかなりモチベーションが下がってしまったため、レベル①からに切り替えました。そのおかげか、徐々に調子を取り戻してきて、結果として②まで解き終えることができました。 数値の入れ替えは、考えるのが大変だったのか、こちらのなんとなく聞いているような感じでしたが、他の問題はきちんと納得しながら解いているようでした。', null, '盛り上がり: ①から解かせたところ、自力でサクサク進められることに自信がついたようで、先に進むモチベーションアップにつながったようでした。'),
  ('e4d55642-b55d-5d76-a35e-dba59e9c91f1', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-10', '17:30:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', 'さすがに①はほぼ問題なくできていました。文字列の結合の記憶がちょっとあやしかったくらいです。 ②については、数値の入れかえと、等号ではなく不等号を使うことについて説明を要しました。②の最後については、はじめは悩んでいたようですが、上から順に何をしているコードなのかを確認していくことで気づくことができました。', null, '盛り上がり: つかみ取りをするために、頑張って問題に取り組めていました。'),
  ('64aff074-f879-5bef-ac0d-02a441eb2435', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-14', '16:30:00', null, '通常 / エラーで学ぶスクラッチ', 'エラーで学ぶスクラッチとつかみどりを行いました。冬休み明けというのもあり、最初の変数の入れ替えに苦戦していました。複雑なプログラミングの操作に対して苦手意識があるようでした。ただ結局のところ「変数は同時には動かせないから保存用の変数を使って1つずつ動かす」という考え方が大事だということを視覚的にわかってもらいました。また算数で不等号も苦手としている様子で、「ぴったりにはならないから超えたところで止める」「変数が50より大きくなったら止める」など丁寧にヒントを出し、不等号の概念を頑張って思い出していました。', null, 'タイピング: 和文を試しましたが漢字変換を伴うものは難しそうでした。'),
  ('c3151b5e-9bc0-574b-8289-2acacf167fd6', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-14', '16:30:00', null, '通常 / エラーで学ぶスクラッチ', 'エラーで学ぶスクラッチとつかみどりを行いました。「りんごとバナナ」ブロックは初めて使った様子でしたが、「文字を組み合わせるのに使いそうな演算ブロックが見つけられる？」と聞くと見つけることができました。比較的スムーズに進めて一足先に解き終わり、同じレベルをやっていたしゅうくんにヒントを出すなどしていたので内容はしっかり頭に入っていました。くじであたりを引いて喜んでいました。', null, 'タイピング: 仲のいいしゅうくんと競うようにやっていました。'),
  ('41939d1a-e12d-5e2f-980e-6c145514504d', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-14', '16:30:00', null, '通常 / エラーで学ぶスクラッチ', '弟くんの体験と同じクラスでレッスンを行いました。エラーで学ぶスクラッチはレベル2から始めましたが、第一問の変数の入れ替えがとても難しかったため、それ以降の問題はそこまで難しくなかったのですがモチベーションが下がってしまいました。そこでレベル1に下げてやってもらいました。それでも問題を解くときに「こんなことのやり方は習ってない」と言って思考を止めようとしてしまったのですが、アイデアが浮かべばすぐだと伝えると持ち直すことができました。その後自力で解決策を思いつき、「頭が固くなっちゃってた」と言って、やっていることは単純だと気づくことができたようでした。無事に全部終えてつかみどりできたときは楽しい表情も見せてくれました。', null, null),
  ('5872c787-40e2-5751-841d-68392dcebf14', '726bac59-fe00-5b0b-a344-344f40441b6d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-14', '16:30:00', null, '通常 / エラーで学ぶスクラッチ', 'エラーで学ぶスクラッチとつかみどりを行いました。変数を増やしていく問題では値が動いていくイメージがつかめていないようでしたが、1→2→3→...というように数字を順番に並べていくと、変数を1ずつ増やし続ければいいことを理解したようでした。最後はしょうたくんからのヒントもモチベーションになり解き切りました。たくさんのお菓子を取れて嬉しそうでした。', null, 'タイピング: 何回か練習し、やるたびに級が上がっていくのが楽しそうでした'),
  ('5ef718f3-26e1-5aea-b379-08bdc9a25d9d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-10', '18:40:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', 'あさひくんにたまに教えたりもしながら、頑張って取り組んでいました。 文字列の結合はブロックを忘れていたようですが、他は問題の意味がわかるときちんと解けていました。 授業終了後にお母さんが曜日を変える希望を出されましたが、あさひくんと離れたくないからといってかなりしぶっていました。', null, '盛り上がり: あさひくんと仲良くなって、楽しそうに話しながら取り組んでいました。'),
  ('5905d051-0d96-5a4d-8ee2-532f21c022f6', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-10', '18:40:00', null, '通常 / エラーチェックの問題を解いてつかみ取りをしよう！', 'きちんと問題に取り組むことができていました。 とうきくんに質問したりおしゃべりをしたりしながら、仲良く頑張っていました。', null, 'タイピング: ホームポジション基礎をがんばっていました
盛り上がり: とうきくんと話しながら進めるのがとても楽しそうでした。'),
  ('b5ff009c-4a72-5551-83b5-a30347a54413', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-09', '16:30:00', null, '通常 / エラーで学ぶレベル2', '数字の入れ替えは考え方を若干説明して取り組んでもらいました。また1~10の和では、もともとのプログラムの理解に時間がかかっていたので、概要を説明しつつ変数が果たす役割を一緒に確認しました。くじ引きのプログラムはコツを伝えるとスムーズに取り組めていました。数字が少し苦手かな？と感じましたが、よく考えて頑張ってとりくんでいました！', null, 'タイピング: 集中して取り組めました。'),
  ('6101d839-5125-592f-b87a-bc8868272cec', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-09', '16:30:00', null, '通常 / エラーで学ぶレベル1', '新年初回だったので集中力が心配でしたが、比較的しっかり取り組むことができました。数字の苦手意識があり、足し算では詰まりましたが、「気合いだー」のプログラムでは、検定でやったことを思い出して（正解とは若干違いましたが）しっかりプログラムできました。算数が苦手なので数字を見ると嫌になってしまうのかなと思います。', null, 'タイピング: ローマ字表が必要＆ローマ字の大文字と小文字の対応が分からないので、練習をやりつつ本番いけるかどうかを考える必要があるかな？と感じました。'),
  ('bcb034b4-f52d-5655-87bf-7bcc11372e03', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-09', '17:30:00', null, '通常 / エラーで学ぶレベル3・Scratchエラー本にあった最終問題', 'レベル3では正方形のプログラムで詰まっていました。最終的には自分で論理的に答えが出せていました。エラー本の内容はかなり難しかったようです。線を最初にうまく書けるようにプログラムを修正しました。プログラムの仕組みがかなり難しかったので、躓きました。じょうたろうくんと私と3人で考えて解決しました。エラー箇所がかなり簡単な部分だったので拍子抜けでした。考え方はよく理解できていました。', null, 'タイピング: 集中して取り組めました。'),
  ('90d0851e-752e-569f-a3ba-aa8f03675a96', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-09', '17:30:00', null, '通常 / エラーで学ぶレベル3・Scratchエラー本にあった最終問題（ボールを飛ばすもの）', 'レベル3は30分ほどでスラスラ終わってしまっていたので、エラー本にあった最終問題に取り組みました。かなり難しかったようです。線を最初にうまく書けるようにプログラムを修正しました。プログラムの仕組みがかなり難しかったので、躓きました。しゅうくんと私と3人で考えて解決しました。エラー箇所がかなり簡単な部分だったので拍子抜けでした。考え方はよく理解できていました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('a7fd80a6-15ff-5ea5-9f4c-4cfda9000b15', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-16', '17:30:00', null, '通常 / テーマ自由製作', '去年もやったやつかと制作に前向きに取り組んでいきました。作りたい内容はかなり盛りだくさんなので、アイデアがあふれていました。テーマは冒険として地面にある宝箱を探していくようなものになりそうです。穴穂ったらジャンプして戻らないようにしたいとか細かい要素もありますが、小技の選別がまだになっているので、程よいタイミングで差し込むとよいと思います。', null, 'タイピング: おうちでも取り組んでいて、熱心でした'),
  ('035beea5-4350-5881-a581-1bc1329a7deb', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-16', '17:30:00', null, '通常 / 自由制作DAYS', 'アルスパークで用意されていた侍の素材を使って作成していました。 とりあえず黙々と作業しようとしていたので、今回のゲーム制作では条件があることを改めて伝えました。 タイムトラベルをテーマに選ぶとのことでしたがアイデアが出てこなかったので、「今の背景は和風のお城だから、背景の時代が変わったらタイムトラベルみたいになるんじゃない？」とアドバイスをするとなるほど！と理解してくれました。 晴くんは取り組むにかかる時間は早いですが、コード作成の細かい部分に集中しすぎて条件など本来の目的を忘れて作業してるケースが割と多いので、 都度声かけをして進捗を聞いてあげるのが良いのかなと感じました。', null, 'タイピング: 集中して取り組めていました'),
  ('0bd6bd72-cee9-550e-80f0-5bdcb9beb953', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-16', '16:30:00', null, '通常 / 自由製作レベル2', 'テーマはタイムトラベルにしていました。ただ物語性がなく、操作すると背景が変わるだけのプログラムのようです（かなり声を掛けましたが...）。ただスプライトの見た目にはこだわっていて、ひよこのスプライトの見た目を丁寧に変更していました。', null, 'タイピング: 集中して取り組めていました。'),
  ('c3639c94-0743-5473-a4f9-f20f20365e18', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-16', '16:30:00', null, '通常 / 自由製作レベル2', 'テーマはタイムトラベルだそうです。全てが何もなかった「無」から始まるそうです。今日はスプライト作成したり、小技を確認したりしていました。クローンを使った残像のプログラムがとてもうまくできていました！前回よりも前向きに、比較的集中して自分から取り組めていたと思います。自由に作るのが好きなのかな...?', null, 'タイピング: 集中力が続かず、ほぼスキップ状態でした。'),
  ('078b347a-6984-5f49-8d1a-4e1e14dd80b8', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-16', '17:30:00', null, '通常 / 自由製作レベル3', 'テーマや構想で詰まっていたので、作りやすさや作品種類（ゲーム、アニメ）、今までの経験などを話して方向性を決めました。探検ものになりました。洞窟のアニメ調の画像を使いたかったようなのですが、なかなか探せず時間がかかっていいました。', null, 'タイピング: とても丁寧に取り組めていました！'),
  ('c09d6246-1513-5ade-b05e-f20fa72f05fe', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-16', '17:30:00', null, '通常 / 自由製作レベル3', 'テーマはタイムトラベルを選んでいました。過去に戻って始まるゲームを作成するそうです。構想は前からあったそうですが、しんどいということで少し温めていたようです。スプライト準備やプログラムをスムーズに行えました。あまり紙に記入してくれなかったのですが、その分コメントを作ってくれたようです。完成が楽しみです（大作になりそう）', null, 'タイピング: 集中して取り組めました。タイプが速すぎて(?)誤タイプが少し多いそうです。'),
  ('c9580ec6-6379-525d-8e1a-2e6102b8220c', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-16', '16:30:00', null, '通常 / テーマ自由製作', '最初のテーマ決めはさくさくと決まっていき、恐竜を弾幕を使って倒していく構図は取れていました。周りの子に気に取られて、自分のことがあまり進んでいない場面は見られたが、エラースクラッチででてきたペンツールも使いたいそうです。現状のコードではうまく使いこなせていないので、どのように取り組んでいくか整理していった方がよさそうです。', null, 'タイピング: なんかかたくなに数回しかやってくれませんでした。
盛り上がり: がくくんからお菓子をたかろうとするのはちょっとな、、、'),
  ('e0118224-ccaf-509c-bc0e-3f23a23de645', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-16', '17:30:00', null, '通常 / 自由制作DAYS①', '条件を一緒に確認しながら作業をしました。 最初、どの小技を使うかを迷っていたので、 一旦はどっちのテーマで作成するか、キャラクターや背景のイメージから決めようという方針になりました。本人に好きなアニメを聞いたところ、ガンダムが好きとのことだったので 宇宙をテーマに人がロボットに変身するものにしよう！という話になり、しばらく画像を検索して探してもらいました。 ただ、自分の伝達不足でアカウントがないとDLできないモノだったので、ipadでドット絵のイラストを自分で描いてもらうことにしました。', null, 'タイピング: 集中して取り組んでいました。 今回は英単語を小文字で入力するタイピングを練習していました。 １行を超えるぐらいの入力スピードになっていて良かったです。'),
  ('78c2f42c-95d5-5e21-9330-6b80bb54834a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-16', '16:30:00', null, '通常 / 自由制作DAYS②', 'アルスパークの素材→バックパックに収納→使いたいスプライトに出す の一連の動きを知らなかったので、手順を教えました。 Ctrl＋C、Ctrl＋V、Ctrl＋Zの裏わざ的な動きを少し知りたがって使おうとしていました。 素材探しではタイムトラベルを表すものとして古風なお城のドット絵素材を探していましたが、思うようなものが中々出ず集中力を切らしていました。 小技に関しては最初弾幕ゲームを採用していましたが、本人の強い意向でいちごの反乱をゲームに取り入れることにしたようです。', null, 'タイピング: やりたくないとのこと'),
  ('9be384a2-4818-5e15-b8d4-1da289e50bd0', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-17', null, null, '通常 / 自由製作', 'なかなか自由製作のテンションが上がらず、構想を考えるのにも時間がかかりました。小技の弾幕が気に入ったようで、ゲーム形式のプログラムを作成しました。小技のプログラムを使い、リンゴが弾幕をよけるゲームになりました。ゲームオーバーを作成できましたが、その後集中が続きませんでした。 その後、ゲームテーマをタイムトラベルにし、ゲームのクリア・失敗によってタイムトラベルが起こるようにしました。まだ、ステージクリアとゲームオーバーになったときに弾幕を止めるのができていないので、次回作成します。', null, '時間帯: その他
タイピング: ミスを防ぐように伝えるとかなり高得点になりました。嬉しそうでした！！'),
  ('024f2d75-0540-5bc7-b01d-7fd6976b9e89', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-17', '16:30:00', null, '通常 / 自由製作', 'りょうまくんと話つつ楽しく取り組んでいました。またかなり大がかりな構想になってしまったので大変な道のりを想像し、少し諦めモードになる瞬間もありました（少し話すと元気が出ていました。よかった）素材を集めたり、プログラムを考えたりとてもいきいきとしていました。楽しそうで良かったです。 考えすぎてしまうところがあるので、気楽に取り組んでもらうような声掛けも必要かな？と感じました。', null, 'タイピング: かなり高得点になりました。嬉しそうでした。'),
  ('1ded494f-b663-5dc4-8119-f43ac7e0cd8a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-17', '17:30:00', null, '通常 / 自由製作', '構想を考えるのが億劫な様子でした。こちらから話し合いつつ、提案をしつつ進めました。最終的にはテーマは探検で、敵と戦いながらのアスレチックを作成する方針になりました。今日は構想を考え、背景を作成しました。手に余る規模の作品になりそうな予感があるので、うまく前に促す必要があるかな？と思いました。', null, 'タイピング: 集中して取り組めました。'),
  ('06c6e20e-d776-5fc5-a581-cd9bad0f88c4', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-17', null, null, '通常 / 自由製作', '最初はアイデアが出ないようで困っていましたが、少し話すとアイデアが浮かんだようで（テーマはタイムトラベル）、さっそくプログラム作成に移っていました。冒頭部分の車がぶつかるアニメーションを作成していましたが、とてもきれいに作成できていました！完成が楽しみです。', null, '時間帯: その他
タイピング: 集中して取り組んでいました。'),
  ('8bd33db8-d3ad-53a2-8fbd-b23d015182ed', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-17', '17:30:00', null, '通常 / 自由創作', '自由創作ゲーム作成とはいえ、なかなかアイデアがすぐ出ないようなので、一緒にアイデア出しをしました。その中で、小技を眺めていて、懐中電灯で光を照らす小技を使って、キャラクターを探すというのをやってみたいということで、その方向に決定。キャラの変身も必要なので、最初は、ガチャガチャや宝箱が表示されているのが、それを発見すると、中に入ったものが出てくる（＝変身する）という形にしようかという大まかなイメージを作りました。レッスン中、ずっと集中力を維持できていて、少し脱線しそうになるも、すぐに本筋の話に戻ってくれて、中身の濃い話ができたと思います。大まかなゲームの流れは、探検をテーマ、猫を探す。猫はガチャガチャや宝箱のどこか一つのとこに隠れている。それらは、暗がりの中から探さなくてはいけない。というゲームです。来週からコード作成です。', null, null),
  ('b0e6600e-c55c-5e94-b08b-5c8172643505', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-17', null, null, '通常 / 自由創作', '自由創作の一番最初なので、アイデア出しのサポートから。なかなか思い浮かばないものの、最近ハマってる「はなおとこ」のゲームにしたいとのこと。鼻男は、鼻だけの人なので、自分（鼻）に合う目や口を探す（探検）ゲームにしようという大まかなイメージを共有しました。まだ詳細はつめていないですが、目や口が複数ゲーム画面上に表示されて、主人公（鼻男）が、しっくりくる目と口のとこに移動することで、顔が出来上がってゲーム終了という、そんなイメージです。なかなか難しいですが、来週は細かいゲームの進め方の決定と素材の作成ができたらなと思います。できればコード作りも始められたらと。', null, '時間帯: その他'),
  ('d3ba58e0-0592-5ef1-92fa-b007effee686', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-17', '16:30:00', null, '通常 / テーマ自由製作', 'テーマの説明し終わったら、新しいスプライトに興味をもって使い始めてくれました。とりあえず、スプライトを集めて、侍を軸としていく対戦冒険ゲームを作っていきました。結構作りながら手を止めずにやっていきました。そんで、途中で全体的な構想を聞いてみたら、作り終わるまで半年くらい作りたいとやる気満々でした。はじめのイントロのストーリーを作って、次回は先頭の内容が作れそうです。', null, 'タイピング: 準2級程度まで届いていました。
盛り上がり: たいようくんがちょくちょくぼけてくるのを冷静につっこんで楽しんでいました。'),
  ('906f6a86-0f9c-5050-a75b-cdf68de472de', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-17', '17:30:00', null, '通常 / 自由製作day', '最初のオープニングからメッセージのやり取りで駆使して、上手に作れていました。ときたま、向きの感覚があまり慣れていない感じはしますが、やりたい動きを細かく自分で作れている気がします。次回は、端に行ったら場面転換して、時代が変わっていけるような仕組みを作れていいと思います。', null, 'タイピング: ミスが少なめでした'),
  ('1ceaaa6e-623c-5b00-a72c-04d7595f7593', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-18', '18:40:00', null, '通常 / エラースクラッチ', '一番の最初の難関の「変数の入れ替え」では、数字の値を変えたり、問題文勝手に変えたり、ツッコミ待ちの力技な部分が見えましたw実物で物の入れ替えでやった時にはすーむずにできていたので、自力ではあともうちょっとでした。足し算のときも、力技をはっきしてそうじゃないだろな感じでした。ちゃんと細かく動かしていけない条件を指定すれば、自分で考えて大方の問題は解けました。最後のくじ引きの問題では、一番時間をかけましたが、自力で論理順序を正せていました。', null, 'タイピング: 家でも練習していてスコアがよかったです
盛り上がり: うまい棒狙いでうまくつかみとっていました。'),
  ('d6fbe4e8-71ec-5b3d-8980-e3958d3fb270', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-18', null, null, '通常 / 毎パソ＆自由制作', '自由に制作していいとなると本人も手が止まってしまうみたいで、都度声掛けをしていました。小技の変数から探しに行くか、背景などビジュアルから探すのとどちらがいいかと聞くとどちらかといえば見た目がいいとのことだったので、スプライトをバックパックに入れる方法を教えつつ、本人に使いたい画像を選ばせていました。 ただ、それでも迷っているのか作業がほとんど進んでいなかったです。 普段好きなこと・遊んでいることから作るアイデアを得ようとしましたが、口下手であまり答えてはくれませんでした。 ただ、帰りに真幸くんと掴み取りをする時には楽しそうに笑ってくれたので、そこは良かったと思いました。', null, '時間帯: その他
タイピング: 集中して取り組んでいました。'),
  ('9af46911-45ca-5e81-a8a1-f8d863cef142', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-18', null, null, '通常 / 自由制作', '自由制作の説明すると、自分で作りたいように作れるのが楽しいのかとても顔を輝かせて興味があることを感じさせてくれました。まだ、ストーリー等の詳細は決まっていないものの、まずは主人公のキャラが大事だと、主人公作成に夢中になっていて、帽子を被ったアルくんを作成していました。色々とやりたいことがあって、集中して考えてはいましたが、まだ考えが収束していないようで、家で考えて作ったりしてみると言っていました。また、お菓子の掴み取りもしてもらったのですが、そのお菓子を教室に置き忘れて帰ってしまったようです。真幸くんのお菓子は、掴み取り段ボールの隣に付箋を付け加えて置いています。', null, '時間帯: その他
タイピング: 急いでミスタイプが多くなってしまうので、急ぐよりミスしないで安定したタイピングを心がけるようアドバイスした'),
  ('b0c68b02-d6d5-5158-b1b0-435b425ec0cd', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-18', null, null, '通常 / 毎パソ＆自由制作', '夏芽ちゃんは検定での取り組みから、テーマやビジュアルのイメージで発送を膨らませるのではなく、まず小技から気に入ったコードを選んでアレンジしてもらう方がやりやすそうだと思い、コードをバックパックに入れて取り出す方法を教えました。 ゲームの形式は弾幕ゲームが良いとのことだったので、気に入ったものを複数組み合わせてみるとゲームとしては面白いのではないかと提案をしました。 佑香ちゃん同様、手が止まっていたりどんな小技を使うか長いこと悩んでいる様子でしたが、最後の方は何か思いついたことがあったのか、鉛筆で用紙に何か記入しようとしている様子を見かけました。', null, '時間帯: その他
タイピング: 集中して取り組めていました。 タイピング検定ついて、夏芽ちゃんのお婆様は知らなかったようなので、本日の申し込みはありませんでした。ただ、タイピングのやる気自体はあるらしく、「夏芽ちゃんの親御さんと話し合い、もし申込むのであれば来週提出する」とのことでした。'),
  ('e45e1355-d85b-5380-9d12-9c1239a65167', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-18', '16:30:00', null, '通常 / 自由制作', 'いつも授業の最初の方に自由に制作したがるのもあり、隣の希空くんの画面を見ながらとても楽しそうにはしゃいで取り組んでいました。 バックパックの使い方は慣れているらしく、また本人の世界観のイメージがはっきりしているのもあり、私が見た時にはすでにスプライトと背景と小技のコードが入力された順調そうな状態でした。 本人の独特な世界観があるので具体的なストーリーまではわかりませんでしたが、矢印キーを動かして暗闇の中で恐竜を発見するという面白そうなゲームでした。 コード入力する際は途中まで一緒に取り組んでいたのですが、「（恐竜の色）が（矢印の色）に当たった時に背景の見た目が変わる」という見た目に関わるコード配置がうまくいっていないようでした。 最後の方は疲れてちょっと怠そうにしていたので、飴をあげて元気に帰ってもらいました。', null, 'タイピング: すぐ自由制作に取り組みたがったため無し'),
  ('d8cd94ec-e021-50a8-979c-549847057463', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-18', null, null, '通常 / 自由作成day', '最初は遊んでいて乗り気ではありませんでしたが、小技を見ていくうちにスクロールに興味を持ちました。自由時間にアルスタジオで遊んでいたシューティングゲームが縦スクロール式だったので、横スクロールの小技を改造してこのようなものを再現したいとのことでした。x座標とy座標を変えればいいことに気付くと、試行錯誤しながら改造を進めることができました。画面の端に背景の一部が残るのが気になったようで、端の座標に来たときにうまく消すこともできました。', null, '時間帯: その他
タイピング: 「ローマ字」をしばらく集中して練習し、お迎えのときに申し込みをしました。親御さんによると、最近はよく自宅のパソコンでタイピングの練習をしているとのことでした。'),
  ('dcff635c-de62-5faf-bf39-44cd0f81f038', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-18', null, null, '通常 / Excel検定準備', '来週のExcel検定の対策をしておきたいとのことだったので、自由製作はあとにして模擬問題を解きました。いくつかの問題を集中して進めることができました。', null, '時間帯: その他'),
  ('7efa5a3f-8829-59e3-aeaf-6448c8033ab2', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-18', '17:30:00', null, '通常 / 毎パソ＆アルスパーク', '慣れているのもあり、説明をした時の飲み込みが早かったです。 バックパックの使い方、さらにPC内にある画像をアルスパークに出す方法まで教えました。 ゲームの形式はどんなのが良いか最初に質問したところ、物語系が良いとのことだったので、次にテーマを選ばせてあげると本人の中でイメージが固まってきたらしく、独り言を言いながら黙々と制作に取り組んでいました。 タイムトラベルを演出するために画像効果渦巻きを選んでいて、アレンジ力があると感じました。次週も時間をかけて良い作品を作ってもらえたらと思います。', null, 'タイピング: ２段目の終わり手前まで打つことが出来ていて、個人的に早いなと感じました。新記録を狙っていたみたいで、終わるたびに毎回悔しそうに声を出していました。'),
  ('00dec9ce-c157-578f-8f34-7e317e352457', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-18', null, null, '通常 / 自由制作', '自由制作の説明をしている段階から、興味がある感じで目を輝かせていました。最初はアイデアがなかなか浮かばなかったようですが、世界地図の背景を見つけて、それをきっかけに、アイデアを色々話し合い、地図に隠した宝探しのゲームなんかはどう？という提案に納得して、大まかなゲームの流れを決めました（世界地図→家とかを配置（複数）→家の中にステージ移動して、お宝が置いてあり、それを集めるゲーム）。早速ゲーム作成を開始して、主人公キャラが上下左右に移動するところまでは作成。次週は、家のようなものの決定、配置、ステージ移動あたりの作成になるかと思います。レッスン中、ずっと集中していました。 親御さんからは、タイピングはどんな感じか、コンテストに参加すべきかという質問があり、今日のタイピングを見て、低学年とは信じられないくらいポジションをしっかり把握してタイピングされていて（速度が早いわけではないが）スゴい、ローマ字で受けても良いのではとお話をしました。結果、ローマ字で申し込みをするということで、今日申し込み用紙にその場でご記入、支払いもその場でしていただきました。 また、掴み取りもしてもらいました、うまい棒がどうしても欲しいということで、楽しんで挑戦して、うまい棒もゲットして嬉しそうでした。', null, '時間帯: その他
タイピング: しっかりとホームポジションを意識して丁寧にタイピングできていました。タイプ速度の話は置いといて、正直低学年でこんなしっかりできるとはびっくりしました。'),
  ('39a91799-0abb-5929-a1a5-485b76af30da', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-18', null, null, '通常 / 自由製作day', '自由製作を進めました。小技を見ていて面白いものがいくつかあったようでしたが、特に【小技】エネルギーをためてビームを巨大化する が好きだったようで採用することにしました。二人のキャラがビームを出し合って戦う構図に決め、小技のコードやデザインの作成を進めました。ボタンを押して場面転換するスキルも使えていました。キャラの変身や細かいゲーム設定については考えられていないと思うので次回以降決めることになりそうです。', null, '時間帯: その他
タイピング: ある程度ひらがなが打てるので「ローマ字」の練習に取り組みました。ただ、親御さんと話したところ今回の受検は見送るとのことでした。'),
  ('cf14ddcc-fd15-5d84-841f-438b58a329d4', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-18', null, null, '通常 / 自由製作day', '自由作成はどちらかというと楽しい気持ちで始め、小技を一通り見ていったのですがその時点でピンとくるものはなく、タイムトラベルのストーリーから作成していくことにしました。場面転換のときには、最初は背景番号で判定していたのですが、そのうちそれではうまくいかなかったのでメッセージを使うことを促しました。時間移動のシーンを作るときに横スクロールを使いたいと思ったようで、そこで使う小技が決まりました。スプライトの表示/非表示の設定を忘れがちですが理解してはいるので、忘れたときにすぐ直すことができています。', null, '時間帯: その他
タイピング: 「ローマ字」に取り組み、やっているうちに級が上がっていくのに喜んでいました。お迎えのとき申し込みをしました。'),
  ('35ee45f8-9513-5b07-b2fc-7feb223f2ecd', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-20', '16:30:00', null, '通常 / 自由制作', '前半は隣に岳くんがいたのか、タイピング後もテンションが上がってふざけてしまう頻度が多かったです。自由制作の説明は「今は話を聞いてほしい」と言いながら一旦PCを閉じて聞いてもらいました。また本人に操作させると寄り道や不慣れな動作に騒いでしまいそうだったので、私が操作しながら説明するか、指で画面をガイドするように努めました。 素材や小技を好きに選ばせて、気に入ったものをバックパックに入れていくよう案内したのですが、小技や既にある素材がイマイチだ！とのことで、モチベーション向上のためにアルスパーク内のゲームから選ばせるようにしました。 最終的に宇宙船のシューティングーゲームのボスの見た目が気に入ったみたいで、そのゲームを基盤にできる範囲でアレンジを加えることになりました。', null, 'タイピング: 最初は隣の岳くんとふざけてタイピングで遊んでいましたが、「ミスタイピングが少ない方が今日の一位だね！」と言うと競争心で2ミスまで抑えてタイピングに取り組んでくれました。'),
  ('41e6663c-dff3-5d92-9619-7653386f03ef', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-20', '16:30:00', null, '通常 / 自由製作（黄）', '前回の続きから取り組みました。ゆうさくくんの内容が気になるようで、進みは弱かったです。小技等を見て楽しく取り組めました。作りたい作品像がある程度あるようで（生き物を使ったプログラム）、スプライトを準備したり背景を変更したりしました。「どこかへ行く」のプログラムもよく覚えて使えていました。〇秒入りの使い分けについては補足しました。', null, 'タイピング: ミス率が少なく集中して取り組めました。'),
  ('b267de49-119a-5879-981a-4e66dde34cee', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-20', '17:30:00', null, '通常 / 自由製作（青）', '最初はあまりやりたくなさそうでしたが、話していくと作品の方向性やアイデアを出すことができました。バナナとおさるの探検（ゲーム）だそうです。小技は弾幕を使い、必要に応じてコードをうまく修正していました！またおさるは自分で描いたものを使いたかったようなので、iPadの8bitで作製しました。次回はもう少しプログラムを進められるといいかな？と思います。', null, 'タイピング: あまりやる気がなかったです。'),
  ('0af2c3e4-52cf-5fda-970e-d069b48fda33', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-20', '17:30:00', null, '通常 / 自由製作（青）', '風船が下から上へと移動していくゲームを作成したいようです。背景の縦スクロールを、小技の横スクロールを改造して作成していました。制御の部分はアドバイスしましたが、ほぼ自力でプログラムできました。またその後は、風船を用意したり、途中出現する雲のプログラムを考えていました。作品の完成が楽しみです。', null, 'タイピング: 思ったようにできず、今日は1~2回の挑戦で終わりました。'),
  ('555e773b-30f0-5b84-8b42-23e2932c0a53', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-20', '17:30:00', null, '振替 / 自由製作（青）', '集中して取り組めました。メッセージがきっかけの移動を次のステージに移るまで有効にするプログラムを一緒に考えました。「まで繰り返す」を使うことと、座標で限定することを提案しました。（端に触れたら～を自分で考えて試せていたので良かったです）座標は苦手そうだったので、図を作りながら説明しました。次回は次のステージを作成・タイムトラベルに移る（もう後半戦らしい）を作成するようです。', null, 'タイピング: 集中して取り組めていました。'),
  ('db2bdcac-779a-5760-b210-303081c2ff63', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-20', '17:30:00', null, '通常 / 自由制作', '先生方から説明を聞いた後、悩んで手が止まっていたので「電車をモチーフにしてみたらどうか」というアドバイスから一緒にアイデアを展開していきました。 参考程度に話した内容で、私が「列車といえばディズニーのテーマパークで時代を越える鉄道があるんだよ」と話してあげると、アイデアを気に入ったみたいでタイムトラベルをテーマに制作を進めてくれました。 「キャラクターが変化する」と言う条件に関して、「電車が新幹線に変わる」と言うアイデアで対応してくれました。 口下手な部分はありますが、今日は授業中はチラチラ振り返っては先生を探していて、 自分のやりたいことについていつもより多く話してくれたと思いました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('d464c0ba-3e45-5405-b1bf-3b1c655e3154', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-20', '17:30:00', null, '通常 / バグ潰し②＆自由制作', '今日は最初の30分でバグ潰しと掴み取り、後半は自由制作をしました。 バグ潰しの方は「スタンプを4回押す」と言う問題で、習っていなかったらしくしばらく詰まっていました。ヒントを3回ぐらい出してもピンと来ていなかったので、最終的にほぼ答えのようなヒントを与えて解いてもらいました。 掴み取りでは始める前に掴む練習をしていて、結果かなりの数のうまい棒を持ち帰ることに成功していました。 ただ、教室内が暖かいのか、後半の自由制作を始めるにあたって眠気で中々本腰を入れてスタートが出来ませんでした。 5分程度雑談をして顔を洗ってきてもらい、最後の10分でお題のテーマからどんなゲームが良いだろうか？と言うアイデアを、次週忘れないよう書いてメモしてもらうことにしました。', null, 'タイピング: 最初の方は上手くいってたみたいでしたが、 後半にかけてミスタイピングが多く、大体２行目で終わってしまい悔しそうな様子でした。'),
  ('e7e99ede-dbc3-5e65-8968-c22978188ddf', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-21', '16:30:00', null, '通常 / 自由製作day', '最初は何から始めればいいか分からずゲームを遊んでいたのですが、小技を一通り見て興味のあるものを選んでみようと促すとそうしてくれました。体力ゲージを使ってみたいと思ったそうで早速リミックスし、自分のゲームとして見た目などをアレンジし始めました。戦いの場面はできてきましたがまだストーリーなどは決まっていないので次回考えたいところです。', null, null),
  ('1482e200-481b-5061-91a9-93c9c607a264', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-21', '16:30:00', null, '通常 / 毎パソ＆自由制作', 'フリー素材のサイトで検索したドット絵の画像を、ダウンロードの方法が分からなかったのか、全て自分で描いて準備していたのにとても驚きました。 しかも完成させてしまう時間が早く、クオリティが高くて驚きでした。 テーマ→ビジュアル…と決めていったようなので、他の条件（背景を変える）を達成する方法を考えさせたところ、小技で横スクロールのコードがあったのでそれを採用することにしました。 また、探検がテーマだったので、どういったシチュエーションなら横スクロールを使えるだろうか？と一緒に考え、「モンスターに追いかけられて逃げるゲームなら使えそう」と言う結論に至りました。 最後の方、スクロール背景のスプライトにミスがあったようなので次週修正が必要だと思われます。', null, 'タイピング: 集中して取り組めていました。'),
  ('79fbc205-5e9e-51d1-a249-bc840400fb4a', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-21', '16:30:00', null, '通常 / 毎パソ＆自由制作', '前回の続きで様子を伺ったところ、珍しくテーマからビジュアルのイメージが浮かんだそうで、海の生物から逃げる弾幕ゲームを制作しようとしていました。 最初から漠然としたお題を与えるのではなく、具体的な選択肢からお題に関連させてイメージさせた方が上手くいくのかなと感じました。 その後は順調そうに黙々と集中して作業をしていて、タコがイカ墨を吐いて戦うという部分まで上手く制作出来ていました。', null, 'タイピング: 集中して取り組んでいたようです。'),
  ('8ecd9d06-a28e-533a-8fa8-f4a1306f140b', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-23', '16:30:00', null, '通常 / 自由製作', '前回のアイデアが気に食わなかったそうで、ブレストカードを使ってアイデアを作り出していました。とはいっても、カードを何度も何度も引き直して、なかなか定まらない感じでした。それで、りょうやくんが引いたカードを基に、作り始めましたが、素材が散らかるだけの表現にとどまっています。ペンと弾幕を使いたいが、組みあわせ方が上手くいっていないようです。もともと、創作意欲は低めに感じるので、そこをコツコツ積み上げられたら良いと思います。', '親御さんとタイピングの練習は絶対すると約束をしました。', 'タイピング: まったくやりませんでした'),
  ('77708a99-d139-5375-ba02-5763a457593c', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-23', '16:30:00', null, '通常 / 毎パソ＆自由制作', '前回素材と小技を選んでもらったので、どんなゲームなら面白そうか、ブレストカードを使ってアイデア出しをしてもらいました。 背景の暗闇に目を描いたら怖くて面白いんじゃないかと考えたようで、「それなら目が瞬きする動きになったら面白いのでは」と提案したところ、気に入ってくれ、丁寧にスプライトを描いていました。 また、一体のアヒルがカラフルに回転して背景が変わりタイムワープするという作品でしたが、もう一体いたアヒルに動きがなかったので「左から右へ横移動するようにしたら？」と言ったところ、意図を汲んですぐにコード作成が出来ていたのが良かったです。', null, 'タイピング: 集中して取り組めていました。'),
  ('a5f96c00-bb83-5ae2-bd48-fcfe0ffa4443', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-23', '16:30:00', null, '通常 / 自由製作', '最初は、こたろう君とともにブレストカードで遊んでいました。そこで得られたカードを基に、後半は、新たにスプライトをかなり集中的に作っていきました。デューダの鳥もどきの目新しい絵がかけていてなかなかに器用でした。ほかに、壁のカードも得られたので、作るものの道筋を立てていけたらいいと思います。', null, 'タイピング: すぐ制作に取り掛かりました。'),
  ('d81eb13d-ec7c-599a-b1b1-5b4d5d4b5423', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-23', '17:30:00', null, '通常 / 自由製作', '探検物で、穴に落ちて世界が変わっていく様子を作っていました。その際、落ちていくときに動きの表現がコスチュームも含め何回も試行錯誤していたので、回転して落ちいてくこともアドバイスとしてあげました。それに付随したストーリーも着実に作れていました。', null, 'タイピング: 30分も集中していてやっていました。段まであと少し'),
  ('4d1e4a29-e5bc-5590-b62c-037937f20947', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-23', '16:30:00', null, '通常 / 毎パソ＆自由制作', '集中力がなく、授業に入ってしばらくしてもゲームで遊ぼうとしていたので止めました。 自由制作は、小技として利用したゲームの見た目をアレンジして制作していました。 「何かセリフをキャラクターぽく変えてみたら？」と提案してみたのですが、サムライのセリフが思いつかなかったようで飽き始めてしまいました。 弾幕の動きを変える方法も他の先生にお願いしてやらせようとしましたが、ピンと来なかったみたいで、最終的に体験会に来ていた歳下の子に絡んでしまいました。 それすらも飽きてしまったよおうで、最後はずっとゲームをして過ごしていました。 1つ良かったのが、タイピングはやらないけど何故か前回教えたCtrl＋C、Ctrl＋Vが使いこなせるようになったことです…。本人曰く「基礎はやらないけど応用はできちゃう」とのことです。 今回の様子は現状で使えるプログラミング技術の手数が少ないのが原因だと思うので、 次月以降基礎を飽きずに定着させることを考える必要があるのかなと感じました。', null, 'タイピング: やりたくないとのこと'),
  ('7f67fe40-8084-52ba-b537-656f92295b45', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-23', '17:30:00', null, '通常 / 自由製作', 'スポットライトを使って、穴あき足場をみえなくさせている部分を作っていきました。全体の大体の構想は事細かに考え込んでいるので、その構想の多さに作品にめんどくさがらずに作っていけるか見ものです。着実にできていけそうです。', null, null),
  ('d91c9a28-cd24-5b41-9d6b-964fa96a2d67', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-23', '16:30:00', null, '通常 / 毎パソ＆自由制作', '前回は背景と世界観のイメージを考えてもらったので、前回素材がネットに無かったため制作途中したガンダムのドット絵を完成してもらうことにしました。 授業のほとんどの時間を制作に当てていて、完成した頃には「もう描きたくない…」と疲れ果てていました。 自分で描いたイラストがアルスパークで使えるようになったのをみて「あとは作るだけだ！」と意気込んでいました。', null, 'タイピング: ホームポジション（英文字） 集中して取り組めていました。'),
  ('70e521c3-9d29-5361-b074-325195af7bc0', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-23', '17:30:00', null, '通常 / 毎パソ＆アルスパーク', '前回素材をDLして作ってもらっていたのですが、データが正常に保存出来ておらず、前回の状況まで手動で直しました。 テーマはタイムスリップとのことだったので、テーマからストーリーを考えるためにブレストカードを使ってもらったりしました。 アニメーションみたいに「キャラクターが自動で動いてセリフを言う」といった制作をしようとしていました。 ただ、動かし方が画像を複製した後、角度や見た目を連続で変えるやり方だったので、 「それよりも角度や繰り返しを使った方がシンプルだよ！」と伝えると気づいて修正していました。 最終的に完成した動きはアニメのように滑らかに仕上がっていて、調整が上手だなと感じました。 セリフやストーリーもきちんとテーマやサムライの口調になっていて、細かい配慮が得意なのを感じました。', null, 'タイピング: タイピングが早く、文字入力で４行目までいけてました。 毎朝学校でタイピングをするから慣れているそうです。'),
  ('b3ca4e9e-ea03-519f-8fcc-7d21677b6495', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-23', '17:30:00', null, '通常 / 自由制作', '先に背景やスプライトを作り込んでから、やりたい動き（穴を掘る）をどうすればよいのか悩んでいました。 マイクラのように、地面をブロック形式にして掘る＝コスチュームを変えて表現する、というのを提案しましたが、ブロックを並べるのに困惑して手が止まっていたので、穴の代わりに黒丸をスタンプでおしていく表現を採用することにしました。 やりたいことと表現方法は決まったのですが、スプライトの階層などがなかなか思うようにいかずに時間切れになりました。 とりあえず表現方法が決まったので、少しすっきりしたようでした。', null, '盛り上がり: スタンプを本格的に使ったことがなかったそうで、面白がっていました。'),
  ('0e563b68-97f1-5aee-b751-fc845950d496', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-20', '17:30:00', null, '通常 / 自由制作', '久しぶりにScratchでの作成で、ロブロックスをやりたそうにしながらも、頑張って取り組んでいました。 ロブロックスは自分で公開したのを見てほしそうな様子でした。 コースカリキュラムのチラシも興味を持ってみてくれて、家で話してみると言っていました。', null, null),
  ('7d015a8b-d6df-55dc-981e-47cfb42ec8f0', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-16', '16:30:00', null, '振替 / エラーで学ぶ', '基本的に、自分で思いついたことをぱっとやってみたがります。 自分で思い付きがあるときは、ヒントやアドバイスは耳に入らないようで、邪魔しないでほしいといった感じになります。手が先に動くので、あれこれいじりまくって、結局うまくいかずに「わからない」となってしまうことも…。 アイディアをすぐに形にしたいタイプなので、このタイプの教材はあまり向いていないかもです…。', null, null),
  ('4e8df140-ed38-5138-ab4b-7d30410ce58b', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-24', '17:30:00', null, '通常 / エラー問題と自由制作', '今年初の授業のため、エラー問題４問解いて掴み取りに挑戦、色々取れて喜んでいました。自由制作では、タイムトラベルを選択、イチゴ（タイムトラベルの実？）を食べると過去or未来にタイムトラベルしてしまうというストーリーでアニメーションを作っていました。小技は、エネルギーを溜めてビームを放つときのスペースを押しているときの丸くぐにゃぐにゃになるの表現を、タイムトラベルするときの背景エフェクトとして使いたいようで、それのお試しドラフト版みたいなのを作成したところで時間となりました。このペースであれば、次回、もしくはあと２回程で問題なく完了できそうな雰囲気です。', null, 'タイピング: 集中していました'),
  ('499ce560-2241-503e-96b4-9f36314fba37', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-24', null, null, '振替 / 自由制作の続き', '前回の続きで、懐中電灯で暗闇を探す小技を使って、ゲームを仕上げました。内容は、ガチャガチャを３つ用意（ゲーム開始の度に場所が変わる）、３つのうちのどれかに猫が隠れていて、正解のガチャガチャをクリックすると、「にゃー」という音とともに猫が現れるというものです。大まかなヒントは上げましたが、細かいことを言わなくてもきちんと作り上げることができました。周りに、あさひ君ととうき君がいて、話に夢中になって若干うるさくなる時はありましたが、すぐに集中する時間に戻って１０分前に完了することができて自由時間としました。本人も母親にゲームを見せながら、スクリプトの作成が楽しかったと言っていましたのでよかったです。次回は、このゲームをこれで終わりとするか、間違ったガチャガチャをクリックしたときに、ゲームオーバーとか何かの処理を作るかを聞いてあげて、それ次第で次のやることを決めるで良いと思います。', null, '時間帯: その他'),
  ('f257ca2c-86f0-5858-a131-73309d6b4843', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-24', null, null, '通常 / 自由制作の続き', '前回の続きで弾幕の小技を使ったゲーム制作の続き。弾幕にぶつかったら過去にタイムトラベルする処理を作成（背景が変わる）。弾幕を避け切ったら未来にタイムトラベルしてゲーム終了となるものですが、未来にタイムトラベルの方はまだ完了していないようで、次回完了させるとのことなので、次回で自由制作は完了できそうな雰囲気です。集中して作業できていました。', null, '時間帯: その他
タイピング: 集中していました'),
  ('d14ac456-13bf-5862-9232-860b589155d2', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-24', null, null, '通常 / 自由制作の続き', '前回の続き。今日はスクリプトの作成まで辿り着きませんでしたが、自作の音声素材、スプライト素材の作成に集中して取り組んでいました。ゲームの基本の流れは、鼻だけの主人公「はなおとこ」が、顔（目・口）を探すゲーム。顔は複数画面上に落ちていて、間違った顔を選ぶと、オナラの音が出て、う○ちが出るとか、子供らしい？発想で、ゲームの流れ作成と素材作成を面白おかしく、だけども集中して進めていました。発想は面白いですが、顔のスプライトは、一つのスプライトに、複数の顔を書いている状態なので、顔をどうやって選択させるかが、これではちょっと難しいかも。それぞれの顔の色を変えて、色判定にするのか、顔ごとにスプライトを分けて作るとかしないと、顔選択の処理が実現難しそうなので、この点の処理の実装に関して、アドバイス＆サポートが必要と感じました。', null, '時間帯: その他'),
  ('ae9dfa9f-646f-52ac-b8f5-26b2195b1e05', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-24', null, null, '通常 / Excelの復習をする', 'Scratchの自由制作、Excel、プロゲートからやりたいものを選んでもらうと、Excelの復習がしたいと即答でした。 本人の話によると、 ●模擬問題のテキストは一通り全部やった。 ●ただ、毎回最初の方だけやって時間がなくなってしまうので、どの問題も「問題2」の最初あたりまでしかやっていない。（つまり、やれているのは表の書式設定のところまで） ●関数がわからないというわけではない（と本人が言いました）が、問題文を読んで、関数をどうやって表に活用するのかがわからない。 ●グラフはやっていないのでわからない。 とのことでした。 問題2から、少し一緒にやっていこうか、と声をかけると、嬉しそうにしてくれました。 一緒にやってみた感じでは… ●基本的な関数（合計、平均、最大、最小）の入れ方はわかっているが、関数をオートフィルでコピーではなく毎回入れている、加えて関数内の範囲設定にとまどって時間がかかっている。 ●「ROUND関数を使って達成率を求めなさい」のような問題文の意味がわかっていなかったようで、関数の中に数式を入れるやり方を一から教える必要があった。 ●表が画面におさまりきっていないときのドラッグがとにかく手間取っていた。試験の際は画面がさらに分割されてExcelシートの範囲が狭くなるため、かなり手間取ったと思われる。ShiftキーやCtrlキーを使った範囲指定のやり方を教えてたので、これに慣れてもらう必要有り。 といった感じでした。 問題集の練習問題①と②の、それぞれ「問題2」をやって、関数問題に少し慣れてもらいました。練習問題②の方は自力でできたので、少し自信がついた様子。 残り時間10分で、グラフにも挑戦してみたいと前向きになったので、練習問題①の方のグラフを一緒にやりました。 グラフは完全に一から教えました。 問題の内容がビジネスよりで理解しにくいのでは、というよりも、根本的に準備不足という印象でした。 テキスト通りの数式の入れ方や書式設定を毎回少し悩みながらやっているので、これでは時間が足りなくて当然というところです。テキストには載っていないExcelやWindowsの操作を素早くできないと、試験用の分割された小さな画面で時間内に作業を終えるのは相当難しいのではと思えました。 このあたりは最初に教えてあげて、それから練習を積んで操作に慣れてもらわないと厳しいと思います。', null, '時間帯: その他
タイピング: ローマ字、和文、英文と一通りチャレンジしていました。
盛り上がり: 2回目の問題2にチャレンジしたあたりから、問題文が理解できるようになったのか、目も覚めたようで集中力が増してきたようでした。 グラフも完成図の通りにできて達成感が味わえたようでした。'),
  ('8dedf470-3cef-5161-8edd-d4a1f9d66a17', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-25', '16:30:00', null, '通常 / 自由製作', '何かシューティングゲーム系なものを作ろうとはしていたが、具体的なものは決まっていなかったので、ブレストカードでアイデアを追加してくれました。そしたら、やる気側に傾いたので、効果的でした。ただ、クローンの使い方が「クローンされた時」を使うのを忘れていたり、スクロールの条件がいまいち組み合わなかったり、若干物忘れ感があります。でも、ビームの発射などもの組み立ても自走してできているので、できるところはできると思います。', null, 'タイピング: ジュ2級にもう少しが何度かありました'),
  ('3283dfcb-12af-52a5-a5f8-edc08490cbe1', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-25', null, null, '通常 / 自由制作', '前回に決まったものは、使う背景と、使う小技（マウスポインタに目玉が向く小技）のみ。どのようなストーリーでどのようなゲームを作るかは決まっておらず、なかなか思い浮かばないようだったのでアイデア出しのサポートをしました。自分の意見をあまり述べないものの、こちらのアドバイスを取り入れたり、自分のアイデアをこっそりと入れたりして、ある程度動くものを作成しました。ゲームの流れとしては、テーマは探検、主人公キャラ（宝石）が、地図のような背景の上を動き回れて、ある場所（家のような所）に行くと、家の中のような背景に切り替わるような処理まで作成しました。小技も取り入れて、目玉が常に主人公のいる場所を向くような処理を組み込んでいました。ただ、それらが、どんなストーリーで、探検というテーマに結びつけるかというものができておらず、その辺の説得力が何か欲しい所です。次回は、ストーリー作成、ゲームの終わり方が決められたら良いかなと思います。', null, '時間帯: その他
タイピング: 集中して取り組んでいました。'),
  ('0cde95a1-20f5-5e35-a015-a4ca86e6e77f', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-25', '16:30:00', null, '通常 / 自由製作', '今年初めてだったので、まずはアイデア探しから始めました。小技から、アイテムからちょくちょく見回って、考え込んでいました。その中で、10秒ぴったたりに押せば、竹が切れるゲームを作はじめました。10秒から誤差で演出が変わってくるそうです。今回は、構想と素材集めで終わったので次回から作成です。', null, 'タイピング: そこそこ頑張っていました'),
  ('172fd94d-fdc4-5507-90cc-5d961a6ca432', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-25', null, null, '通常 / 毎パソ&自由制作', '一通り素材の使い方やバックパックの使い方を教えた後、テーマをどうするか聞いてみたところ「探検でキャラが門を潜って移動したらキャラが変わるでもいい？」とアイデアを出してくれたので、横スクロールの小技が使えそうだと提案すると採用してくれました。 小技をいじりながら、同じ背景のステージの横スクロールではなくて背景の種類が変わる方が好みだと聞いたので、こちらで再現できそうな小技や方法を探しつつ、 本人には使いたい残りの背景を２枚探してもらいました。 背景探しは伝達ミスでちょっと時間がかかってしまいました。', null, '時間帯: その他
タイピング: ホームポジション（英文字） 最初は1行目まで行かない程度でしたが、「2行目まで行けたらすごいね！」と応援してあげると、集中して取り組んでくれて、最終的に2行目最後まで行けるようになりました。
備考: ★親御さんの方針で、今後は高い水準の目標を決めて授業に取り組んでほしいとのことだそうです。 ただ、本人の意欲自体はまだそこまで高く無いので、 教室での指導方針としてはタスク進度の優先を強調し過ぎず、 本人とよくコミュニケーションを取りながらサポートした方が良いと思います。'),
  ('2794948a-6465-596f-ad32-bde7ab3b1422', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-25', null, null, '通常 / 自由制作', 'エクセル検定終了したため、自由制作を進めましたが、スクラッチでの自由制作は気が進まない様子。JavaScriptでの自由制作をするとのことでそれを進めてもらいました。途中、少しエンジニア目線での小話を交えたりしてコミュニケーションを取りました。', null, '時間帯: その他
タイピング: タイピング検定受験を提案しましたが、その場では決めかねている様子。申し込み用紙を渡して、来週までに検討してくるとのこと。'),
  ('2c7a2270-b7f6-5d65-b72f-349636517b92', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-25', '17:30:00', null, '通常 / 自由製作', '未来のパートで卵を集めていくところがあったが、繰り返す回数とクローンされる回数が異なるバグが発生していました。なかなか解決できそうになかったので、過去パートの方を先に考えてもらいました。その際、ネットから画像を保存数方法教えて、餅つきを行うゲームを作りかけて、構想があって手が止まらなかったのがよかったです。 前述したバグはまだ解消できていないので、詳しく見直す必要があります。 追記：なぜかゆうと君のコードだと何秒待つのコード入れしまうクローンが生成されず、バグ解消できないので、別の案をすすめてみてください。べつのところで真似して作ると、バグにならずできるのですが、、', null, 'タイピング: 30分と長く練習しすぎて最後の方はミスが目立っていました。'),
  ('7fd1dd39-a640-5de0-9fdf-3f0d351d8b67', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-25', '16:30:00', null, '通常 / 毎パソ&自由制作', '前回小技やスプライトを入れて作ってくれたゲームから、更にスプライトをアレンジしてみようと提案しました。 アメコミが好きだと聞いたので、元々アルくんや他のキャラクターだったスプライトをアメコミキャラに変えてみたら伝えたところ、ipadで絵を描いてみることになりました。 他の生徒さんは16bitでの描画だったのですが、もっと滑らかな線に変更したいとのことでアイビスペイントを使ってもらいました。', null, 'タイピング: 英文でタイピングしていました。 記録だと4行目程度まで到達していて、検索している時もタイピングがかなり早くて驚きました。'),
  ('684efdd3-49e2-592f-bd37-998fcdfb3d13', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-25', null, null, '通常 / 自由制作', '他のみんなのような条件ありバージョンではなく、和真君は自由にオリジナルゲーム制作をすることを伝えると、すでに制作中のオリジナルゲームがあるようなので、それを始めてもらいました。射的ゲームを作成中で、鉄砲やバズーカ等で、動く標的を狙うゲームで、先生方に特にサポートを求めることもなく集中して作成していました。', null, '時間帯: その他
タイピング: 最初ローマ字で挑戦しているようでしたが、申し込み用紙を見ると、和文中学生のようだったので、そちらを練習してはと促して集中して取り組んでいました。'),
  ('c8440cc1-7c8f-5cf4-bfe5-b1f27e123989', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-25', '17:30:00', null, '通常 / 毎パソ&アルスパーク', '前回はタイムトラベルをテーマに小技とスプライトを選んでもらい、ある程度は出来上がっていました。 本人がやりたがっていたことが「キャラクターが左右に動いて時代が変わる時、背景（時代）が切り替わるごとに、背景（時代）とは違う別のスプライトによってカットインを入れたい」とのことだったので、問題解決のために他の先生方にサポートをしてもらいました。 クローンの小技を土台に差し替えながら、「メッセージを送る・受け取る・このスクリプトを止める」を駆使し、無事改善出来たようです。 その間は泰徳君が暇になってしまうので、アルスパーク内のキャラクターじゃなくて自分で描いてみよう！と提案すると熱心に取り組んでくれました。', null, 'タイピング: 記録を伸ばそうと熱心に取り組んでくれました'),
  ('23c8cd3e-cf0b-5d11-8fa4-545ba114173c', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-27', '16:30:00', null, '通常 / 自由製作', '初球のコスチューム変化ではなく、ステージ変化を使ってやりたいそうです。基本的に、やりたいことが決まっているので、それがどのコードが使えるか補助していく感じで進めたら、思うものがカタチにできていました。メッセージを使うやり取りでは、使えそうな存在は気づいていましたが、どのコードか忘れ飛んでいました。3つの背景を移動する仕組みはできましたが、そのあとは集中力が切れてアイデアが進まず勇作君と遊んでしまうなので場面がみられました。なので次回はブレストカードを使ってもよさそうです。 ただ、久しぶりに月曜に入った感じ、がくくんの他人任せ感が増えた気がします。意欲的にはわかんなくて嫌だだという感じはしないので、もうちょい質のあるレベルアップをしたいな', null, 'タイピング: 毎パソだとまだつまらなくて、まだ早かったそうです'),
  ('82858d04-8ac6-5515-b896-d7b718ac1aa3', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-27', '17:30:00', null, '通常 / 自由製作', '前回の構想が思い残っていたので、序盤から自ら進んでくれました。体力制だったり、自分で書いたコスチュームも取り入れていて、休まず進んでいてかなり良かったです。体力のところは、変数の切り替えがうまく機能していました。そして休憩後、ビームと球の相殺がうまく作れないとのことだったので、こちらから案は出しましたが、休憩気分が引きづっていてまた来週でした。最初から40分くらい続けられたことはなかなかにいいことだが、最後聞いといて作らんのかいとは感じました。', null, 'タイピング: 最初はさぼっていたが、作成途中の休憩でやったら、'),
  ('4d83d03f-bd98-5c8b-a465-39cab9550e03', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-27', '16:30:00', null, '通常 / 自由制作', '前回同様落ち着きがなく、元々がく君と隣だった席を離して授業をしました。 ただ、横について一緒にアレンジを考えようとしても自分が作っているシューティングゲームを何度も遊ぼうとしてしまい、あまり話をきいてくれそうにありませんでした。 一応シューティングゲームの実機のスプライトのエンジン部分のスプライトまでは完成させることが出来ました。 「レベルが変わったら出てくる敵が変わったらいいよね」という提案もしたのですが、 私の技術不足もあり、上手く再現してあげられず、授業後半はゲームで遊ばせるだけの状態を意図せず作ってしまいました。', '自由制作をこのまま続けるのか、新しいこと（基本操作コースⅠの続き）をやってみるのか聞いてから始めた方がいいと思います。', 'タイピング: お試しで毎パソをやらせてみたのですがつまらない！とのことでした'),
  ('eb77d6e5-7093-5622-a236-60d21db1ab44', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-27', '17:30:00', null, '通常 / 毎パソ&自由制作', '前回の続きを黙々と制作していました。 前回は新幹線などスプライトを熱心に用意していましたが、今回はタイムトラベルする 乗り物のセリフを熱心に考えてくれました。 内容を確認しましたが、過去に乗り物が行く時のセリフが前後関係のわかるストーリー仕立てになっており、秋くんの脳内イメージが全て完成したら面白そうな作品でした。', null, 'タイピング: 集中して取り組めていました。最後に「5級までいった」と自慢してくれました。'),
  ('04aa022f-e639-577f-9723-01e6cfbb9ab7', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-27', '17:30:00', null, '通常 / 自由製作', '今日から自由製作で、ひいろ君なんで着々と構想はできていました。武士を使った残像を使ったアクションを使っていました。まだ序盤ですが、いいものができそうです。', null, 'タイピング: ミスが多く1級まであと少し'),
  ('997481b5-10ed-531a-adf0-573b01e510de', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-27', '17:30:00', null, '通常 / 毎パソ&自由制作', '前回考えて書いてくれたアイデアを変えたい、とのことでイメージを口で伝えてもらいました。「探検で、食べ物やお宝をGETするゲームが良い」とのことだったので、 「小技：体力ゲージ（定義なし）」を提案したところ採用してくれました。 体力ゲージのゲームはキャラクター同士で弾を当ててHPを削るゲームだったのですが、これをアレンジした結果、食べ物をGETするとHPが増える/美味しくない食べ物をGETするとHPが減るというゲームになりました。 光梨ちゃんはイラストが得意とのことで、授業の最後までおにぎりのスプライトのアレンジに取り組んでいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('d2a9c835-81cb-563f-adb6-e3edf6e99fd4', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-28', '16:30:00', null, '通常 / 自由製作', '主人公スプライトの変更、背景スクロールの変更、恐竜のプログラム作成を行いました。背景スクロールをエンドレスに続けるため、メッセージを見直したり消える位置を調整したりしました。また恐竜の攻撃方法が思いつかなったようでこちらから提案したのですが、うまくプログラムを組めていました。私がしらない間にかなりスキルアップしている気がしてびっくりでした..', null, 'タイピング: 検定級は思ったように伸びなかったようですが、頑張って集中して取り組めていました。'),
  ('516f3636-90fb-5b8b-aa44-fe35aa554f9a', 'd63b574a-d732-55ef-81da-8e7b43904949', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-28', '16:30:00', null, '通常 / 基本操作コース02_04~06', '授業に来る前にひと悶着あったそうですが、来てから少し休憩すると自分で前回作成していたプログラムを開き、遊ぶことができていました。プログラムをするのは嫌いではないみたい。 今日は「〇歩進む」と「大きさを変更する」、「スペースキーで動かす」をやりました。大きさ、スペースキーについてはある程度理解できていそうです。まだ0より小さい数になじみがなさそうなので、フォローが必要そうです。', null, 'タイピング: ぴよコムでマウス練習をしました。もぐらたたきは最初全然スコアがでませんでしたが、徐々にうまくできました。またジグソーパズルは模様に苦戦していました。ピースが欠けていてびっくりしていました。'),
  ('c6b41d11-0b89-54a7-9ca9-08f3c18933ed', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-28', '16:30:00', null, '通常 / 自由製作day', '体力ゲージを使った自由製作を続けました。「主人公がいろいろな技でクマを攻撃する」「クマを倒すとステージが変わる」というようにイメージが固まってきたようで、前回書く気にならなかった自由製作プリントを書いてくれました。クマのHPゲージを作るのをめんどくさそうにしていましたが、主人公のそれを複製して変えるべきところだけ帰ればいいと伝えるとやっていました。主人公のHPゲージ攻撃技に回転を加えたり上の方から飛ばしてみたりとかっこいい技の出し方を追求していました。「もし体力<4000なら背景を変える」というようにステージ変更もできていました。', null, 'タイピング: 頑張っていました'),
  ('274e42b8-6e60-5cff-8c54-fb7e8cdf2c02', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-01-28', '16:30:00', null, '通常 / 自由製作day開始', '前回休みだったので今日から自由製作に取り組みました。小技やスプライトを色々見ていき、すらすらとアイデア出しをしていました。魔法のつえで敵を攻撃するゲームにするというイメージができたそうで、合う小技などを選び、そのあとで追加・変更をして試行錯誤していました。今日は計画を固める日にして製作自体はまだなので次回以降はどんどん作りそうです。', null, 'タイピング: 毎パソは受けないとのことで好きなタイピングをやりました'),
  ('7a2b2aff-9654-5af1-8166-5619f4f0f94e', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-24', null, null, '通常 / 自由製作', '前回作成したアニメーションの背景スライドがうまくいかず、作り直していました。スプライトのタイミングは良いのですが、背景スライドに間が出来ていしまうそうです。私と相談するよりもむしろ自分で考えている時間の方が長かったです。', null, '時間帯: その他
タイピング: 集中してとりくめました。かなり長い時間練習していましたが、 ミスが多く思うように結果が出ないことが多く、悔しそうでした。'),
  ('52007c27-c928-5e4a-b62d-f9c87f10e232', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-24', null, null, '通常 / 自由製作', '迷路を作成するそうです。今日はマイパソに集中してしまい、プログラムまではいきませんでした。定義はあんまり使いたくない様子でしたが、繰り返し処理がスムーズになると思うので、一度作ってから定義の使いどころを考えてみてもよいかな？と感じています。', null, '時間帯: その他
タイピング: 集中して取り組めていました。良い成績を狙いたいようです。 かなり長い時間やっていました。'),
  ('81ff3d4f-1ff7-5403-93f8-da0057521f4d', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-30', null, null, '通常 / 自由製作初回', 'テーマはタイムトラベルにしたそうです。お話の流れはイメージできたそうですが、背景選びでかなり苦戦していました。過去のイメージの背景はそこそこ良いのがあったそうですが、未来のイメージが難しいそうです。小技として残像をチョイスしていました。残像の数などをプログラムを変更して調整できていたので良かったです。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('da1b471d-bf5e-5b61-84bf-54e8856bb2dd', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-24', '17:30:00', null, '通常 / 自由製作', '前回から引き続き作成しました。複雑だったプログラムを簡単に整理しました。一方でアイデアに詰まっていたので、ブレストカードでけいとくんと一緒にアイデア出しをしました。ビビッと来たものがあったそうで、その後はスムーズに作成できていました。', null, 'タイピング: 集中して取り組めました。寿司うちの方がすきなようです...'),
  ('386b5153-7022-5980-994a-935dd440243d', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-24', '17:30:00', null, '通常 / 自由製作', '集中して取り組めました。ステージ・スプライトともにかっこよく仕上がっています。プログラムに移るように伝え、ジャンプや移動の部分を作成していました。大枠はよくできていたのですが（ではないも使えていた！）、空中浮遊してしまうときがあったので一緒にプログラムを確認して修正しました。旗もかっこよく作れていました！たのしそうで良かったです。', null, 'タイピング: こちらが声をかけるとしっかり取り組めました。'),
  ('d2f4b7a3-2c95-5605-9bb9-78cf1e051b8f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-24', '17:30:00', null, '通常 / 自由製作（新しく考え直した）', 'カウントゲームを作成するそうです。白い人と黒い人が家の中に移動するので、その数をカウントするそうです。テーマと方向性がずれないか若干心配ですが、頑張って対応するそうです。小技やスプライト準備、プログラムにも取り組めました。いつもよりは集中力に欠けているかなと思いましたが、ゆづきくんと相談しながら楽しく作成していました。', null, 'タイピング: 集中して取り組めました。'),
  ('e590e899-fa24-5f3b-a2cc-b8547529e966', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-24', '16:30:00', null, '通常 / 自由製作', '前回の作品ではなく、別の作品に取り組むことになりました。歴史シミュレーションゲームです。今まで作成したこともあったそうですが、かなり大変で諦めてしまう部分があったそうですが、今回挑戦してみるそうです。城の建設、キャラクターの作製をメインにしていました。', null, 'タイピング: 来て早々に練習していました。2級くらい取得していました。'),
  ('735bf6ef-384b-5177-b0ee-f86a604c2d1a', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-30', '16:30:00', null, '通常 / 自由製作続き', '前回より集中して取り組めました。勝ちの条件をプログラムしました。「10秒耐えたら」とのプログラムでしたが、変数などを使わずに「～秒待つ」を使ってうまくプログラムできました。またメッセージを勝ったときに送るようにしたのですが、そのことであるくんに話せたり、プログラムを止めたりできました。算数はまだ苦手なようですが、勉強したことがちょっとずる使えるようになってきたかな？と思います。', null, 'タイピング: かなりやりたくなさそうでしたが、なんとか取り組めました！'),
  ('66db33ec-43e2-504b-9d05-229e6ca19bf2', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-30', '16:30:00', null, '通常 / 自由製作続き', 'アヒルの回転を止め、穴が開いたようなプログラムを作製していました。自由製作はもう完成だったようなので、作品名と作品紹介を書いて公開していました。次に自分が作製していたオリジナル作品のプログラムをしていました。攻撃の弾が回るようなプログラムを作製したかったようなのですが、回転⁺動きに苦戦していました。一緒に考えましたが、コスチュームを変化させるような方法しかないとなりました。手間に感じてしまったようで、弾を回転させずそのまま作品を公開しました。作品説明も書けました。', null, 'タイピング: 集中して取り組めました。'),
  ('d5dd1de2-bb2d-5aac-92da-5d52629de889', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-30', '17:30:00', null, '通常 / 自由製作続き', 'かなりマイパソに集中していたので、自由製作の重点が軽かったです。全体のストーリーの振り返り、ステージのセット、小技の選択をしていました。懐中電灯のプログラムを使うそうです。もうすでにスプライトの移動のプログラムはできていましたが、次回以降は物語を進行させていきたいです。', null, 'タイピング: 頑張っていました。あと4点で初段だったそうです。しかし序盤の方でうまくいかないとモヤモヤしてなげてしまう癖があるので、途中からでも立て直せる気概があるといいかな？と思いました。'),
  ('40565eb5-fb31-5aad-b70a-16c784cb3ec7', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-01-30', '17:30:00', null, '通常 / 自由製作続き', '歩いた経路がうまくスタンプででなかったので、一緒にいろいろ検証しました。スライとを背景として指定していると、最背面設定をしていてもそれよりも後ろにスタンプが表示されてしまうそうです。解決できました。また障害物を隠しておいておくことになり、幽霊の効果を使うことを提案しました。大きさや配置を工夫してプログラムを作製できました。次回以降、他のステージや他の障害物をプログラムする予定です。', null, 'タイピング: 4級でした。集中して取り組めました。'),
  ('1ae1fe4e-ec1a-5712-9668-37422332c317', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-30', '16:30:00', null, '通常 / 毎パソ＆自由制作', '前回作ったアニメーションがほとんど完成しているとのことだったので、 公開にあたってタイトル・概要・バグ修正をすることになりました。 タイトルでは自分で案が思いつかず悩んでいましたが、とりあえず書いて思いつくアイデアを３案出して検討してみようと進めて最終的にタイトルを決めてくれました。 概要も同様に悩んでいましたが、「あらすじ風に書いてみたら？」と提案すると、普段読書をしている習慣があるのかすぐ理解して一文書いてくれました。 公開したては本人も完成したものだと思っていましたが、やはりバグが出てしまい、熱心に修正を頑張っていました。途中何かバグ修正でのコツを掴んだらしく、「わかったかも！」と嬉しそうに伝えてくれました。', null, 'タイピング: 集中して取り組めていました。'),
  ('383de64e-a42d-5d38-b416-26bae5378a0a', '57f45872-1f3e-5540-b676-bf9023444e39', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-01-30', '16:30:00', null, '通常 / 毎パソ＆自由制作', '前回までで小技やスプライトを決めて大体完成したとのことで、仕上げのスプライトの調整（追加）やバグ修正をしてもらいました。 小技の条件を使ったゲーム制作は出来ていましたが、肝心のテーマを忘れていたらしく、 とりあえず背景とタイトルを探検風味のあるものに変えてもらいました。 途中離席が少しありましたが、ちゃんと作業に戻って無事に完成させることができました。 ゲームの公開は恥ずかしいためしたくないとのことです。 完成後しばらく時間があったので、他の生徒さんのゲームでしばらく遊んでもらっていました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('362b6901-d5e7-5210-a721-cdbeb8bd43ed', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-31', '16:30:00', null, '振替 / 自由制作', '少し遅れて到着。自由制作から開始。先週作ったのは難しくなりそうだからだと、新たに最初から作り直したいとのことで、１から作り始めました。最初から、あまり悩むことなく、条件は探検を選択して「海の中で、ダイバーが宝探しをして、時間が経つと酸素ボンベの酸素がなくなって、ゲームオーバーになる」という構想を共有してくれました。アイデアはポンポン浮かんで表現してくれるタイプなので、自由制作向きだと思います。また、自分の作りたいものと言うこともあってか、最初から最後までずっと制作に集中していました。酸素の変数を作って、それが時間とともに減って、０になったら、ダイバーを目がバッテンマークのコスチュームに切り替えて海の底に沈んでいって、「あなたは○にました」のようなメッセージが出る。と言うようなことをしたいと言いつつ、時間になりました。', null, null),
  ('8a0ffa30-3768-5c37-9765-611e408cd5d8', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-31', '18:40:00', null, '通常 / 自由製作', '前回でほぼほぼ完成していたので、細かいところを直していきました。クリアまたはオーバーの背景が変わった後に、少し寂し気に感じいたので、何か注文しました。そしたら、辿り着いた先に未来や過去に文字が演出が2色カラーで鮮やかになっていました。美的センスもよくなっていました。', null, 'タイピング: 準1級でミスが少なけれ届いていました
盛り上がり: お母さんにも見せられて喜んでいました。'),
  ('46c3ec3a-c721-5a39-bc0f-ef2d85a5edb6', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-31', '16:30:00', null, '通常 / 自由製作', '前回作っていたものは休みのうちに完成させていて、その第2部のゲームが作成していました。1度完成したものをまずは見せてもらって、基本的な流れはしっかりしていましたが、完成度を上げる今後のためにスプライトの位置や向きについてアドバイスをしてあげました。 第2部のゲームでは、背景の切り替わりのタイミングがずれているところがあったので、順次処理の考え方を考えてもらいました。メッセージに順番が不都合があったことを自分で気づけていたので、今後は減らしていきたいです。 また、今まで音がついてなかったので、取り入れてみるかと鍵盤のコードで遊んでいたら、幼稚園や小学校で聞いた曲をその場で作曲していて、ほんと耳がいいんだなと感じました。隠れた才能が出てきました。', null, 'タイピング: 準2級が安定的に出ていました'),
  ('151e02fd-f2fb-508d-accc-352cec3591a9', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-31', '17:30:00', null, '通常 / 自由製作', 'アクション系をおつくりでしたが、基本は常に進んでいるように見えます。ただ、はる君の悪い癖で、わかないところがあれば、一度は修正を考えるが、わからなければ次に進んでしまうことが発生していました。今回では、色判定で、足場に登れるようにしていたが、背景にも足場と同じ色を使っていたので、勝手に上っていてしまう事案が発生しました。色判定仕掛けのジャンプは使いやすいですが、背景は変えたくないそうなので、ほかのジャンプを次回進めてほしいです。', null, 'タイピング: やる気はなさげでした'),
  ('81734afe-54ab-503f-92cf-46d987424d52', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-01-31', '18:40:00', null, '通常 / 自由製作', '前回、素材はある程度揃っていたので、始まりからコードを作っていきました。こちらがやることの起点を立てたら、自分でコードの何が必要か自分で持って苦しそうに持ってこれていました。ただ、明らかに能力が穴あきな感じあって、上下左右に動かすことに、こちらから補助を加える必要がありました。上下なのに、座標を変えずに良いとしてしまうなど、、、進んだことには良いですが、今回もあちこち気が散っていました。 次回は、パーツを集めていくことコードが作る予定ですが、本人は背景を変えてやろうとしているため、スプライトで別に作った方がわかりやすいことを伝えてから始める', null, 'タイピング: 真剣に取り組んでくれました。
盛り上がり: イラストの方もかなり興味がありげでした。'),
  ('5d753b52-9c64-5b76-bb1a-3766fcf15ef1', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-31', '17:30:00', null, '通常 / 自由制作の続き', '前回の続きからで、やるべきことがきちんとわかっているようで、特にこちらから何も促さなくても、黙々と作業を進めていました。途中、条件の一つである、ステージ変更に変数を使うことという部分がいまいちピンと来なかったようですが、説明をして理解したようで、それを取り入れていました。制作物の中身は、ゲームではなく、自動的に物語が展開していくアニメーションのようなもので、特にこれといったアドバイスも必要なく、思い通りのイメージの動きを作成していました。', null, 'タイピング: 何回も挑戦しては、失敗を悔しがっていました。良い結果を残したい気持ちが伝わってきました。'),
  ('d8a475f3-40a8-5a67-bc9b-a846ea402fc4', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-01-31', null, null, '振替 / 自由制作の続き', '前回である程度完成したとの事だが、ガチャガチャの表示位置を毎回変える処理を、向きを変える＋100進むみたいな力技でやっていたので、乱数を使うように提案。ヒントを与えながら自分の頭で考えて実現してもらいました。さらに、ガチャガチャを２回選んで猫ちゃんを見つけられなかったらゲームオーバーする処理（ゲームオーバーのスプライトが表示される）を作成しました。その際に、変数を使う事をアドバイスとして伝え、どうなったらゲームオーバーのスプライトを表示できるようになるべきかを、根気強くヒントを与えて、なんとかその処理を作成できました。あとは、ゲームクリア時、ゲームオーバー時に効果音を鳴らす処理を作成しているところで時間となりました。', null, '時間帯: その他'),
  ('e5ea917b-25c8-5c6c-999b-8c501fa7c6ea', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-01', '16:30:00', null, '通常 / 自由制作の続き', '前回の続き。家でも少し進めていたようで、制作の意欲は高いです。所々アドバイスを求められて回答していましたが、プロのプログラマーがどんなことやっているかみたいな事も興味津々だったので、そのような話も交えました。ゲームの内容としては、シューティングゲームなのですが、スタートボタンを押したら、オープニングが流れてゲームが始まるみたいな、なんらかのストーリーも考えているみたいで、今はオープニングの処理を作っているようでした。また、小技としては、横スクロールの小技を、縦スクロールとして使うように修正して使うとのことでした。レッスン時間中は、とてもやる気に溢れていて、家で作ったもの、これから実現したいことを熱心に語ってくれました。', null, null),
  ('6bf0c40d-3a1a-55ac-89d5-5f9e37437f7b', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-01', null, null, '通常 / 自由制作の続き', '前回の続き。主人公が宝石で、宝探しのようなものをする探検ものらしいのですが、本人が、やりたいこと、ゲームの全体像、どうすればゲームクリアになるのかについては、うーんと首を捻っていて、まだイメージできていないような雰囲気でした。背景が地図で、地図の中の家とかに触れると、画面が家の中に切り替わり、そこで何かをする。みたいな意図はわかったのですが、具体的に家で何をするのかが本人もまだ想像できていない雰囲気。また、ボタンの作成をしていましたが、ボタンをどのように使うかのイメージはできているが、そのイメージをうまく説明できないのか、語ってくれませんでした。全体的に、コミュニケーションがなかなかうまく取れず、ゆうかちゃんに対する先生の声かけ方、進め方が今のやり方で良いのか、考えてみて、先生間で共有した方が良いのかなと感じました。', null, '時間帯: その他
タイピング: 集中して取り組んでいました'),
  ('ee75dc8a-b434-5845-ba6d-d3355b295ab2', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-01', null, null, '通常 / 自由', '特にやることがないので、先週やっていたJavascriptは？といってみると、それも特にやる気がないようで、少しエンジニアとしての話をしたり、プログラミング業界の小話などをしてみました。そのうち、ITパスポートを受けるという話になり、本人が持っているその問題集をとくという事になり、何個かわからないことを私が教えたりしていました。来週もどうすれば良いですかときた時、何か考えておいた方が良いのかもしれません。', null, '時間帯: その他'),
  ('be12d24c-a0f8-5ea4-a6db-4150beb746df', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-01', null, null, '通常 / 自由製作day', '縦スクロールゲームの製作を続けました。「よけろフンツノゼミ」から着想を得つつ自分のデザインやアイデアを加えたようなゲームとして作っていました。新しいスプライトとして、迫ってくる敵や回復用のアイテムを追加していました。敵をビームで攻撃できるようにするのがオリジナルの要素で、ビームが敵に当たった時の演出を丁寧に作っていました。ただ、冒険ゲームとしてステージが変わっていく流れはまだイメージできていない様子だったので、話し合っていきたいところです。', null, '時間帯: その他
タイピング: 本番直前というのもあり、レッスン時間が始まるとすぐに切り替えてタイピングを頑張っていました。'),
  ('075b0173-f00b-5a0c-ab60-a6530b5b8fca', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-01', null, null, '通常 / 自由製作day', '過去の自由製作ではアイデアに詰まることも多かったですが、今回はゲーム全体のイメージがつかめていて、問いかけるとそれを話してくれました。敵の攻撃をよけつつ倒したらステージを移動してラスボスに挑むという、RPG風の冒険ゲームを作るとのことでした。弾幕系の小技を使っていましたが、自分で弾を撃つのではなく相手が自動的に打ってくるので、もとのコードをうまく変更して使えていました。', null, '時間帯: その他
タイピング: ミス0で終える回も多く、頑張れていました。'),
  ('d64100a5-e315-5128-9b67-75eb082aff8a', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-01', null, null, '通常 / 自由製作day', '冒険系のゲームの続きを作りました。アルスタジオから取ったゼルダのマップを使いましたが、森の部分を普通に通れてしまうのが気になったようで、森の部分だけを別のスプライトで用意して、森に入るとプレイヤーの姿が隠れるようにしていました。これを使って、森の中から宝探しをするゲームを作りたいというアイデアを思い浮かんでいました。選んだBGMもつけて、好みのゲームになってきたという様子でした。', null, '時間帯: その他
タイピング: 熱中して長いこと続けていました。一回ミスするとすぐにやり直そうとしていましたが、「ミス数が少ないのはいいことだけど本番のように一分間やりきるのも大事だよ」と話しました。'),
  ('032e65c5-6dfc-5bc2-86e2-24d773b9108c', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-01', null, null, '通常 / 自由製作day', 'タイムトラベルゲームの続きを製作しました。今日は未来ステージと過去ステージのうち、未来ステージの完成を目指しました。爆弾をよけつつ卵を取るゲームでは、ゲームバランスを考えて、テストプレイしつつ数値を調整していました。ステージ変更にはメッセージを使っていて、たくさんのメッセージを使わないといけないのが大変と言いつつもきちんと遷移できていました。ゲームが終わったら得点を言ったり、結果によってクリア/ゲームオーバーを分けたりでき、このステージは完成できたようでした。次回は、一回のプレイで未来と過去の両方に行けるようにしたいとのことでした。', null, '時間帯: その他
タイピング: 本番に向けて集中していました。'),
  ('7d7c3d9a-311b-5732-87dc-e9046f556550', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-01', null, null, '通常 / 毎パソ＆自由制作', '横スクロールについて教えようとしましたがやり方がわからず、他の講師側巻き込んで問題解決しようとしましたが、結局小技に解決方法があったため来週改めて解説して引用させるつもりです。今日は大きくは進んでいませんでしたが、メッセージを送る/受け取るの仕組みについて教えようとするとちゃんと聞いてついていこうとしてくれました。 自由制作以降にスキルアップの授業をしてプログラミングに対する理解が深まってわかることが多くなれば、もしかするとより意欲的になれるかもしれないと思いました。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('8c2930b8-3268-5653-b9c3-c336d7b920d1', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-01', null, null, '通常 / 自由制作', '前回の続き。画面上にある過去ボタン、未来ボタンに触れるとそれぞれ過去未来に画面遷移するものを作っていました。画面遷移の際に、幕が右から左に開いていくような演出していますが、そこで幕が開かないバグがあり、それを一緒に解決。次に、未来からさらに先の未来にも行けるようにしたいということで、過去１⇄過去２⇄現在⇄未来１⇄未来２を順番に行き来できるように作成中です。「時間」という変数を作り、その変数の値で、画面遷移を管理する仕組みを作っている途中で今日は終了してしまいました。小学生低学年ではちょっと難しいと思いつつも、本人も挑戦してみたいという事でこのような難しい処理に挑戦中です。次は、この変数を使って、きちんとそれぞれの背景遷移ができるようになるところまで行けたらと思います。なお、ゲームのクリアとしては、それぞれの、時代で、ミニゲームをクリアして、全てのミニゲームをクリアしたらゴールみたいなことを言っていました。全ての時代でのミニゲームを作るのはちょっと時間が足りないかもしれません。', null, '時間帯: その他
タイピング: ホームポジション基礎を集中して挑戦していました。たまにローマ字に挑戦してましたが、まだローマ字の挑戦は早いかなという感じです。'),
  ('018818bf-f7c7-5054-9f78-29d9b8c24737', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-01', '16:30:00', null, '通常 / 自由制作', '自由制作に夢中で取り組んでいました。前回作っていたゲームがボツになってしまったらしく、深海で冒険をする（酸素がなくなると死んでゲームオーバー）というゲームを熱心に作っていました。後ろの真幸くんから時々絡まれ、「それ塗りつぶしの方が早いんじゃないの？」と言われていましたが、「いや、手書きで塗りつぶした方が心がこもるから」とこだわりを見せていました。楽しそうに雑談して制作出来たと思います。', null, 'タイピング: なし'),
  ('56511ac5-6cd5-5830-946f-385579641fa6', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-01', '17:30:00', null, '通常 / 自由制作', '受験が終わったようなので春休みは何するの?といった雑談をしました。 自由制作では先に小技を決めてからイメージを決めると言って作業をしていました。 何十分かごとに進捗を確認していましたが、進捗がそこまで無いとのことで停滞していたように見えましたが、様子を見るとゲームコントロールコマンドをPCゲーム風に割り当てようと奮闘をしていました。 帰る前にイラストコースの話も少し出来ました。 絵を描くと言うよりは３D制作に興味があるようで、ゆき先生から人体がかけることは３D制作にも大きく繋がると言う提案を受けるとイラストコースを習うことに華香乗り気でした。 やるならWindowsのアイビスで自分のPCで作業できるようにしたい、とのこと。Adobeのツールをすべて使えるようなので、最終的にPhotoshopを使いこなせたら良いなと思います。', null, 'タイピング: なし'),
  ('f50f7205-c02f-5c0a-b4b9-eb2d3db02c1a', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-01', '17:30:00', null, '通常 / 毎パソ＆自由制作', '自分のミスで、前回描いてもらったイラストをインポートできずしばらく待たせてしまいました。時間がかかっている間、「何か他で追加出来そうな小技やアレンジを考えてみて！」と声をかけましたが、じっとイラストが入るのを待っていました。 今作っているゲームはスペースキーを長押しすると弾が大きく発射できると言うゲームで、この弾の撃ち合いをするスプライトがアルスパーク内の既存の素材でした。このスプライトをのあくんの好きなキャラにしてもらっています。 次回はキャラ差し替えからどう攻撃させたらそのキャラクターぽくなるだろうか、などノアくんの好みに寄せながら新しいことを提案できたら良いなと思います。', null, 'タイピング: 集中して取り組めていました。'),
  ('731097b7-587f-5e6e-bbe3-e06afbc8848d', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-03', '16:30:00', null, '通常 / 自由製作・他の人のゲームのプレイ', '背景変更とウサギのスタンプが消えるようにプログラムを作製しました。スタンプが消える仕組みはシンプルでしたが、全部自分で考えてプログラムを作製できました。背景変更はパンサーの動きとリンクしながらの作製だったのでちょっと難しそうでした。ただ背景変更が完成すると「おわり」のスプライトはスムーズに表示させることができました。パンサーの動きは端についたまま背景が変わっていたので修正が必要かな？と思いましたが、本人的には問題はなかったそうです。 ゆうさくくんの隣だと、パソコンの画面が見えてどうしても気が散ってしまうようなので、「顔をみて話せるよ～」といって授業中だけは向かい合って座ってもらった方がよさそうです。', null, 'タイピング: 集中して取り組めました。'),
  ('f4fa1ca4-f91c-5bb6-a713-6a4df5a799c2', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-03', '17:30:00', null, '通常 / 自由製作', 'タイムトラベルをする部分をうまく作製できました。メッセージと「ずっと、もし」を併用していたので、「～まで待つ」を使ってバグが少なくなるようなプログラムを紹介しました。全体的に進行が難しいプログラムだと思いますが、メッセージをうまく管理して頑張っていました。次回はクローンを動かす（岩をよけるゲームの作製？）ことが目的です。クローンを作ることはできていましたが、そこから先が自力で進めないようです。 集中力は低めでした。', null, 'タイピング: 集中して取り組めました。'),
  ('b994cb7c-2604-55cf-aa09-3e869ff9035f', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-03', '17:30:00', null, '通常 / 自由製作', '集中力は低めでした。 恐竜に当たったときに個体数をカウントするプログラムを作製しました。一つずつスプライトを作っているので、かなりプログラムに時間がかかりました。いくつかプログラム方法を一緒に考えましたが（考えられるのはえらい！）、「面倒くさそう」「大変そう」でなかなか作業に移れませんでした。その後、なんとかプログラムを進め、うまくカウントさせることはできました。次回は繰り返し恐竜が出て遊べるようにすること、レベルのプログラムを作製すること、レベル20でプログラムを終了するようにすること、それまでのタイムを計測することなどが目標のようです。', null, 'タイピング: 集中して取り組めました。'),
  ('9627981c-7173-5a52-b332-ac30058a9103', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-03', '17:30:00', null, '通常 / 自由制作', 'タイミングを合わせることによって刀の威力が増すゲージを熱心に作成していました。仕様は自分で考えたそうです。 電車ゲームでもよくオリジナルのパーツを作成しているので、良いのができたら「小技」としてアルスタジオで公開してみても面白いかもと声掛けをしたら、嬉しそうにしていました。 オリジナルのゲーム要素を入れることと、その完成度を上げること（ゲージの速さをレベル別にしたりできると面白いね、という話をしました）を目標に、今月中の完成を目指して頑張っていこう、ということでレッスンを終えました。', null, 'タイピング: 準1級あたりはとれそうな感じでした。本番は来週にしたいとのこと。
盛り上がり: 久しぶりの電車以外のScratch制作のせいか、とても熱心に取り組めていました。他のゲームで見た要素を自分で作成できるのが楽しそうでした。'),
  ('24f974eb-9859-5031-be7c-0902eb7bac1f', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-03', '17:30:00', null, '通常 / 毎パソ＆自由制作', '授業前半までは和先生から、流れてくる食べ物（スプライト）が上手く動作するようにコードの考え方を教えてもらったようです。 後半では、iPadを使って絵を描いてスプライトの見た目を変えてみてはどうかと提案をし、資料を見ながらテーマに沿った猫の探検家のキャラクターを描いてもらいました。 途中、猫の横顔時の耳の描き方について悩んでいたため遠近法の説明を交えてアドバイスをしてあげました。', null, 'タイピング: タイピングで「準1級までいった！」と報告してくれました。'),
  ('50fe121b-0046-5256-ba82-733676927469', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-03', '17:30:00', null, '通常 / 自由制作', '前半は、セリフをたくさん入れてストーリーを完成させていました。秋くんの好きな電車とタイムトラベル要素をうまく組み合わせて、自分なりの世界観を作ることができていました。 ただ、背景を変えるタイミングをすべて〇秒待つでやっていて、時間の数値の指定を試行錯誤していたため、メッセージの使い方を教えました。「メッセージを使ったことがあるか？」という問いかけには「知っている」と答えていましたが、いまいち使いどころが理解しきれていなかったようなので、背景を「終わり」に切り替えるタイミングを例に説明したところ、「便利！」となったようでした。 一通りのお話ができあがったので、音楽を入れることを勧めてみたところ、一生懸命に音楽を吟味して、エンディングの音楽を入れていました。 効果音として電車の音のフリー素材も使用し、とても満足そうにしていました。 https://soundeffect-lab.info/sound/machine/ 電車の効果音がそれなりの長さのため「終わるまで音を鳴らす」ブロックを使用する際、繰り返しの中に入れていたので電車の横移動がおかしくなりました。「終わるまで」を使うと、その次のブロック動作まで時間がかかること、動きのコードと音のコードを並列にすると並行してブロックを進められることを説明しました。', '電車の発車の音が長すぎて、次の場面に切り替わっても止まらない問題を直していく予定です。', 'タイピング: 丁寧に練習していました。
盛り上がり: とにかく楽しんで作成できているようです。ニコニコしながらできたこところを見せてくれるのを何度も繰り返していました。'),
  ('ca7ead68-cb9e-54a4-bc30-ec464fe75900', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-03', '16:30:00', null, '通常 / 自由制作', '授業スタートしてしばらく経った後も隣の岳くんとマイクラで盛り上がってしまい、自由制作に入ってもらうまで時間がかかっていました。最終的に「授業終わる15分前ならマイクラやってもいいよ」という提案を受け、気持ちを切り替えて作業してもらいました。 作業に入る前にまずアレンジの続きをするか、アレンジに飽きたならドリルなどスキルアップの作業をするかを選んでもらいました。 ドリルはつまらないのと、家でアレンジ案を1つ考えてきてくれたと言うのもあり、時間まで自由制作を一緒にしました。 アレンジ案としては、前回設定した実機のサイズだと弾幕に対して小さすぎて流石につまらないとのことでもう１サイズ程度大きくする と言う内容でした。 ビジュアルに注目してアレンジを考えてきてくれたので、ipadで自分の敵を描いてみたら？と提案すると「やるやる〜」と描いてくれました。 技術面ではPC操作として「マウスをドラッグして画像サイズを拡大・縮小する」方法を習得することが出来ました。 スプライトを変えただけで敵が自分の描いた絵になり、 アレンジとしては完成度が高く見えたようでかなり満足してアレンジ完了してもらいました。', null, 'タイピング: 授業が始まってタイピングに入ってくれるまで中々時間がかかりました。 プレイグラムの一番難易度が高いコースをプレイした後、「難しい！」と言って一回で終わってしまいました。'),
  ('325a3de1-7c2f-5cc3-b07a-79024d723bf2', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-04', '16:30:00', null, '通常 / 自由製作', 'クマの攻撃材料を新しく作成していました。スムーズに作成できていてびっくりしました。ランダムに鶏が出てくるようにアドバイスをしました！またHPバーが正常に動くように、仕組みを詳細に説明しつつ私の方で計算して修正しました。かなり面白いゲームになり、遊び方を詳細に説明して公開してくれました１ また他の人が作成したプログラムを遊んでいたのですが、リクエストするとリミックスしてアレンジ（回転）を加えてくれました。私が個人的に悩んでいたところだったので、大変助かりました！', null, 'タイピング: 集中して取り組めました。'),
  ('af3476eb-96f5-5fac-afe5-7f118df7ff8f', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-04', '16:30:00', null, '通常 / 自由製作・マイパソ本番', '集中して取り組めました。小技として残像を使っていました。アレンジするといろいろ表現ができることを伝えたのですが、ピクセル化を使ってたくさん探検家がいるように見せていました！すごい！またクリア画面を作成していたようなのですが、背景の切り替えとうまくマッチしていなかったので、スプライトととして設定してタイミングよく表示できるように提案しました。またクリア条件を作成しました。 今日で完成したので公開しました！操作説明も丁寧に書いてくれました！', null, 'タイピング: 集中して取り組めました。本番ですが、少し緊張（？）をしたようで、若干悔しそうでした。'),
  ('7a6baae6-b8d9-56c2-9625-9f7e6c2c3b6c', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2025-02-04', '16:30:00', null, '休み（未対象）', null, null, null),
  ('80a351ee-0b1e-5959-a032-299d8cc3eee8', 'd63b574a-d732-55ef-81da-8e7b43904949', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-04', '16:30:00', null, '通常 / 基本操作コースを進める', 'キャラクターを動かすのが楽しく、「～と言う」「どこかの場所へ行く」など色々な動きを習得していきました。また、前まで区別があやふやだった「スペースキーが押されたなら」「このスプライトが押されたなら」といった操作方法もだんだん認識できるようになってきました。ただx座標/y座標の概念は少し難しいようで、数字を変えると場所が変わるということだけなんとなく理解してもらいました。スプライトを増やすのが好きで、やりかけていたコード作成を忘れてしまうこともありましたが、声をかけると思い出して作っていました。お兄さんのそうすけくんの作ったゲームが気になったようで、最後はアルスタジオに公開されたそれを楽しんでいました。', null, 'タイピング: 前回達成できなかったパズル完成ができて嬉しそうでした。'),
  ('373961f5-81e5-5d73-a3d7-ef9bc5e1f1f4', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-04', '17:30:00', null, '通常 / 自由製作', 'ゲームはほぼできているとのことでしたが、もう一工夫を加えてもらいました。ゲームオーバーやクリアで終わったときの音を追加したり、1ダメージで即アウトではなくいくつかライフをつけたりしました。ライフは変数を使えば作れることはすぐにわかりました。ただ、BGMを鳴らすコードとライフを減らすコードを同じスクリプトに書いていたためうまく動きませんでした。そこで、「上から順番に動いていって同時にはできないから分けないといけないね」と順次処理の概念を理解してもらいました。また、「このスクリプトを止める」「すべてを止める」が混ざっていたことでゲームがきちんと終わらなかったので、それぞれの止まるブロックが何を止めるのかを整理しました。これで満足に完成したようなので説明を書いて公開してもらいました。', null, 'タイピング: 毎パソの本番を行いました。やる気はあるが早く終えてしまいたいとのことで練習も一回のみで本番に臨んでいました。
盛り上がり: 曜日変更により、金曜で仲良くなった友達と離れないといけないことは残念そうにしていましたが、受け入れてくれてはいるようです。'),
  ('ec616c1a-7226-51db-9940-25e5d0dddee8', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-30', '16:30:00', null, '通常 / 自由制作', '背景と弾の絵柄をそろえるなど、りょうやくんらしい、デザイン面での工夫が見られました。 小技も含め、参考にしたいコードを持ってきて自分でアレンジをしていました。コード全体を見て間違った部分をさがすなど、コードのブロックをかたまりとして見た時の判断力はあるのですが、一文字一文字を追うのが苦手なようで、変数名やスプライト名が元のままなためにうまく動かない、という箇所がいくつかありました。 スプライト名や変数名を、画像的に見ても判断できるように、文字数を変えてみるなどの工夫をしていくと良いかもしれません。', null, '盛り上がり: たまにこたろうくんのおしゃべりにのったりもしていましたが、制作自体は楽しんでできていて、集中して取り組むこともできていました。'),
  ('e93fc4a5-bd54-5351-8736-b2c7246453a6', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-30', '17:30:00', null, '通常 / 自由制作', '自分でスプライトを描いたせいか、こだわりを持って熱心に作成していました。 イベントのタイミングを秒数でカウントしようとしていたので、「背景が○○になったとき」や「〇キーが押されたとき」のイベントブロックを学習し、早速活用していました。 繰り返しの中のブロックの順番について、少しの違いで動きが大きく変わることを実感として学習できたと思います。', null, 'タイピング: よくがんばっていました
盛り上がり: 作成したキャラクターが動くのが楽しそうで、熱心に取り組めていました。'),
  ('b87e4e68-8eb4-508c-8c86-6c2120d9564c', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-01-30', '17:30:00', null, '通常 / 自由制作', '考えたストーリーをスプライトの効果を使ってどう表現するか、熱心に考えて作成していました。', null, '盛り上がり: やりたいことがあふれているようで、時間が足りないとぼやきながらも熱心に作成していました。'),
  ('66820a31-7c9a-5526-803a-fc4febeba385', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-06', '16:30:00', null, '通常 / 自由製作', '自由製作のプログラムには雲のスプライトを新しくしました！また作品説明も自分で加えて公開しました。他の人のプログラムもあそんだのですが、そうすけくんのプログラムが面白かったようです。攻撃方法がたくさんあるのが嬉しそうでした。 その後は集中力が減ってしまったのですが、その後はねずみチーズに取り組みました。ねずみの動きを作製しました。壁に触れたら戻るプログラムはできていませんが、矢印キーでシンプルに動かすプログラムは自力で完成できました！ただねずみチーズのプログラムは好きではないみたいなので、別のゲームが良いかもしれません。', null, 'タイピング: 取り組むように伝えたのですが、途中でリタイアしていました。'),
  ('929aa753-2b80-5642-8579-92f7e54c8da9', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-06', '16:30:00', null, '通常 / 基本操作コースキャッチ（配置と落下）', '前回公開した攻撃のプログラムで攻撃の弾が回転するようにプログラムを追加しました。理論は大まかに解説しました。嬉しそうで良かったです。 また基本操作コースキャッチに取り組んでいなかったので、やることになりました。コスチュームにこだわっていたので。スプライトや背景準備に少し時間がかかりました。またキャッチをするスプライトは矢印キーではなく、一定速度で動くようにしていました。', null, 'タイピング: 集中して取り組めました。'),
  ('9bd7bce0-7559-5d89-ae67-87da07462166', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-06', '16:30:00', null, '通常 / 毎パソ＆自由制作', '登場するキャラのセリフを考えたあと、虎太郎くんと一緒にボイスを入れてアレンジしてくれました。ボスから一定時間避けるゲームでしたが、ぱっと見だとどのくらいの時間を避けたらいいかわからなかったため「タイマーや変数を使って右上に表示したら？」と提案したところ、「時間がかかって面倒だから」と右上に「3分」とだけテキストで表記していました。 変数を習っているはずなのでもう少しコード的なアレンジが出来たらなと感じましたが、良治くんはスプライトの色の効果などビジュアル面でのアレンジに意欲的でした。 その後、虎太郎くんのゲームを交換してお互いにアレンジし合っていました。', null, 'タイピング: タイピングをしたのは1回きりでしたが早く出来なかったようでやや自信なさげでした'),
  ('f55b0a44-58fa-5051-bef1-08ed717399b6', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-06', '17:30:00', null, '通常 / 自由製作', '今までのプログラムの見直し、2ステージ目の追加、邪魔なスプライトのプログラムの変更、足跡削除をしました。今作製しているプログラムが相当気に入っているようで（とてもよいことなのですが）振り返りがどうしても多く、若干進みが遅いです。2ステージ目では邪魔ものスプライトが動くようにプログラムを作製しました。自力でうまくできました。足跡削除もしくみを提案すれば、自分でプログラムを作製できました。宝箱の表示非表示は少し詰まりましたが、一緒に考えつつトライしつつでうまくプログラムできました。', 'ステージ作成続きです（次のステージかな？）全部で4~5ステージ作りたいそうです。', 'タイピング: 集中して取り組めました。'),
  ('41439346-d34a-5706-be68-2c6e7af9723e', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-06', '17:30:00', null, '通常 / 自由製作', '穴へ落ちるプログラムがとてもよくできていました。お城へ入るプログラムの仕組みに悩んでいたので、幽霊の効果を活用してプログラムを作製することを提案しました。その後は全部自分で作製できていましたが、お城の外へ戻るプログラムに苦戦したようです。（幽霊効果を使ってプログラムを作ったものの、ごちゃごちゃしてうまくいかなかったようです）プログラム全体の構成を考えつつ、妥協したり要素を増やしたりしていくようです。', null, 'タイピング: 初段がとれず、悔しそうでした。'),
  ('f615efbd-67bf-56f0-81f2-44c0b42f6efb', '57f45872-1f3e-5540-b676-bf9023444e39', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-06', '16:30:00', null, '通常 / 毎パソ＆自由制作', 'アレンジでボイスを入れてみようと声を何パターンか音声を録音して楽しんでいました。 アレンジの完成後、良治くんとお互いのゲームを交換してアレンジするとのことで、 良治くんのゲームのセリフを変えたり、既存のスプライトを塗りつぶしたりしてアレンジしていました。 コードのアレンジというよりはビジュアル面でのアレンジがほとんどで、アレンジの発想の幅に制限があるように見えたので自由制作後は基礎の定着が再度必要なのかと感じました。', null, 'タイピング: 2回挑戦してくれました。２行目行かない程度までタイピングが出来たようです。'),
  ('609cbee5-7791-5f1a-bfba-00ac7aa8b26a', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-06', '17:30:00', null, '通常 / ジャンプゲームで新しいスキルを学ぶ', '自由制作は前回で完成したとのことだったので、基本操作コースをきちんと終わらせることの意義を説明した上で、ジャンプかキャッチを提示し、ジャンプゲームを選びました。 ジャンプするゲームはScratchでよく見るので、ぜひやってみたいと思っていたとのこと。 教室のジャンプゲームのカードがなかったため、完成形を見せてから作成させるパターンでやりました。 ジャンプの動きは、もとの動きを見ただけですぐに自力で作成できました。 障害物が左へ動くコードも、自分で「x座標が○○になるまで繰り返す」を使って作成していました。ただ、不等号の向きとx座標のプラスマイナスに少し混乱が見られ、実際に動くようになるまで3回くらいやり直しました。落ち着いて現在のスプライトの座標を確認させることで改善ができました。 障害物のコスチュームや登場するタイミング、速さなども、乱数を使ってアレンジができました。 ゲームオーバーの音楽が鳴りやむまで障害物が出続けてしまうのが気になったようで、メッセージを使って工夫しようと努力していました。 コードが少し複雑にはなるものの、晴君が興味を示したため、変数を使って繰り返しのコントロールをする例を試してみたところ、とても満足したようでした。', '音楽とのタイミングを変数を使った繰り返しで解決しましたが、「他のスクリプトをとめる」タイミングでも解決できることを少しだけ触れておいてもよいかもしれません。', 'タイピング: 準2級は毎回とれていました。2級を目指して来週がんばるそうです。
盛り上がり: 変数はあまり自信がないと言っていたので、スコアとしての使い方とフラグとしての使い方を学んだところ、自分がレベルアップした！という実感がわいたのか、とても満足そうでした。'),
  ('21c2f6d6-5d9d-5894-9266-7074f153816c', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-06', '17:30:00', null, '通常 / 毎パソ＆自由制作', '前回はスプライトと小技の弾幕を配置してもらったので、今回は 「これが対戦ゲームになるようにHPバーを作成しよう」という提案をしました。 はじめに、そもそもスプライト同士のサイズが大きすぎて弾幕にすぐ当たってしまいそうだったので、一旦スプライトのサイズを小さくしてもらうことにしました。 サイズ変更の方法に詳しくなかったようなので、マウスをドラッグしてスプライトを縮小させる方法を教えました。 加えて、HPバーが出てくる小技をバックパックから自分のゲームに入れてもらい、スプライトも入れ替えてもらいました。一気に説明してしまった感があったので、来週はまず目的を確認してから進めていけたらいいなと思います。', null, 'タイピング: 大文字表記のキーボードに変えて取り組んでもらいました。まだ慣れていない様子でした。'),
  ('ff7e9a2a-2fe8-5c10-9038-2b564f943d34', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-07', '16:30:00', null, '通常 / 自由制作（作り直し）', '前半は、この前の続きで自作の音楽作成からスタート。ただ、音楽に時間をかけすぎだったので、このペースだとゲーム作成が進まないよという事を伝えて、それもそうだなと、頭がゲーム作成に切り替わると、今度は、新しくゲームを作り直したいかなという話をしてきました。せっかく先週作っていたゲームがなくなってしまうので、引き止めましたが、どうしても新しいのを一から作りたいということで、一緒に考えました。 アルくん（の頭）が主人公で、スーパーマリオみたいな横スクロールゲームで、穴に落ちるとゲームオーバー、ゴールまで達するとゲームクリアするというテーマが探検のゲームを作り始めました（小技はスクロール）。私が、あれこれ言わずとも、サクサクと簡単にジャンプの処理を作ったり、背景スクロールの処理を作っていて、この辺の基本の動きはきちんと理解しているしすぐに作成できるのだなと感心させられました（小２という事もあり）。終わりの時間間際に、できないと悩んでいたのが、穴に落ちる処理。ジャンプ時に穴に落ちるのはできるようなのですが、ジャンプをしていない通常スクロール時に穴に落ちない（y座標が変わらない）とのことで、次はこの辺の処理を実現するためのサポートからと思います。また、背景や地面等はとりあえずサクッと適当に選びましたという感じなので、もっと良い感じに改善できたら良いかと思います。', null, 'タイピング: 集中していました。準２級相当が多かったです。あと数点で２級の時もありました'),
  ('a857ac0b-cb2b-5792-9c4b-6c7a2c3084e8', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-07', '18:40:00', null, '通常 / Excel検定のための学習', 'タイピング2部門の練習と本番をやってから、残り30分でExcelをがんばっていました。 試験の形式の慣れること、少しでも早く解いていくためのコツをつかみながら学習することを目標として、一緒に解いていきました。 連続データをオートフィルで入力すること、ShiftキーやCtrlキーを使った範囲選択、セルの書式設定メニューを出すショートカットは、今日の時点ではだいぶ慣れたようでした。これが使いこなせるようになると、問題を解くのがはやくなるというのは納得したようでした。 ちょうど大問1が終わったところで終了しました。', '大問2から続きの予定', 'タイピング: 本番を2つ終わらせました
盛り上がり: 疲れていたようではありましたが、それでも一生懸命に取り組めていました。 オートフィルの連続データ入力などは感心していました。'),
  ('5ae5e70e-ce3c-5afa-900b-56b53b0a70dd', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-07', '16:30:00', null, '通常 / 自由製作', 'アルネコをうまくアレンジして、各武将の衣装に変わり果てていました。シミュレーションゲームなので、出陣前に武器購入や兵力を高めていました。変数のお金の仕組みがうまく活用できていました。武将の名前をリスト表示させる場面があったが、リストがずっと追加されているだけで、使い道がうまくいっていませんでした。なので、リストの使い方を軽く説明してあげました。兵攻撃の場面で、動かし方に何度もやり直していたので、家でもやって攻勢を考えてくるそうです。', null, 'タイピング: 授業前に早めに終わらせました'),
  ('36fc40eb-626e-5d44-8763-b1281e6c140a', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-07', '17:30:00', null, '通常 / 自由製作', '今回も、内容変えるとなり、トンボとバイクを合わせたものを作りましたが、なかなか小技まで含めたものになると、その先が進みません。そこで、ブレストカードも活用してみるも、なかなか手が進むようになりませんでした。いつも自発のくそゲームを何個も作り出せているが、今回のような少し高めのスキル（小技）を組合す条件になると、考えが狭まっている傾向があります。今日作ったものも、雑にまとめようとしているので、早めに切り上げた方がいいかも', null, 'タイピング: 今日はなかなか集中力が続かないので、本番は来週'),
  ('c56d2fab-acc3-5c7d-a66e-cf70b345ce39', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-07', '17:30:00', null, '通常 / 自由制作（続き）', 'タイムトラベルをテーマとしたアニメーションの続き。どのようにストーリーを進めて終わりとするかを考えてもらい、そのイメージを共有しました。簡単なあらすじとしては、いちご（ヘーゲル）を食べることでタイムスリップしてしまい、はるか未来の魔法村に来てしまい、魔法使いに、現代に戻る魔法で現代に戻してもらうというもの。魔法の発動のためにあるアイテム（ゾンビの頭）をゲットする必要があるというもの。セリフを話して、簡単な動きを表現するというものなので、スクリプト的にはシンプルだとは思うのだが、途中、タイムスリップ時のエフェクトの使い方（渦巻き効果）とかは素晴らしいと思いました。今回は、特にスクリプトのアドバイスをすることはなくて、どちらかというと、ストーリーのアイデア出しとかが中心となりました。１時間ずっと集中していました。次回にやるべきことは、自由制作の紙に書いたので、それを参照にして、次回開始したら良いと思います。', null, 'タイピング: 集中していました'),
  ('3c6ccba4-d05f-5b35-ba3e-586b38ca7581', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-07', '17:30:00', null, '通常 / 自由製作', '前回背景色でジャンプが勝手にしてしまうバグがありましたが、はる君は必死に同系色でチャレンジしていましたが、こちらが全く違う色になるように説得して何とか修正できました。着々と新たなステージを作れています。そのちょうしで、数回あれば終わるような気がします。', null, 'タイピング: 練習量が毎回少なめです'),
  ('ad59431c-d86d-55ef-b1a6-3aa04f0f88fa', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-07', '18:40:00', null, '通常 / 自由製作', '今回は前回の続きを作っていこうと思ったが、ただはなおとこを動かす時間が多く、ただ何しようかのアプローチだと全く作業に進みませんでした。そこで、はなおとこのコンセプトについてもう一度教えてもらう、旅ををしていろんなのと出会いがあるということが引き出せたので。出会った者を作っていきました。それぞれ個性的な特徴を持ったものが出来上がり、作っている最中もあさひくんはかなり楽しそうでした。3体は完成できたので、そのあとの終わりをつけてあげれば、形として完成に近づくと思います。', null, 'タイピング: 練習は5分バージョンをうまく活用していました。'),
  ('1d29ab62-73b7-514d-a9ff-840149f04979', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-07', null, null, '通常 / 自由制作（続き）', null, null, '時間帯: その他
タイピング: 集中して挑戦していました。'),
  ('3aa29a2f-06ff-5e0d-bbdb-e9514519f258', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-08', null, null, '通常 / 毎パソ＆自由制作', '時間が過ぎてもしばらくタイピングにハマっており、 様子を見ながら声を掛けてもしばらく反応がありませんでしたが、対面できちんとお願いしたところ、ちゃんと自由制作に戻ってくれました。 縦スクロールのシューティングゲームを制作していて、実機でビームも撃てるようにコードを作成していました。 私が最初に確認した時には敵が四隅になっていたので修正してもらいました。 クローンの出没もランダムに設定したようです。 攻略法として、壁際にずっといると簡単に避けれてしまうとのことだったので、 四隅に触れたらHPが減る方がいいのではないか…など二人で話し合いもできました。', null, '時間帯: その他
タイピング: 自由制作に取り掛かる作業の時間になってもしばらくタイピングに取り掛かっていました。'),
  ('311d0774-fd26-52a6-8873-5d2df5871b83', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-08', null, null, '通常 / 自由製作', '背景スプライトのごちゃごちゃしていたので、まずはこの作品はどうゆう流れのコンセプトになるか聞きました。そしたら、背景が変わるごとにコスチューム変化も行いたいそうでした。そのため、まずはメッセージを使う背景スクロールを教えていきました。そのあと、どのときに、どのメッセージで送ったらコス変化をするか自力で考えてもらってメッセージの仕組みを理解することができました。また、カラスも横に流れるように動くようにしたかったので、背景スクロールのコードから誘導するように作らせたら、良くなっていました。この際、スプライトによって恥に行ける座標限界が異なるので、そこの修正は補助してあげました。次回は、コスチューム変化するタイミングは少しずれてしまっているので、その直しと自分で動けるコードを学びながら作れて行けれればいいと思います。', null, '時間帯: その他
タイピング: ミスが少なくなっています。'),
  ('1c4dfc04-8a83-51f0-b427-3dded3faee75', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-08', '17:30:00', null, '通常 / 毎パソ＆自由制作', '前回までは使用するスプライト、どんなゲームにするのかイメージ、何のキーで動かすのかを決めてもらいました。 実機で攻撃するタイプのゲームは時間がかかるとのことで、一定時間ボスの弾幕を避けたら次のボスへ行くといった内容にするそうです。 今日進んだところとしては、 ・弾幕を作ったが上手く機能しないところがあり、その部分の確認が出来た ・弾幕に当たった時に体力が減る定義を作った とのことです。 また次回は ・弾幕の修正 ・回復用のアイテムを設置する とのことでした。', null, 'タイピング: 集中して取り組んでいました。'),
  ('0a5d7e72-c2fd-562c-9571-aff26fc15a36', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-08', null, null, '通常 / 自由製作', '時間ぴったりに止めるゲームなので、今回は小技にもあったクロックを導入しました。元ある素材から自分が使いたいところだけ、選び出せていたので、良かったです。その際、時間の桁数をどう制御すればいいかは対処してあげました。それ以外にも、斬首のイラストなども追加されてたので、次回は肝心の時間ごとの演出を作っていくべきです。', null, '時間帯: その他'),
  ('a3fecb85-5029-5c0d-998f-cb593601880c', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-08', '17:30:00', null, '通常 / 毎パソ＆自由制作', '本日も黙々と作業をしていました。 今日進んだところとしては、 ・景品にHPを追加した ・発車した時に銃弾が表示されるようにした とのことです。 次回やりたいところとして、 ・景品が消えてしまったので修正 ・スタート画面を設定する とのことでした。', null, 'タイピング: 集中して取り組んでいました。'),
  ('a9803aa3-defb-5310-9002-b67e3c211f5e', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-08', null, null, '通常 / 自由製作', 'ゲームはだいたいできているとのことですがブラッシュアップしました。ガチャを引いて猫を出すゲームですが、キャラクターの変身もかねて、出てきたときの演出を追加しました。閉じたカプセルが出てきて、それが開くと同時にネコを出すことができました。このとき、スプライトの表示やコスチュームの変更の順番を考えないとおかしくなるので時系列で考えてもらいました。ゲーム終了後に中心に移動することで結果を見られるのですが、「初めての人に分かりやすくするにはどうすればいいかな？」と問いかけると矢印を追加していました。', null, '時間帯: その他'),
  ('3239e6a1-14da-5d84-8d11-90847c4b24ad', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-08', null, null, '通常 / 自由製作', '前回で自由製作が満足いく出来になり、条件も満たしたので次の自由作品に取り掛かりました。人がボタンを押してクワガタにエサをあげるゲームで、一瞬で構想を考えて制作を始めていました。ボタンを押したことの判定では、「(スプライト)に触れたら」でうまく反応せず、臨機応変に色での判定を使っていました。エサを大量に出すシーンでは、クローンを使えばいいことをすぐにわかっていました。本体の動きとクローンの動きを混同するなどしてバグになり、少しイライラしてしまったようですが、ヒントを出すときちんと考えて修正できました。', null, '時間帯: その他'),
  ('1678f363-3e48-5051-b948-e813d538a7c3', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-08', '16:30:00', null, '通常 / 自由製作', 'まずは素材だけが散らかり具合になっていたので、どこを目指すか聞きました。その結果、 スタート画面からボタンを押し、バトルスタート 自分、敵(バットマン)はビームの打ち合いができる そのHPの変化はHPバーの小技を使って表したい どちらかがHP0になったら終わり のコンセプトが思いついていました。そのため、今回はHPバーを導入していきました。ペンツールのコードだったので、なじみ深く扱うことができました。そして、もとからあったバットマンのビームを右向きから左向きへ変えていく作業をしました。その修正作業で、向きをー90に変える、「座標< OO」のところを修正すればいいと自力で見つけ出せていました。でもそこからうまくいっていませんでした。その難点として、座標のマイナスの感覚がかなり鈍いです。左に行くと座標は小さくなることは理解できてますが、マイナスに変化するところがあいまいな感じです。こちら側からマイナスの言葉を使ってやっとでした。そこはこれからも重点的に見るべきです。 次回は、敵、自分のHPバーやビームが不足しているのでその追加です。', null, 'タイピング: 英文をしっかり取り組んでいました'),
  ('b841dc74-0180-5944-9c5e-37858b2a7c2b', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-08', null, null, '通常 / 自由製作', '最初のマップで、主人公より手前に表示されてほしい森が奥に表示されていたので、最前面/最背面について伝えました。その概念はすぐ理解したようでした。そのマップは完成したので、そこを抜けたら家や他のステージに行くという部分を作りました。「背景が～になったとき」を使ってきちんとスプライトの表示などを管理できていました。ただ、最後のほうでスプライトの大きさについて「～ずつ変える」と「～にする」を混同していたので次回修正することになりそうです。', null, '時間帯: その他
タイピング: 今回も集中していました'),
  ('51de531a-9c2e-5ca6-b418-21f72c466b51', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-08', null, null, '通常 / 自由製作', '未来/過去へのタイムスリップゲームで、未来での卵取りゲームはほぼ完成していましたが、飛んでくる爆弾を上下に動かしてみるなど工夫を加えていました。次に過去での餅つきゲームの製作に入りました。画像の保存にはまだ慣れないようですが頑張ってフリー素材を取ってきました。「臼が特定の色になったタイミングで衝く」という斬新なアイデアを思いついて作っていました。杵の動かしかたに困っていましたが、どこを中心に回転させればいいのかを試行錯誤して考えてくれました。', null, '時間帯: その他
タイピング: 今週か来週のうち好きなほうで受けられると伝えると今週がいいとのことだったので本番に取り組みました。そこそこできたという様子でした。'),
  ('3ead3f92-3c19-570e-9e18-50ff8bb1375f', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-08', '17:30:00', null, '通常 / 自由製作', '前回までで、過去と未来へ行く分岐の仕組みはほぼ完成していたので、今回は、行った先のミニゲームを考えていきました。先生にアイデアを募ら羅れたので、ブレストカードを渡してあげました。普段他の子なら、カードに遊んでアイデアが反映されずになることが多いが、やすのりくんならきれいにはアイデアを集めることができました。過去の餅つきでは、元の太鼓のイラストをリメイクして臼っぽく書き換えられていました。ミニゲームを始めるボタンの挙動が最後まで気に入ってなかったポカったので見てあげてください。次回は、そのミニゲームのコードを作れそうです。', null, 'タイピング: 今日は調子がよくないみたい'),
  ('f5da2090-76d5-543d-958d-62b25b3aa87e', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-08', null, null, '通常 / 自由製作', '戦いのゲームなので主人公と敵のHPを作成しました。HPを減らす時に一度でたくさん減ってしまったので原因を考えてもらいました。過去の経験から、「もし～触れたなら」が一瞬で何回も反応しているとわかり、「～秒待つ」を追加して解決することができました。今日は第一の敵を倒してラスボスに移行するところまででき、ゲーム全体のイメージを持ちながら製作を進められているようです。', null, '時間帯: その他
タイピング: 集中していました'),
  ('2b03d747-024a-51ae-a2ce-f72b8cf54161', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-08', '17:30:00', null, '通常 / 毎パソ＆自由制作', '振替分と２コマ連続で授業が入っていましたが、1コマ目はほとんどロブロックスで遊んで過ごしていました。 ２コマ目に入った際、さすがに自由制作をやろうよと誘ったところ、折れて制作してくれました。 本人の独り言がずっと多かったので、しばらく雑談をしながら一緒に作っていきました。 途中、弾幕ゲームのクローンの仕組みで「弾幕を売っているスプライトがブレブレになってしまう」ことについて、理解した！と言いながら解説をしてくれました。 「スプライトが回転しながらクローンを生み出してしまうから、点対象のスプライトなら回転せず静止して弾幕を打つだろう」という高度な解釈をしてゲーム制作に取り組んでいました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('013880a3-aecd-5680-a4f7-c10d2c676162', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-02-10', '16:30:00', null, '通常 / 自由制作DAY、ピンポンゲーム', '前回まで作成していた自由制作DAYのゲームを完成させていきました。ストーリー形式の作品で、を変更していくことで場所移動を行っているような表現を取り入れていました。小技内容としては、ウサギを回転させることで花びらのような柄にすることで画面を華やかにしていました。完成後は、ピンポンゲームの作成を復習も兼ねて行っていきました。以前に作成した内容でしたが、あまり定着させることができていなかったようでボールの跳ね返りや、板の動きについてかなり悩んでいました。そのため、次回の授業で復習をしっかりと終えて基礎部分について定着させていきたいです。', null, null),
  ('cbdb39d3-6c25-5758-8a2c-f41371de32d1', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-10', '16:30:00', null, '通常 / 毎パソ＆自由制作', '今回でゲームを完成させることが出来ました。内容は「探検家が探検で疲れたからご飯を食べるゲーム」とのことです。 アレンジとしては、横向きの猫やおにぎり、腐ったおにぎりなどのスプライトの描画に集中して頑張っていました。猫がジャンプする時に効果音をつけてみては？と提案しましたが、描くのに満足したのかそこまでのアレンジには至らなかったようです。', null, 'タイピング: 集中して取り組んでいました。'),
  ('0ee90b6a-34c7-5911-8d39-00d8bb17278b', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-02-10', '17:30:00', null, '振替 / 自由制作DAY', '前回からの続きを作成していきました。内容はストーリー形式で、自動車が衝突事故を起こしたところから始まっているようで、ホワイトアウトした後に別画面へと移動している部分まで作成していきました。本人曰く進捗が30％ほどということで、内容としてはかなり大きなものを想定しているため、来週までの完成は難しいと思います。オンライン授業をメインで、Scratchについては息抜きも兼ねて行っている節があるため、このままゆっくりと完成させていきたい様子でした。', null, null),
  ('c818e6d0-9062-53e9-94a0-3e89bfb0de4a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-02-10', '17:30:00', null, '通常 / 自由制作DAY', '初めに、毎パソの本番に向けて何度も練習をして指を慣らしていきました。１回きりの挑戦ということもあり、自身の納得のいく結果が出るまで続けて熱心に取り組んでいました。本番では、練習していた通りの成果を出すことができたようで、終了後には達成感を感じている様子でした。自由制作DAYに関しては、RPG風のバトルゲームを作成しているようで、ゲージを指定された空間内で止めて攻撃をしていく反射神経やタイミングが求められる内容となっていました。コードに関しても、指定されている条件だけでなく複雑な内容を行っていき、ゲームとしてより面白い内容にしようと努力していました。完成については、あまり目処が立っていないようなので、自身の納得のいくものが出来上がるまで作成を続けていきたい様子でした。', null, 'タイピング: 今日本番のため、特に集中して何度も練習を重ねていました。'),
  ('29e4fe72-f47e-5f8c-bb32-2d9a90d6ad00', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-10', '17:30:00', null, '通常 / 毎パソ＆自由制作', '前回までアニメーションの細かい調節をしてくれたようで、自由制作に入ってからしばらくしてオープニングとエンディングのサムネイル作りに熱心に取り組んでいました。 ストーリーの中に電車の見た目が変化するシーンがあり、アドバイスとして色の効果とその効果をどうアニメーションへ組み込めるかを伝えてあげました。しばらく様々な効果で遊んでもらい、最終的にカラフルに変色してからフォルムチェンジするといった形に改善することが出来ました。 ただ、メッセージを送る/受け取るはコードに組み込まれていたので出来ていたようですが、 いつもアニメーション系の作品ばかり作りがちなようで、色や動作を繰り返すことでどう動くのかイメージがまだ拙いように感じました。', null, 'タイピング: 直前まで熱心にローマ字で練習してくれていたのですが、申し込んでいたのがホームポジション基礎のようで、そこだけ十分な準備が不足したまま大会に参加してもらうことになってしまいました。それだけでは勿体ないと感じたので大会参加後も一度だけローマ字で本番さながらタイピングをして測ってもらいました。 緊張したようでミスは普段より多くなってしまいましたが、次回の大会でもっと良い結果が出せたらと思います。'),
  ('46eb83bb-c576-579e-840d-59c60422aab1', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-10', '16:30:00', null, '通常 / 自由製作紹介/ピンポンゲームの再確認', '前回で作品が完成したのことでしたので、岳くんとともに作品の見せ合いをやりました。ゆうさくくんの作品はアレンジの形なので、自分の言葉でアレンジ個所を説明することができました。岳くんの作品には、ウサギの回転スタンプに面白がっていました。 続いて、1度はやったピンポンゲームの振り返りをしました。ちょうど、2人がゲームを作りたいテンションになっていたのでよかったです。作成に移ると、最初のボールが跳ね返る動きでは、勢いままに「端に触れたら跳ね返る」を自分で選んでこれいました。ほかにも跳ね返すバーの動きで「マウスポインターのx座標」を自慢げにすぐ持ってこれていたので、肝心なところはしっかり身についていました。逆に、よく使う動きにブロックについてはたくさんありすぎるのか時間がかかっています。でも、残り30分くらいから作り始めたが、ゲームオーバーまで作成することができました。次回はスコアをつけて完成したいです。', null, null),
  ('f34f338b-59e1-5b1b-8959-5704fc865098', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-10', '17:30:00', null, '通常 / 毎パソ＆自由制作', '前回同様スクラッチのゲームをしてばかりました。 ロブロックスコースのためにプログラミング検定1級を取る必要があるようで、ただそのモチベーションが無いためにゲームばっかりになっているようです。 本人の口から「来週から切り替えて取り組む」と確認したので、面談を含めて次回は検定対策に集中できたら良いなと思います。', null, 'タイピング: 本番一度きり挑戦して終わったようです。'),
  ('d4222b63-5344-595b-b64d-8537ce6c618a', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-10', '17:30:00', null, '通常 / 毎パソ＆自由制作', '制作に飽きてしまい、周りの子たちに流されて途中からゲームを遊んでばかりでいました。 帰り際にロブロックスに興味があること、「検定2級を取った」と話をしたとのことなので、 今週金曜の授業は4月から次のコースへ移行するためにも次の検定対策に取り組んでみた方が良いのかもしれません。', null, 'タイピング: 来週検定のようですがそこまで熱心には取り組んでいなかったようです。'),
  ('c4d42956-cd97-511c-a030-b5b8d2ae34f2', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-10', '17:30:00', null, '通常 / 自由製作', 'クローンをバグがこんがらがっていたので、そこを直していきました。内容はクローンというよりかはそこでのずっとや模試の使い方が上手く機能していませんでした。そこで、「まで繰り返す」を使うと、コードすっきりできると教えたら、いい感じに喜んでいました。あと、乱数の存在もかすかになっていたので、中級レベルのコードをもうちょい使いこなせてほしいです。その後、周りのもう作成は終わった雰囲気に流されて、遊びに流れていきました。 来週こそは完成させると言っていたので完成させます。', null, null),
  ('6c6b8348-2cd8-546c-adc3-3bf8b3dd291e', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-13', '16:30:00', null, '通常 / ドリル 13, 14,15 後半は少し自由創作', '初めにドリルをしました。短いスクリプトは自分で考えてプログラムできていたのですが、長い指示＆長いスプライトになると自分で取り組むことができなそうです。私が質問しつつ、話しつつだとプログラムを作成することができました。 またオリジナル作品ではワープのプログラムをりょうやくんと作製しました。プログラムの意味を理解しているかは微妙です。また作品のためのプログラムを一部バックパックからそのまま持ってきて使い回しているので、残念に感じました。。', null, 'タイピング: どうしても無理とのことで今日はしませんでした。'),
  ('1ed11fbf-3079-5f31-bab0-4d4bbd682409', '57f45872-1f3e-5540-b676-bf9023444e39', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-13', '16:30:00', null, '通常 / 自由製作', '集中力が低かったです。自分の作品のテレポートの部分をりょうやくんに教えてもらいながら作成していました。ただ、プログラムでうまくいっていない部分をりょうやくんに丸投げしていて、本当に残念でした。 こちらから声をかけて一緒に取り組みました。プログラムの該当箇所を探すように促したり、自分で手を動かしたりするように声かけました。分かっていてもやらないことが多いので残念です。', null, 'タイピング: 頑張っていました。'),
  ('fe7c8fe4-038f-55c0-9f5c-d467e0b71327', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-13', '17:30:00', null, '通常 / 自由製作', 'メッセージの処理がうまくいかず、困っていたそうですが、自己解決できていました。またバグにも慌てることなく自分で解決できていて素晴らしかったです。頑張っていました。 表示非表示を忘れていたり、制御ブロックの使い方が甘かったりする部分については助言をしました。今回でほぼ完成だそうです。来週、作品名を決めたり微調整をしたりします。', null, 'タイピング: 練習ではかなり良い結果を出していました。 本番はあまりうまくできなかったようで、悔しそうでした。'),
  ('59bbb544-7869-5623-b15e-09212abe4766', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-13', '17:30:00', null, '通常 / 基本操作コース・キャッチゲーム', '見本を見せながら進めました。上から下に移動させるところまでは良くできていました。下についたときに「隠れる」と言っていたので、位置に注目するように伝えました。プログラム全体を少し意識できるようになったかな？と思います。右左に滑らかに動かす方法もよく覚えていました。「キャッチ」の様子も、見本とはプログラムが違いましたが表示非表示を駆使してよくプログラムできていました。クリア条件のスコアの部分では、≧≦を使った考え方を共有しました。 アレンジたくさんしたそうなので、ぜひやってください！', null, 'タイピング: 練習も本番も集中して頑張っていました。'),
  ('4c7c795f-1ff8-52d4-be8a-ec0b2e194eb9', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-13', '17:30:00', null, '通常 / 自由制作', '導入部分の主人公の動きを、タイミングや大きさなどを上手く調整して丁寧に作成していました。本人の予想以上に長くなったようで、メッセージを駆使しているコードが煩雑になって苦労している部分もありましたが、残り時間で変数などを使ったコードに書き直すのは難しそう、ということで、そのまま進めていました。 今後このような作品を作る際には、毎回冒頭からストーリーを見るのも大変なので、変数等をうまく使ってChapterで場面をとばしたり、個々のスプライトの表示非表示などを管理できると良いかもという話はしました。', null, 'タイピング: 練習では初段を出せていたのですが、本番はミスが多くなってしまったそうで、しばらく頭を抱えて悔しがっていました。それでも、練習とはいえ初段の記録を出せたことは自信になったようで、記念に画面の写真を撮っていました。
盛り上がり: オンラインの授業をとても楽しみにしていると言いつつ、教室でのScratchも楽しんでいるようでした。両立してがんばっていきたいそうです！'),
  ('bf16f011-73ef-52a8-872a-6d1ae9cd1a87', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-13', '16:30:00', null, '通常 / 毎パソ＆自由制作', '自由制作に入る前、前回製作していた「キャッチゲーム」のアレンジの微調整に取り組んでいました。降ってくる剣にアルくんが触れるとアルくんが昇天するというゲームで、ゆうれいの画像効果が上手く使えていました。 今回は過去問ブロンズの「無人島で生き残れ」を制作してもらいました。 まず無人島にいる人間を可愛くアレンジしようと、可愛い色選びは無いのかと聞いてきたりしていました。 試験ではやりませんが、こだわりが強いのかまずスプライトのアレンジから進めるやり方が好きみたいです。', null, 'タイピング: 集中して取り組んでいました。'),
  ('38051263-5d6f-58c4-8e14-2a77fd97a4f5', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-13', '16:30:00', null, '通常 / 毎パソ＆自由製作', '同じ時間帯のるい君が虎太郎君の隣で一緒にやりたいとのことだったので、みんなで集まるなら仲の良い2人に対して教えてもらおうとのことで机を3人並びで座れる配置にして製作しました。 良治君のゲーム内でブラックホールを踏むと次のステージに行けるという仕掛けがあり、それについて教えてもらおうとしていたのですが、難しかったのかプログラム的な説明があまり無いまま進んでいたようです。 アレンジとしては、既存のスプライトをコラージュして作成してブラックホールのスプライトにこだわっている様子でした。', null, 'タイピング: 集中して取り組んでいました。'),
  ('65dfcc3b-8c98-59c7-a913-15bb627e0720', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-13', '17:30:00', null, '通常 / 毎パソ＆自由製作', '弾幕の小技と「宇宙の戦い」のようなHPの小技を2つ使ってガンダム同士を対戦させるゲームが良いのでは無いかと進めていたのですが、小技自体がアレンジとタイピング慣れしてないせいで入力に時間がかかってしまい難しく、小技を変更したいと要望を受けました。 次回は他の小技を、本人だけでなく隣でサポートしながら一緒に選んでいく必要があると思います。 スプライトの描画はとてもクオリティが高いので他のゲームにも使ってもらうか、 今取り組んでいるゲームも別に今期で完成させる必要は無いのかもしれません。', null, 'タイピング: 集中して取り組んでいました。'),
  ('9d97cd9c-53ee-56e9-b9e8-40a423236226', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-14', '17:30:00', null, '通常 / 自由制作', '最初の２０分近くは、タイピングに時間を費やしました。前回同様、自由創作アニメーションの続き。自分の部屋（？）→どこかの異世界（タイムトラベル？）へ移動→その異世界を滅ぼそうとする敵と遭遇→宇宙空間に移動して敵とバトルという流れのようです。敵とのバトルの決着で物語が終わるので、来週終わらせられるかなという感じではあります。背景遷移の際、若干唐突間があるので、もし時間があるようだったら、その辺の改善提案をしても良いのではと思いました。', null, 'タイピング: 集中していました。練習では準一級をとって喜んでいました。検定本番は、準一級取れた時よりも少しミスがあったようなので、結果がどうなるか気になるところです。'),
  ('02141b85-6934-539c-8b8a-dce1ad2e7cd5', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-14', null, null, '通常 / 自由制作の続き', '前回の続き、鼻男の冒険ゲームのようなものを作っており、鼻男が、いろんな顔に触れる（自分に合う顔を探している？）ことで、変な音（奇声？？）が出るような仕組みになっている。今日は、その変な音がまだ完成していなかったので、その音作りから開始。なかなかに奇抜なコンセプトで面白いと思いました。で、どのようにゲームを終わらせるのか？ゲームクリアとゲームオーバーについても話し合ったのですが、自分に合う顔を時間内に見つけられなかったら、鼻男がう○ちをして、オナラの音を鳴らしてゲームオーバーにする。制限時間内に見つけられたらゲームクリアとする。というようなことを言っていました。次回は、これをどうにかして実現させたいところですね。', null, '時間帯: その他
タイピング: 検定本番（ホームポジション基礎）なので、練習を10分ほどして本番に挑みました。集中していました'),
  ('c6d2979e-1115-5a82-9e84-ab3f19d1435e', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-15', '16:30:00', null, '通常 / 毎パソ&自由制作', '今回はサメを実機に追わせるアレンジに取り組んでおり、このアレンジが完成したら作品製作は完了とのことでした。ただ、思ったようにいかず授業内では終わりませんでした。サメ以外のアレンジは特にやらないようで、完成したあとは過去問に取り組もうという話になりました。 検定2級以上のシルバーVer.3.0の問題を印刷したので、次回アレンジが終わり次第取り組んでもらう予定です。', null, 'タイピング: 集中して取り組めていました。'),
  ('d5766836-3c9d-531c-8d3d-314e38d1f024', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-15', '16:30:00', null, '通常 / 毎パソ&自由製作', '前々回からスプライトと小技を配置してずっと考えてくれていましたが、この時間でも結局アイデアが思いつかずずっと頭を悩ませていました。 「こういうアイデアはどう？」と何人かの先生からアドバイスをもらっていましたが、結局授業の最後まで進展はありませんでした。 このまま詰まっている作品に取り組んでも進まなそうだったので、 「次回は新しく自由制作の作品作り直すのと過去問やるならどっちがいい？」と質問し、次回は過去問に取り組むことにしました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('fedfbd1a-7bf9-544f-bca0-eaf45f0617ea', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-15', '16:30:00', null, '通常 / 毎パソ&アルスパーク', 'タイピング大会の結果が振るわなかったせいで自由制作のやる気が下がってしまったようです。 前回からスクロールするたび背景の色が変わるよう設定をしてくれたようですが、それ以外は停滞していて見てあげないとまたミニゲーム遊びに戻ってしまいました。 目の前に同じシューティングゲームを作っているさねゆき君が座っていたので、制作を進めるアドバイスをもらっていました。話の途中でロブロックスの話題になり、2人とも家でやっているとのことだったのでもしかしたらそっち方面で制作した方が楽しいのかなと感じました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('64b6fbb1-13f4-5eab-ab6f-d0e500e3395a', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-15', '16:30:00', null, '通常 / 毎パソ&自由製作', '以前自分で作成したノイズエフェクトを出す素材を使ってかっこいいゲームスタート画面を作っていました。仮あてスプライトを置いて弾幕シューティングゲームのコードを作っていて、このあとはタイマーを利用してボスを3段階ごとに見た目を変化させるとのことです。 定義を最近理解して便利だと教えてくれたので、定義について本人から教えてもらったり、リストについても教えてもらいました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('b8fd0b00-f9af-5f11-9695-d5673b8e258b', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-15', null, null, '通常 / 自由制作', '前回の続きで、制限時間を設けて、タイムアウトでゲームオーバーする処理を作成しました。が、ゲームオーバーにせよ、ゲームクリアにせよ、専用のスプライトが表示されるのだが、暗がりの裏側に表示されてわかりづらいので、個人的にはまだ改善の余地があるように感じたので、その部分をなんとかして完成としたいところです。。簡単なスクリプトではありますが、自分でアドバイスを求めずに作っていた部分もあったので、少しずつではありますが、成長しているとは感じました。', null, '時間帯: その他'),
  ('8822a46e-7fb1-5bb9-a5d9-bf90340e333b', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-15', '16:30:00', null, '通常 / 自由製作', '最初の1時間目はロブロックスばかり遊んでいましたが、 アレンジでボスをカラフルに変化させていたり、弾幕の色も変えてアレンジしてくれました。2時間目になってからしばらくアレンジが思いつかず頭を抱えていたので、普段遊んでいるゲームに関する雑談をしながら「弾幕で検索して他の作品も見てみたら？」と案内しました。 検索したところ、たくさんのアイデアに触れたり有益なサイトを発見することが出来たので意欲的になれた様子でした。 最終的に小技にあった弾幕のコードよりサイトで見たコードの方が汎用性が高い、とのことでコードを変更し、使う小技は残像の小技にしました。', null, 'タイピング: なし'),
  ('1c33e0c8-178d-5aaf-b18a-22df3d8ad387', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-15', null, null, '通常 / 自由制作の続き', '自由制作の続き。キャラクターがスペースキーを押して、パワーを貯めてビームを発射。相手が、そのビームに触れている間HPが減っていく処理を作成。最初に、HPを１００とかにしてどんどん減らすようにしたらと言ったのだけど、HPは０スタートが良くて、HPがマイナスになってしまうのでよいとの事。HPのゲージも、どんどん赤色のげーじが溜まっていって、いっぱいになると、キャラクターがやられてゲームオーバーにするという構想のようです。次はゲームオーバー処理の作成ができたらと思います。', null, '時間帯: その他
タイピング: 集中して取り組みました'),
  ('98ac496c-eb9b-5605-8aa2-10b14547701b', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-15', null, null, '通常 / エクセル', 'サーティファイというエクセルのデジタル問題集のWEBページで、問題を開き、実際にエクセルの練習問題１を解いてもらいました。目的は、問題とエクセルを別々に開いて問題を解くことで、実際のテスト本番の環境に慣れること。それだけでなく、本番では時間が足りなかったとのことだったので、スピードを意識して解くことを伝えました。過去に解いたことのある問題だったようですが、復習となってより記憶の定着が進んで、より早く解けるようになるのではないかと思います。特に問題なくこなしていました。', null, '時間帯: その他'),
  ('a2b79d25-e717-5838-8a95-7b1366b12511', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-15', null, null, '通常 / 自由制作', '前回の続き、過去１に行った時の、餅つきミニゲームを作成していました。杵の振り下ろす動作の表現がうまくできなかったようで悩んでいたのでアドバイスしました。（自分もうまく考えられなくてコウさんにアドバイスもらいました。他のプログラミング言語だと簡単にできることがスクラッチではできないようでした）。結局、「ずっと」の中で「スペースキーを押されるまで待つ」と「スペースキーを押される、ではない」まで待つの組み合わせで処理を実現させました。そして、杵を振るたびに、餅がどんどん大きくなるところまで作りました。あとは、この餅つきのミニゲームの終わり方、このゲーム自体の終わらせ方を聞いて、なんとか作成完了まで持っていきたいところです。', null, '時間帯: その他
タイピング: 練習してか ら検定本番したらと言ったら、いきなり本番で良いと、成績にはあまり興味がないのかなという感じでした。'),
  ('ca9a46b2-8b0d-503b-9450-5e3215c8dcd6', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-15', null, null, '通常 / 自由製作', '横スクロールで画面が移動していくのは前回できましたが、複数の背景が切り替わる順番がおかしかったので調整しました。背景切り替えのメッセージは設定していましたが、旗が押されたときの背景は決まっていないため表示がおかしくなっていることに自分で気づくことができました。また、上下移動の処理を作成しつつ座標の復習を行いました。「x座標とy座標」「『～にする』と『～ずつ変える』」などの紛らわしい概念について理解が怪しかったので、問いかけながら適切なものを選んでもらいました。その後、敵にぶつかったらゲームオーバーとするなど、ゲームとして仕上がってきました。また、ゲーム開始の前にカウントダウンを追加したいとのことでそれを途中まで作っていました。', null, '時間帯: その他
タイピング: 本番を行いました。練習の最初は調子が出ずに落ち込んだものの、改めてタイピング表を確認しながら練習していくと、本番で自分なりのベストを尽くせたようでした。'),
  ('f8ed4635-fd54-51d6-8907-382bd81405c5', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-15', null, null, '通常 / 自由製作', 'ボタンを押したらエサを発射するところできちんと出てこないので一緒に修正しました。ボタンを押したときに座標の設定とスプライトの表示をしていなかったので、「何を設定しないといけないかな？」と問いかけると気づくことができました。また、スプライトを発射し終わって隠すタイミングも間違っていたので考えてもらいました。そうしてイメージ通りの動きができたときはとても喜んでいました。クワガタがエサを食べた回数をポイントとして記録したいそうでしたが、きちんと数えられていなかったので次回やることになりそうです。', null, '時間帯: その他'),
  ('b236c006-4c02-590b-9bff-1efa36040a6c', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-15', null, null, '通常 / 自由製作', '場面転換の作成を進めました。それぞれのスプライトについて、どの背景で表示してどの背景で隠すのか考えながら設定していきました。無事に最後のステージまで移行できて、その後は細かい部分を作っていきました。ストーリーの流れがわかりやすいように、セリフや説明用の新キャラを追加していました。タイピングをやりたくない裏返しかもしれませんが、製作にはとても集中していました。', null, '時間帯: その他
タイピング: 本番の日だったので最初にやってもらおうとしましたが気乗りしませんでした。最後にやることにし、「このコンテストには不合格はないよ」などと伝えましたがやはりやりたくないようでした。親御さんによると試験形式のものが好きではないようで、最終的には気軽な練習感覚でやってもらいました。'),
  ('3cb95c46-e01a-5ecf-be8a-263e9ca362f8', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-15', null, null, '通常 / 自由製作', '2つのミニゲームについて、クリアとゲームオーバーの処理を作っていきました。その後ゲームの動作確認をしたとき、最善ルートしか確認していなかったので、あえて減点を食らうルートの確認も促しました。するとバグが見つかったので、いろいろなケースを試す必要性を理解してくれたようでした。デバッグの際にはメッセージをたどる必要があり、メッセージ名がめちゃくちゃだったので、きちんとした名前にする必要性もわかったようでした。すべてのケースを動作確認し終わり、ゲームを完成することができました。10分くらい余った時間は新しいマリオ風のゲームを楽しく作りました。', null, '時間帯: その他'),
  ('b472bf02-cf84-5753-922f-e40e6d01a087', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-15', null, null, '通常 / 自由製作', '弾幕ゲームの作成を進めました。「ずっと～」の処理の後ろに別の処理をつけようとしていたので、順次処理を考えると後ろの処理は行えないことを説明しました。代わりに、スクリプトを分離することで二つの処理を両立することができました。また、クローンの動きと本体の動きを混同していたときがあったため、必要なときは「クローンされたとき」ブロックを使うことを改めて確認しました。', null, '時間帯: その他
盛り上がり: 途中、高校入試の話などでまみ先生と盛り上がっていました。'),
  ('2ad5b0e0-1007-51b1-8843-b30f1fcd2939', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-17', '16:30:00', null, '通常 / 「ではない待つ」を知ろう', '最初、前回のピンポンゲームのスコア付けをやっていこうかと思ったが、本人的にはめんどくさくてやりたくなく、新しいゲームをやりたいことだったので、レース順位ゲームの方を作っていきました。試遊の段階で、ゆうさくくんは結構このゲームにはまって実力もすごかったです。その勢いで、まずは自分が思うように作りたいとコードを組み立ててきました。「もし」を使う場面は「すべて」を伴うことが忘れずにできています。作っていく中で、どうしても連打ではなく長押しができてしまうことに苦戦をしていました。「何秒待つ」など入れて近づける場面はうかがえました。それでもだめだったので、「ではない」と「まで待つ」のコードを誘導をつけて教えていきました。そのコードをどこへ入れればいいか悩まずに自力で完成できていました。 また、最初にピンポンのように変数を使うのがまだ苦手のようなので、ゴールの風船は触れたら消えるようにすることを自力でできていました。その分終わった後はかなりお疲れでした。', null, '盛り上がり: 最近作成意欲が高めなので、なかなか作業に移れない岳くんをせかす場面が増えてきました。'),
  ('af98a3fa-e48d-522d-8b83-cf5e37942989', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-17', '17:30:00', null, '通常 / 検定1級の合格を目指す', '3月に検定1級をとる、という目標があったためか、授業開始前に「そろそろ始める」と自分から声をかけてきました。 サーティファイの試験出題範囲を見せて、1級取得のためにはリスト、定義、クローンの学習が必要なことを伝え、それ以外の分野に関しては2級まで好成績で検定合格しているため大丈夫だろうと話すと、嬉しそうにしていました。 上記教材を使い、それぞれの機能について説明をしてから該当ブロックを削除してその部分のコードを自力で作成する手順で進めました。上記教材の程度なら比較的簡単だったようで、一通りクリアしてお遊びモードに入ってしまったため、わからなかったら一緒に学習するので声掛けOKとして、検定問題に入りました。 「x座標を〇〇のx座標より20大きい数にする」「○○よりも右側にいるとき」などの意図を文字から読み取るのが難しいらしく、その都度脱線したくなっていましたが、一緒に問題を音読すると意味がわかるようで、結局自力で解決することはできていました。 スキルというよりも、問題の言い回しが難しい、といった様子でした。 3ページ目まで解き終わりました。', '4ページめの頭から。一応、残り時間25分。', '盛り上がり: 検定対策へのやる気はあって、ステップアップできるのが嬉しい、といった様子がある反面、行き詰まるとすぐに現実逃避してゲームに逃げることもありました。'),
  ('50b438ab-ab91-56a6-aa53-680d346a9109', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-17', '17:30:00', null, '通常 / ピンポンゲーム', '基本操作コースがまだ終わっていなかったので、ピンポンをやっていきました。コス選びで、バスと硬貨でしゅうくんの趣味の交通系に選んでくれました。動きの観察がよくできているので、バートの跳ね返りの動作以外は着々とできていました。変数のスコアのところはどこに差し込めばいいか悩む場面がうかがえました。ですが、数回試しを行えば正しい位置に作れていました。完成後もバスのイラストを変化させ、都バスう風になっていました。', null, 'タイピング: よくしゅうちゅうしていました'),
  ('ebf34d33-4dbe-5060-b95e-9b9f03239886', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-17', '17:30:00', null, '通常 / 毎パソ本番', '本番を望む前につかれていたので、バイクランやマリオ、つむつむなどをしてかなり息抜きをしていました。そっこで、ラスト10分からからまたタイピングに戻り、本番をやり遂げていました。', null, 'タイピング: 始まってから何度何度も練習して疲弊感が出ていました'),
  ('56e250b9-f2ed-5058-8db0-03ef4a27b521', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-17', '17:30:00', null, '通常 / 自由制作', '久しぶりにScratchで凝った作品を作るのが楽しかったのか、30分近く延長して熱心に取り組んでいました。 ゲージを使った攻撃威力の設定やバリアの設定など、工夫して面白い作品になっていたと思います。 授業終わりの18時半ごろにちょうどバグが見つかったらしく、必死で修正をして完成させていました。 公開を勧めましたが恥ずかしいからいいとのこと、先生達が見てくれるのは歓迎っぽかったです。 次回以降は、このゲームで使っている小技を抜き出して登録してほしいと頼み、了承してくれました。', null, '盛り上がり: 「できた！」と言って、表示していたたくさんの変数を、必要な2つを残して隠していく作業が満足気でした。'),
  ('de6a5be4-5f30-5562-a470-8b854631e8da', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-17', '16:30:00', null, '通常 / 【コード探求】だるまさんが転んだ', '終始眠たげだったので雑談を交えながら制作をしてもらいました。 アルゴンの「だるまさんが転んだ」の声のトーンが変わるやり方を一緒に考えました。しばらく一定の間隔でしかと音が変化しないと言っていましたが、ヒントを出してあげると自力で答えることができました。 「もし〜なら」のコードですが、後ろに「ずっと〜」つけるタイミングをつい忘れてしまうようです。', null, 'タイピング: 集中して取り組んでいました。'),
  ('a2eb1ce5-becc-5edd-ae69-ee45229df5d2', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-18', '17:30:00', null, '通常 / プラットフォーマー', '自由創作が終わったのでプラットフォーマーゲームの作成に移りました。以前作ったジャンプゲームに似ている要素があったためまず復習しました。ジャンプと横スクロールを使ったことを思い出してもらいました。プラットフォーマーは自力でやるにはレベルが高いので細分化しながらコードを写していきました。ただ、冗長なところまでそのまま丸写ししようとしていたので、「何キーが押されたらどうするか」など大事なポイントを問いかけで整理しながら一緒に作りました。左右の動きを距離の変数で管理する考え方は少し難しいようでしたが理解できていました。ジャンプの細かい作り方も忘れていましたが、y座標を上げてから下げるという考え方を思い出して作れました。背景スプライトのx座標を変えて横スクロールをするところまでできました。', null, '盛り上がり: 最初はあまり元気がないように見えましたが、ゲームが段々できてくるとテンションが上がっていきました。'),
  ('80513630-54ac-5125-9afa-6f1b720da85c', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-18', '16:30:00', null, '通常 / 検定練習', '今日から検定1級の対策をする予定でしたが、前回2級がギリギリ合格だったので、できていない場所を把握しつつウォーミングアップするため過去問を解きなおしました。しかしやる気が出ない様子で最初からほとんど進まず、途中で一緒に解くことも提案しましたが乗ってくれませんでした。ただなんとか最初の1ページ分は解き終わりました。またデジタルイラストコースへの移行を提案すると、それには少し興味を持ってくれました。', null, 'タイピング: 真面目にできていました'),
  ('58d4b384-6e2b-5428-a0b3-2029eed173aa', 'd63b574a-d732-55ef-81da-8e7b43904949', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-18', '16:30:00', null, '通常 / 基本操作コース', '教室に入りたくなく何もしたくない様子で、授業開始後も入口近くのスペースでずっと座っていました。そこにパソコンを持っていくと、しだいに先生と一緒に色々なゲームで遊びました。プログラミング自体はできませんでしたがが気持ちが上がっていき、最後はアルスタジオのゲームを見て「これ作ってみたい」と言っていました。(保護者さんと話し合い済み)', null, null),
  ('f99e6a9f-5da0-5e44-b93b-bf8a7a0acb74', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-18', '16:30:00', null, '通常 / プラットフォーマー', '自由創作で扱った横スクロールを応用するゲームとして、プラットフォーマーゲームを作り始めました。お手本のコードを見ながら、重要なポイントを細分化してから作りました。前回の横スクロールは自動で動きましたが、今回はプレイヤーの位置に合わせて動くのでその方法を一緒に理解しました。進んだ距離を変数として記録し、それに応じて背景の座標を変える意味を納得してくれました。4枚ある背景の位置関係もイメージできて、スクロールが完成しました。坂を自動で上り下りする仕組みについても、色判定を使うことを理解して作ることができました。今日はお手本ゲームの再現(ロケットを除く)までできて、アレンジに意欲的でした。', null, 'タイピング: 集中していました。'),
  ('d4328f88-4333-53ac-bb5c-14cbbdcfb972', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2025-02-18', '16:30:00', null, '休み（未対象）', null, null, null),
  ('31aff0dc-1875-5d49-92e6-0786da30764d', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-20', '17:30:00', null, '通常 / 基本操作コース_ピンポンゲーム', '前回まで作成してもらった自由制作のコードが難しすぎるため、一旦制作は置いてスキルアップしてからまた制作しようと言う話になりました。 三ヶ月前にピンポンを制作していたので、覚えているか聞いてみたところ自信が無さそうだったので復習をしました。 パドルを動かす際、矢印キー+〜歩ずつ動かそうとしていたので、マウスの座標が関係して動いているという解説を交えながら自分でコードを組み合わせてもらいました。 「〜に触れた」「ずっと」のコードを言われるまで発見に迷う時間があったので、今回の制作で使い方を思い出せたかと思います。', null, 'タイピング: 集中して取り組めていました。'),
  ('a885c44b-fdca-5bd7-8dc0-03aecad42346', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-20', '16:30:00', null, '通常 / 検定問題ブロンズ「無人島で生き残れ」', '前回からコスチュームアレンジに気合いが入っており、ずっとペイント作業をしていました。今日中に完成させたいね〜とは声をかけていましたが、作業量が想定以上に多かったみたいです。次回にはそろそろコード作成に入ってもらいたいのですが、本人のこだわりが強いので様子見しながら声をかけようと思います。', null, 'タイピング: 集中して取り組めていました。'),
  ('b6e32b89-817d-5953-b896-ffafef778290', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-02-20', '16:30:00', null, '通常 / アイビスペイントの使い方/イラストコース-顔の描き方①、②', '初回だったので、まずデジタルイラストのソフトについてどの程度理解しているのか質問しながら進めました。りょうやくんはアイビスに関してはそこまで詳しくありませんでしたが、自宅でProcreateというツールで描いているようで、ペンの太さの変え方やペンの不透明度の変え方までは知っていました。レイヤーの概念を知らなかったようなので、実際に紙を用いて説明すると「動画でみたことある」と瞬時に理解してくれました。また、選択ツールについて質問されたのでそれに関してもざっくり説明しました。 今回はキャラか物なら「人描くの苦手だから」という理由で顔を描く練習をしてもらいました。本人の描画力が元々高いので、特徴的な顔を描き上げることができました。 キャラクターの髪の毛の描画で、正面から描くのは難しいはずなのに見事に描けていて良かったです。', null, 'タイピング: 集中して取り組めていました。'),
  ('e46dc7c8-1a6b-5808-9ce7-a9cf03f05d99', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-20', '16:30:00', null, '通常 / 必要なコードを読み取って、自分で作成をする', '自由制作の間、なんとなくブロックをいじって遊ぶ、というモードが続いてしまったので、興味を持ちそうなゲームを題材に、「コードの一部だけ作ってみよう」を目標にしてみました。 幸い、ゲーム自体にはとても興味を持ってくれて、かなり盛り上がってプレイしてくれました。一通り遊んだあとは、こたろうくんとおとなしくコードを開いてくれて、小技のコードを見てなんとなくでも理解をしてから、自分で横スクロールのメインコードとクローンされたときのコードを作成できました。 コードを作成する過程で、座標、～まで繰り返す、不等号の演算式の復習をしました。 迷ったところはこたろうくんのコードを見ながら、なんとか完成させて、満足そうにしていました。', null, '盛り上がり: ゲーム自体がとても楽しかったようで、進んだ距離が出たら面白い、などとアレンジを考えたりもしていました。「とても久しぶりにプログラムをした！！」と自画自賛していました。'),
  ('53f7decc-1388-5366-8e88-79dcf2568c23', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-20', '16:30:00', null, '通常 / 必要なコードを読み取って、自分で作成をする', '自由制作の間、適当に小技などを付け加えてスプライトを動かして満足！というモードが続いてしまったので、興味を持ちそうなゲームを題材に、「コードの一部だけ作ってみよう」を目標にしてみました。 ゲーム自体にはとても興味を持てたようで、かなり盛り上がってプレイしていました。一通り遊んだ後は、こちらが促すと素直にコードを開いてくれて、コードの多さに「これ難しい！」と引きかけましたが、今日はスクロールの復習のため、作成するコードは2か所だけ、と伝えると、やる気になってくれました。 小技のコードを見て、最初の座標の指定、～まで繰り返すのコードの意味などを質問すると、おぼろげながらも答えることができました。 コードを見て解読してからは、自分で横スクロールのメインコードとクローンされたときのコードを作成することができました。', null, '盛り上がり: ゲーム自体にはとても盛り上がって、るいくんとタイミングを合わせて競争したりと大いに楽しんでいました。コードの作成では、るいくんに教えられるように先に作成を促すと、年上らしく教えたりすることもありました。'),
  ('c4107eb0-7e49-5e16-a8e8-38bd546f4f72', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-20', '17:30:00', null, '通常 / キャッチゲームのアレンジをする', '前回の続きのアレンジをしたい！ということで、1時間熱心にアレンジをしていました。 複数のフルーツが落ちてくるタイミングが一緒になってしまうのが嫌だということで、タイミングをずらすにはどうすればよいかと発問し、片方のスプライトに「待つ」を入れて調整していました。待つ時間をランダムにしたら？という問いかけにもすぐに反応し、乱数を使用していました。 基本的に、こちらの提案には素直に感心してくれて、すぐに手を動かす様子が見られました。 2つのスプライトが一緒に動くようにするところで「ずっと」の入れ忘れがありましたが、すぐに対応できました。 カウントダウンのスプライトなど、自分で工夫して入れていました。', 'カウントダウンの「ゴー」の縁取りを、数字と合わせて白にしたいそうです。', 'タイピング: 丁寧に練習していました
盛り上がり: タイミングや色調など、何度もプレイして考えて、楽しそうにアレンジに取り組んでいました。'),
  ('dfba4d45-3eb3-593c-a1f2-763e97467926', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-20', '17:30:00', null, '通常 / Excelの基本操作を学ぶ', '授業開始時に自分から「今日はExcelをやりたい」と申し出てきました。Excelをさわるのは初めてということだったので、セルの選択などからやりました。テキストを見つつ、こちらで効率的なやりかたを教えては自力で実践するというスタイルで学習を進めました。 オートフィルや数式の入れ方など、基本的に楽しそうに学習できていました。 セルの選択、SUM、AVERAGE、ROUNDDOWN、IF関数と、比率の求め方、セルの書式設定、絶対参照を学習しました。', 'グラフ、スパークライン、ワードアートなどの学習', 'タイピング: 一昨日、自宅で本番をしたもらいましたが、準1級くらいはとれたんじゃないかな、という感想でした。今日も毎パソで練習をしていて、こたろうくんに尊敬の目で見られていました。
盛り上がり: 表の罫線や列幅を調整し、桁区切りなどを入れると「表っぽくなった！」と満足そうにしていました。'),
  ('4f4692ea-157e-55df-af95-3601495518c3', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-14', '17:30:00', null, '通常 / 自由製作', 'HPゲージをもってきた！バーの中身の調整に時間がかかりました。どうしてもゲージ内でバーを動かすのは難易度が高いので、計算とプログラムを手伝いました。同時にHPの設定もしました。 またそのほか、背景にあった障害物をスプライトに変更したり、あたり判定の作製をしたりしていました。全体を通してやる気があり、モチベが高かったです！さらにきちんと考えて進められていたのでよかったです！', null, 'タイピング: 頑張っていました！'),
  ('dee3a874-0307-5286-91ad-8fdae77ee2dc', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-14', '16:30:00', null, '通常 / 自由製作', 'ささーーっとつくって終わりにしてしまう癖があるので、今回の作品は今日と次回に欠けて作成してみるように伝えました。 また、クリックしたものを他の場所に置くのに、クローンとクリックを使ってうまくプログラムをしていました。たまたまうまくいったそうですが、たまたまを作れているのもすごいなと思いました。ただ一方でずっとカーソルについてきてしまったので、次回修正します。私の方でもプログラムを考えています。また最前面、最背面の使い方も紹介しました。', null, 'タイピング: 少しミスをしたようですが、集中して頑張っていました！'),
  ('df60695c-88d5-50ff-97b8-b084978858d4', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-21', '18:40:00', null, '通常 / Excelの数式、関数の入れ方を学ぶ', '上記教材を使用して、四則演算や比率、SUM、AVARAGE、MAX、MIN、IF、ROUNDDOWN関数の入れ方、パーセントスタイルと桁区切りスタイル、列幅の調整、セルの書式設定の学習をしました。 解説⇒例題⇒演習の流れがやりやすかったのか、途中で転寝することもなく、熱心に取り組めていました。 範囲選択とオートフィルのときのカーソルの形の違いを説明しなおして、範囲選択とオートフィルの違いをやり直したら、だいぶ操作が安定してきました。', 'グラフ、スパークラインの復習', '盛り上がり: 自走していたときよりも様々な情報が整理できたのか、だいぶすっきりした感じで操作ができているようでした。少し自信もついたようです。'),
  ('e9dd1470-3753-5cd4-8a55-912a23077a49', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-21', '17:30:00', null, '通常 / オリジナルゲーム', '検定でクローン、リストを使うことを説明し、問題文を一通り確認してもらいました！なんとなくいけそう、とのことです。次回は検定をやることを説明し、今回はオリジナルゲームを作成することにしました。 クローンの使い方を復習してオリジナルゲームを作りました。質問と制御のブロックのプログラムの作製に困っていたので、アドバイスをしました！だいぶ整理されたと思います！クローンは最後の最後で使いました。動きの作製方法について少し助言しました。', '1級検定問題', 'タイピング: 集中して取り組めました。'),
  ('1a80b7ff-0f90-5978-9a0c-c2a57cb913fc', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-21', '17:30:00', null, '通常 / 自由製作', '自由製作、中盤の会話文を「～秒まつ」を使ってプログラムを作成していました。タイミングを調製するのに大変そうだったので、大枠ができていましたがメッセージを使うことを提案しました。序盤こそ手伝いましたが、その後は自分で全部把握しうまく調整することができていました！ その後ストーリーを進めステッキやカードを登場させ、完成させることができました。最後「続く」という画面を作っていました！楽しく取り組めていて良かったです！', null, 'タイピング: 集中して取り組めました！'),
  ('1a44cef4-b37a-524d-9a91-5aeba55b1a19', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-21', '18:40:00', null, '通常 / クローンについて', 'クローンは使ったことがあるものの、よくしらないということだったので詳細を説明しました。「クローンされたとき」のブロックの存在を忘れてしまうようですが、大事な考え方は理解できていそうです。マユネコも自分なりにアレンジして楽しんで取り組めました。宇宙バトルはクローンの削除のタイミングになやんでいました。長押しすると弾が出続けているプログラムですが、プレイするのが楽しいようです。', null, 'タイピング: 集中して取り組めました。'),
  ('e4c35e27-1fd1-5f20-9c42-9de3c9f830c4', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-21', '18:40:00', null, '通常 / 自由製作', '自由製作のゲームクリアとゲームオーバーを作製しました！もうスプライトが完成していたので、表示非表示をコントロールするプログラムを作成しました。大まかな考え方は一緒に確認しました。「もし～」「～に触れたら」は問題なく使えそうですが、ずっとの存在を忘れてしまうようです。メッセージはうまく使えていました！また理解として表示非表示が別物なようで、スタートのときにスプライトを隠すアイデアがなかなか出てきませんでした！最後に作品名を付けて完成しました！ その後、次回からやる予定のジャンプゲームを遊んでもらいました！', 'ジャンプゲームに入る！', 'タイピング: 集中して取り組めました。'),
  ('ce7273d6-bea0-544e-99f6-5d109c8e5499', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-21', '16:30:00', null, '通常 / 温泉建築ゲーム', '自分で温泉設置のプログラムを変えていました！移動中はクローン、設置はスタンプが見えるようにしてプログラムを変えていました。作りながら詳しい仕組みを考えていたわけではなかったそうですが、よくできていました！ その後、背景が変わって戻ってきたときも同じようにスタンプが押され、温泉の位置を再現するようにしたかったそうなんどえ、リストを使ってプログラムを提案しました！原理は難しかったですが、大まかな流れとプログラムの方針は理解できていました！', null, 'タイピング: 集中して繰り返しました。'),
  ('e3da6e4d-41a6-5d40-bd47-9cb26e2ba942', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-21', '18:40:00', null, '通常 / Excelの数式、関数の入れ方を学ぶ', '上記教材を使用して、四則演算や比率、SUM、AVARAGE、MAX、MIN、IF、ROUNDDOWN関数の入れ方、パーセントスタイルと桁区切りスタイル、列幅の調整、セルの書式設定の学習をしました。 学校でExcelをやっているそうですが、範囲選択のコツやショートカット、オートフィルなどにその都度反応してくれて、良いムードメーカーになってくれました。 数式を入れている最中に関係のないセルをクリックする癖があって数式が乱れることがありましたが、練習していくうちに慣れたようで、スムーズに入力ができるようになっていました。 Ctrl+矢印キーやCtlr＋1のショートカットキーを面白がって、何度も試していました。', null, '盛り上がり: 一つ一つ、数式や機能を紹介するたびに面白がってくれました。授業開始時には「眠い」と言っていましたが、最後まで眠そうにすることもなく、とても熱心に楽しんで取り組めていました。'),
  ('f918e360-636a-5857-ab96-c9109ade3fe4', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-02-21', '18:40:00', null, '通常 / Excelの数式、関数の入れ方を学ぶ', '上記教材を使用して、四則演算や比率、SUM、AVARAGE、MAX、MIN、IF、ROUNDDOWN関数の入れ方、パーセントスタイルと桁区切りスタイル、列幅の調整、セルの書式設定の学習をしました。 一緒に学習した3名の中では唯一、Excelを使ったことがないとのことでしたが、飲み込みは早く、入力に慣れてからは操作もとても速くなっていました。 授業の前半では入力に戸惑うこともありましたが、こちらの見本画面を熱心に見てやり方を覚えていて、習得しようという意志を感じました。 最後に表の体裁を整えた時は、満足そうにしていました。', null, '盛り上がり: Excelの機能に素直に感心していたようで、熱心に取り組んでいました。'),
  ('39accfdb-0b5e-5fba-94ac-d8609d377875', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-21', '17:30:00', null, '通常 / 自由製作完成＆ジャンプ基礎', '本日で自由製作の作品を完成させることができました！ゲームクリアしたのにゲームオーバーが表示されてしまうバグを直していきました。本人的にも秒数の変数が原因でバグが起こってることを理解していたので、スムーズに改善方法の「他を止める」コードを一緒に閑雅ることができました。そして、紹介文を作り、作品を公開することができました。 残り時間が少なかったので、ジャンピングゲームはまず、ジャンプの基礎の「何回繰り返す」の活用法を教えてました。次回から作成です。', null, '盛り上がり: はじめて自分で作った作品をアルスタジオに公開していてかなり喜んできました。'),
  ('5e658db8-be54-5f53-b779-9516af7fcae0', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-21', '16:30:00', null, '通常 / プール開発ゲーム', 'りょうま君が作っていた開発型ゲームが気に入ったらしく、別のもので自分も作ってみることでした。アイデア出しに苦労していましたが、身近にあるプールの形をとってみることにしました。スタート画面の構成作りが今回はメインとなりましたが、今後の作る要素はしっかり組み立てられていました。', null, null),
  ('f355d94a-828e-5b0c-9868-168800aa9837', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-22', '17:30:00', null, '通常', 'ストーリー部分の進み、対決場面を作り始めました。突然、バトル画面に移り変わるだけではなく、操作説明画面を挟むことで新設設計になっていました。武器がスラボーニ触れて、別のスプライトを動かすにはどうすrばいいか悩んでいたので、色判定かメッセージの受け渡しを教えてあげました。今日で終わりかと思い込んでいたので、まだ次回以降にも作成できると知って安心していました。', null, 'タイピング: 集中して取り組めていました。'),
  ('674fd443-212b-5abe-a5e8-3f5335f110b4', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-21', '16:30:00', null, '振替 / 横スクロールでアレンジしよう', '今回は基本のスクロールにコインも追加していきました。最初は動いてもコインとの距離が画面を固定されてうまくいっていませんでした。そこで、今一度背景のスクロールをどのように作ったのか振り返り、同じコードを入れてみると、どうなるか試してもらいました。そこでの気づきがうまく働き、その先のコイン位置調整を距離の変数を見ながら、自分で治すことができていました。完成した時は満足げに浸っていました。', null, 'タイピング: 1つ1つ確認しながら打てていました'),
  ('e1486def-a3a7-58c9-8be1-27e8e0ee6ec6', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-22', '16:30:00', null, '通常 / エクセル練習', '上記教材を使用して、四則演算や比率、SUM、AVARAGE、MAX、MIN、IF、ROUNDDOWN関数の入れ方、パーセントスタイルと桁区切りスタイル、列幅の調整、セルの書式設定の学習をしました。二人とも少しは関数を触れているので、主に入力の効率化(オートフィルやショートカット)を中心に教えていきました。 数式の連続した際に、最初はコピペをしていて手間をかけていたので、ダブルクリックや長押しオートフィルやShftやCtrlの使い方は初めてで、非常に役立っていました。罫線や書式設定もCtrl＋１で操作も身について、練習問題ではかなりスムーズに完成していました。この形式で教えていったら下手に手間がかかる作業減らしていける思考が育ちそうです。', null, null),
  ('559c697e-c2f9-5f97-809c-1870d3961afa', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-22', null, null, '通常 / 検定１級準備', '自由制作か、検定１級の問題に挑戦するのをどちらにするかを聞くと、わからない自分で決められないとのこと。ただ、１級の難しさがわからないので、どれくらいの難易度かを感じてみたいとのことだったので、検定１級の一番最初の問題にトライ。自由制作は、検定後に完成させれば良いのかなと思います。初めての１級問題だったので、つまるところがあったら、相談しても良いからねと伝えたのですが、大丈夫ですとのことで、特に何も聞いてくるところがなく時間終了となりました。大体50分近くかけて、残りあと、２問ほどできていない状態でした。答え合わせもする時間がなかったので、うまくいかなかったところを認識してできるようにするためにも、次回は答え合わせからした方が良いと思います。解いてみた感想を聞くと、やはり難しいとのことでした。この問題はクローンが出てくるものの、リストは出題されていないので、リストの使い方も別途教えることをした方が良いと思います。リストについては、他に１級受ける人もまとめて教えてしまうとかでも良いかもしれません。', null, '時間帯: その他'),
  ('d6ced0be-9fb4-5329-8032-f9f7a69ee058', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-22', '16:30:00', null, '通常 / エクセル練習', '上記教材を使用して、四則演算や比率、SUM、AVARAGE、MAX、MIN、IF、ROUNDDOWN関数の入れ方、パーセントスタイルと桁区切りスタイル、列幅の調整、セルの書式設定の学習をしました。二人とも少しは学校で関数を触れているので、主に入力の効率化(オートフィルやショートカット)を中心に教えていきました。tab, enterの移動、shft, Ctrlの範囲選択はかなり新鮮味で受け取ってくれました。 最初の四則演算の計算をとりあえず解いてみて渡したら、足し算でもないのに引き算で「=sum(B3-C3)」のようなsum関数の無駄遣いをしていました。本人曰く、sum関数を計算式の答えを表す関数だと勘違いしていました。今回はちひろくんペースでゆっくりやっていたので、はるくんは一人で勝手にどんどん進んでいきました。そこで、上記の件があったので、とりあえずそれぞれの関数を見直しました。そしたら、210以上の判定を>=の形で表させていなかったり惜しい所の知識が抜けています。絶対参照のところで、列固定と行固定の話も少し触れましたが、そこは練習問題のところでも律儀に使いなおしてくれました。ただ、そのショートカットを教えてても、まだ、マウスを使って手直しして場面も見れました。今回は本人はほとんど知っているところだったので退屈だったりしたかもしれません。', null, null),
  ('e0949929-b527-57fe-9c31-6a47113cf5c3', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-22', null, null, '通常 / 検定１級準備', '自由制作にするか、検定１級の対策をするかどちらがいいか、自分では決められないということですが、１級の難しさがわからず、対策もしっかりしたいとのことで、検定１級に問題に挑戦することにしました。50分ほどで、問題を解いて、実際に動かして確認するところまで完了したようです。が、答え合わせをする時間が取れませんでしたので、次回は答え合わせからできれば良いかなと思います。途中、詰まってるところがない？と確認すると、「星が0.1秒間隔で点滅する」というのをスクリプトでどう作ればよいかわからないとのことだったので、点滅するということはどういうことかを、もっと噛み砕いて別の言い方で表現してみようかということで、表示すると隠すを0.1秒ごとに繰り返すということで納得できました。１級を初めて挑戦して、やはり難しいという感想でした。まだ、リストの問題には挑戦できていないので、リストの使い方の個別勉強（ゆうかちゃんと一緒でも良いかも）をしてから、また検定１級問題に挑戦して対策していけば良いのかなと思います。', null, '時間帯: その他'),
  ('eb336dde-fb4a-5aed-ae08-2979dd8f4354', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-22', null, null, '通常 / 自由製作', 'アルスタジオの製作が今日が最後だったので、何とか完成の形まで仕上げました。残っていた終わりの演出と作り上げて1通りは作れましたが、攻撃のパターンが1パターンだけで本人の出来栄えとしては微妙な感じでした。アイデアがあれば付け加えたいそうです。', null, '時間帯: その他'),
  ('766cd7c8-1c56-507f-ab24-77ffdcc180ec', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-02-22', null, null, '通常 / 自由製作', '今回は、景品が流れてこないバグに主に向き合っていました。その原因として、HPの変数が阻害しているところはこちら側から手伝えました。そのあとは、本人の気づきでクローンを使っていたので、グローバル変数からローカル変数の変更でバグを修正することができました。その余波でほかの変数もできる限りローカル変数に揃えられるところは直して、景品が流れれる仕組みは直せました。', null, '時間帯: その他'),
  ('1f142efa-0fec-54c2-bb06-ffd6cf811c27', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-22', null, null, '通常 / 自由制作', '前回からの続きで、スパイダーマンがビームを受けたら、HPが減っていく処理を作っていきました。どうしても、HPの減り方は、普通の減り方ではイヤなようで、ビームに触れている間に、赤い体力ゲージのようなものが、左側にどんどん伸びていき、画面左端まで辿り着いたら、ゲームオーバーの背景を表示するという流れになりました。HPもマイナスになっていきますが、それもそれで良いとのこと。自由制作もこれで終了で良いとのことです。HP（体力）という変数を導入したこと、ビームにぶつかった時にHPゲージの長さを変化させる等、色々な方法を学んだと思います。', null, '時間帯: その他
タイピング: レッスンの最初だけでなく、途中の時間にも、なぜか英文のタイピングに挑戦していました。英単語のタイピングは早いですね。'),
  ('21721e85-eb00-5d75-86cc-52c6af1c1648', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-22', null, null, '通常 / 自由制作', '前回の続き。タイムトラベル冒険物で、今日で完了させることができました。最初の背景から家に入る→タイムマシンがありそれに触れるとタイムトラベルする→移動先でモンスターがいて、それを剣でやっつける（剣がモンスターに触れて体力が０になる）と、タイムマシーンが故障して、いろんな世界を永遠にぐるぐる回る状態になって、それでゲーム終了とのこと。特に今日は、モンスターをやっつけるための処理で、体力用の変数作成、モンスターに剣が触れることで体力変数が減っていくという処理を割と簡単にサクサクと作っていました。基本的に、あまりコチラがアドバイスしなくても、サクッと作っていくので、低学年としてはかなりすごいなと感心させられます。', null, '時間帯: その他'),
  ('487c10bb-fece-5317-810d-a003894a3c6e', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-02-22', null, null, '通常 / 自由制作', '前回の続き、過去１に行って、餅つきをするミニゲームの処理を作っていきました。音楽にこだわりもあるようで、音楽の追加も行っていました。やけに陽気なダンスミュージックみたいなのを選んで、その曲がかかると、自分でも踊りながら制作を進めていました。餅つきミニゲームは、新たに餅つき時間の変数を導入して、30秒餅つきしたらミニゲーム終了とのこと。せっかく餅をつくと、餅がどんどん大きくなるので、餅の大きさもミニゲームクリアの要素として使って欲しかったところですが、それはしなくても良いとのこと、30秒処理＆判定ロジックを自分で考えて作ったので、それはそれで良いかとひとまず次に進もうとなりました。今回で自由制作の終了はできませんでしたが、意欲は高いので、引き続き自由制作で良いと思います。他にミニゲームを何個かクリアしたらゲーム完了とのこと。他のミニゲームの作成はさほど時間がかからず終わると思うとのことだったので、あと１回で完了させられたら良いなと思います。', null, '時間帯: その他'),
  ('e5e5c879-d18a-50fe-bbe3-3b6c6d333c23', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-25', '16:30:00', null, '通常 / ジオメトリーダッシュの表現部分（ぶつかったときの拡散、スプライトの残像）', 'ゲーム全体を作製するのは厳しそうだったので、主人公の動きにフォーカスして作製しました。もとのプログラムを開いて大まかな流れを一緒に確認しました。定義は使ったことなかったそうですが、プログラムを作成しました。変数を調節していろいろ試していました。その後、残像を作製してもらいました。こちらは拡散よりも原理が難しかったので、内容を解説しつつ、大きさと幽霊の効果と工夫の説明をしてプログラムをしてもらいました。 その後ジャンプを「あるくんの冒険」を確認しながらプログラムしました。背景スクロールこそしなかったものの、クリアを付けて作品っぽく仕上げました！', null, 'タイピング: 集中して取り組めました！'),
  ('7fcf591c-7c75-550e-8478-ed399c6f0d37', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-02-25', '17:30:00', null, '通常 / カエルを家に帰せ（続き）', 'ジャンプのプログラムと地面の判定のプログラムをまず作製しました。見本通りだと考え方が難しいように感じたので地面の判定をふまえたジャンプのプログラムを作成しました。その後少しアレンジを加え、家に着くと電話の音が鳴り仕事に行くストーリーが完成しました。コイン出現のプログラムも作製しました。プログラムを考えるのが難しかったようなので、大まかに考えて背景と同じ動きをすることを確認してもらいました。コインを量産し、楽しんでいました。来週は宇宙に富んでいくプログラムを作りたいそうです。', '次回はカエルを宇宙に飛ばしたいそうです！！', 'タイピング: 集中して取り組めました。'),
  ('23c995c8-6f7f-50a0-80aa-5a986b215ef1', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-22', '16:30:00', null, '通常 / 自由製作', '検定を受けることになりましたが、今週だけは自由製作を進めることにしました。HPが0になったら終わる処理、回復薬がちょうどいい頻度で出て来るようにするなど、ゲームとして必要な処理を作っていきました。「～秒待つ」などを使って、何回も当たり判定が出てしまうのを防ぐこともきちんとできていました。途中で遊んでしまうこともありましたが少しずつ進めてくれました。', null, null),
  ('f4122c29-f0f3-5390-a4b5-fddcd8614cfd', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-22', null, null, '通常 / 自由製作', '横スクロールで特定の背景が消えてしまうバグを直しました。最初は適当にいじっていて進展がありませんでした。そこで、スクロール用の背景を切り替えるメッセージがいくつかあるので、どういう順番で送ったり受け取ったりしているのかを整理しました。すると、背景1→背景2→背景3→背景1→...のようにメッセージを使ってループさせていることに気づき、メッセージの名前を間違えている場所を発見することができました。', null, '時間帯: その他
タイピング: 前よりスムーズになってきています
盛り上がり: 適切にアプローチすれば好奇心をもって取り組んでくれます'),
  ('01a0c3b0-cc5f-5a1b-b524-dadfbf6614ac', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-22', '16:30:00', null, '通常 / 自由製作', '自由製作の続きをしました。終始robloxに夢中で乗り気ではなかったですが、弾幕の作成を少しだけやってくれました。確かに弾幕とそれをよけるプレーヤーの動きはきれいに作れていました。あとはHPの作成とゲームクリアの処理という簡単な作業だけ残っていることを自分で把握していました。しかし、あと少しだけだと逆にやる気が出ないとのことでした。', null, null),
  ('055d695f-441a-5aff-8ba4-81d92b8ec733', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-22', '16:30:00', null, '通常 / 自由製作', '自由製作ゲームの2つめを進めました。クワガタの口がパクパクするはずなのにしないというバグに対して、頑張って原因を探っていました。メッセージの送信元をたどってみるなどの考え方を促すと、あまりイライラしたりせずコードを見なおすことができました。結局は全角数字によるバグでしたが、直ったことに喜んでいました。背景やセリフも自分で作って、満足のいくゲームになりました。', null, null),
  ('fc88884f-8c10-5d52-909c-67f030a092de', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-02-22', null, null, '通常 / 自由製作', '自由製作ゲームの2つめを作っていきました。家で背景などを少し作ってきたとのことでやる気があるようでした。上のほうにある地面に飛び移れるようにするのに、色の判定を使ってうまくやっていました。スプライトを往復させるために「端に触れたら跳ね返る」と「x座標を～ずつ変える」を同時に使っていましたが、それではスプライト自体の向きが変わるだけで移動する向きは変わらないので「～歩動く」に変えることを促しました。これを通して「跳ね返る」の仕組みをしっかり理解したようでした。', null, '時間帯: その他'),
  ('0acdd888-94ca-5f4a-b8fb-b2db39e6b688', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-03', '16:30:00', null, '通常 / 色動き見た目のアレンジスキルを高める', '始めてきたこうすけくんと先導するように楽しく遊んでいることができました。二人ともマイクラがスクだったので、スクラッチでのマイクラのやり方を教えてあげていました。 授業では、タイマーの使い方や見た目の基礎の再確認をしました。タイマーのブロックになじみがなかったので教えましたが、「何秒待つ」でもいいじゃんと言い返されましたが、スキルアップのために教えていきました。5秒の判定では、不等号の登場に難しがるかと思ったが、勉強の方が最近習っていたので、得意げに作ることができました。色大きさが同時に変化をするとロコでは、隣のこうすけくんにやり方を教えてあげて一緒に楽しんでいました。がくくんは教え方が上手かったので、すんなり幸助君も作れていました。', null, 'タイピング: ハイスコアでした'),
  ('21ed50ae-7c9f-53ec-bb5c-dfccd88341a4', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-03', '17:30:00', null, '通常 / アレンジ', '前回作った作品がかなり気にいていたので、アレンジを続けていきました。硬貨だけではなく、紙幣も増やして、見ごたえある藻に仕上がっていました。運賃も適正価格になっていました。 そのあと、少しの時間基本操作コースの踊ろうも取り掛かりました。コス変化の動かしが一瞬になってしまうのを間隔を取ることによって見せることができるを学べていました。', null, null),
  ('ba916bf5-6bdb-5478-a4ee-3b6c73829e77', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-03', '17:30:00', null, '通常 / イラストコース-キャラ 授業説明と1章①〜④', '授業に入る前に今後どのように授業を進行していくかの説明と、アイビスをどこまで活用できるかの質問をしました。対象定規を使ったり、投げ縄塗りを使いこなして髪の毛を描くといったテクニックを持っていました。 ただ、レイヤーの合成モードは知らないようで、可愛く仕上げる方法はあるようですがもっと色んなポーズを描けるようになりたいそうです。 授業では対象定規やレイヤーの透過を利用して綺麗に正面からの顔を描き上げてくれました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('d70074a7-31cb-5ec6-a993-ffeb89bc6675', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-03', '17:30:00', null, '通常 / 検定問題続き', '前回の続きが非常につながりが悪い所だったので、最初から目をそらしてげーーむに行ってしまうところが多かったです。今回の問題は、座標の種類がたくさんあったので、どの表記での座標か迷い間違っている場面が多く見られました。そこは、文章の読み込みが必要だと思います。それ以外は、かなり作れていたので、できないことがあった時のやる気がそれてしまうことが心配です。', '今回早めに終わったので、次回は授業初めから検定問題始める厳守', null),
  ('63fd2d9b-8d19-5cdd-a188-229a2bbb816c', 'e22d8f70-f1a1-5ca4-9ed4-4d27cb0e164f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-03', '16:30:00', null, '通常 / 基本操作コース02', 'レッスンの踊らせようまで完了しました。 教材にはありませんでしたが隣のガク君がいたので、教えてもらいながら「マウスポインターを向けた時大きさが2ずつ変わる」を制作してアレンジしていました。 他にも自主的に背景をつけていたりと自分から作っていく姿勢がよかったです。 動かしたい時にどのコードを見ればいいのか、迷いや詰まりは今のところ無さそうでした。', null, 'タイピング: 集中して取り組んでいました。'),
  ('e7fa5c09-f2d4-5eb7-b821-08dbb3930834', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-03', '17:30:00', null, '通常 / Excelの基本的なデータ入力を学ぶ', '本人の希望でExcelに取りかかりました。検定を受ける気もあるようです。 Windowsは普段使っているとのことだったので、基本操作は軽く確認程度にして、数式や関数の入力とセルの書式設定をメインに学習しました。 Windowsでもショートカットキーを使うとのことだったので、Excelでも範囲選択などで活用できるキーを教えると、自分で色々と試していました。 年齢的なものなのか、プログラミングほど自分の世界に入り込まないためか、こちらの問いかけに対しても良く反応し、いつもより会話をしながら進めることができました。久しぶりに「授業を受けた」実感があったかもしれません(^^;) 後半は練習問題2を自分で解いていました。教えていなかったROUNDDOWNも自分で解決できていて、ちょっと得意そうでした。', 'スパークライン、グラフなどの学習', 'タイピング: タイピング自体は省略しましたが、毎パソの記録はとても嬉しそうに書類を見ていました。
盛り上がり: Excelに対しては、思ったよりできるかも、といった感じで、検定を受ける気にもなっていました。終始楽しそうに取り組めていました。'),
  ('9ff9a5dd-9e6e-5beb-a545-905f456b935f', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-04', '16:30:00', null, '通常 / あるくんの冒険（2）、図形を描く', 'あるくんの冒険（2）は、ジャンプのプロ黒グラムのバリエーションを増やすために取り組んでもらいました！あまり面白くなかったそうです。90度に向けて10歩あるくプログラムがx座標10ずつ増える の関係性を説明。理屈は理解していたが、どうしてわざわざプログラムを書き換えるのか、納得がいかない様子でした。その後、正方形、三角形、円を描くをしました。ペンの書き方はレクチャーしましたが、基本的に全部自分で考えてプログラムできました。「〇度に向ける」を使ってプログラムをしていましたが、三角形では困っていたので「〇度まわす」を使って考えるようにアドバイスしました。 その後、自分でアレンジを加えてペンツールと図形で遊んでいました。面白かったそうです。', null, 'タイピング: 集中して取り組めました。'),
  ('7b47d4b4-137f-59f5-9a6e-1aedebca75b7', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-04', '16:30:00', null, '通常 / カエル_コインのカウント・むらっちバレーボール', 'カエルの冒険プログラムでコインカウントがうまく動いていなかったので修正しました。コインが隠れるタイミングとコインのカウントのタイミングが悪かったので、変更しました。修正点は私が見つけましたが、うまくいっていない理由についてしっかり言葉で説明できていたのでとても良かったです！ バレーボールでは、見本のプログラムをみてプログラムの仕組みをよく理解できていました！丁寧に説明してくれました。一方でボールの落とし方やプログラムの順序には悩んでいたので、キャッチゲームの資料を見せながら取り組んでもらいました。こちらが少し伝えるとその後は自分でプログラムできていました！！ボールが左右に動くプログラムと、必要に応じてボールの落下プログラムを今後守勢していく予定です。', null, 'タイピング: 集中して取り組めました！'),
  ('cd090eec-436c-5557-a674-1bafc6778596', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2025-03-04', '17:30:00', null, '通常 / カエルの冒険_宇宙へ', 'コインが実際の枚数よりも多くカウントされていたので修正をしました。二重でプログラムされていたのが原因のようでしたが、プレイする人によって変数が違ったのが少し謎です...コインのカウントがマックスになったときに宇宙へいくようにプログラムを作りました。 背景スクロールの仕組みは、変数を使って横向きのものを方向転換して横向きになっていることを伝えました。概要は理解できたようです。またその後、オリジナルのキャラを使ってアレンジをしました。ゲーム難易度が上がりました。また宇宙3の画面をアレンジして終わりの画面を作製しました。完成です！説明を付けて作品を公開しました！楽しそうで良かったです。', null, 'タイピング: 集中して取り組めました。'),
  ('8445ebd5-c902-5101-af8e-9d6be5c8cb49', '1c7005cc-2815-558f-993a-9c7617d34c44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-04', '16:30:00', null, '通常 / 教室に慣れる、Scratchの基本的なブロックを一つでも覚える', '入校同意書を書きながら、お母さんと「きちんと授業を受ける」と約束してきたようで、体験のときのような脱線もなく、58分間しっかりとレッスンを受けることができていました。 「作る」ことに対しても、体験のときよりも前向きで、最後まで飽きずに取り組めていました。 アルスタジオのレッスンのペースはわりと合っているようで、動画を見ながら操作することにより興味の対象がふらふらせずに済んでいた面もあったようです。 今日はレッスン内にあった「コスチュームの色を変える」「スプライトをずっと、〇秒でどこかの場所へいく」という二つをマスターすることを意識させ、5つのスプライトで同じ作業を反復することによって、最後の2つは先生がついていなくても自力でできるようになりました。完成するたびに、嬉しそうに先生を呼んでから緑の旗を押していました。 〇秒でどこかの場所へ行く、のブロックの後半が選べることが気になったようで、色々なスプライトを指定したりもしていましたが、途中でスプライトが動き続けず、水族館のようにならないことに気が付いて、元にもどしていました。 レッスンの範囲が完成したら、「これをゲームにしてみたい」と自分から言い出して、網のスプライトを追加し、今日学んだブロックを「マウスポインタ―に行く」にして、とても盛り上がっていました。', '今回の作品を、もっとゲームっぽくしたい、と言っていたので、「○○に触れたら」を学習できたらと思います。', 'タイピング: ゆっくりですが、一生懸命に最後まで打っていました。タイピングをするなら、大文字パソコンの方が良いかもしれません。
盛り上がり: 体験のときは、「作る」ことに対しての意欲がほとんど見られずに心配しましたが、今日はしっかりと「作る」ことを楽しめていました。コスチュームの色を変えることが面白かったようで、こだわって熱心にやっていました。お絵描き要素とプログラミング要素の両方ができたのも、よかったのかもしれません。'),
  ('8e1d4fe1-173d-5aa6-8f4b-86f33b7c65f5', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-06', '16:30:00', null, '通常 / 検定問題3級Eパターン', '複数回にわたってこの問題をおこなってきたため、そろそろ終わらせていきたいためコード作成に注力して取り組んでいきました。本人としては、イラスト部分にかなりこだわりがあるようなので、コード作成にはいまいち身が入っていない様子でしたが、完成後に行いたいイメージをしっかりと作品に入れていきたいという思いが強くなったようで、途中から集中して取り組むことができていました。時間としてはぎりぎりになってしまいましたが、作品を完成させてアレンジも入れられたということで満足していました。', null, null),
  ('34611e1d-4d26-5aa5-8a32-39820b956c29', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2025-03-06', '17:30:00', null, '通常 / 検定問題３級サンプル問題', '今月末に検定の本番があるということで、いつも以上に真剣に取り組んでいました。問題内容自体は本人のレベルからすると解けるものが多いですが、検定自体にあまり慣れていないようで、適切なブロックを選択するのにかなり戸惑っていた様子でした。そのため、とにかく量をこなしていくことによって検定問題に慣れていく必要があると感じました。そして、一度理解してしまえば同じような部分については順調に解いていくことができていたため、 本番までに経験を積ませていきたいです。', null, 'タイピング: より上の級を目指していこうと集中して取り組めていました。
備考: 条件分岐の順位づけで曖昧な箇所が見られたため、復習を行なっていく必要があるかもしれません。'),
  ('5c429f67-e388-5b17-bd34-a58d11e6968d', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-06', '17:30:00', null, '通常 / Excelの検定内容に慣れる', 'イラストコースがどのようなものなのか説明だけ聞いてみたいとのことで、柊くんと一緒に曹先生のコース内容説明を聞いていました。 結果、Excelの方がいいとのことで、授業内容を切り替えました。 前回作成した練習問題2の数式部分をすべて削除して、復習として入れなおしてみましたが、セルの範囲選択とオートフィルで毎回迷っていました。また、数式内のセルの範囲指定のためのドラッグを、数式入力前にしてしまうなどの混乱が見られたため、とりあえず慣れるまでは、「答えを入れたいセルを選択してから」というのを徹底するよう伝えました。 比を計算する際の絶対参照や、IF関数の書き方などは、よく覚えていました。 数式自体はすぐに理解できるのですが、最初に選ぶメニューをよく迷っているようでした。 新しい学習として、スパークライン、ワードアート、並べ替え、フィルタ、グラフを一通り学習しました。', null, 'タイピング: 毎パソの結果には満足そうでした。
盛り上がり: これまで聞いたことのない単語（オフセットなど）にとまどうこともありましたが、Excelの機能自体は面白がって取り組めていたようでした。
備考: 次回、教室でExcelの検定をする際には声掛けをすると伝え、本人とお母さんも了承しています。'),
  ('91484379-fa32-590a-8145-57a5938dab45', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-06', '16:30:00', null, '通常 / ジオメトリーダッシュ完成', 'ジオメトリーダッシュの続きを行いました。こたろうくんと一緒に、走る距離を作成しました。作った後にきちんと動作していないことに気づき、変数名の間違いを直していました。その後アレンジとして、キャラクターをソニックにしていました。それに合わせてブロックや残像も土の色に変更していました。各スプライトの役割を理解していたためスムーズにデザインの変更が行え、アレンジで詰まっていたこたろうくんにも教えたがっていました。', null, null),
  ('63d8276e-0ba2-5e1a-ac03-934ceb1a7bc6', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-06', '16:30:00', null, '通常 / ジオメトリーダッシュ完成', 'ジオメトリーダッシュの続きを行いました。走る距離が表示されていなかったのでそこから作りました。やる気が出ないようでしたが、距離の変数が旗を押したときどうなるのか、そしてそのあとどうやって増えるのかを追っていくと簡単に作れました。完成したのでアレンジに入り、操作するキャラクターをポケモンに変えるなどしていました。このとき、ポケモンのスプライトを新しく作っていたので全く動かず、プレイヤーのコスチュームとして入れることを促しました。', null, null),
  ('cf9d0131-224a-5912-86ae-07b04ba9dcd1', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-06', '17:30:00', null, '自由製作完成、ジオメトリーダッシュ', '自由製作の作品名を決め、内容を微調整して完成しました。残りの時間はジオメトリーダッシュに取り組みました。横スクロールのコードを書き、x座標を右から左まで流すというイメージをつかんだようでした。着地の当たり判定については、ステージのスプライトをよく観察することを促すと、ブロック上の方にある色で判定しているということに気づいたようでした。ただそのコード作成は次回に持ち越すことになりました。', null, 'タイピング: 長時間集中しました'),
  ('ae6de832-d072-57f9-93d5-94892acd80d8', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2025-03-06', '17:30:00', null, '通常 / 変数で速さを変えるなど', '前回までのキャッチゲームはもう大丈夫とのことで、新しいゲームとして脱出ゲームに取り組みました。遊んでもらったあと、どうやってボールを動かすかやカギはいつ消えるかなどについて軽く細分化しました。その後動画を見ながら作成していき、変数を使って速さをだんだん変えていくという重要なアイデアについては軽く説明して理解してもらいました。若干難しそうではありましたが興味を持って進めてくれました。動画の15分くらいまで終わりました。', null, 'タイピング: 頑張っていました'),
  ('c95a854c-e495-5ca4-a7cb-e4e7301e185c', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2025-03-06', '17:30:00', null, '通常 / ピンポンゲームのアレンジをしながら、基本的なブロックの復習をする', '前半は、スプライトのコスチュームの編集を熱心にやっていました。 他のスプライトのコスチュームを持ってきたり、細かいところを手書きで編集したりして気が済むと、自分から、ちょっとバグのような気がするコードをなんとかしたいと質問してきました。 ボールがパドルに当たった時の動きがおかしいため、どうしてそうなっているのか、「ずっと」の仕組みを説明して、どうすれば良いのかを一緒に考えました。パドルに触れた時にボールを回すブロックしか入れていなかったため、触れた判定が続いてしまっていることを納得させ、こちらが誘導しながら「動く」と「待つ」ブロックを付け足すところまでたどり着くことができました。 ボールがレッドラインに触れた時にコスチュームを変えたいのだけど、すぐにゲームが終わってしまうと質問してきたので、コードを見せて、ゲームが止まる前にコスチュームを変えるにはどうすれば良いかを考えさせ、止める前にメッセージを送ることに気付くことができました。 最終的に、レッドラインに触れた時にコスチュームを変更し、音を鳴らすことができて、満足そうに授業を終えました。', null, 'タイピング: 真面目に取り組んでいました
盛り上がり: やりたかったことができて、アレンジを完成させることができたので、満足気にスタンプを押していました。 「一度やったやつだけど」と謙遜もしていましたが、きちんとアレンジができたことを褒めると、嬉しそうにしていました。'),
  ('4f0b5e9a-bc26-5563-a206-9bad3d3ad274', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-06', '16:30:00', null, '通常 / イラストコース_模写', '今回は教室内の好きな物体を選んで写真を撮って構図を決めてもらい、それをデッサンと模写してもらいました。 デッサンと模写の違いを教えることが出来ました。 最初に好きに真似して描いてもらった時は実物や影をなぞったり、手に持って観察したりして描いていました。 次に模写する時はアイビスを使い、また写真をいくつかのブロックに分割して部分ごとに描いてもらうということをやってもらいました。 レイヤー分けの復習、今回テクニックとして投げ縄ツールとコピー＆ペーストの方法を教えることが出来ました。', null, 'タイピング: 集中して取り組めていました。'),
  ('a685831e-6f31-5c92-8ed0-2bc9cc50f992', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2025-03-06', '17:30:00', null, '通常 / イラストコース体験', 'イラストコースに興味があるとのことだったので説明をしました。 アイビスの教科書を眺めていたので、実際に触らせてあげると機能の多さに驚いていました。教科書表紙の「この光っている感じはどうやってやるの？」と疑問に思っていたので、レイヤーの仕組みや合成レイヤーについて教えました。ご自宅にiPadはあるそうですがペンツールも使ったが事ない様子でしたが、一回の説明で機能を把握していて良かったです。 「こういうので何が描きたいの？」と聞くと「いろいろ描けるようになりたい」とのことでしたが、まだコース加入するかまでの決定には至ってなかったです。', null, 'タイピング: なし'),
  ('0e0d7f26-7788-5b21-a86f-882cc3e0a003', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-07', '16:30:00', null, '通常 / 自由製作', '増築する際に今までの大きさだと画面が狭くなってしまうので、途中で大きさを変えていく仕組みを考えていきました。肝はクローンの大きさをどう制御するかで悩んでいました。そこで、こちら側から変数を挟んで大きさを変動させる方法のヒントを教えてました。そのヒントだけで自分の形にできていました。 今日はりょうじくんもいたかいもあっって、遊び気分が高めでした。', null, 'タイピング: 毎パソ全国4位おめでとう
盛り上がり: 同じ小学校のかなめくんできて喜んでいましたが、たいようくんがいなくなって少し悲しそうでした'),
  ('c741e9ed-0ede-50bc-983b-e39731ed2699', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-07', null, null, '通常 / Prg20ジャンプゲーム', '前回の終わり際に試したPrgジャンプゲームを作りはじめました。最初に、アル君のジャンプの動作について説明して、y座標をプラスマイナスすることで実現させる事は理解したようですが、それをスクリプトで自力で作成することはまだ難しいようだったので、少し手助けしてジャンプ処理自体は完成。次に草のスクロール処理を作るところで、今度はx座標を変えていく説明をしているところで、だいぶ無口になって意欲が低下状態になったと感じたので、少し雑談をして、リラックスしたところで、草スクロールの再会、x座標をマイナスしていって、左端までスクロール(x<-465になったとこ)したところで、x座標を右端に戻す(X=0)説明をしました。頭ではうんうんとうなづいて理解したようなのですが、スクリプトが全く書けないので、ヒントを与えつつサポートしましたが、ほとんど私が教えるような形になってしまいました。次回は続きからですが、若干まだ少し難しいかなとも感じでいます。', null, '時間帯: その他'),
  ('57c9c049-5011-5261-a4e3-595f3803f1db', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2025-03-07', '17:30:00', null, '通常 / 検定練習', '検定をどっちも受けるか考えるために、とりあえず2級の問題を解きました。 少し目を離していたのもあって、大体はみんなが立ち止まるロケットの計算問題回答の条件式のとことろが悩んでいました。文章の簡素化な部分のため、答えを一緒に考えていくと、｢ああなんだもしを使えばいいのか｣と能力的には大丈夫そうです。ほかの部分は7割くらいはできていたので、少し難しい所での文の読み方に慣れてもらいです。', null, null),
  ('97ae0525-9a6d-5faa-89f9-20c16bf4d5c6', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2025-03-07', '17:30:00', null, '通常 / 検定１級最初の問題', '検定１級最初にやる問題に挑戦。途中、ゆづき君、部長と話をしたりして、少し時間をロスした感じはしますが、実質50分より少ない時間で、ある程度完了くらいまで入ったようですが、実際に動作させてうまく動かないところが何箇所かあって、本人の感覚では６０点いくかいかないかくらいとのこと。次回は今日うまくいかなかったところを確認しつつ、新たな１級の問題に挑戦したいところです。', null, null)
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
